export enum UserRole {
  ADMIN = 'ADMIN',
  SPECIALIST = 'SPECIALIST'
}

export enum JobTitle {
  GERENTE = 'Gerente',
  SUBGERENTE = 'Subgerente',
  LIDER_TURNO = 'Líder de turno',
  ENTRENADOR = 'Entrenador',
  MIEMBRO_EQUIPO = 'Miembro de equipo',
  DOMICILIARIO = 'Domiciliario'
}

export const JobHierarchy: Record<JobTitle, number> = {
  [JobTitle.GERENTE]: 1,
  [JobTitle.SUBGERENTE]: 2,
  [JobTitle.LIDER_TURNO]: 3,
  [JobTitle.ENTRENADOR]: 4,
  [JobTitle.MIEMBRO_EQUIPO]: 5,
  [JobTitle.DOMICILIARIO]: 6
};

export interface User {
  id: string;
  username: string;
  role: UserRole;
  assignedZones: string[];
  assignedRestaurants: string[];
}

export interface Employee {
  id: string; // Cédula
  name: string;
  joinDate: string;
  title: JobTitle;
  restaurantId: string;
  zone: string;
  active: boolean;
}

export interface GradeEntry {
  employeeId: string;
  month: string; // YYYY-MM
  group: string;
  category: string;
  score: number; // 0-100
}

export interface Restaurant {
  id: string;
  name: string;
  zone: string;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

export const EVALUATION_GROUPS = {
  'A': {
    name: 'Básicos',
    categories: ['Introducción', 'SST', 'Seguridad de alimentos']
  },
  'B': {
    name: 'Star',
    categories: ['Equipos', 'Producción', 'Servicio', 'Ensamble', 'Domicilios', 'Heladería']
  },
