import { Employee, GradeEntry, User, UserRole, JobTitle } from './types';
import { INITIAL_RESTAURANTS } from './constants';

const STORAGE_KEY_EMPLOYEES = 'la_akademia_employees';
const STORAGE_KEY_GRADES = 'la_akademia_grades';
const STORAGE_KEY_USERS = 'la_akademia_users';

export const dataService = {
  getEmployees: (): Employee[] => {
    const data = localStorage.getItem(STORAGE_KEY_EMPLOYEES);
    if (!data) {
      // Seed data
      const seed: Employee[] = [
        { id: '102030', name: 'Juan Pérez', joinDate: '2023-01-15', title: JobTitle.GERENTE, restaurantId: 'R1', zone: 'Zona Norte', active: true },
        { id: '102031', name: 'Maria Garcia', joinDate: '2023-06-10', title: JobTitle.SUBGERENTE, restaurantId: 'R1', zone: 'Zona Norte', active: true },
        { id: '102032', name: 'Carlos Ruiz', joinDate: '2024-02-20', title: JobTitle.MIEMBRO_EQUIPO, restaurantId: 'R2', zone: 'Zona Norte', active: true },
      ];
      localStorage.setItem(STORAGE_KEY_EMPLOYEES, JSON.stringify(seed));
      return seed;
    }
    return JSON.parse(data);
  },

  saveEmployees: (employees: Employee[]) => {
    localStorage.setItem(STORAGE_KEY_EMPLOYEES, JSON.stringify(employees));
  },

  getGrades: (): GradeEntry[] => {
    const data = localStorage.getItem(STORAGE_KEY_GRADES);
    return data ? JSON.parse(data) : [];
  },

  saveGrades: (grades: GradeEntry[]) => {
    localStorage.setItem(STORAGE_KEY_GRADES, JSON.stringify(grades));
  },

  updateGrade: (entry: GradeEntry) => {
    const grades = dataService.getGrades();
    const index = grades.findIndex(g => 
      g.employeeId === entry.employeeId && 
      g.month === entry.month && 
      g.group === entry.group && 
      g.category === entry.category
    );

    if (index > -1) {
      grades[index] = entry;
    } else {
      grades.push(entry);
    }
    dataService.saveGrades(grades);
  },

  getUsers: (): User[] => {
    const data = localStorage.getItem(STORAGE_KEY_USERS);
    if (!data) {
      const seed: User[] = [
        { id: 'admin1', username: 'admin', role: UserRole.ADMIN, assignedZones: [], assignedRestaurants: [] },
        { id: 'spec1', username: 'especialista1', role: UserRole.SPECIALIST, assignedZones: ['Zona Norte'], assignedRestaurants: ['R1', 'R2'] },
      ];
      localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(seed));
      return seed;
    }
    return JSON.parse(data);
  },

  calculateSeniority: (joinDate: string): number => {
    const join = new Date(joinDate);
    const now = new Date();
    const years = now.getFullYear() - join.getFullYear();
    const months = now.getMonth() - join.getMonth();
    return years * 12 + months;
  },

  importMonthlyExcel: (newData: any[]) => {
    // Simulated Excel Import Logic
    const currentEmployees = dataService.getEmployees();

    // In a real app, we'd map Excel headers to our Employee object
    // For this simulation, we assume newData is already formatted
    const updatedEmployees = newData.map(item => {
      const existing = currentEmployees.find(e => e.id === item.id);
      return {
        ...item,
        // Preserve other data if needed
      };
    });

    dataService.saveEmployees(updatedEmployees);
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, UserRole, AuthState, Employee, Restaurant, JobTitle, JobHierarchy } from './types';
import { dataService } from './dataService';
import { INITIAL_RESTAURANTS } from './constants';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import EmployeeList from './components/EmployeeList';
import AdminPanel from './components/AdminPanel';
import Header from './components/Header';
import { LayoutDashboard, Users, ShieldAlert, LogOut } from 'lucide-react';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({ user: null, isAuthenticated: false });
  const [activeTab, setActiveTab] = useState<'dashboard' | 'employees' | 'admin'>('dashboard');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [restaurants, setRestaurants] = useState<Restaurant[]>(INITIAL_RESTAURANTS);
  const [selectedMonth, setSelectedMonth] = useState<string>(new Date().toISOString().slice(0, 7));

  useEffect(() => {
    // Initial data load
    setEmployees(dataService.getEmployees());
  }, []);

  const handleLogin = (user: User) => {
    setAuth({ user, isAuthenticated: true });
    setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
  };

  const filteredEmployees = useMemo(() => {
    if (!auth.user) return [];
    if (auth.user.role === UserRole.ADMIN) return employees;

    return employees.filter(e => 
      auth.user?.assignedZones.includes(e.zone) || 
      auth.user?.assignedRestaurants.includes(e.restaurantId)
    );
  }, [employees, auth.user]);

  if (!auth.isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="flex h-screen bg-gray-50">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        role={auth.user!.role}
        onLogout={handleLogout}
      />

      <div className="flex-1 flex flex-col overflow-hidden">
        <Header user={auth.user!} selectedMonth={selectedMonth} onMonthChange={setSelectedMonth} />

        <main className="flex-1 overflow-x-hidden overflow-y-auto p-6">
          {activeTab === 'dashboard' && (
            <Dashboard 
              employees={filteredEmployees} 
              selectedMonth={selectedMonth}
              user={auth.user!}
            />
          )}

          {activeTab === 'employees' && (
            <EmployeeList 
              employees={filteredEmployees}
              restaurants={restaurants}
              selectedMonth={selectedMonth}
              user={auth.user!}
              onUpdate={() => setEmployees(dataService.getEmployees())}
            />
          )}

          {activeTab === 'admin' && auth.user?.role === UserRole.ADMIN && (
            <AdminPanel 
              onEmployeesImported={() => setEmployees(dataService.getEmployees())}
            />
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

