import React, { useMemo } from 'react';
import { Employee, GradeEntry, User } from '../types';
import { dataService } from '../dataService';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { CheckCircle, XCircle, Users, Award, TrendingUp } from 'lucide-react';

interface DashboardProps {
  employees: Employee[];
  selectedMonth: string;
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ employees, selectedMonth, user }) => {
  const grades = useMemo(() => dataService.getGrades().filter(g => g.month === selectedMonth), [selectedMonth]);

  const stats = useMemo(() => {
    const totalEmployees = employees.length;
    let approvedCount = 0;

    const groupAvgs = Object.keys(EVALUATION_GROUPS).map(groupId => {
      const groupGrades = grades.filter(g => g.group === groupId && employees.some(e => e.id === g.employeeId));
      const avg = groupGrades.length > 0 ? groupGrades.reduce((sum, g) => sum + g.score, 0) / groupGrades.length : 0;
      return {
        id: groupId,
        name: (EVALUATION_GROUPS as any)[groupId].name,
        avg: Math.round(avg)
      };
    });

    // Simple approval logic: if overall average across all required modules is > threshold
    employees.forEach(emp => {
      const empGrades = grades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        const avg = empGrades.reduce((sum, g) => sum + g.score, 0) / empGrades.length;
        if (avg >= APPROVAL_THRESHOLD) approvedCount++;
      }
    });

    return { totalEmployees, approvedCount, groupAvgs };
  }, [employees, grades]);

  const COLORS = ['#ef4444', '#22c55e'];

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          icon={<Users className="w-6 h-6" />}
          label="Trabajadores"
          value={stats.totalEmployees}
          subValue="Total en zona/asignados"
        />
        <StatCard 
          icon={<Award className="w-6 h-6" />}
          label="Certificados"
          value={stats.approvedCount}
          subValue={`${Math.round((stats.approvedCount / (stats.totalEmployees || 1)) * 100)}% de cumplimiento`}
          color="green"
        />
        <StatCard 
          icon={<TrendingUp className="w-6 h-6" />}
          label="Promedio General"
          value={`${Math.round(stats.groupAvgs.reduce((s, g) => s + g.avg, 0) / stats.groupAvgs.length)}%`}
          subValue="Mes actual"
          color="blue"
        />
        <StatCard 
          icon={<XCircle className="w-6 h-6" />}
          label="Pendientes"
          value={stats.totalEmployees - stats.approvedCount}
          subValue="Sin certificar"
          color="red"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h3 className="text-lg font-bold text-gray-800 mb-6">Promedio por Grupo de Evaluación</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.groupAvgs}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" />
                <YAxis domain={[0, 100]} />
                <Tooltip />
                <Bar dataKey="avg" radius={[4, 4, 0, 0]}>
                  {stats.groupAvgs.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.avg >= APPROVAL_THRESHOLD ? '#22c55e' : '#ef4444'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h3 className="text-lg font-bold text-gray-800 mb-6">Estado de Certificación</h3>
          <div className="h-[300px] flex items-center justify-center">
             <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={[
                      { name: 'No Aprobado', value: stats.totalEmployees - stats.approvedCount },
                      { name: 'Aprobado', value: stats.approvedCount },
                    ]}
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={100}
                    paddingAngle={5}
                    dataKey="value"
                  >
                    {COLORS.map((color, index) => <Cell key={`cell-${index}`} fill={color} />)}
                  </Pie>
                  <Tooltip />
                </PieChart>
             </ResponsiveContainer>
             <div className="absolute flex flex-col items-center">
                <span className="text-3xl font-bold">{Math.round((stats.approvedCount / (stats.totalEmployees || 1)) * 100)}%</span>
                <span className="text-xs text-gray-400">Completado</span>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ icon: React.ReactNode, label: string, value: string | number, subValue: string, color?: string }> = ({ icon, label, value, subValue, color = 'gray' }) => {
  const colorMap: any = {
    red: 'bg-red-50 text-red-600',
    green: 'bg-green-50 text-green-600',
    blue: 'bg-blue-50 text-blue-600',
    gray: 'bg-gray-50 text-gray-600',
  };
  return (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
      <div className="flex items-center space-x-4">
        <div className={`p-3 rounded-lg ${colorMap[color]}`}>{icon}</div>
        <div>
          <p className="text-sm text-gray-500 font-medium">{label}</p>
          <h4 className="text-2xl font-bold text-gray-800">{value}</h4>
          <p className="text-xs text-gray-400 mt-1">{subValue}</p>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Employee, Restaurant, JobHierarchy, User, GradeEntry } from '../types';
import { Search, ChevronRight, Edit3, Filter } from 'lucide-react';
import GradeEditor from './GradeEditor';
import { APPROVAL_THRESHOLD } from '../constants';
import { dataService } from '../dataService';

interface EmployeeListProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
  onUpdate: () => void;
}

const EmployeeList: React.FC<EmployeeListProps> = ({ employees, restaurants, selectedMonth, user, onUpdate }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedRestaurant, setSelectedRestaurant] = useState<string>('all');
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  const filteredAndSorted = useMemo(() => {
    let result = employees.filter(e => 
      (searchTerm === '' || e.name.toLowerCase().includes(searchTerm.toLowerCase()) || e.id.includes(searchTerm)) &&
      (selectedRestaurant === 'all' || e.restaurantId === selectedRestaurant)
    );

    // Sorting by Hierarchy
    return result.sort((a, b) => JobHierarchy[a.title] - JobHierarchy[b.title]);
  }, [employees, searchTerm, selectedRestaurant]);

  const allGrades = useMemo(() => dataService.getGrades().filter(g => g.month === selectedMonth), [selectedMonth, editingEmployee]);

  const getStatus = (employeeId: string) => {
    const grades = allGrades.filter(g => g.employeeId === employeeId);
    if (grades.length === 0) return 'PENDING';
    const avg = grades.reduce((s, g) => s + g.score, 0) / grades.length;
    return avg >= APPROVAL_THRESHOLD ? 'APPROVED' : 'FAILED';
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
