import React, { useState, useEffect } from 'react';
import { Employee, GradeEntry } from '../types';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD } from '../constants';
import { dataService } from '../dataService';
import { X, Save, Info } from 'lucide-react';

interface GradeEditorProps {
  employee: Employee;
  month: string;
  onClose: () => void;
}

const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('A');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);

  useEffect(() => {
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    setFormGrades(existing);
  }, [employee, month]);

  const handleScoreChange = (group: string, category: string, score: number) => {
    const sanitizedScore = Math.max(0, Math.min(100, score));
    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) {
        const next = [...prev];
        next[idx] = { ...next[idx], score: sanitizedScore };
        return next;
      }
      return [...prev, { employeeId: employee.id, month, group, category, score: sanitizedScore }];
    });
  };

  const saveGrades = () => {
    const allGrades = dataService.getGrades();
    // Filter out previous grades for this employee/month to replace with new set
    const filtered = allGrades.filter(g => !(g.employeeId === employee.id && g.month === month));
    dataService.saveGrades([...filtered, ...formGrades]);
    onClose();
  };

  const getScore = (group: string, category: string) => {
    return formGrades.find(g => g.group === group && g.category === category)?.score ?? 0;
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-4xl max-h-[90vh] flex flex-col overflow-hidden">
        <div className="p-6 border-b border-gray-100 flex items-center justify-between bg-red-600 text-white">
          <div>
            <h2 className="text-xl font-bold">{employee.name}</h2>
            <p className="text-xs opacity-80 uppercase tracking-wider">{employee.title} • Cédula: {employee.id} • Mes: {month}</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition">
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="flex-1 flex overflow-hidden">
          {/* Group Navigation */}
          <div className="w-64 bg-gray-50 border-r border-gray-200 overflow-y-auto">
            {Object.entries(EVALUATION_GROUPS).map(([id, group]) => {
               const groupGrades = formGrades.filter(g => g.group === id);
               const avg = groupGrades.length > 0 ? groupGrades.reduce((s, g) => s + g.score, 0) / groupGrades.length : 0;
               return (
                <button
                  key={id}
                  onClick={() => setActiveGroup(id)}
                  className={`w-full text-left px-6 py-4 transition flex flex-col border-b border-gray-100 ${
                    activeGroup === id ? 'bg-white border-l-4 border-l-red-600' : 'hover:bg-gray-100'
                  }`}
                >
                  <span className={`text-xs font-bold uppercase ${activeGroup === id ? 'text-red-600' : 'text-gray-400'}`}>Grupo {id}</span>
                  <span className="text-sm font-semibold text-gray-700 truncate">{group.name}</span>
                  <span className={`text-xs mt-1 font-bold ${avg >= APPROVAL_THRESHOLD ? 'text-green-600' : 'text-red-600'}`}>
                    Avg: {Math.round(avg)}%
                  </span>
                </button>
              );
            })}
          </div>

          {/* Categories Grid */}
          <div className="flex-1 p-8 overflow-y-auto">
            <div className="mb-6 flex items-center p-4 bg-blue-50 text-blue-700 rounded-lg border border-blue-100">
              <Info className="w-5 h-5 mr-3 flex-shrink-0" />
              <p className="text-sm">Ingrese puntajes de 0 a 100%. Recuerde que el mínimo aprobatorio es <strong>{APPROVAL_THRESHOLD}%</strong>.</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                const score = getScore(activeGroup, cat);
                return (
                  <div key={cat} className="space-y-2">
                    <label className="text-sm font-semibold text-gray-700 block">{cat}</label>
                    <div className="flex items-center space-x-3">
                      <input
                        type="number"
                        min="0"
                        max="100"
                        value={score}
                        onChange={(e) => handleScoreChange(activeGroup, cat, parseInt(e.target.value) || 0)}
                        className={`w-24 px-4 py-2 border rounded-lg focus:ring-2 focus:ring-red-500 outline-none font-bold ${
                          score >= APPROVAL_THRESHOLD ? 'border-green-200 bg-green-50 text-green-700' : 'border-red-200 bg-red-50 text-red-700'
                        }`}
                      />
                      <div className="flex-1 h-2 bg-gray-100 rounded-full overflow-hidden">
                        <div 
                          className={`h-full transition-all duration-300 ${score >= APPROVAL_THRESHOLD ? 'bg-green-500' : 'bg-red-500'}`}
                          style={{ width: `${score}%` }}
                        />
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        <div className="p-6 border-t border-gray-100 bg-gray-50 flex justify-end space-x-4">
          <button 
            onClick={onClose}
            className="px-6 py-2 border border-gray-300 rounded-lg text-sm font-semibold text-gray-600 hover:bg-gray-100 transition"
          >
            Cancelar
          </button>
          <button 
            onClick={saveGrades}
            className="px-6 py-2 bg-red-600 text-white rounded-lg text-sm font-semibold hover:bg-red-700 shadow-lg flex items-center transition"
          >
            <Save className="w-4 h-4 mr-2" /> Guardar Cambios
          </button>
        </div>
      </div>
    </div>
  );
};

export default GradeEditor;

