import React, { useState, useEffect, useMemo } from 'react';
import { User, UserRole, AuthState, Employee, Restaurant, JobTitle, JobHierarchy } from './types';
import { dataService } from './dataService';
import { INITIAL_RESTAURANTS } from './constants';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import EmployeeList from './components/EmployeeList';
import AdminPanel from './components/AdminPanel';
import Header from './components/Header';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({ user: null, isAuthenticated: false });
  const [activeTab, setActiveTab] = useState<'dashboard' | 'employees' | 'admin'>('dashboard');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [restaurants, setRestaurants] = useState<Restaurant[]>(INITIAL_RESTAURANTS);
  const [selectedMonth, setSelectedMonth] = useState<string>(new Date().toISOString().slice(0, 7));
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  useEffect(() => {
    // Initial data load
    setEmployees(dataService.getEmployees());
  }, []);

  const handleLogin = (user: User) => {
    setAuth({ user, isAuthenticated: true });
    setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
  };

  const filteredEmployees = useMemo(() => {
    if (!auth.user) return [];
    if (auth.user.role === UserRole.ADMIN) return employees;

    return employees.filter(e => 
      auth.user?.assignedZones.includes(e.zone) || 
      auth.user?.assignedRestaurants.includes(e.restaurantId)
    );
  }, [employees, auth.user]);

  if (!auth.isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden relative">
      {/* Mobile Backdrop */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 lg:hidden" 
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={(tab) => {
          setActiveTab(tab);
          setIsSidebarOpen(false); // Close on mobile after selection
        }} 
        role={auth.user!.role}
        onLogout={handleLogout}
        isOpen={isSidebarOpen}
        setIsOpen={setIsSidebarOpen}
      />

      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header 
          user={auth.user!} 
          selectedMonth={selectedMonth} 
          onMonthChange={setSelectedMonth}
          onMenuClick={() => setIsSidebarOpen(true)}
        />

        <main className="flex-1 overflow-x-hidden overflow-y-auto p-4 md:p-6">
          {activeTab === 'dashboard' && (
            <Dashboard 
              employees={filteredEmployees} 
              selectedMonth={selectedMonth}
              user={auth.user!}
            />
          )}

          {activeTab === 'employees' && (
            <EmployeeList 
              employees={filteredEmployees}
              restaurants={restaurants}
              selectedMonth={selectedMonth}
              user={auth.user!}
              onUpdate={() => setEmployees(dataService.getEmployees())}
            />
          )}

          {activeTab === 'admin' && auth.user?.role === UserRole.ADMIN && (
            <AdminPanel 
              onEmployeesImported={() => setEmployees(dataService.getEmployees())}
            />
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

