import { EVALUATION_GROUPS, APPROVAL_THRESHOLD } from '../constants';
import { dataService } from '../dataService';
import { X, Save, Info } from 'lucide-react';

interface GradeEditorProps {
  employee: Employee;
  month: string;
  onClose: () => void;
}

const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('A');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);

  useEffect(() => {
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    setFormGrades(existing);
  }, [employee, month]);

  const handleScoreChange = (group: string, category: string, score: number) => {
    const sanitizedScore = Math.max(0, Math.min(100, score));
    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) {
        const next = [...prev];
        next[idx] = { ...next[idx], score: sanitizedScore };
        return next;
      }
      return [...prev, { employeeId: employee.id, month, group, category, score: sanitizedScore }];
    });
  };

  const saveGrades = () => {
    const allGrades = dataService.getGrades();
    const filtered = allGrades.filter(g => !(g.employeeId === employee.id && g.month === month));
    dataService.saveGrades([...filtered, ...formGrades]);
    onClose();
  };

  const getScore = (group: string, category: string) => {
    return formGrades.find(g => g.group === group && g.category === category)?.score ?? 0;
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-0 md:p-4">
      <div className="bg-white rounded-none md:rounded-2xl shadow-2xl w-full max-w-4xl h-full md:h-auto md:max-h-[90vh] flex flex-col overflow-hidden">
        {/* Header */}
        <div className="p-4 md:p-6 border-b border-gray-100 flex items-center justify-between bg-red-600 text-white shrink-0">
          <div className="min-w-0">
            <h2 className="text-lg md:text-xl font-bold truncate">{employee.name}</h2>
            <p className="text-[10px] md:text-xs opacity-80 uppercase tracking-wider truncate">
              {employee.title} • {employee.id} • {month}
            </p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition shrink-0 ml-2">
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
          {/* Group Navigation - Horizontal on Mobile, Vertical on Desktop */}
          <div className="w-full md:w-64 bg-gray-50 border-b md:border-b-0 md:border-r border-gray-200 overflow-x-auto md:overflow-y-auto scrollbar-hide shrink-0">
            <div className="flex md:flex-col min-w-max md:min-w-0">
              {Object.entries(EVALUATION_GROUPS).map(([id, group]) => {
                const groupGrades = formGrades.filter(g => g.group === id);
                const avg = groupGrades.length > 0 ? groupGrades.reduce((s, g) => s + g.score, 0) / groupGrades.length : 0;
                const isActive = activeGroup === id;

                return (
                  <button
                    key={id}
                    onClick={() => setActiveGroup(id)}
                    className={`px-4 md:px-6 py-3 md:py-4 transition flex flex-col shrink-0 border-b-2 md:border-b md:border-l-4 text-left ${
                      isActive 
                        ? 'bg-white border-b-red-600 md:border-b-gray-100 md:border-l-red-600' 
                        : 'bg-gray-50 border-b-transparent md:border-b-gray-100 md:border-l-transparent hover:bg-gray-100'
                    }`}
                  >
                    <span className={`text-[10px] font-bold uppercase ${isActive ? 'text-red-600' : 'text-gray-400'}`}>
                      Grupo {id}
                    </span>
                    <span className={`text-xs md:text-sm font-semibold truncate ${isActive ? 'text-gray-900' : 'text-gray-600'}`}>
                      {group.name}
                    </span>
                    <span className={`text-[10px] md:text-xs mt-0.5 font-bold ${avg >= APPROVAL_THRESHOLD ? 'text-green-600' : 'text-red-600'}`}>
                      {Math.round(avg)}%
                    </span>
                  </button>
                );
              })}
            </div>
          </div>

          {/* Categories Grid */}
          <div className="flex-1 p-4 md:p-8 overflow-y-auto bg-white">
            <div className="mb-4 md:mb-6 flex items-start p-3 md:p-4 bg-blue-50 text-blue-700 rounded-lg border border-blue-100">
              <Info className="w-4 h-4 md:w-5 md:h-5 mr-2 md:mr-3 mt-0.5 shrink-0" />
              <p className="text-xs md:text-sm leading-tight">
                Escala: 0-100%. Aprobación: <strong>{APPROVAL_THRESHOLD}%</strong>.
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6">
              {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                const score = getScore(activeGroup, cat);
                return (
                  <div key={cat} className="space-y-1.5 md:space-y-2 p-3 border border-gray-50 rounded-xl bg-gray-50/30 md:bg-transparent">
                    <label className="text-xs md:text-sm font-semibold text-gray-700 block line-clamp-1">{cat}</label>
                    <div className="flex items-center space-x-3">
                      <input
                        type="number"
                        min="0"
                        max="100"
                        inputMode="numeric"
                        value={score}
                        onChange={(e) => handleScoreChange(activeGroup, cat, parseInt(e.target.value) || 0)}
                        className={`w-16 md:w-20 px-2 md:px-3 py-2 border rounded-lg focus:ring-2 focus:ring-red-500 outline-none font-bold text-center text-sm md:text-base ${
                          score >= APPROVAL_THRESHOLD ? 'border-green-200 bg-green-50 text-green-700' : 'border-red-200 bg-red-50 text-red-700'
                        }`}
                      />
                      <div className="flex-1 h-2 md:h-2.5 bg-gray-200 rounded-full overflow-hidden">
                        <div 
                          className={`h-full transition-all duration-300 ${score >= APPROVAL_THRESHOLD ? 'bg-green-500' : 'bg-red-500'}`}
                          style={{ width: `${score}%` }}
                        />
                      </div>
                      <span className={`text-xs font-bold w-8 text-right ${score >= APPROVAL_THRESHOLD ? 'text-green-600' : 'text-red-600'}`}>
                        {score}%
                      </span>
                    </div>
                  </div>
                );
              })}
            </div>

            {/* Spacer for mobile scroll */}
            <div className="h-20 md:hidden" />
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-4 md:p-6 border-t border-gray-100 bg-gray-50 flex flex-col md:flex-row justify-end gap-3 md:gap-4 shrink-0">
          <button 
            onClick={onClose}
            className="w-full md:w-auto px-6 py-2.5 md:py-2 border border-gray-300 rounded-xl text-sm font-semibold text-gray-600 hover:bg-gray-100 transition order-2 md:order-1"
          >
            Cancelar
          </button>
          <button 
            onClick={saveGrades}
            className="w-full md:w-auto px-6 py-2.5 md:py-2 bg-red-600 text-white rounded-xl text-sm font-semibold hover:bg-red-700 shadow-lg flex items-center justify-center transition order-1 md:order-2"
          >
            <Save className="w-4 h-4 mr-2" /> Guardar Cambios
          </button>
        </div>
      </div>
    </div>
  );
};

export default GradeEditor;

import React, { useState, useEffect, useMemo } from 'react';
import { User, UserRole, AuthState, Employee, Restaurant, JobTitle, JobHierarchy } from './types';
import { dataService } from './dataService';
import { INITIAL_RESTAURANTS } from './constants';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import EmployeeList from './components/EmployeeList';
import AdminPanel from './components/AdminPanel';
import Header from './components/Header';
import MyStores from './components/MyStores';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({ user: null, isAuthenticated: false });
  const [activeTab, setActiveTab] = useState<'dashboard' | 'my-stores' | 'employees' | 'admin'>('dashboard');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [restaurants, setRestaurants] = useState<Restaurant[]>(INITIAL_RESTAURANTS);
  const [selectedMonth, setSelectedMonth] = useState<string>(new Date().toISOString().slice(0, 7));
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  useEffect(() => {
    setEmployees(dataService.getEmployees());
  }, []);

  const handleLogin = (user: User) => {
    setAuth({ user, isAuthenticated: true });
    setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
  };

  const filteredEmployees = useMemo(() => {
    if (!auth.user) return [];
    if (auth.user.role === UserRole.ADMIN) return employees;

    return employees.filter(e => 
      auth.user?.assignedZones.includes(e.zone) || 
      auth.user?.assignedRestaurants.includes(e.restaurantId)
    );
  }, [employees, auth.user]);

  if (!auth.isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden relative">
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 lg:hidden" 
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={(tab) => {
          setActiveTab(tab);
          setIsSidebarOpen(false);
        }} 
        role={auth.user!.role}
        onLogout={handleLogout}
        isOpen={isSidebarOpen}
        setIsOpen={setIsSidebarOpen}
      />

      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header 
          user={auth.user!} 
          selectedMonth={selectedMonth} 
          onMonthChange={setSelectedMonth}
          onMenuClick={() => setIsSidebarOpen(true)}
        />

        <main className="flex-1 overflow-x-hidden overflow-y-auto p-4 md:p-6">
          {activeTab === 'dashboard' && (
            <Dashboard 
              employees={filteredEmployees} 
              restaurants={restaurants}
              selectedMonth={selectedMonth}
              user={auth.user!}
            />
          )}

          {activeTab === 'my-stores' && (
            <MyStores 
              user={auth.user!}
              restaurants={restaurants}
              employees={employees}
              selectedMonth={selectedMonth}
            />
          )}

          {activeTab === 'employees' && (
            <EmployeeList 
              employees={filteredEmployees}
              restaurants={restaurants}
              selectedMonth={selectedMonth}
              user={auth.user!}
              onUpdate={() => setEmployees(dataService.getEmployees())}
            />
          )}

          {activeTab === 'admin' && auth.user?.role === UserRole.ADMIN && (
            <AdminPanel 
              onEmployeesImported={() => setEmployees(dataService.getEmployees())}
            />
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

