import React, { useMemo, useState } from 'react';
import { Employee, GradeEntry, User, Restaurant, UserRole } from '../types';
import { dataService } from '../dataService';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, INITIAL_ZONES } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { CheckCircle, XCircle, Users, Award, TrendingUp, Search, Filter } from 'lucide-react';

interface DashboardProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ employees: initialEmployees, restaurants, selectedMonth, user }) => {
  const [searchPerson, setSearchPerson] = useState('');
  const [filterStore, setFilterStore] = useState('all');
  const [filterZone, setFilterZone] = useState('all');

  const filteredData = useMemo(() => {
    return initialEmployees.filter(e => {
      const matchPerson = searchPerson === '' || e.name.toLowerCase().includes(searchPerson.toLowerCase()) || e.id.includes(searchPerson);
      const matchStore = filterStore === 'all' || e.restaurantId === filterStore;
      const matchZone = filterZone === 'all' || e.zone === filterZone;
      return matchPerson && matchStore && matchZone;
    });
  }, [initialEmployees, searchPerson, filterStore, filterZone]);

  const grades = useMemo(() => dataService.getGrades().filter(g => g.month === selectedMonth), [selectedMonth]);

  const stats = useMemo(() => {
    const totalEmployees = filteredData.length;
    let approvedCount = 0;

    const groupAvgs = Object.keys(EVALUATION_GROUPS).map(groupId => {
      const groupGrades = grades.filter(g => g.group === groupId && filteredData.some(e => e.id === g.employeeId));
      const avg = groupGrades.length > 0 ? groupGrades.reduce((sum, g) => sum + g.score, 0) / groupGrades.length : 0;
      return {
        id: groupId,
        name: (EVALUATION_GROUPS as any)[groupId].name,
        avg: Math.round(avg)
      };
    });

    filteredData.forEach(emp => {
      const empGrades = grades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        const avg = empGrades.reduce((sum, g) => sum + g.score, 0) / empGrades.length;
        if (avg >= APPROVAL_THRESHOLD) approvedCount++;
      }
    });

    return { totalEmployees, approvedCount, groupAvgs };
  }, [filteredData, grades]);

  const COLORS = ['#ef4444', '#22c55e'];

  return (
    <div className="space-y-6">
      {/* Filters Section */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="relative">
          <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Buscar Persona</label>
          <div className="relative">
            <Search className="w-4 h-4 text-gray-400 absolute left-3 top-1/2 -translate-y-1/2" />
            <input 
              type="text" 
              placeholder="Cédula o nombre..."
              value={searchPerson}
              onChange={(e) => setSearchPerson(e.target.value)}
              className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-red-500 outline-none"
            />
          </div>
        </div>
        <div>
          <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Filtrar Tienda</label>
          <select 
            value={filterStore}
            onChange={(e) => setFilterStore(e.target.value)}
            className="w-full px-4 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-red-500 outline-none appearance-none bg-white"
          >
            <option value="all">Todas las tiendas</option>
            {restaurants.filter(r => user.role === UserRole.ADMIN || user.assignedRestaurants.includes(r.id)).map(r => (
              <option key={r.id} value={r.id}>{r.name}</option>
            ))}
          </select>
        </div>
        <div>
          <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Filtrar Zona</label>
          <select 
            value={filterZone}
            onChange={(e) => setFilterZone(e.target.value)}
            className="w-full px-4 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-red-500 outline-none appearance-none bg-white"
          >
            <option value="all">Todas las zonas</option>
            {INITIAL_ZONES.filter(z => user.role === UserRole.ADMIN || user.assignedZones.includes(z)).map(z => (
              <option key={z} value={z}>{z}</option>
            ))}
          </select>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          icon={<Users className="w-6 h-6" />}
          label="Trabajadores"
          value={stats.totalEmployees}
          subValue="En el filtro actual"
        />
        <StatCard 
          icon={<Award className="w-6 h-6" />}
          label="Certificados"
          value={stats.approvedCount}
          subValue={`${stats.totalEmployees > 0 ? Math.round((stats.approvedCount / stats.totalEmployees) * 100) : 0}% de cumplimiento`}
          color="green"
        />
        <StatCard 
          icon={<TrendingUp className="w-6 h-6" />}
          label="Promedio General"
          value={`${stats.groupAvgs.length > 0 ? Math.round(stats.groupAvgs.reduce((s, g) => s + g.avg, 0) / stats.groupAvgs.length) : 0}%`}
          subValue="Selección actual"
          color="blue"
        />
        <StatCard 
          icon={<XCircle className="w-6 h-6" />}
          label="Pendientes"
          value={stats.totalEmployees - stats.approvedCount}
          subValue="Por certificar"
          color="red"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h3 className="text-lg font-bold text-gray-800 mb-6">Promedio por Grupo de Evaluación</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.groupAvgs}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" />
                <YAxis domain={[0, 100]} />
                <Tooltip />
                <Bar dataKey="avg" radius={[4, 4, 0, 0]}>
                  {stats.groupAvgs.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.avg >= APPROVAL_THRESHOLD ? '#22c55e' : '#ef4444'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h3 className="text-lg font-bold text-gray-800 mb-6">Estado de Certificación</h3>
          <div className="h-[300px] flex items-center justify-center relative">
             <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={[
                      { name: 'No Aprobado', value: stats.totalEmployees - stats.approvedCount },
                      { name: 'Aprobado', value: stats.approvedCount },
                    ]}
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={100}
                    paddingAngle={5}
                    dataKey="value"
                  >
                    {COLORS.map((color, index) => <Cell key={`cell-${index}`} fill={color} />)}
                  </Pie>
                  <Tooltip />
                </PieChart>
             </ResponsiveContainer>
             <div className="absolute flex flex-col items-center">
                <span className="text-3xl font-bold">{stats.totalEmployees > 0 ? Math.round((stats.approvedCount / stats.totalEmployees) * 100) : 0}%</span>
                <span className="text-xs text-gray-400">Completado</span>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ icon: React.ReactNode, label: string, value: string | number, subValue: string, color?: string }> = ({ icon, label, value, subValue, color = 'gray' }) => {
  const colorMap: any = {
    red: 'bg-red-50 text-red-600',
    green: 'bg-green-50 text-green-600',
    blue: 'bg-blue-50 text-blue-600',
    gray: 'bg-gray-50 text-gray-600',
  };
  return (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
      <div className="flex items-center space-x-4">
        <div className={`p-3 rounded-lg ${colorMap[color]}`}>{icon}</div>
        <div>
          <p className="text-sm text-gray-500 font-medium">{label}</p>
          <h4 className="text-2xl font-bold text-gray-800">{value}</h4>
          <p className="text-xs text-gray-400 mt-1">{subValue}</p>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Employee, GradeEntry } from '../types';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD } from '../constants';
import { dataService } from '../dataService';
import { X, Save, Info } from 'lucide-react';

interface GradeEditorProps {
  employee: Employee;
  month: string;
  onClose: () => void;
}

const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('A');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);

  useEffect(() => {
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    setFormGrades(existing);
  }, [employee, month]);

  const handleScoreChange = (group: string, category: string, scoreStr: string) => {
    let score = parseInt(scoreStr) || 0;
    const sanitizedScore = Math.max(0, Math.min(100, score));
    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) {
        const next = [...prev];
        next[idx] = { ...next[idx], score: sanitizedScore };
        return next;
      }
      return [...prev, { employeeId: employee.id, month, group, category, score: sanitizedScore }];
    });
  };

  const saveGrades = () => {
    const allGrades = dataService.getGrades();
    const filtered = allGrades.filter(g => !(g.employeeId === employee.id && g.month === month));
    dataService.saveGrades([...filtered, ...formGrades]);
    onClose();
  };

  const getScore = (group: string, category: string) => {
    return formGrades.find(g => g.group === group && g.category === category)?.score ?? 0;
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-0 md:p-4">
      <div className="bg-white rounded-none md:rounded-2xl shadow-2xl w-full max-w-4xl h-full md:h-auto md:max-h-[90vh] flex flex-col overflow-hidden">
        {/* Header */}
        <div className="p-4 md:p-6 border-b border-gray-100 flex items-center justify-between bg-red-600 text-white shrink-0">
          <div className="min-w-0">
            <h2 className="text-lg md:text-xl font-bold truncate">{employee.name}</h2>
            <p className="text-[10px] md:text-xs opacity-80 uppercase tracking-wider truncate">
              {employee.title} • {employee.id} • {month}
            </p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition shrink-0 ml-2">
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
          {/* Group Navigation */}
          <div className="w-full md:w-64 bg-gray-50 border-b md:border-b-0 md:border-r border-gray-200 overflow-x-auto md:overflow-y-auto scrollbar-hide shrink-0">
            <div className="flex md:flex-col min-w-max md:min-w-0">
              {Object.entries(EVALUATION_GROUPS).map(([id, group]) => {
                const groupGrades = formGrades.filter(g => g.group === id);
                const avg = groupGrades.length > 0 ? groupGrades.reduce((s, g) => s + g.score, 0) / groupGrades.length : 0;
                const isActive = activeGroup === id;

                return (
                  <button
                    key={id}
                    onClick={() => setActiveGroup(id)}
                    className={`px-4 md:px-6 py-3 md:py-4 transition flex flex-col shrink-0 border-b-2 md:border-b md:border-l-4 text-left ${
                      isActive 
                        ? 'bg-white border-b-red-600 md:border-b-gray-100 md:border-l-red-600' 
                        : 'bg-gray-50 border-b-transparent md:border-b-gray-100 md:border-l-transparent hover:bg-gray-100'
                    }`}
                  >
                    <span className={`text-xs md:text-sm font-bold truncate ${isActive ? 'text-gray-900' : 'text-gray-600'}`}>
                      {group.name}
                    </span>
                    <span className={`text-[10px] md:text-xs mt-0.5 font-bold ${avg >= APPROVAL_THRESHOLD ? 'text-green-600' : 'text-red-600'}`}>
                      {Math.round(avg)}%
                    </span>
                  </button>
                );
              })}
            </div>
          </div>

          {/* Categories Grid */}
          <div className="flex-1 p-4 md:p-8 overflow-y-auto bg-white">
            <div className="mb-4 md:mb-6 flex items-start p-3 md:p-4 bg-blue-50 text-blue-700 rounded-lg border border-blue-100">
              <Info className="w-4 h-4 md:w-5 md:h-5 mr-2 md:mr-3 mt-0.5 shrink-0" />
              <p className="text-xs md:text-sm leading-tight">
                Escala obligatoria: 0-100%. Mínimo aprobatorio: <strong>{APPROVAL_THRESHOLD}%</strong>.
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6">
              {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                const score = getScore(activeGroup, cat);
                return (
                  <div key={cat} className="space-y-1.5 md:space-y-2 p-3 border border-gray-50 rounded-xl bg-gray-50/30 md:bg-transparent">
                    <label className="text-xs md:text-sm font-semibold text-gray-700 block line-clamp-1">{cat}</label>
                    <div className="flex items-center space-x-3">
                      <div className="relative">
                        <input
                          type="number"
                          min="0"
                          max="100"
                          inputMode="numeric"
                          value={score}
                          onChange={(e) => handleScoreChange(activeGroup, cat, e.target.value)}
                          onKeyDown={(e) => ['e', 'E', '+', '-'].includes(e.key) && e.preventDefault()}
                          className={`w-16 md:w-20 px-2 md:px-3 py-2 border rounded-lg focus:ring-2 focus:ring-red-500 outline-none font-bold text-center text-sm md:text-base ${
                            score >= APPROVAL_THRESHOLD ? 'border-green-200 bg-green-50 text-green-700' : 'border-red-200 bg-red-50 text-red-700'
                          }`}
                        />
                        <span className="absolute -top-4 left-1/2 -translate-x-1/2 text-[10px] font-bold text-gray-300">%</span>
                      </div>
                      <div className="flex-1 h-2 md:h-2.5 bg-gray-200 rounded-full overflow-hidden">
                        <div 
                          className={`h-full transition-all duration-300 ${score >= APPROVAL_THRESHOLD ? 'bg-green-500' : 'bg-red-500'}`}
                          style={{ width: `${score}%` }}
                        />
                      </div>
                      <span className={`text-xs font-bold w-10 text-right ${score >= APPROVAL_THRESHOLD ? 'text-green-600' : 'text-red-600'}`}>
                        {score}%
                      </span>
                    </div>
                  </div>
                );
              })}
            </div>

            <div className="h-20 md:hidden" />
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-4 md:p-6 border-t border-gray-100 bg-gray-50 flex flex-col md:flex-row justify-end gap-3 md:gap-4 shrink-0">
          <button 
            onClick={onClose}
            className="w-full md:w-auto px-6 py-2.5 md:py-2 border border-gray-300 rounded-xl text-sm font-semibold text-gray-600 hover:bg-gray-100 transition order-2 md:order-1"
          >
            Cancelar
          </button>
          <button 
            onClick={saveGrades}
            className="w-full md:w-auto px-6 py-2.5 md:py-2 bg-red-600 text-white rounded-xl text-sm font-semibold hover:bg-red-700 shadow-lg flex items-center justify-center transition order-1 md:order-2"
          >
            <Save className="w-4 h-4 mr-2" /> Guardar Cambios
          </button>
        </div>
      </div>
    </div>
  );
};

export default GradeEditor;

