import React, { useMemo } from 'react';
import { User, Restaurant, Employee, UserRole } from '../types';
import { Store, MapPin, Users, Award } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD } from '../constants';

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth }) => {
  const assigned = useMemo(() => {
    if (user.role === UserRole.ADMIN) return restaurants;
    return restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));
  }, [user, restaurants]);

  const grades = useMemo(() => dataService.getGrades().filter(g => g.month === selectedMonth), [selectedMonth]);

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-gray-800">Mis Tiendas Asignadas</h2>
        <p className="text-sm text-gray-500">{assigned.length} tiendas encontradas</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {assigned.map(store => {
          const storeEmployees = employees.filter(e => e.restaurantId === store.id);
          let storeApproved = 0;
          storeEmployees.forEach(emp => {
            const empGrades = grades.filter(g => g.employeeId === emp.id);
            if (empGrades.length > 0) {
              const avg = empGrades.reduce((s, g) => s + g.score, 0) / empGrades.length;
              if (avg >= APPROVAL_THRESHOLD) storeApproved++;
            }
          });

          return (
            <div key={store.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden hover:shadow-md transition group">
              <div className="p-6 border-b border-gray-50 flex items-center justify-between">
                <div className="flex items-center space-x-3">
                  <div className="p-2 bg-red-50 text-red-600 rounded-lg group-hover:bg-red-600 group-hover:text-white transition">
                    <Store className="w-5 h-5" />
                  </div>
                  <div>
                    <h3 className="font-bold text-gray-800">{store.name}</h3>
                    <p className="text-[10px] text-gray-400 flex items-center"><MapPin className="w-3 h-3 mr-1" /> {store.zone}</p>
                  </div>
                </div>
              </div>
              <div className="p-6 grid grid-cols-2 gap-4">
                <div className="bg-gray-50 p-3 rounded-xl border border-gray-100">
                  <p className="text-[10px] font-bold text-gray-400 uppercase mb-1">Trabajadores</p>
                  <div className="flex items-center text-gray-800">
                    <Users className="w-4 h-4 mr-2 text-blue-500" />
                    <span className="font-bold">{storeEmployees.length}</span>
                  </div>
                </div>
                <div className="bg-gray-50 p-3 rounded-xl border border-gray-100">
                  <p className="text-[10px] font-bold text-gray-400 uppercase mb-1">Certificados</p>
                  <div className="flex items-center text-gray-800">
                    <Award className="w-4 h-4 mr-2 text-green-500" />
                    <span className="font-bold">{storeApproved}</span>
                  </div>
                </div>
              </div>
              <div className="px-6 pb-6">
                <div className="h-1.5 w-full bg-gray-100 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-green-500 transition-all duration-1000" 
                    style={{ width: `${storeEmployees.length > 0 ? (storeApproved / storeEmployees.length) * 100 : 0}%` }}
                  />
                </div>
                <div className="flex justify-between mt-1.5">
                  <span className="text-[10px] font-bold text-gray-400 uppercase">Cumplimiento</span>
                  <span className="text-[10px] font-bold text-green-600">{storeEmployees.length > 0 ? Math.round((storeApproved / storeEmployees.length) * 100) : 0}%</span>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {assigned.length === 0 && (
        <div className="bg-white p-12 text-center rounded-2xl border border-dashed border-gray-300">
          <p className="text-gray-400 italic">No tienes tiendas asignadas bajo tu perfil actual.</p>
        </div>
      )}
    </div>
  );
};

export default MyStores;

import React, { useState, useEffect } from 'react';
import { Employee, GradeEntry } from '../types';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD } from '../constants';
import { dataService } from '../dataService';
import { X, Save, Info } from 'lucide-react';

interface GradeEditorProps {
  employee: Employee;
  month: string;
  onClose: () => void;
}

const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('A');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);

  useEffect(() => {
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    setFormGrades(existing);
  }, [employee, month]);

  const handleScoreChange = (group: string, category: string, scoreStr: string) => {
    let score = parseInt(scoreStr);
    if (isNaN(score)) score = 0;
    const sanitizedScore = Math.max(0, Math.min(100, score));

    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) {
        const next = [...prev];
        next[idx] = { ...next[idx], score: sanitizedScore };
        return next;
      }
      return [...prev, { employeeId: employee.id, month, group, category, score: sanitizedScore }];
    });
  };

  const saveGrades = () => {
    const allGrades = dataService.getGrades();
    const filtered = allGrades.filter(g => !(g.employeeId === employee.id && g.month === month));
    dataService.saveGrades([...filtered, ...formGrades]);
    onClose();
  };

  const getScore = (group: string, category: string) => {
    const entry = formGrades.find(g => g.group === group && g.category === category);
    return entry ? entry.score : 0;
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm p-0 md:p-4">
      <div className="bg-white rounded-none md:rounded-2xl shadow-2xl w-full max-w-4xl h-full md:h-auto md:max-h-[95vh] flex flex-col overflow-hidden">
        {/* Header */}
        <div className="p-4 md:p-6 border-b border-gray-100 flex items-center justify-between bg-red-600 text-white shrink-0">
          <div className="min-w-0">
            <h2 className="text-lg md:text-xl font-bold truncate text-white">{employee.name}</h2>
            <p className="text-[10px] md:text-xs opacity-90 uppercase tracking-wider truncate text-white">
              {employee.title} • ID: {employee.id} • Período: {month}
            </p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/20 rounded-full transition shrink-0 ml-2 text-white">
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
          {/* Group Navigation */}
          <div className="w-full md:w-64 bg-slate-50 border-b md:border-b-0 md:border-r border-gray-200 overflow-x-auto md:overflow-y-auto scrollbar-hide shrink-0">
            <div className="flex md:flex-col min-w-max md:min-w-0">
              {Object.entries(EVALUATION_GROUPS).map(([id, group]) => {
                const groupGrades = formGrades.filter(g => g.group === id);
                const avg = groupGrades.length > 0 ? groupGrades.reduce((s, g) => s + g.score, 0) / groupGrades.length : 0;
                const isActive = activeGroup === id;

                return (
                  <button
                    key={id}
                    onClick={() => setActiveGroup(id)}
                    className={`px-5 md:px-6 py-4 md:py-5 transition flex flex-col shrink-0 border-b-2 md:border-b md:border-l-4 text-left ${
                      isActive 
                        ? 'bg-white border-b-red-600 md:border-b-gray-200 md:border-l-red-600 shadow-sm z-10' 
                        : 'bg-slate-50 border-b-transparent md:border-b-gray-200 md:border-l-transparent hover:bg-slate-100'
                    }`}
                  >
                    <span className={`text-xs md:text-sm font-bold truncate ${isActive ? 'text-gray-900' : 'text-gray-500'}`}>
                      {group.name}
                    </span>
                    <span className={`text-[10px] md:text-xs mt-1 font-black ${avg >= APPROVAL_THRESHOLD ? 'text-green-600' : 'text-red-600'}`}>
                      Promedio: {Math.round(avg)}%
                    </span>
                  </button>
                );
              })}
            </div>
          </div>

          {/* Categories Grid */}
          <div className="flex-1 p-5 md:p-8 overflow-y-auto bg-white">
            <div className="mb-6 flex items-start p-4 bg-blue-50 text-blue-800 rounded-xl border border-blue-100">
              <Info className="w-5 h-5 mr-3 mt-0.5 shrink-0 text-blue-600" />
              <p className="text-sm leading-snug font-medium">
                Ingrese el porcentaje obtenido (0 a 100). Meta de aprobación: <strong className="text-red-600">{APPROVAL_THRESHOLD}%</strong>.
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-5 md:gap-8">
              {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                const score = getScore(activeGroup, cat);
                return (
                  <div key={cat} className="space-y-3 p-4 border border-gray-100 rounded-2xl bg-slate-50/50">
                    <label className="text-xs md:text-sm font-bold text-slate-700 block line-clamp-2 min-h-[2.5rem] leading-tight">{cat}</label>
                    <div className="flex items-center space-x-4">
                      <div className="relative shrink-0">
                        <input
                          type="number"
                          min="0"
                          max="100"
                          inputMode="numeric"
                          value={score}
                          onChange={(e) => handleScoreChange(activeGroup, cat, e.target.value)}
                          onFocus={(e) => e.target.select()}
                          className={`w-20 md:w-24 px-3 py-3 border-2 rounded-xl focus:ring-4 focus:ring-red-100 outline-none font-black text-center text-base md:text-lg transition-all ${
                            score >= APPROVAL_THRESHOLD 
                              ? 'border-green-500 bg-white text-green-700 shadow-sm' 
                              : 'border-red-400 bg-white text-red-700 shadow-sm'
                          }`}
                        />
                        <span className="absolute -top-3 left-1/2 -translate-x-1/2 text-[10px] font-black text-slate-400 uppercase tracking-tighter bg-white px-1">%</span>
                      </div>
                      <div className="flex-1 space-y-2">
                        <div className="h-3 bg-slate-200 rounded-full overflow-hidden shadow-inner">
                          <div 
                            className={`h-full transition-all duration-500 ease-out ${score >= APPROVAL_THRESHOLD ? 'bg-green-500' : 'bg-red-500'}`}
                            style={{ width: `${score}%` }}
                          />
                        </div>
                        <div className="flex justify-between text-[10px] font-black uppercase text-slate-400">
                          <span>0</span>
                          <span>100</span>
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>

            <div className="h-24 md:hidden" />
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-4 md:p-6 border-t border-gray-100 bg-slate-50 flex flex-col md:flex-row justify-end gap-3 md:gap-4 shrink-0">
          <button 
            onClick={onClose}
            className="w-full md:w-auto px-8 py-3 md:py-2 border-2 border-slate-300 rounded-xl text-sm font-black text-slate-600 hover:bg-slate-100 transition order-2 md:order-1 active:scale-95"
          >
            CANCELAR
          </button>
          <button 
            onClick={saveGrades}
            className="w-full md:w-auto px-10 py-3 md:py-2 bg-red-600 text-white rounded-xl text-sm font-black hover:bg-red-700 shadow-xl shadow-red-200 flex items-center justify-center transition order-1 md:order-2 active:scale-95"
          >
            <Save className="w-5 h-5 mr-2" /> GUARDAR CAMBIOS
          </button>
        </div>
      </div>
    </div>
  );
};

