import React, { useMemo, useState } from 'react';
import { Employee, GradeEntry, User, Restaurant, UserRole } from '../types';
import { dataService } from '../dataService';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, INITIAL_ZONES } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { CheckCircle, XCircle, Users, Award, TrendingUp, Search, Filter } from 'lucide-react';

interface DashboardProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ employees: initialEmployees, restaurants, selectedMonth, user }) => {
  const [searchPerson, setSearchPerson] = useState('');
  const [filterStore, setFilterStore] = useState('all');
  const [filterZone, setFilterZone] = useState('all');

  const filteredData = useMemo(() => {
    return initialEmployees.filter(e => {
      const matchPerson = searchPerson === '' || e.name.toLowerCase().includes(searchPerson.toLowerCase()) || e.id.includes(searchPerson);
      const matchStore = filterStore === 'all' || e.restaurantId === filterStore;
      const matchZone = filterZone === 'all' || e.zone === filterZone;
      return matchPerson && matchStore && matchZone;
    });
  }, [initialEmployees, searchPerson, filterStore, filterZone]);

  const grades = useMemo(() => dataService.getGrades().filter(g => g.month === selectedMonth), [selectedMonth]);

  const stats = useMemo(() => {
    const totalEmployees = filteredData.length;
    let approvedCount = 0;

    const groupAvgs = Object.keys(EVALUATION_GROUPS).map(groupId => {
      const groupGrades = grades.filter(g => g.group === groupId && filteredData.some(e => e.id === g.employeeId));
      const avg = groupGrades.length > 0 ? groupGrades.reduce((sum, g) => sum + g.score, 0) / groupGrades.length : 0;
      return {
        id: groupId,
        name: (EVALUATION_GROUPS as any)[groupId].name,
        avg: Math.round(avg)
      };
    });

    filteredData.forEach(emp => {
      const empGrades = grades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        const avg = empGrades.reduce((sum, g) => sum + g.score, 0) / empGrades.length;
        if (avg >= APPROVAL_THRESHOLD) approvedCount++;
      }
    });

    return { totalEmployees, approvedCount, groupAvgs };
  }, [filteredData, grades]);

  const COLORS = ['#ef4444', '#22c55e'];

  return (
    <div className="space-y-6">
      {/* Filters Section */}
      <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-3 gap-5">
        <div className="relative">
          <label className="block text-[11px] font-black text-slate-400 uppercase mb-2 tracking-widest">Persona</label>
          <div className="relative">
            <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <input 
              type="text" 
              placeholder="Nombre o cédula..."
              value={searchPerson}
              onChange={(e) => setSearchPerson(e.target.value)}
              className="w-full pl-12 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-bold text-slate-800 focus:bg-white focus:border-red-500 focus:ring-4 focus:ring-red-100 outline-none transition-all placeholder:text-slate-300 placeholder:font-medium"
            />
          </div>
        </div>
        <div>
          <label className="block text-[11px] font-black text-slate-400 uppercase mb-2 tracking-widest">Tienda</label>
          <div className="relative">
            <select 
              value={filterStore}
              onChange={(e) => setFilterStore(e.target.value)}
              className="w-full pl-4 pr-10 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-bold text-slate-800 focus:bg-white focus:border-red-500 focus:ring-4 focus:ring-red-100 outline-none transition-all appearance-none cursor-pointer"
            >
              <option value="all">Todas las tiendas</option>
              {restaurants.filter(r => user.role === UserRole.ADMIN || user.assignedRestaurants.includes(r.id)).map(r => (
                <option key={r.id} value={r.id}>{r.name}</option>
              ))}
            </select>
            <Filter className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
          </div>
        </div>
        <div>
          <label className="block text-[11px] font-black text-slate-400 uppercase mb-2 tracking-widest">Zona</label>
          <div className="relative">
            <select 
              value={filterZone}
              onChange={(e) => setFilterZone(e.target.value)}
              className="w-full pl-4 pr-10 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-bold text-slate-800 focus:bg-white focus:border-red-500 focus:ring-4 focus:ring-red-100 outline-none transition-all appearance-none cursor-pointer"
            >
              <option value="all">Todas las zonas</option>
              {INITIAL_ZONES.filter(z => user.role === UserRole.ADMIN || user.assignedZones.includes(z)).map(z => (
                <option key={z} value={z}>{z}</option>
              ))}
            </select>
            <Filter className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          icon={<Users className="w-6 h-6" />}
          label="Trabajadores"
          value={stats.totalEmployees}
          subValue="En selección actual"
        />
        <StatCard 
          icon={<Award className="w-6 h-6" />}
          label="Certificados"
          value={stats.approvedCount}
          subValue={`${stats.totalEmployees > 0 ? Math.round((stats.approvedCount / stats.totalEmployees) * 100) : 0}% cumplimiento`}
          color="green"
        />
        <StatCard 
          icon={<TrendingUp className="w-6 h-6" />}
          label="Promedio Gral."
          value={`${stats.groupAvgs.length > 0 ? Math.round(stats.groupAvgs.reduce((s, g) => s + g.avg, 0) / stats.groupAvgs.length) : 0}%`}
          subValue="Métricas del mes"
          color="blue"
        />
        <StatCard 
          icon={<XCircle className="w-6 h-6" />}
          label="Pendientes"
          value={stats.totalEmployees - stats.approvedCount}
          subValue="Por certificar"
          color="red"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-base font-black text-slate-800 mb-6 uppercase tracking-wider">Desempeño por Grupo</h3>
          <div className="h-[320px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.groupAvgs} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis 
                  dataKey="name" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 11, fontWeight: 700, fill: '#64748b' }} 
                />
                <YAxis 
                  domain={[0, 100]} 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 11, fontWeight: 700, fill: '#64748b' }} 
                />
                <Tooltip 
                  cursor={{ fill: '#f8fafc' }}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontWeight: 'bold' }}
                />
                <Bar dataKey="avg" radius={[6, 6, 0, 0]} barSize={40}>
                  {stats.groupAvgs.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.avg >= APPROVAL_THRESHOLD ? '#10b981' : '#ef4444'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-base font-black text-slate-800 mb-6 uppercase tracking-wider">Cumplimiento Global</h3>
          <div className="h-[320px] flex items-center justify-center relative">
             <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={[
                      { name: 'No Aprobado', value: stats.totalEmployees - stats.approvedCount },
                      { name: 'Aprobado', value: stats.approvedCount },
                    ]}
                    cx="50%"
                    cy="50%"
                    innerRadius={70}
                    outerRadius={105}
                    paddingAngle={8}
                    dataKey="value"
                    stroke="none"
                  >
                    {COLORS.map((color, index) => <Cell key={`cell-${index}`} fill={color} />)}
                  </Pie>
                  <Tooltip 
                    contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontWeight: 'bold' }}
                  />
                </PieChart>
             </ResponsiveContainer>
             <div className="absolute flex flex-col items-center">
                <span className="text-4xl font-black text-slate-800">{stats.totalEmployees > 0 ? Math.round((stats.approvedCount / stats.totalEmployees) * 100) : 0}%</span>
                <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Meta</span>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ icon: React.ReactNode, label: string, value: string | number, subValue: string, color?: string }> = ({ icon, label, value, subValue, color = 'gray' }) => {
  const colorMap: any = {
    red: 'bg-red-50 text-red-600 ring-red-100',
    green: 'bg-emerald-50 text-emerald-600 ring-emerald-100',
    blue: 'bg-blue-50 text-blue-600 ring-blue-100',
    gray: 'bg-slate-50 text-slate-600 ring-slate-100',
  };
  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 ring-1 ring-slate-50">
      <div className="flex items-center space-x-5">
        <div className={`p-4 rounded-xl ring-4 ${colorMap[color]}`}>{icon}</div>
        <div>
          <p className="text-[11px] text-slate-400 font-black uppercase tracking-widest mb-1">{label}</p>
          <h4 className="text-3xl font-black text-slate-800 leading-none">{value}</h4>
          <p className="text-[11px] text-slate-500 font-bold mt-2 truncate">{subValue}</p>
        </div>
      </div>
    </div>
  );
};

