              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase block mb-1">Nueva Contraseña</label>
                <input type="password" value={passData.new} onChange={e => setPassData({...passData, new: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-200 rounded-xl text-sm font-bold outline-none focus:border-red-500" />
