import React, { useState, useEffect } from 'react';
import { Employee, GradeEntry, JobTitle } from '../types';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, INITIAL_RESTAURANTS } from '../constants';
import { dataService } from '../dataService';
import { X, Save, Info, User, Calendar, MapPin, Briefcase, History } from 'lucide-react';

interface GradeEditorProps {
  employee: Employee;
  month: string;
  onClose: () => void;
}

const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('A');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);

  useEffect(() => {
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    setFormGrades(existing);
  }, [employee, month]);

  const handleScoreChange = (group: string, category: string, scoreStr: string) => {
    let score = parseInt(scoreStr);
    if (isNaN(score)) score = 0;
    const sanitizedScore = Math.max(0, Math.min(100, score));
    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) {
        const next = [...prev];
        next[idx] = { ...next[idx], score: sanitizedScore };
        return next;
      }
      return [...prev, { employeeId: employee.id, month, group, category, score: sanitizedScore }];
    });
  };

  const saveGrades = () => {
    const allGrades = dataService.getGrades();
    const filtered = allGrades.filter(g => !(g.employeeId === employee.id && g.month === month));
    dataService.saveGrades([...filtered, ...formGrades]);
    onClose();
  };

  const getScore = (group: string, category: string) => {
    return formGrades.find(g => g.group === group && g.category === category)?.score ?? 0;
  };

  const currentStore = INITIAL_RESTAURANTS.find(r => r.id === employee.restaurantId);

  return (
    <div className="fixed inset-0 z-[80] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-0 md:p-4">
      <div className="bg-white rounded-none md:rounded-[40px] shadow-2xl w-full max-w-5xl h-full md:h-auto md:max-h-[92vh] flex flex-col overflow-hidden border-4 border-white">
        {/* Profile Header */}
        <div className="p-8 bg-red-600 text-white shrink-0">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div className="flex items-center space-x-6">
              <div className="w-20 h-20 bg-white/20 rounded-[28px] flex items-center justify-center backdrop-blur-md border-2 border-white/20 shadow-inner">
                <User className="w-10 h-10 text-white" />
              </div>
              <div>
                <h2 className="text-3xl font-black tracking-tighter uppercase leading-none mb-2">{employee.name}</h2>
                <div className="flex flex-wrap gap-x-6 gap-y-2">
                  <span className="flex items-center text-[10px] font-black uppercase tracking-widest"><Briefcase className="w-3 h-3 mr-2"/> {employee.title}</span>
                  <span className="flex items-center text-[10px] font-black uppercase tracking-widest"><MapPin className="w-3 h-3 mr-2"/> {currentStore?.name} • {employee.zone}</span>
                  <span className="flex items-center text-[10px] font-black uppercase tracking-widest"><Calendar className="w-3 h-3 mr-2"/> Ingreso: {employee.joinDate}</span>
                </div>
              </div>
            </div>
            <button onClick={onClose} className="p-4 bg-white/10 hover:bg-white/20 rounded-2xl transition-all self-end md:self-auto"><X className="w-6 h-6"/></button>
          </div>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
          {/* Navigation & History */}
          <div className="w-full md:w-72 bg-slate-50 border-r border-slate-100 flex flex-col overflow-y-auto">
            <div className="p-6 border-b border-slate-100">
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Grupos Evaluativos</p>
               <div className="space-y-2">
                {Object.entries(EVALUATION_GROUPS).map(([id, group]) => {
                  const isActive = activeGroup === id;
                  const groupGrades = formGrades.filter(g => g.group === id);
                  const avg = groupGrades.length > 0 ? groupGrades.reduce((s, g) => s + g.score, 0) / groupGrades.length : 0;
                  return (
                    <button key={id} onClick={() => setActiveGroup(id)} className={`w-full p-4 rounded-2xl text-left transition-all border-2 ${isActive ? 'bg-white border-red-500 shadow-lg shadow-red-50' : 'bg-transparent border-transparent hover:bg-slate-100'}`}>
                      <p className={`text-xs font-black truncate ${isActive ? 'text-slate-900' : 'text-slate-400'}`}>{group.name}</p>
                      <div className="flex items-center justify-between mt-2">
                        <div className="flex-1 h-1 bg-slate-200 rounded-full mr-4 overflow-hidden"><div className={`h-full ${avg >= APPROVAL_THRESHOLD ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${avg}%`}}/></div>
                        <span className={`text-[10px] font-black ${avg >= APPROVAL_THRESHOLD ? 'text-emerald-600' : 'text-red-600'}`}>{Math.round(avg)}%</span>
                      </div>
                    </button>
                  );
                })}
               </div>
            </div>
            <div className="p-6">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center"><History className="w-3 h-3 mr-2"/> Historial de Traslados</p>
              <div className="space-y-4">
                <div className="relative pl-6 before:absolute before:left-0 before:top-1 before:bottom-0 before:w-px before:bg-slate-200">
                   <div className="absolute left-[-4px] top-1 w-2 h-2 rounded-full bg-red-600" />
                   <p className="text-[10px] font-black text-slate-800 uppercase tracking-tighter">Posición Actual</p>
                   <p className="text-[9px] font-bold text-slate-400">{currentStore?.name}</p>
                </div>
                {employee.history?.map((h, i) => (
                  <div key={i} className="relative pl-6 before:absolute before:left-0 before:top-1 before:bottom-0 before:w-px before:bg-slate-200 last:before:hidden">
                    <div className="absolute left-[-4px] top-1 w-2 h-2 rounded-full bg-slate-300" />
                    <p className="text-[10px] font-black text-slate-500 uppercase tracking-tighter">{h.action}: {h.date}</p>
                    <p className="text-[9px] font-bold text-slate-400">{h.restaurantName}</p>
                  </div>
                ))}
                {!employee.history && <p className="text-[9px] font-bold text-slate-300 italic">No registra traslados previos.</p>}
              </div>
            </div>
          </div>

          {/* Grading Content */}
          <div className="flex-1 p-8 md:p-12 overflow-y-auto bg-white">
            <div className="flex items-start p-6 bg-slate-50 rounded-[32px] border-2 border-slate-100 mb-10">
              <Info className="w-6 h-6 text-red-600 mr-4 mt-0.5" />
              <div>
                <p className="text-sm font-black text-slate-800 uppercase tracking-tight">Evaluación de { (EVALUATION_GROUPS as any)[activeGroup].name }</p>
                <p className="text-xs text-slate-500 font-bold leading-relaxed">Asigne puntajes entre 0% y 100%. Los cambios se verán reflejados en el promedio global del periodo.</p>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-10">
              {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                const score = getScore(activeGroup, cat);
                return (
                  <div key={cat} className="space-y-4">
                    <div className="flex justify-between items-end">
                      <label className="text-xs font-black text-slate-700 uppercase tracking-widest line-clamp-1">{cat}</label>
                      <span className={`text-[10px] font-black ${score >= APPROVAL_THRESHOLD ? 'text-emerald-600' : 'text-red-600'}`}>{score >= APPROVAL_THRESHOLD ? 'APROBADO' : 'REPROBADO'}</span>
                    </div>
                    <div className="flex items-center space-x-6">
                      <div className="relative">
                        <input type="number" min="0" max="100" value={score} onChange={e => handleScoreChange(activeGroup, cat, e.target.value)} onFocus={e => e.target.select()} className={`w-24 px-4 py-4 bg-slate-50 border-4 rounded-3xl text-xl font-black text-center outline-none transition-all ${score >= APPROVAL_THRESHOLD ? 'border-emerald-100 text-emerald-700' : 'border-red-100 text-red-700'}`} />
                        <span className="absolute -top-3 left-1/2 -translate-x-1/2 bg-white px-2 text-[9px] font-black text-slate-300 uppercase tracking-widest border border-slate-100 rounded-full">% PUNTOS</span>
                      </div>
                      <div className="flex-1 h-2 bg-slate-100 rounded-full overflow-hidden shadow-inner"><div className={`h-full transition-all duration-700 ${score >= APPROVAL_THRESHOLD ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${score}%`}} /></div>
                    </div>
                  </div>
                );
              })}
            </div>
            <div className="h-20 md:hidden" />
          </div>
        </div>

        {/* Footer */}
        <div className="p-8 border-t border-slate-100 bg-slate-50 flex flex-col md:flex-row justify-end gap-4 shrink-0 px-12">
          <button onClick={onClose} className="px-10 py-5 font-black text-slate-400 text-xs uppercase tracking-widest hover:text-slate-600 transition">Cancelar Operación</button>
          <button onClick={saveGrades} className="px-14 py-5 bg-slate-900 text-white font-black rounded-[24px] shadow-2xl shadow-slate-200 hover:bg-black transition-all active:scale-95 text-xs uppercase tracking-widest flex items-center justify-center">
            <Save className="w-4 h-4 mr-3" /> Confirmar Notas
          </button>
        </div>
      </div>
    </div>
  );
};

export default GradeEditor;

import React, { useMemo, useState } from 'react';
import { User, Restaurant, Employee, UserRole } from '../types';
import { Store, MapPin, Users, Award, ChevronRight, X, User as UserIcon } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD } from '../constants';
import GradeEditor from './GradeEditor';

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  const assigned = useMemo(() => {
    if (user.role === UserRole.ADMIN) return restaurants;
    return restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));
  }, [user, restaurants]);

  const grades = useMemo(() => dataService.getGrades().filter(g => g.month === selectedMonth), [selectedMonth]);

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Mi Territorio</h2>
          <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Supervisión de puntos de venta asignados</p>
