                <div className="flex items-center space-x-4">
                  <div className="p-4 bg-slate-50 text-slate-400 rounded-2xl group-hover:bg-red-600 group-hover:text-white transition-all shadow-inner">
                    <Store className="w-6 h-6" />
                  </div>
                  <div>
                    <h3 className="font-black text-slate-800 text-lg leading-tight">{store.name}</h3>
                    <p className="text-[10px] text-slate-400 font-bold flex items-center uppercase tracking-tighter mt-1"><MapPin className="w-3 h-3 mr-1" /> {store.region} • {store.zone}</p>
                  </div>
                </div>
              </div>

              <div className="px-8 pb-8 flex-1 flex flex-col justify-end">
                <div className="grid grid-cols-2 gap-4 mb-8">
                  <div className="bg-slate-50 p-4 rounded-[24px] border border-slate-100">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Equipo</p>
                    <p className="text-2xl font-black text-slate-800 tracking-tighter">{storeEmployees.length}</p>
                  </div>
                  <div className="bg-slate-50 p-4 rounded-[24px] border border-slate-100">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Meta</p>
                    <p className="text-2xl font-black text-emerald-600 tracking-tighter">{storeEmployees.length > 0 ? Math.round((storeApproved / storeEmployees.length) * 100) : 0}%</p>
                  </div>
                </div>

                <button 
                  onClick={() => setSelectedStore(store)}
                  className="w-full py-4 bg-slate-900 text-white text-xs font-black rounded-2xl group-hover:bg-red-600 transition-colors shadow-lg shadow-slate-100 uppercase tracking-widest flex items-center justify-center"
                >
                  Ver Detalles <ChevronRight className="w-4 h-4 ml-2" />
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {selectedStore && (
        <div className="fixed inset-0 z-[90] flex items-center justify-center bg-slate-900/90 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col border-4 border-white">
            <div className="p-8 bg-slate-900 text-white flex justify-between items-center shrink-0">
              <div className="flex items-center space-x-4">
                <div className="p-3 bg-red-600 rounded-2xl"><Store className="w-6 h-6"/></div>
                <div>
                  <h3 className="text-xl font-black tracking-tighter uppercase leading-none">{selectedStore.name}</h3>
                  <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">{selectedStore.region} • {selectedStore.zone}</p>
                </div>
              </div>
              <button onClick={() => setSelectedStore(null)} className="p-2 hover:bg-white/10 rounded-xl transition"><X className="w-6 h-6"/></button>
            </div>

            <div className="p-8 overflow-y-auto flex-1 space-y-6">
              <div className="flex justify-between items-end border-b-2 border-slate-50 pb-6">
                <div>
                  <p className="text-3xl font-black text-slate-800 tracking-tighter">Colaboradores</p>
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Lista detallada del punto de venta</p>
                </div>
              </div>

              <div className="space-y-3">
                {employees.filter(e => e.restaurantId === selectedStore.id).map(emp => {
                  const empGrades = grades.filter(g => g.employeeId === emp.id);
                  const avg = empGrades.length > 0 ? empGrades.reduce((s, g) => s + g.score, 0) / empGrades.length : 0;
                  return (
                    <div key={emp.id} className="p-5 border-2 border-slate-50 rounded-3xl flex items-center justify-between hover:border-red-100 transition-all bg-slate-50/30">
                      <div className="flex items-center space-x-4">
                        <div className="w-10 h-10 bg-white border border-slate-200 rounded-xl flex items-center justify-center shadow-sm">
                          <UserIcon className="w-5 h-5 text-slate-400" />
                        </div>
                        <div>
                          <p className="text-sm font-black text-slate-800 leading-none">{emp.name}</p>
                          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter mt-1">{emp.title} • {emp.id}</p>
                        </div>
                      </div>
                      <div className="flex items-center space-x-6">
                        <div className="text-right">
                          <p className={`text-lg font-black tracking-tighter leading-none ${avg >= APPROVAL_THRESHOLD ? 'text-emerald-600' : 'text-red-500'}`}>{Math.round(avg)}%</p>
                          <p className="text-[8px] font-black text-slate-300 uppercase mt-1">Puntaje</p>
                        </div>
                        <button 
                          onClick={() => setEditingEmployee(emp)}
                          className="p-3 bg-white border border-slate-200 text-slate-400 hover:text-red-600 hover:border-red-600 rounded-xl transition-all shadow-sm active:scale-90"
                        >
                          <Edit3 className="w-4 h-4" />
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>
      )}

      {editingEmployee && (
        <GradeEditor 
          employee={editingEmployee}
          month={selectedMonth}
          onClose={() => { setEditingEmployee(null); }}
        />
      )}
    </div>
  );
};

