import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD } from '../constants';
import GradeEditor from './GradeEditor';

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  const assigned = useMemo(() => {
    if (user.role === UserRole.ADMIN) return restaurants;
    return restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));
  }, [user, restaurants]);

  const grades = useMemo(() => dataService.getGrades().filter(g => g.month === selectedMonth), [selectedMonth]);

  const getStoreStats = (storeId: string) => {
    const storeEmployees = employees.filter(e => e.restaurantId === storeId);
    let storeApproved = 0;
    storeEmployees.forEach(emp => {
      const empGrades = grades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        const avg = empGrades.reduce((s, g) => s + g.score, 0) / empGrades.length;
        if (avg >= APPROVAL_THRESHOLD) storeApproved++;
      }
    });
    return {
      total: storeEmployees.length,
      approved: storeApproved,
      percent: storeEmployees.length > 0 ? Math.round((storeApproved / storeEmployees.length) * 100) : 0
    };
  };

  // View: Detailed Store Page
  if (selectedStore) {
    const stats = getStoreStats(selectedStore.id);
