          <DetailStatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approved} color="green" />
          <DetailStatCard icon={<TrendingUp className="w-6 h-6" />} label="Cumplimiento" value={`${stats.percent}%`} color="red" />
