                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Acciones</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {storeEmps.map(emp => {
                  const empGrades = grades.filter(g => g.employeeId === emp.id);
                  const avg = empGrades.length > 0 ? empGrades.reduce((s, g) => s + g.score, 0) / empGrades.length : 0;
                  return (
                    <tr key={emp.id} className="hover:bg-slate-50/50 transition-colors group">
