                      </td>
                      <td className="px-8 py-6">
                        <span className="px-3 py-1 bg-white border border-slate-200 text-slate-500 rounded-lg text-[9px] font-black uppercase">
                          {emp.title}
                        </span>
                      </td>
                      <td className="px-8 py-6">
                        <div className="flex items-center space-x-3">
                          <div className="w-32 h-2 bg-slate-100 rounded-full overflow-hidden">
                            <div 
                              className={`h-full transition-all duration-700 ${avg >= APPROVAL_THRESHOLD ? 'bg-emerald-500' : 'bg-red-500'}`}
                              style={{ width: `${avg}%` }}
                            />
                          </div>
                          <span className={`text-xs font-black ${avg >= APPROVAL_THRESHOLD ? 'text-emerald-600' : 'text-red-600'}`}>
