  onClose: () => void;
}

const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('A');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  useEffect(() => {
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    setFormGrades(existing);
  }, [employee, month]);

  const handleScoreChange = (group: string, category: string, scoreStr: string) => {
    let score = parseInt(scoreStr);
    if (isNaN(score)) score = 0;
    const sanitizedScore = Math.max(0, Math.min(100, score));
    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) {
        const next = [...prev];
        next[idx] = { ...next[idx], score: sanitizedScore };
        return next;
      }
      return [...prev, { employeeId: employee.id, month, group, category, score: sanitizedScore }];
    });
  };

  const saveGrades = () => {
    const allGrades = dataService.getGrades();
    const filtered = allGrades.filter(g => !(g.employeeId === employee.id && g.month === month));
    dataService.saveGrades([...filtered, ...formGrades]);
    onClose();
  };

  const getScore = (group: string, category: string) => {
    return formGrades.find(g => g.group === group && g.category === category)?.score ?? 0;
  };

  const currentStore = INITIAL_RESTAURANTS.find(r => r.id === employee.restaurantId);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-0 md:p-4 animate-in fade-in duration-200">
      <div className="bg-white rounded-none md:rounded-[40px] shadow-[0_0_100px_rgba(0,0,0,0.5)] w-full max-w-5xl h-full md:h-auto md:max-h-[92vh] flex flex-col overflow-hidden border-4 border-white ring-1 ring-slate-800">

        {/* Profile Header */}
        <div className="p-8 bg-red-600 text-white shrink-0 relative overflow-hidden">
          <div className="absolute right-0 top-0 opacity-10 rotate-12 -translate-y-4 translate-x-4">
             <Briefcase className="w-48 h-48" />
          </div>

          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 relative z-10">
            <div className="flex items-center space-x-6">
              <div className="w-20 h-20 bg-white/20 rounded-[28px] flex items-center justify-center backdrop-blur-md border-2 border-white/20 shadow-inner shrink-0">
                <User className="w-10 h-10 text-white" />
              </div>
              <div>
                <div className="flex items-center gap-4 mb-2">
                   <h2 className="text-3xl font-black tracking-tighter uppercase leading-none">{employee.name}</h2>
                   <button 
                    onClick={() => setShowHistory(!showHistory)}
                    className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center transition-all ${showHistory ? 'bg-white text-red-600 shadow-lg' : 'bg-white/10 text-white hover:bg-white/20'}`}
                   >
                     <History className="w-3.5 h-3.5 mr-2" /> Historial de Traslados
                   </button>
                </div>
                <div className="flex flex-wrap gap-x-6 gap-y-2">
                  <span className="flex items-center text-[10px] font-black uppercase tracking-widest"><Briefcase className="w-3 h-3 mr-2 text-red-200"/> {employee.title}</span>
                  <span className="flex items-center text-[10px] font-black uppercase tracking-widest"><MapPin className="w-3 h-3 mr-2 text-red-200"/> {currentStore?.name} • {employee.zone}</span>
                  <span className="flex items-center text-[10px] font-black uppercase tracking-widest"><Calendar className="w-3 h-3 mr-2 text-red-200"/> Ingreso: {employee.joinDate}</span>
                </div>
              </div>
            </div>
            <button onClick={onClose} className="p-4 bg-white/10 hover:bg-white/20 rounded-2xl transition-all self-end md:self-auto shadow-sm">
              <X className="w-6 h-6"/>
            </button>
          </div>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
          {/* Navigation Sidebar */}
          <div className="w-full md:w-72 bg-slate-50 border-r border-slate-100 flex flex-col overflow-y-auto shrink-0">
            <div className="p-8">
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6 px-1">Secciones de Evaluación</p>
               <div className="space-y-3">
                {Object.entries(EVALUATION_GROUPS).map(([id, group]) => {
                  const isActive = activeGroup === id;
                  const groupGrades = formGrades.filter(g => g.group === id);
                  const avg = groupGrades.length > 0 ? groupGrades.reduce((s, g) => s + g.score, 0) / groupGrades.length : 0;
                  return (
                    <button 
                      key={id} 
                      onClick={() => { setActiveGroup(id); setShowHistory(false); }} 
                      className={`w-full p-4 rounded-2xl text-left transition-all border-2 ${isActive && !showHistory ? 'bg-white border-red-500 shadow-xl shadow-red-50/50 scale-[1.02]' : 'bg-transparent border-transparent hover:bg-slate-100 opacity-70 hover:opacity-100'}`}
                    >
                      <p className={`text-xs font-black truncate mb-2 ${isActive && !showHistory ? 'text-slate-900' : 'text-slate-400'}`}>{group.name}</p>
                      <div className="flex items-center justify-between">
                        <div className="flex-1 h-1.5 bg-slate-200 rounded-full mr-3 overflow-hidden">
                          <div className={`h-full transition-all duration-700 ${avg >= APPROVAL_THRESHOLD ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${avg}%`}}/>
                        </div>
                        <span className={`text-[10px] font-black tabular-nums ${avg >= APPROVAL_THRESHOLD ? 'text-emerald-600' : 'text-red-600'}`}>{Math.round(avg)}%</span>
                      </div>
                    </button>
                  );
                })}
               </div>
            </div>

            <div className="mt-auto p-8 border-t border-slate-100 bg-slate-100/30">
               <div className="flex items-center space-x-3 text-slate-400">
                  <Info className="w-4 h-4" />
                  <p className="text-[9px] font-bold uppercase leading-tight tracking-wider">Los datos se guardan al presionar el botón inferior.</p>
               </div>
            </div>
          </div>

          {/* Main Content Area */}
          <div className="flex-1 p-8 md:p-14 overflow-y-auto bg-white scroll-smooth">
            {showHistory ? (
              <div className="animate-in slide-in-from-right-4 duration-300">
                 <div className="flex items-center justify-between mb-10 pb-6 border-b-2 border-slate-50">
                    <h3 className="text-2xl font-black text-slate-800 tracking-tighter flex items-center">
                       <History className="w-6 h-6 mr-3 text-red-600" /> Registro de Movimientos
                    </h3>
                    <button onClick={() => setShowHistory(false)} className="text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-red-600">Regresar a notas</button>
                 </div>

                 <div className="space-y-8 relative before:absolute before:left-3 before:top-4 before:bottom-4 before:w-1 before:bg-slate-50 before:rounded-full">
                    <div className="relative pl-12 group">
                       <div className="absolute left-0 top-1 w-7 h-7 bg-red-600 rounded-full flex items-center justify-center border-4 border-white shadow-lg z-10 scale-110">
                          <div className="w-1.5 h-1.5 rounded-full bg-white" />
                       </div>
                       <p className="text-[10px] font-black text-red-600 uppercase tracking-widest mb-1">Estado Actual</p>
                       <div className="bg-white p-5 rounded-3xl border-2 border-red-50 shadow-sm">
                          <p className="text-lg font-black text-slate-800 tracking-tight">{currentStore?.name}</p>
                          <p className="text-xs font-bold text-slate-400 uppercase mt-1">{employee.zone} • {employee.title}</p>
                       </div>
                    </div>

                    {employee.history?.map((h, i) => (
                      <div key={i} className="relative pl-12">
                         <div className="absolute left-1.5 top-2 w-4 h-4 bg-slate-200 rounded-full border-4 border-white z-10" />
                         <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{h.action} - {h.date}</p>
                         <div className="bg-slate-50/50 p-5 rounded-3xl border-2 border-slate-50">
                            <p className="text-md font-black text-slate-600 tracking-tight">{h.restaurantName}</p>
                         </div>
                      </div>
                    ))}

                    {!employee.history && (
                      <div className="pl-12 py-10">
                        <div className="p-8 border-2 border-slate-50 border-dashed rounded-[32px] text-center">
                          <History className="w-10 h-10 text-slate-100 mx-auto mb-3" />
                          <p className="text-xs font-bold text-slate-300 italic">No se registran traslados históricos para este colaborador.</p>
                        </div>
                      </div>
                    )}
                 </div>
              </div>
            ) : (
              <div className="animate-in slide-in-from-left-4 duration-300">
                <div className="flex items-start p-8 bg-slate-900 text-white rounded-[40px] mb-12 shadow-2xl shadow-slate-200 relative overflow-hidden group">
                  <div className="absolute right-0 bottom-0 scale-150 translate-x-1/4 translate-y-1/4 opacity-10 group-hover:rotate-12 transition-transform duration-1000">
                    <TrendingUp className="w-48 h-48" />
                  </div>
                  <Info className="w-8 h-8 text-red-500 mr-6 mt-0.5 shrink-0" />
                  <div className="relative z-10">
                    <p className="text-xl font-black tracking-tight uppercase">Evaluación: { (EVALUATION_GROUPS as any)[activeGroup].name }</p>
                    <p className="text-sm text-slate-400 font-bold mt-2 leading-relaxed max-w-lg">
                      Ingrese puntajes reales del <span className="text-white">0%</span> al <span className="text-white">100%</span>. El umbral de excelencia es <span className="text-red-500 font-black">{APPROVAL_THRESHOLD}%</span>.
                    </p>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-x-14 gap-y-12">
                  {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                    const score = getScore(activeGroup, cat);
                    return (
                      <div key={cat} className="space-y-5 animate-in fade-in duration-500">
                        <div className="flex justify-between items-end px-1">
                          <label className="text-[11px] font-black text-slate-800 uppercase tracking-widest line-clamp-1">{cat}</label>
                          <span className={`text-[10px] font-black px-2 py-0.5 rounded ${score >= APPROVAL_THRESHOLD ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                            {score >= APPROVAL_THRESHOLD ? '✓ EXCELENCIA' : '○ EN PROCESO'}
                          </span>
                        </div>
                        <div className="flex items-center space-x-8">
                          <div className="relative shrink-0">
                            <input 
                              type="number" 
                              min="0" 
                              max="100" 
                              value={score} 
                              onChange={e => handleScoreChange(activeGroup, cat, e.target.value)} 
                              onFocus={e => e.target.select()} 
                              className={`w-28 px-5 py-5 bg-white border-4 rounded-[28px] text-2xl font-black text-slate-900 text-center outline-none transition-all shadow-sm ${score >= APPROVAL_THRESHOLD ? 'border-emerald-100 focus:border-emerald-400' : 'border-slate-100 focus:border-red-500'}`} 
                            />
                            <span className="absolute -top-3 left-1/2 -translate-x-1/2 bg-white px-2 text-[10px] font-black text-slate-300 uppercase tracking-widest border border-slate-100 rounded-full shadow-sm">%</span>
                          </div>
                          <div className="flex-1 space-y-3">
                            <div className="h-2.5 bg-slate-50 rounded-full overflow-hidden shadow-inner ring-1 ring-slate-100">
                              <div className={`h-full transition-all duration-700 ease-out ${score >= APPROVAL_THRESHOLD ? 'bg-emerald-500' : 'bg-red-600'}`} style={{width: `${score}%`}} />
                            </div>
                            <div className="flex justify-between text-[9px] font-black text-slate-300 tracking-tighter">
                               <span>PUNTAJE OBTENIDO</span>
                               <span>OBJETIVO: 100%</span>
                            </div>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}
            <div className="h-28 md:hidden" />
          </div>
        </div>

        {/* Footer Action Bar */}
        <div className="p-8 border-t border-slate-100 bg-slate-50 flex flex-col md:flex-row justify-end gap-5 shrink-0 px-14">
          <button 
            onClick={onClose} 
            className="px-8 font-black text-slate-400 text-[11px] uppercase tracking-[0.2em] hover:text-slate-800 transition py-4 md:py-0"
          >
            DESCARTAR CAMBIOS
          </button>
          <button 
            onClick={saveGrades} 
            className="px-16 py-6 bg-slate-900 text-white font-black rounded-[28px] shadow-2xl shadow-slate-200 hover:bg-black hover:-translate-y-1 transition-all active:scale-95 text-[11px] uppercase tracking-[0.2em] flex items-center justify-center ring-4 ring-slate-100"
          >
            <Save className="w-4.5 h-4.5 mr-3" /> CONFIRMAR NOTAS
          </button>
        </div>
      </div>
    </div>
  );
};

export default GradeEditor;

import React, { useMemo, useState } from 'react';
import { Employee, GradeEntry, User, Restaurant, UserRole } from '../types';
import { dataService } from '../dataService';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, INITIAL_ZONES, INITIAL_REGIONS } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { XCircle, Users, Award, TrendingUp, Search, MapPin, Filter } from 'lucide-react';

interface DashboardProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ employees: initialEmployees, restaurants, selectedMonth, user }) => {
  const [searchPerson, setSearchPerson] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterStore, setFilterStore] = useState('all');
  const [filterZone, setFilterZone] = useState('all');

  const filteredData = useMemo(() => {
    return initialEmployees.filter(e => {
      const store = restaurants.find(r => r.id === e.restaurantId);
      const matchPerson = searchPerson === '' || e.name.toLowerCase().includes(searchPerson.toLowerCase()) || e.id.includes(searchPerson);
      const matchStore = filterStore === 'all' || e.restaurantId === filterStore;
      const matchZone = filterZone === 'all' || e.zone === filterZone;
      const matchRegion = filterRegion === 'all' || store?.region === filterRegion;
      return matchPerson && matchStore && matchZone && matchRegion;
    });
  }, [initialEmployees, searchPerson, filterStore, filterZone, filterRegion, restaurants]);

  const grades = useMemo(() => dataService.getGrades().filter(g => g.month === selectedMonth), [selectedMonth]);

  const stats = useMemo(() => {
    const totalEmployees = filteredData.length;
    let approvedCount = 0;

    const groupAvgs = Object.keys(EVALUATION_GROUPS).map(groupId => {
      const groupGrades = grades.filter(g => g.group === groupId && filteredData.some(e => e.id === g.employeeId));
      const avg = groupGrades.length > 0 ? groupGrades.reduce((sum, g) => sum + g.score, 0) / groupGrades.length : 0;
      return {
        id: groupId,
        name: (EVALUATION_GROUPS as any)[groupId].name,
        avg: Math.round(avg)
      };
    });

    filteredData.forEach(emp => {
      const empGrades = grades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        const avg = empGrades.reduce((sum, g) => sum + g.score, 0) / empGrades.length;
        if (avg >= APPROVAL_THRESHOLD) approvedCount++;
      }
    });

    return { totalEmployees, approvedCount, groupAvgs };
  }, [filteredData, grades]);

  const COLORS = ['#ef4444', '#22c55e'];

  return (
    <div className="space-y-6">
      {/* Filters Section */}
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {user.role === UserRole.ADMIN && (
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
            <div className="relative">
              <select 
                value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 transition-all outline-none appearance-none"
              >
                <option value="all">Todas las Regiones</option>
                {INITIAL_REGIONS.map(r => <option key={r} value={r}>{r}</option>)}
              </select>
              <MapPin className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
          </div>
        )}

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
          <div className="relative">
            <select 
              value={filterZone} onChange={(e) => setFilterZone(e.target.value)}
              className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 transition-all outline-none appearance-none"
            >
              <option value="all">Todas las Zonas</option>
              {INITIAL_ZONES.filter(z => user.role === UserRole.ADMIN || user.assignedZones.includes(z)).map(z => (
                <option key={z} value={z}>{z}</option>
              ))}
            </select>
            <Filter className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Tienda</label>
          <div className="relative">
            <select 
              value={filterStore} onChange={(e) => setFilterStore(e.target.value)}
              className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 transition-all outline-none appearance-none"
            >
              <option value="all">Todas las Tiendas</option>
              {restaurants.filter(r => user.role === UserRole.ADMIN || user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone)).map(r => (
                <option key={r.id} value={r.id}>{r.name}</option>
              ))}
            </select>
            <Filter className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Persona</label>
          <div className="relative">
            <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <input 
              type="text" placeholder="Nombre o ID..." value={searchPerson} onChange={(e) => setSearchPerson(e.target.value)}
              className="w-full pl-11 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 outline-none transition-all placeholder:text-slate-300"
            />
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard icon={<Users className="w-6 h-6" />} label="Equipo" value={stats.totalEmployees} subValue="Personal Activo" />
        <StatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approvedCount} subValue="Meta Cumplida" color="green" />
        <StatCard icon={<TrendingUp className="w-6 h-6" />} label="Desempeño" value={`${stats.groupAvgs.length > 0 ? Math.round(stats.groupAvgs.reduce((s, g) => s + g.avg, 0) / stats.groupAvgs.length) : 0}%`} subValue="Promedio Mes" color="blue" />
        <StatCard icon={<XCircle className="w-6 h-6" />} label="Faltantes" value={stats.totalEmployees - stats.approvedCount} subValue="Por evaluar" color="red" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
          <h3 className="text-sm font-black text-slate-800 mb-8 uppercase tracking-widest flex items-center">
            <TrendingUp className="w-4 h-4 mr-2 text-red-500" /> Desempeño por Grupo Evaluativo
          </h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.groupAvgs} margin={{ top: 0, right: 0, left: -25, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                <YAxis domain={[0, 100]} axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                <Tooltip cursor={{ fill: '#f8fafc' }} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', fontWeight: '900', fontSize: '12px' }} />
                <Bar dataKey="avg" radius={[10, 10, 0, 0]} barSize={45}>
                  {stats.groupAvgs.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.avg >= APPROVAL_THRESHOLD ? '#10b981' : '#ef4444'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
          <h3 className="text-sm font-black text-slate-800 mb-8 uppercase tracking-widest flex items-center">
            <Award className="w-4 h-4 mr-2 text-red-500" /> Nivel de Certificación
          </h3>
          <div className="h-[300px] flex items-center justify-center relative">
             <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={[
                      { name: 'Pendiente', value: stats.totalEmployees - stats.approvedCount },
                      { name: 'Certificado', value: stats.approvedCount },
                    ]}
                    cx="50%" cy="50%" innerRadius={80} outerRadius={110} paddingAngle={10} dataKey="value" stroke="none"
                  >
                    {COLORS.map((color, index) => <Cell key={`cell-${index}`} fill={color} />)}
                  </Pie>
                  <Tooltip contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', fontWeight: '900' }} />
                </PieChart>
             </ResponsiveContainer>
             <div className="absolute flex flex-col items-center">
                <span className="text-5xl font-black text-slate-800 tracking-tighter">{stats.totalEmployees > 0 ? Math.round((stats.approvedCount / stats.totalEmployees) * 100) : 0}%</span>
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Global</span>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ icon: React.ReactNode, label: string, value: string | number, subValue: string, color?: string }> = ({ icon, label, value, subValue, color = 'gray' }) => {
  const colorMap: any = {
    red: 'bg-red-50 text-red-600', green: 'bg-emerald-50 text-emerald-600',
    blue: 'bg-blue-50 text-blue-600', gray: 'bg-slate-50 text-slate-600',
  };
  return (
    <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 transition-transform hover:scale-[1.02]">
      <div className="flex items-center space-x-5">
        <div className={`p-4 rounded-2xl ${colorMap[color]}`}>{icon}</div>
        <div>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-1">{label}</p>
          <h4 className="text-3xl font-black text-slate-800 tracking-tighter leading-none">{value}</h4>
          <p className="text-[10px] text-slate-400 font-bold mt-2 truncate">{subValue}</p>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Employee, Restaurant, JobHierarchy, User } from '../types';
import { Search, ChevronRight, Edit3, Filter, Users } from 'lucide-react';
import GradeEditor from './GradeEditor';
import { APPROVAL_THRESHOLD } from '../constants';
import { dataService } from '../dataService';

interface EmployeeListProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
  onUpdate: () => void;
}

const EmployeeList: React.FC<EmployeeListProps> = ({ employees, restaurants, selectedMonth, user, onUpdate }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedRestaurant, setSelectedRestaurant] = useState<string>('all');
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  const filteredAndSorted = useMemo(() => {
    let result = employees.filter(e => 
      (searchTerm === '' || e.name.toLowerCase().includes(searchTerm.toLowerCase()) || e.id.includes(searchTerm)) &&
      (selectedRestaurant === 'all' || e.restaurantId === selectedRestaurant)
    );
    return result.sort((a, b) => JobHierarchy[a.title] - JobHierarchy[b.title]);
  }, [employees, searchTerm, selectedRestaurant]);

  const allGrades = useMemo(() => dataService.getGrades().filter(g => g.month === selectedMonth), [selectedMonth, editingEmployee]);

  const getStatus = (employeeId: string) => {
    const grades = allGrades.filter(g => g.employeeId === employeeId);
    if (grades.length === 0) return 'PENDING';
    const avg = grades.reduce((s, g) => s + g.score, 0) / grades.length;
    return avg >= APPROVAL_THRESHOLD ? 'APPROVED' : 'FAILED';
  };

  return (
    <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
      <div className="p-8 border-b border-slate-50 flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h2 className="text-2xl font-black text-slate-800 tracking-tight flex items-center">
            <Users className="w-6 h-6 mr-3 text-red-600" /> Trabajadores
          </h2>
          <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Gestión de capital humano y métricas</p>
        </div>

        <div className="flex flex-col md:flex-row items-center gap-4">
          <div className="relative w-full md:w-72">
            <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <input
              type="text" placeholder="Buscar por nombre o ID..."
              className="w-full pl-12 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 transition-all outline-none placeholder:text-slate-300"
              value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="relative w-full md:w-64">
            <Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <select
              className="w-full pl-12 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 outline-none appearance-none cursor-pointer"
              value={selectedRestaurant} onChange={(e) => setSelectedRestaurant(e.target.value)}
            >
              <option value="all">Todas las Tiendas</option>
              {restaurants.filter(r => user.role === 'ADMIN' || user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone)).map(r => (
                <option key={r.id} value={r.id}>{r.name}</option>
              ))}
            </select>
          </div>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50/50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">ID / Cédula</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Rol</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Tienda</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Estado</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {filteredAndSorted.map(emp => {
              const status = getStatus(emp.id);
              return (
                <tr key={emp.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-5">
                    <div className="font-black text-slate-800 group-hover:text-red-600 transition-colors">{emp.name}</div>
                  </td>
                  <td className="px-8 py-5 text-sm font-bold text-slate-500">{emp.id}</td>
                  <td className="px-8 py-5">
                    <span className="px-3 py-1 bg-white border border-slate-200 text-slate-500 rounded-lg text-[10px] font-black uppercase tracking-tighter">
                      {emp.title}
                    </span>
                  </td>
                  <td className="px-8 py-5">
                    <div className="text-sm font-black text-slate-700">{restaurants.find(r => r.id === emp.restaurantId)?.name}</div>
                    <div className="text-[10px] font-bold text-slate-400 uppercase">{emp.zone}</div>
                  </td>
                  <td className="px-8 py-5">
                    {status === 'APPROVED' && <span className="inline-flex items-center px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[9px] font-black uppercase">✓ Aprobado</span>}
                    {status === 'FAILED' && <span className="inline-flex items-center px-3 py-1 bg-red-50 text-red-600 rounded-full text-[9px] font-black uppercase">✗ Reprobado</span>}
                    {status === 'PENDING' && <span className="inline-flex items-center px-3 py-1 bg-slate-50 text-slate-400 rounded-full text-[9px] font-black uppercase">○ Pendiente</span>}
                  </td>
                  <td className="px-8 py-5 text-center">
                    <button 
                      onClick={() => setEditingEmployee(emp)}
                      className="p-3 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-2xl transition-all active:scale-90"
                    >
                      <Edit3 className="w-5 h-5" />
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {editingEmployee && (
        <GradeEditor 
          employee={editingEmployee}
          month={selectedMonth}
          onClose={() => { setEditingEmployee(null); onUpdate(); }}
        />
      )}
    </div>
  );
};

export default EmployeeList;

import React, { useState, useEffect } from 'react';
import { Employee, GradeEntry, JobTitle } from '../types';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, INITIAL_RESTAURANTS } from '../constants';
import { dataService } from '../dataService';
// Added TrendingUp to the lucide-react imports to fix "Cannot find name 'TrendingUp'" error
import { X, Save, Info, User, Calendar, MapPin, Briefcase, History, ChevronRight, TrendingUp } from 'lucide-react';

interface GradeEditorProps {
  employee: Employee;
  month: string;
  onClose: () => void;
}

const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('A');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  useEffect(() => {
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    setFormGrades(existing);
  }, [employee, month]);

  const handleScoreChange = (group: string, category: string, scoreStr: string) => {
    let score = parseInt(scoreStr);
    if (isNaN(score)) score = 0;
    const sanitizedScore = Math.max(0, Math.min(100, score));
    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) {
        const next = [...prev];
        next[idx] = { ...next[idx], score: sanitizedScore };
        return next;
      }
      return [...prev, { employeeId: employee.id, month, group, category, score: sanitizedScore }];
    });
  };

  const saveGrades = () => {
    const allGrades = dataService.getGrades();
    const filtered = allGrades.filter(g => !(g.employeeId === employee.id && g.month === month));
    dataService.saveGrades([...filtered, ...formGrades]);
    onClose();
  };

  const getScore = (group: string, category: string) => {
    return formGrades.find(g => g.group === group && g.category === category)?.score ?? 0;
  };

  const currentStore = INITIAL_RESTAURANTS.find(r => r.id === employee.restaurantId);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-0 md:p-4 animate-in fade-in duration-200">
      <div className="bg-white rounded-none md:rounded-[40px] shadow-[0_0_100px_rgba(0,0,0,0.5)] w-full max-w-5xl h-full md:h-auto md:max-h-[92vh] flex flex-col overflow-hidden border-4 border-white ring-1 ring-slate-800">

        {/* Profile Header */}
        <div className="p-8 bg-red-600 text-white shrink-0 relative overflow-hidden">
          <div className="absolute right-0 top-0 opacity-10 rotate-12 -translate-y-4 translate-x-4">
             <Briefcase className="w-48 h-48" />
          </div>

          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 relative z-10">
            <div className="flex items-center space-x-6">
              <div className="w-20 h-20 bg-white/20 rounded-[28px] flex items-center justify-center backdrop-blur-md border-2 border-white/20 shadow-inner shrink-0">
                <User className="w-10 h-10 text-white" />
              </div>
              <div>
                <div className="flex items-center gap-4 mb-2">
                   <h2 className="text-3xl font-black tracking-tighter uppercase leading-none">{employee.name}</h2>
                   <button 
                    onClick={() => setShowHistory(!showHistory)}
                    className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center transition-all ${showHistory ? 'bg-white text-red-600 shadow-lg' : 'bg-white/10 text-white hover:bg-white/20'}`}
                   >
                     <History className="w-3.5 h-3.5 mr-2" /> Historial de Traslados
                   </button>
                </div>
                <div className="flex flex-wrap gap-x-6 gap-y-2">
                  <span className="flex items-center text-[10px] font-black uppercase tracking-widest"><Briefcase className="w-3 h-3 mr-2 text-red-200"/> {employee.title}</span>
                  <span className="flex items-center text-[10px] font-black uppercase tracking-widest"><MapPin className="w-3 h-3 mr-2 text-red-200"/> {currentStore?.name} • {employee.zone}</span>
                  <span className="flex items-center text-[10px] font-black uppercase tracking-widest"><Calendar className="w-3 h-3 mr-2 text-red-200"/> Ingreso: {employee.joinDate}</span>
                </div>
              </div>
            </div>
            <button onClick={onClose} className="p-4 bg-white/10 hover:bg-white/20 rounded-2xl transition-all self-end md:self-auto shadow-sm">
              <X className="w-6 h-6"/>
            </button>
          </div>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
          {/* Navigation Sidebar */}
          <div className="w-full md:w-72 bg-slate-50 border-r border-slate-100 flex flex-col overflow-y-auto shrink-0">
            <div className="p-8">
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6 px-1">Secciones de Evaluación</p>
               <div className="space-y-3">
                {Object.entries(EVALUATION_GROUPS).map(([id, group]) => {
                  const isActive = activeGroup === id;
                  const groupGrades = formGrades.filter(g => g.group === id);
                  const avg = groupGrades.length > 0 ? groupGrades.reduce((s, g) => s + g.score, 0) / groupGrades.length : 0;
                  return (
                    <button 
                      key={id} 
                      onClick={() => { setActiveGroup(id); setShowHistory(false); }} 
                      className={`w-full p-4 rounded-2xl text-left transition-all border-2 ${isActive && !showHistory ? 'bg-white border-red-500 shadow-xl shadow-red-50/50 scale-[1.02]' : 'bg-transparent border-transparent hover:bg-slate-100 opacity-70 hover:opacity-100'}`}
                    >
                      <p className={`text-xs font-black truncate mb-2 ${isActive && !showHistory ? 'text-slate-900' : 'text-slate-400'}`}>{group.name}</p>
                      <div className="flex items-center justify-between">
                        <div className="flex-1 h-1.5 bg-slate-200 rounded-full mr-3 overflow-hidden">
                          <div className={`h-full transition-all duration-700 ${avg >= APPROVAL_THRESHOLD ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${avg}%`}}/>
                        </div>
                        <span className={`text-[10px] font-black tabular-nums ${avg >= APPROVAL_THRESHOLD ? 'text-emerald-600' : 'text-red-600'}`}>{Math.round(avg)}%</span>
                      </div>
                    </button>
                  );
                })}
               </div>
            </div>

            <div className="mt-auto p-8 border-t border-slate-100 bg-slate-100/30">
               <div className="flex items-center space-x-3 text-slate-400">
                  <Info className="w-4 h-4" />
                  <p className="text-[9px] font-bold uppercase leading-tight tracking-wider">Los datos se guardan al presionar el botón inferior.</p>
               </div>
            </div>
          </div>

          {/* Main Content Area */}
          <div className="flex-1 p-8 md:p-14 overflow-y-auto bg-white scroll-smooth">
            {showHistory ? (
              <div className="animate-in slide-in-from-right-4 duration-300">
                 <div className="flex items-center justify-between mb-10 pb-6 border-b-2 border-slate-50">
                    <h3 className="text-2xl font-black text-slate-800 tracking-tighter flex items-center">
                       <History className="w-6 h-6 mr-3 text-red-600" /> Registro de Movimientos
                    </h3>
                    <button onClick={() => setShowHistory(false)} className="text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-red-600">Regresar a notas</button>
                 </div>

                 <div className="space-y-8 relative before:absolute before:left-3 before:top-4 before:bottom-4 before:w-1 before:bg-slate-50 before:rounded-full">
                    <div className="relative pl-12 group">
                       <div className="absolute left-0 top-1 w-7 h-7 bg-red-600 rounded-full flex items-center justify-center border-4 border-white shadow-lg z-10 scale-110">
                          <div className="w-1.5 h-1.5 rounded-full bg-white" />
                       </div>
                       <p className="text-[10px] font-black text-red-600 uppercase tracking-widest mb-1">Estado Actual</p>
                       <div className="bg-white p-5 rounded-3xl border-2 border-red-50 shadow-sm">
                          <p className="text-lg font-black text-slate-800 tracking-tight">{currentStore?.name}</p>
                          <p className="text-xs font-bold text-slate-400 uppercase mt-1">{employee.zone} • {employee.title}</p>
                       </div>
                    </div>

                    {employee.history?.map((h, i) => (
                      <div key={i} className="relative pl-12">
                         <div className="absolute left-1.5 top-2 w-4 h-4 bg-slate-200 rounded-full border-4 border-white z-10" />
                         <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{h.action} - {h.date}</p>
                         <div className="bg-slate-50/50 p-5 rounded-3xl border-2 border-slate-50">
                            <p className="text-md font-black text-slate-600 tracking-tight">{h.restaurantName}</p>
                         </div>
                      </div>
                    ))}

                    {!employee.history && (
                      <div className="pl-12 py-10">
                        <div className="p-8 border-2 border-slate-50 border-dashed rounded-[32px] text-center">
                          <History className="w-10 h-10 text-slate-100 mx-auto mb-3" />
                          <p className="text-xs font-bold text-slate-300 italic">No se registran traslados históricos para este colaborador.</p>
                        </div>
                      </div>
                    )}
                 </div>
              </div>
            ) : (
              <div className="animate-in slide-in-from-left-4 duration-300">
                <div className="flex items-start p-8 bg-slate-900 text-white rounded-[40px] mb-12 shadow-2xl shadow-slate-200 relative overflow-hidden group">
                  <div className="absolute right-0 bottom-0 scale-150 translate-x-1/4 translate-y-1/4 opacity-10 group-hover:rotate-12 transition-transform duration-1000">
                    <TrendingUp className="w-48 h-48" />
                  </div>
                  <Info className="w-8 h-8 text-red-500 mr-6 mt-0.5 shrink-0" />
                  <div className="relative z-10">
                    <p className="text-xl font-black tracking-tight uppercase">Evaluación: { (EVALUATION_GROUPS as any)[activeGroup].name }</p>
                    <p className="text-sm text-slate-400 font-bold mt-2 leading-relaxed max-w-lg">
                      Ingrese puntajes reales del <span className="text-white">0%</span> al <span className="text-white">100%</span>. El umbral de excelencia es <span className="text-red-500 font-black">{APPROVAL_THRESHOLD}%</span>.
