import React, { useState } from 'react';
import { Upload, UserPlus, Database, Search, X, Check, ChevronDown, Lock, Shield, FileSpreadsheet } from 'lucide-react';
import { dataService } from '../dataService';
import { UserRole, User } from '../types';
import { INITIAL_RESTAURANTS, INITIAL_ZONES } from '../constants';

interface AdminPanelProps {
  onEmployeesImported: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onEmployeesImported }) => {
  const [importStatus, setImportStatus] = useState<string | null>(null);
  const [isImporting, setIsImporting] = useState(false);
  const [showUserModal, setShowUserModal] = useState(false);
  const [newUserData, setNewUserData] = useState({
    username: '',
    password: '',
    role: UserRole.SPECIALIST,
    assignedZones: [] as string[],
  });

  const handleSimulateImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files?.[0]) return;

    setIsImporting(true);
    setImportStatus('Leyendo archivo...');

    // Simulamos el procesamiento del Excel
    setTimeout(() => {
      const current = dataService.getEmployees();
      // Simulación: Actualizamos todos a activos y detectamos "cambios"
      const updated = current.map(e => ({ ...e, active: true }));
      dataService.saveEmployees(updated);

      setIsImporting(false);
      setImportStatus('Sincronización mensual completada con éxito');
      onEmployeesImported();
      setTimeout(() => setImportStatus(null), 4000);
    }, 2000);
  };

  const handleCreateUser = () => {
    if (!newUserData.username || !newUserData.password) return;
    const users = dataService.getUsers();
    const newUser: User = {
      id: `u-${Date.now()}`,
      username: newUserData.username,
      password: newUserData.password,
      role: newUserData.role,
      assignedZones: newUserData.assignedZones,
      assignedRestaurants: []
    };
    localStorage.setItem('la_akademia_users', JSON.stringify([...users, newUser]));
    setShowUserModal(false);
    setNewUserData({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [] });
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-10 rounded-[40px] shadow-sm border border-slate-100">
        <div className="flex items-center space-x-6 mb-10">
          <div className="p-5 bg-red-600 text-white rounded-[24px] shadow-xl shadow-red-100">
            <Shield className="w-10 h-10" />
          </div>
          <div>
            <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Administración del Sistema</h2>
            <p className="text-slate-500 font-bold uppercase tracking-widest text-[10px]">Gestión de Accesos e Integridad de Datos</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
          {/* Panel de Importación */}
