                    <button 
                      key={id} 
                      onClick={() => { setActiveGroup(id); setShowHistory(false); }} 
                      className={`w-full p-4 rounded-2xl text-left transition-all border-2 ${isActive && !showHistory ? 'bg-white border-red-500 shadow-xl shadow-red-50/50 scale-[1.02]' : 'bg-transparent border-transparent hover:bg-slate-100 opacity-80 hover:opacity-100'}`}
                    >
                      <p className={`text-xs font-black truncate mb-2 ${isActive && !showHistory ? 'text-slate-900' : 'text-slate-700'}`}>{group.name}</p>
