                  <p className="text-[9px] font-bold uppercase leading-tight tracking-wider">Los datos se guardan al presionar el botón inferior.</p>
               </div>
            </div>
          </div>

          {/* Main Content Area */}
          <div className="flex-1 p-8 md:p-14 overflow-y-auto bg-white scroll-smooth">
            {showHistory ? (
              <div className="animate-in slide-in-from-right-4 duration-300">
                 <div className="flex items-center justify-between mb-10 pb-6 border-b-2 border-slate-50">
                    <h3 className="text-2xl font-black text-slate-800 tracking-tighter flex items-center">
                       <History className="w-6 h-6 mr-3 text-red-600" /> Registro de Movimientos
                    </h3>
                    <button onClick={() => setShowHistory(false)} className="text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-red-600">Regresar a notas</button>
                 </div>

                 <div className="space-y-8 relative before:absolute before:left-3 before:top-4 before:bottom-4 before:w-1 before:bg-slate-50 before:rounded-full">
