                            <div className="h-2.5 bg-slate-50 rounded-full overflow-hidden shadow-inner ring-1 ring-slate-100">
                              <div className={`h-full transition-all duration-700 ease-out ${score >= APPROVAL_THRESHOLD ? 'bg-emerald-500' : 'bg-red-600'}`} style={{width: `${score}%`}} />
                            </div>
                            <div className="flex justify-between text-[9px] font-black text-slate-300 tracking-tighter">
                               <span>PUNTAJE OBTENIDO</span>
                               <span>OBJETIVO: 100%</span>
                            </div>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}
            <div className="h-28 md:hidden" />
          </div>
        </div>

        {/* Footer Action Bar */}
        <div className="p-8 border-t border-slate-100 bg-slate-50 flex flex-col md:flex-row justify-end gap-5 shrink-0 px-14">
          <button 
            onClick={onClose} 
            className="px-8 font-black text-slate-400 text-[11px] uppercase tracking-[0.2em] hover:text-slate-800 transition py-4 md:py-0"
          >
            DESCARTAR CAMBIOS
          </button>
          <button 
            onClick={saveGrades} 
            className="px-16 py-6 bg-slate-900 text-white font-black rounded-[28px] shadow-2xl shadow-slate-200 hover:bg-black hover:-translate-y-1 transition-all active:scale-95 text-[11px] uppercase tracking-[0.2em] flex items-center justify-center ring-4 ring-slate-100"
          >
            <Save className="w-4.5 h-4.5 mr-3" /> CONFIRMAR NOTAS
          </button>
        </div>
      </div>
    </div>
  );
};

