                       </div>
                       <p className="text-[10px] font-black text-red-600 uppercase tracking-widest mb-1">Estado Actual</p>
                       <div className="bg-white p-5 rounded-3xl border-2 border-red-50 shadow-sm">
                          <p className="text-lg font-black text-slate-800 tracking-tight">{currentStore?.name}</p>
                          <p className="text-xs font-bold text-slate-400 uppercase mt-1">{employee.zone} • {employee.title}</p>
