                  <div className="relative z-10">
                    <p className="text-xl font-black tracking-tight uppercase">Evaluación: { (EVALUATION_GROUPS as any)[activeGroup].name }</p>
                    <p className="text-sm text-slate-400 font-bold mt-2 leading-relaxed max-w-lg">
                      Ingrese puntajes reales del <span className="text-white">0%</span> al <span className="text-white">100%</span>. El umbral de excelencia es <span className="text-red-500 font-black">{APPROVAL_THRESHOLD}%</span>.
                    </p>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-x-14 gap-y-12">
