import React, { useMemo, useState } from 'react';
import { Employee, GradeEntry, User, Restaurant, UserRole } from '../types';
import { dataService } from '../dataService';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, INITIAL_ZONES, INITIAL_REGIONS, TOTAL_CATEGORIES_COUNT } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { XCircle, Users, Award, TrendingUp, Search, MapPin, Filter } from 'lucide-react';

interface DashboardProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ employees: initialEmployees, restaurants, selectedMonth, user }) => {
  const [searchPerson, setSearchPerson] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterStore, setFilterStore] = useState('all');
  const [filterZone, setFilterZone] = useState('all');

  const filteredData = useMemo(() => {
    return initialEmployees.filter(e => {
      const store = restaurants.find(r => r.id === e.restaurantId);
      const matchPerson = searchPerson === '' || e.name.toLowerCase().includes(searchPerson.toLowerCase()) || e.id.includes(searchPerson);
      const matchStore = filterStore === 'all' || e.restaurantId === filterStore;
      const matchZone = filterZone === 'all' || e.zone === filterZone;
      const matchRegion = filterRegion === 'all' || store?.region === filterRegion;
      return matchPerson && matchStore && matchZone && matchRegion;
    });
  }, [initialEmployees, searchPerson, filterStore, filterZone, filterRegion, restaurants]);

  const grades = useMemo(() => dataService.getGrades().filter(g => g.month === selectedMonth), [selectedMonth]);

  const stats = useMemo(() => {
    const totalEmployees = filteredData.length;
    let approvedCount = 0;

    const groupAvgs = Object.keys(EVALUATION_GROUPS).map(groupId => {
      const groupData = (EVALUATION_GROUPS as any)[groupId];
      const groupGrades = grades.filter(g => g.group === groupId && filteredData.some(e => e.id === g.employeeId));

      // Promedio corregido: suma de notas / (número de empleados * categorías del grupo)
      const totalPossibleCategories = filteredData.length * groupData.categories.length;
      const sumScores = groupGrades.reduce((sum, g) => sum + g.score, 0);
      const avg = totalPossibleCategories > 0 ? sumScores / totalPossibleCategories : 0;

      return {
        id: groupId,
        name: groupData.name,
        avg: Math.round(avg)
      };
    });

    filteredData.forEach(emp => {
      const empGrades = grades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        // Promedio del empleado: suma / 22 categorías totales
        const sum = empGrades.reduce((sum, g) => sum + g.score, 0);
        const avg = sum / TOTAL_CATEGORIES_COUNT;
        if (avg >= APPROVAL_THRESHOLD) approvedCount++;
      }
    });

    return { totalEmployees, approvedCount, groupAvgs };
  }, [filteredData, grades]);

  const COLORS = ['#ef4444', '#22c55e'];

  return (
    <div className="space-y-6">
      {/* Filters Section */}
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {user.role === UserRole.ADMIN && (
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
            <div className="relative">
              <select 
                value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 transition-all outline-none appearance-none"
              >
                <option value="all">Todas las Regiones</option>
                {INITIAL_REGIONS.map(r => <option key={r} value={r}>{r}</option>)}
              </select>
              <MapPin className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
          </div>
        )}

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
          <div className="relative">
            <select 
              value={filterZone} onChange={(e) => setFilterZone(e.target.value)}
              className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 transition-all outline-none appearance-none"
            >
              <option value="all">Todas las Zonas</option>
              {INITIAL_ZONES.filter(z => user.role === UserRole.ADMIN || user.assignedZones.includes(z)).map(z => (
                <option key={z} value={z}>{z}</option>
              ))}
            </select>
            <Filter className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Tienda</label>
          <div className="relative">
            <select 
              value={filterStore} onChange={(e) => setFilterStore(e.target.value)}
              className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 transition-all outline-none appearance-none"
            >
              <option value="all">Todas las Tiendas</option>
              {restaurants.filter(r => user.role === UserRole.ADMIN || user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone)).map(r => (
                <option key={r.id} value={r.id}>{r.name}</option>
              ))}
            </select>
            <Filter className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Persona</label>
          <div className="relative">
            <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <input 
              type="text" placeholder="Nombre o ID..." value={searchPerson} onChange={(e) => setSearchPerson(e.target.value)}
              className="w-full pl-11 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 outline-none transition-all placeholder:text-slate-300"
            />
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard icon={<Users className="w-6 h-6" />} label="Equipo" value={stats.totalEmployees} subValue="Personal Activo" />
        <StatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approvedCount} subValue="Meta Cumplida" color="green" />
        <StatCard icon={<TrendingUp className="w-6 h-6" />} label="Desempeño" value={`${stats.groupAvgs.length > 0 ? Math.round(stats.groupAvgs.reduce((s, g) => s + g.avg, 0) / stats.groupAvgs.length) : 0}%`} subValue="Promedio Mes" color="blue" />
        <StatCard icon={<XCircle className="w-6 h-6" />} label="Faltantes" value={stats.totalEmployees - stats.approvedCount} subValue="Por evaluar" color="red" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
          <h3 className="text-sm font-black text-slate-800 mb-8 uppercase tracking-widest flex items-center">
            <TrendingUp className="w-4 h-4 mr-2 text-red-500" /> Desempeño por Grupo Evaluativo
          </h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.groupAvgs} margin={{ top: 0, right: 0, left: -25, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                <YAxis domain={[0, 100]} axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                <Tooltip cursor={{ fill: '#f8fafc' }} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', fontWeight: '900', fontSize: '12px' }} />
                <Bar dataKey="avg" radius={[10, 10, 0, 0]} barSize={45}>
                  {stats.groupAvgs.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.avg >= APPROVAL_THRESHOLD ? '#10b981' : '#ef4444'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
          <h3 className="text-sm font-black text-slate-800 mb-8 uppercase tracking-widest flex items-center">
            <Award className="w-4 h-4 mr-2 text-red-500" /> Nivel de Certificación
          </h3>
          <div className="h-[300px] flex items-center justify-center relative">
             <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={[
                      { name: 'Pendiente', value: stats.totalEmployees - stats.approvedCount },
                      { name: 'Certificado', value: stats.approvedCount },
                    ]}
                    cx="50%" cy="50%" innerRadius={80} outerRadius={110} paddingAngle={10} dataKey="value" stroke="none"
                  >
                    {COLORS.map((color, index) => <Cell key={`cell-${index}`} fill={color} />)}
                  </Pie>
                  <Tooltip contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', fontWeight: '900' }} />
                </PieChart>
             </ResponsiveContainer>
             <div className="absolute flex flex-col items-center">
                <span className="text-5xl font-black text-slate-800 tracking-tighter">{stats.totalEmployees > 0 ? Math.round((stats.approvedCount / stats.totalEmployees) * 100) : 0}%</span>
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Global</span>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ icon: React.ReactNode, label: string, value: string | number, subValue: string, color?: string }> = ({ icon, label, value, subValue, color = 'gray' }) => {
  const colorMap: any = {
    red: 'bg-red-50 text-red-600', green: 'bg-emerald-50 text-emerald-600',
    blue: 'bg-blue-50 text-blue-600', gray: 'bg-slate-50 text-slate-600',
  };
  return (
    <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 transition-transform hover:scale-[1.02]">
      <div className="flex items-center space-x-5">
        <div className={`p-4 rounded-2xl ${colorMap[color]}`}>{icon}</div>
        <div>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-1">{label}</p>
          <h4 className="text-3xl font-black text-slate-800 tracking-tighter leading-none">{value}</h4>
          <p className="text-[10px] text-slate-400 font-bold mt-2 truncate">{subValue}</p>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Employee, Restaurant, JobHierarchy, User } from '../types';
import { Search, ChevronRight, Edit3, Filter, Users } from 'lucide-react';
import GradeEditor from './GradeEditor';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { dataService } from '../dataService';

interface EmployeeListProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
  onUpdate: () => void;
}

const EmployeeList: React.FC<EmployeeListProps> = ({ employees, restaurants, selectedMonth, user, onUpdate }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedRestaurant, setSelectedRestaurant] = useState<string>('all');
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  const filteredAndSorted = useMemo(() => {
    let result = employees.filter(e => 
      (searchTerm === '' || e.name.toLowerCase().includes(searchTerm.toLowerCase()) || e.id.includes(searchTerm)) &&
      (selectedRestaurant === 'all' || e.restaurantId === selectedRestaurant)
    );
    return result.sort((a, b) => JobHierarchy[a.title] - JobHierarchy[b.title]);
  }, [employees, searchTerm, selectedRestaurant]);

  const allGrades = useMemo(() => dataService.getGrades().filter(g => g.month === selectedMonth), [selectedMonth, editingEmployee]);

  const getStatus = (employeeId: string) => {
    const grades = allGrades.filter(g => g.employeeId === employeeId);
    if (grades.length === 0) return 'PENDING';

    // El promedio debe considerar TODAS las categorías obligatorias del sistema
    const sum = grades.reduce((s, g) => s + g.score, 0);
    const avg = sum / TOTAL_CATEGORIES_COUNT;

    return avg >= APPROVAL_THRESHOLD ? 'APPROVED' : 'FAILED';
  };

  return (
    <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
      <div className="p-8 border-b border-slate-50 flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h2 className="text-2xl font-black text-slate-800 tracking-tight flex items-center">
            <Users className="w-6 h-6 mr-3 text-red-600" /> Trabajadores
          </h2>
          <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Gestión de capital humano y métricas</p>
        </div>

        <div className="flex flex-col md:flex-row items-center gap-4">
          <div className="relative w-full md:w-72">
            <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <input
              type="text" placeholder="Buscar por nombre o ID..."
              className="w-full pl-12 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 transition-all outline-none placeholder:text-slate-300"
              value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="relative w-full md:w-64">
            <Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <select
              className="w-full pl-12 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 outline-none appearance-none cursor-pointer"
              value={selectedRestaurant} onChange={(e) => setSelectedRestaurant(e.target.value)}
            >
              <option value="all">Todas las Tiendas</option>
              {restaurants.filter(r => user.role === 'ADMIN' || user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone)).map(r => (
                <option key={r.id} value={r.id}>{r.name}</option>
              ))}
            </select>
          </div>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50/50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">ID / Cédula</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Rol</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Tienda</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Estado</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {filteredAndSorted.map(emp => {
              const status = getStatus(emp.id);
              return (
                <tr key={emp.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-5">
                    <div className="font-black text-slate-800 group-hover:text-red-600 transition-colors">{emp.name}</div>
                  </td>
                  <td className="px-8 py-5 text-sm font-bold text-slate-500">{emp.id}</td>
                  <td className="px-8 py-5">
                    <span className="px-3 py-1 bg-white border border-slate-200 text-slate-500 rounded-lg text-[10px] font-black uppercase tracking-tighter">
                      {emp.title}
                    </span>
                  </td>
                  <td className="px-8 py-5">
                    <div className="text-sm font-black text-slate-700">{restaurants.find(r => r.id === emp.restaurantId)?.name}</div>
                    <div className="text-[10px] font-bold text-slate-400 uppercase">{emp.zone}</div>
                  </td>
                  <td className="px-8 py-5">
                    {status === 'APPROVED' && <span className="inline-flex items-center px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[9px] font-black uppercase">✓ Aprobado</span>}
                    {status === 'FAILED' && <span className="inline-flex items-center px-3 py-1 bg-red-50 text-red-600 rounded-full text-[9px] font-black uppercase">✗ Reprobado</span>}
                    {status === 'PENDING' && <span className="inline-flex items-center px-3 py-1 bg-slate-50 text-slate-400 rounded-full text-[9px] font-black uppercase">○ Pendiente</span>}
                  </td>
                  <td className="px-8 py-5 text-center">
                    <button 
                      onClick={() => setEditingEmployee(emp)}
                      className="p-3 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-2xl transition-all active:scale-90"
                    >
                      <Edit3 className="w-5 h-5" />
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {editingEmployee && (
        <GradeEditor 
          employee={editingEmployee}
          month={selectedMonth}
          onClose={() => { setEditingEmployee(null); onUpdate(); }}
        />
      )}
    </div>
  );
};

export default EmployeeList;

