                      Ingrese puntajes reales del <span className="text-white">0%</span> al <span className="text-white">100%</span>. El objetivo es <span className="text-red-500 font-black">{APPROVAL_THRESHOLD}%</span>.
                    </p>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 md:gap-x-14 gap-y-8 md:gap-y-12">
                  {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                    const score = getScore(activeGroup, cat);
