  const downloadTemplate = () => {
    const headers = ["Documento", "Nombre completo", "Estado", "Fecha de ingreso", "Fecha fin", "Cargo", "Nombre_Ceco", "Jefe de area", "region"];
    const example = ["102030", "Juan Perez", "Activo", "2023-01-15", "", "Gerente", "KFC Centro", "Zona Norte", "Bogota"];

    const csvContent = "data:text/csv;charset=utf-8," 
      + headers.join(",") + "\n"
      + example.join(",");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "plantilla_akademia_kfc.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleSimulateImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files?.[0]) return;

