import { Employee, GradeEntry, User, UserRole, JobTitle, StoreHistory, Restaurant } from './types';
import { INITIAL_RESTAURANTS } from './constants';

const STORAGE_KEY_EMPLOYEES = 'la_akademia_employees';
const STORAGE_KEY_GRADES = 'la_akademia_grades';
const STORAGE_KEY_USERS = 'la_akademia_users';
const STORAGE_KEY_STORES = 'la_akademia_stores';

export const dataService = {
  getEmployees: (): Employee[] => {
    const data = localStorage.getItem(STORAGE_KEY_EMPLOYEES);
    return data ? JSON.parse(data) : [];
  },

  saveEmployees: (employees: Employee[]) => {
    localStorage.setItem(STORAGE_KEY_EMPLOYEES, JSON.stringify(employees));
  },

  getRestaurants: (): Restaurant[] => {
    const data = localStorage.getItem(STORAGE_KEY_STORES);
    // Inicia vacío si no hay datos persistidos
    return data ? JSON.parse(data) : [];
  },

  saveRestaurants: (stores: Restaurant[]) => {
    localStorage.setItem(STORAGE_KEY_STORES, JSON.stringify(stores));
  },

  getGrades: (): GradeEntry[] => {
    const data = localStorage.getItem(STORAGE_KEY_GRADES);
    return data ? JSON.parse(data) : [];
  },

  saveGrades: (grades: GradeEntry[]) => {
    localStorage.setItem(STORAGE_KEY_GRADES, JSON.stringify(grades));
  },

  getUsers: (): User[] => {
    const data = localStorage.getItem(STORAGE_KEY_USERS);
    if (!data) {
      const seed: User[] = [
        { id: 'admin1', username: 'admin', password: '123', role: UserRole.ADMIN, assignedZones: [], assignedRestaurants: [] },
      ];
      localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(seed));
      return seed;
    }
    return JSON.parse(data);
  },

  // Proceso de Importación Real
  importMonthlyExcel: (rawData: any[]) => {
    const currentEmployees = dataService.getEmployees();
    const currentStores = dataService.getRestaurants();
    const today = new Date().toISOString().split('T')[0];

    const newStoresMap = new Map<string, Restaurant>();
    currentStores.forEach(s => newStoresMap.set(s.id, s));

    // Procesar cada fila del archivo
    const importedEmployees = rawData.map(item => {
      const storeId = item.Nombre_Ceco || 'CECO_SIN_NOMBRE';
      const docId = String(item.Documento || item.documento || '');

      if (!docId) return null;

      // 1. Crear o actualizar restaurante dinámicamente
      if (!newStoresMap.has(storeId)) {
        newStoresMap.set(storeId, {
          id: storeId,
          name: storeId,
          zone: item["Jefe de area"] || 'Sin Zona',
          region: item.region || 'Sin Región'
        });
      } else {
        // Actualizar jerarquía si hubo cambios en el Excel para una tienda existente
        const existingStore = newStoresMap.get(storeId)!;
        existingStore.zone = item["Jefe de area"] || existingStore.zone;
        existingStore.region = item.region || existingStore.region;
      }

      const existing = currentEmployees.find(e => e.id === docId);

      const employeeData: Employee = {
        id: docId,
        name: item["Nombre completo"] || item.nombre || 'Sin Nombre',
        joinDate: item["Fecha de ingreso"] || today,
        title: (item.Cargo || item.cargo || JobTitle.MIEMBRO_EQUIPO) as JobTitle,
        restaurantId: storeId,
        zone: item["Jefe de area"] || 'Sin Zona',
        active: item.Estado === 'Activo' || item.estado === 'Activo',
        history: existing?.history || []
      };

      // 2. Rastrear movimientos
      if (existing) {
        if (existing.restaurantId !== storeId) {
          const oldStore = currentStores.find(r => r.id === existing.restaurantId);
          employeeData.history = [...(existing.history || []), {
            date: today,
            restaurantName: oldStore?.name || existing.restaurantId,
            action: 'TRASLADO'
          }];
        }
      } else {
        employeeData.history = [{ date: today, restaurantName: 'Nuevo Ingreso', action: 'INGRESO' }];
      }

      return employeeData;
    }).filter(e => e !== null) as Employee[];

    // 3. Detectar retiros (Gente que estaba activa pero ya no viene en el nuevo Excel)
    const importedIds = new Set(importedEmployees.map(e => e.id));
    const retiredEmployees = currentEmployees
      .filter(e => !importedIds.has(e.id) && e.active)
      .map(e => ({
        ...e,
        active: false,
        history: [...(e.history || []), { date: today, restaurantName: 'N/A', action: 'RETIRO' as const }]
      }));

    const finalEmployeeList = [...importedEmployees, ...retiredEmployees];

    dataService.saveRestaurants(Array.from(newStoresMap.values()));
    dataService.saveEmployees(finalEmployeeList);
  }
};

import React, { useState } from 'react';
import { Upload, UserPlus, Database, Search, X, Check, ChevronDown, Lock, Shield, FileSpreadsheet, Download } from 'lucide-react';
import { dataService } from '../dataService';
import { UserRole, User, JobTitle } from '../types';
import { INITIAL_ZONES } from '../constants';
import * as XLSX from 'xlsx';

interface AdminPanelProps {
  onEmployeesImported: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onEmployeesImported }) => {
  const [importStatus, setImportStatus] = useState<string | null>(null);
  const [isImporting, setIsImporting] = useState(false);
  const [showUserModal, setShowUserModal] = useState(false);
  const [newUserData, setNewUserData] = useState({
    username: '',
    password: '',
    role: UserRole.SPECIALIST,
    assignedZones: [] as string[],
  });

  const downloadTemplate = () => {
    const headers = [["Documento", "Nombre completo", "Estado", "Fecha de ingreso", "Fecha fin", "Cargo", "Nombre_Ceco", "Jefe de area", "region"]];
    const ws = XLSX.utils.aoa_to_sheet(headers);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Plantilla");
    XLSX.writeFile(wb, "plantilla_akademia_kfc.xlsx");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsImporting(true);
    setImportStatus('Procesando archivo...');

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws);

        if (data.length === 0) {
           throw new Error("El archivo está vacío");
        }

        dataService.importMonthlyExcel(data);

        setIsImporting(false);
        setImportStatus(`Carga exitosa: ${data.length} registros procesados.`);
        onEmployeesImported();
        setTimeout(() => setImportStatus(null), 5000);
      } catch (err) {
        setIsImporting(false);
        setImportStatus('Error: Formato de archivo no válido o vacío.');
        console.error(err);
      }
    };
    reader.readAsBinaryString(file);
  };

  const handleCreateUser = () => {
    if (!newUserData.username || !newUserData.password) return;
    const users = dataService.getUsers();
    const newUser: User = {
      id: `u-${Date.now()}`,
      username: newUserData.username,
      password: newUserData.password,
      role: newUserData.role,
      assignedZones: newUserData.assignedZones,
      assignedRestaurants: []
    };
    localStorage.setItem('la_akademia_users', JSON.stringify([...users, newUser]));
    setShowUserModal(false);
    setNewUserData({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [] });
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-10 rounded-3xl md:rounded-[40px] shadow-sm border border-slate-100">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
          <div className="flex items-center space-x-6">
            <div className="p-4 md:p-5 bg-red-600 text-white rounded-2xl md:rounded-[24px] shadow-xl shadow-red-100">
              <Shield className="w-8 h-8 md:w-10 md:h-10" />
            </div>
            <div>
              <h2 className="text-2xl md:text-3xl font-black text-slate-800 tracking-tighter">Administración KFC</h2>
              <p className="text-slate-500 font-bold uppercase tracking-widest text-[9px] md:text-[10px]">Importación de Datos y Usuarios</p>
            </div>
          </div>

          <button 
            onClick={downloadTemplate}
            className="flex items-center justify-center space-x-3 px-6 py-4 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-black transition shadow-lg shadow-slate-100 uppercase tracking-widest"
          >
            <Download className="w-4 h-4" />
            <span>Descargar Plantilla Excel</span>
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
          {/* Panel de Importación Real */}
          <div className="p-6 md:p-8 border-2 border-slate-50 rounded-[32px] bg-slate-50/30 flex flex-col justify-between relative overflow-hidden">
            {isImporting && (
              <div className="absolute inset-0 bg-white/60 backdrop-blur-sm z-10 flex flex-col items-center justify-center">
                <div className="w-12 h-12 border-4 border-red-600 border-t-transparent rounded-full animate-spin mb-4"></div>
                <p className="text-xs font-black text-slate-800 uppercase tracking-widest">Sincronizando...</p>
              </div>
            )}
            <div>
              <h3 className="text-lg font-black text-slate-800 mb-4 flex items-center tracking-tight">
                <FileSpreadsheet className="w-5 h-5 mr-3 text-red-600" /> Sincronización Mensual
              </h3>
              <p className="text-sm text-slate-500 font-bold leading-relaxed mb-8">
                Cargue el archivo .xlsx para actualizar automáticamente tiendas, jefes de área y la base de personal.
              </p>
              <label className="flex flex-col items-center justify-center w-full h-44 border-4 border-slate-100 border-dashed rounded-[32px] cursor-pointer bg-white hover:border-red-200 transition-all group mb-6">
