import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import GradeEditor from './GradeEditor';

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
  onUpdate: () => void;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth, onUpdate }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  const assigned = useMemo(() => {
    if (user.role === UserRole.ADMIN) return restaurants;
    return restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));
  }, [user, restaurants]);

  const grades = useMemo(() => dataService.getGrades().filter(g => g.month === selectedMonth), [selectedMonth, editingEmployee]);

  const getStoreStats = (storeId: string) => {
    // Para estadísticas mensuales usamos a todos los que tengan notas incluso inactivos
    const idsWithGrades = new Set(grades.filter(g => employees.some(e => e.id === g.employeeId && e.restaurantId === storeId)).map(g => g.employeeId));
    const storeEmployees = employees.filter(e => e.restaurantId === storeId && (e.active || idsWithGrades.has(e.id)));

    let storeApproved = 0;
    storeEmployees.forEach(emp => {
      const empGrades = grades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        const sum = empGrades.reduce((s, g) => s + g.score, 0);
        const avg = sum / TOTAL_CATEGORIES_COUNT;
        if (avg >= APPROVAL_THRESHOLD) storeApproved++;
      }
