const parseExcelDate = (serial: any) => {
  if (!serial) return '';
  if (typeof serial === 'string') return serial;
  try {
    const date = XLSX.SSF.parse_date_code(serial);
    const month = String(date.m).padStart(2, '0');
    const day = String(date.d).padStart(2, '0');
    return `${date.y}-${month}-${day}`;
  } catch (e) {
    return String(serial);
  }
};

// Seed Helper: Genera notas aleatorias para un mes
const generateRandomGrades = (empId: string, month: string): GradeEntry[] => {
  const grades: GradeEntry[] = [];
  const groups = ['A', 'B', 'C', 'D', 'E'];
  const categories: any = {
    'A': ['Introducción', 'SST', 'Seguridad de alimentos'],
    'B': ['Equipos', 'Producción', 'Servicio', 'Ensamble', 'Domicilios', 'Heladería'],
    'C': ['Equipos', 'Producción', 'Servicio', 'Ensamble', 'Domicilios', 'Heladería'],
    'D': ['Control y prevención de plagas', 'Manejo de sustancias químicas'],
    'E': ['Fundamentos básicos', 'FOH', 'BOH', 'MOH', 'Delivery']
  };

  groups.forEach(g => {
    categories[g].forEach((cat: string) => {
      grades.push({
        employeeId: empId,
        month,
        group: g,
        category: cat,
        score: Math.floor(Math.random() * (100 - 70 + 1)) + 70 // Notas entre 70 y 100
      });
    });
  });
  return grades;
};

