        { id: '10004', name: 'Diana Entrenadora', joinDate: '2022-11-12', title: JobTitle.ENTRENADOR, restaurantId: 'KFC-002', zone: 'Zona Antioquia', active: true, history: [] },
        { id: '10005', name: 'Eduardo Domicilio', joinDate: '2023-06-01', title: JobTitle.DOMICILIARIO, restaurantId: 'KFC-002', zone: 'Zona Antioquia', active: true, history: [] },
        { id: '99999', name: 'Carlos Retirado', joinDate: '2021-08-10', title: JobTitle.MIEMBRO_EQUIPO, restaurantId: 'KFC-001', zone: 'Zona Occidente', active: false, history: [{ date: '2024-01-01', restaurantName: 'KFC-001', action: 'RETIRO' }] }
      ];
      localStorage.setItem(STORAGE_KEY_EMPLOYEES, JSON.stringify(seed));
      return seed;
    }
    return JSON.parse(data);
  },

  getRestaurants: (): Restaurant[] => {
    const data = localStorage.getItem(STORAGE_KEY_STORES);
    if (!data) {
      const seed = [
        { id: 'KFC-001', name: 'KFC Titan Plaza', zone: 'Zona Occidente', region: 'Bogotá' },
        { id: 'KFC-002', name: 'KFC El Tesoro', zone: 'Zona Antioquia', region: 'Antioquia' },
        { id: 'KFC-003', name: 'KFC Unicentro Cali', zone: 'Zona Valle', region: 'Occidente' },
        { id: 'KFC-004', name: 'KFC Buenavista', zone: 'Zona Costa', region: 'Costa' }
      ];
      localStorage.setItem(STORAGE_KEY_STORES, JSON.stringify(seed));
      return seed;
    }
    return JSON.parse(data);
  },

  getGrades: (): GradeEntry[] => {
    const data = localStorage.getItem(STORAGE_KEY_GRADES);
    if (!data) {
      const seed: GradeEntry[] = [];
      const emps = dataService.getEmployees();
      const currentMonth = new Date().toISOString().slice(0, 7);
      const prevMonths = ['2024-10', '2024-11', '2024-12', '2025-01'];

      emps.forEach(e => {
        prevMonths.forEach(m => {
          // Incluso el retirado tiene notas en meses previos
          if (e.id === '99999' && m > '2024-11') return;
          seed.push(...generateRandomGrades(e.id, m));
        });
        seed.push(...generateRandomGrades(e.id, currentMonth));
      });

      localStorage.setItem(STORAGE_KEY_GRADES, JSON.stringify(seed));
      return seed;
    }
    return JSON.parse(data);
  },

  saveEmployees: (employees: Employee[]) => {
    localStorage.setItem(STORAGE_KEY_EMPLOYEES, JSON.stringify(employees));
  },

  saveRestaurants: (stores: Restaurant[]) => {
    localStorage.setItem(STORAGE_KEY_STORES, JSON.stringify(stores));
  },

  saveGrades: (grades: GradeEntry[]) => {
    localStorage.setItem(STORAGE_KEY_GRADES, JSON.stringify(grades));
  },

  getUsers: (): User[] => {
    const data = localStorage.getItem(STORAGE_KEY_USERS);
    if (!data) {
      const seed: User[] = [
        { id: 'admin1', username: 'admin', password: '123', role: UserRole.ADMIN, assignedZones: [], assignedRestaurants: [] },
        { id: 'spec1', username: 'especialista1', password: '123', role: UserRole.SPECIALIST, assignedZones: ['Zona Occidente'], assignedRestaurants: [] }
      ];
      localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(seed));
      return seed;
    }
    return JSON.parse(data);
  },

  importMonthlyExcel: (rawData: any[]) => {
    const currentEmployees = dataService.getEmployees();
    const currentStores = dataService.getRestaurants();
    const today = new Date().toISOString().split('T')[0];

    const newStoresMap = new Map<string, Restaurant>();
    currentStores.forEach(s => newStoresMap.set(s.id, s));

    const importedIds = new Set();

    const importedEmployees = rawData.map(item => {
      const storeId = String(item.Nombre_Ceco || item.nombre_ceco || 'SIN_CECO').trim();
      const docId = String(item.Documento || item.documento || '').trim();
      if (!docId) return null;

      importedIds.add(docId);

      if (!newStoresMap.has(storeId)) {
        newStoresMap.set(storeId, {
          id: storeId,
          name: storeId,
          zone: item["Jefe de area"] || item.jefe_de_area || 'Sin Zona',
          region: item.region || 'Sin Región'
        });
      } else {
        const s = newStoresMap.get(storeId)!;
        s.zone = item["Jefe de area"] || item.jefe_de_area || s.zone;
        s.region = item.region || s.region;
      }

      const existing = currentEmployees.find(e => e.id === docId);
      const isActive = String(item.Estado || item.estado).toLowerCase().includes('activo');

      const emp: Employee = {
        id: docId,
        name: item["Nombre completo"] || item.nombre || 'Sin Nombre',
        joinDate: parseExcelDate(item["Fecha de ingreso"] || item.fecha_de_ingreso),
        title: (item.Cargo || item.cargo) as JobTitle,
        restaurantId: storeId,
        zone: item["Jefe de area"] || item.jefe_de_area || 'Sin Zona',
        active: isActive,
        history: existing?.history || []
      };

      if (existing) {
        if (existing.restaurantId !== storeId) {
          emp.history = [...(existing.history || []), {
            date: today,
            restaurantName: existing.restaurantId,
            action: 'TRASLADO'
          }];
        }
        if (existing.active && !isActive) {
           emp.history = [...(existing.history || []), {
            date: today,
            restaurantName: storeId,
            action: 'RETIRO'
          }];
        }
      } else {
        emp.history = [{ date: today, restaurantName: 'N/A', action: 'INGRESO' }];
      }

      return emp;
    }).filter(e => e !== null) as Employee[];

    const retired = currentEmployees
      .filter(e => !importedIds.has(e.id) && e.active)
      .map(e => ({
        ...e,
        active: false,
        history: [...(e.history || []), { date: today, restaurantName: 'Sincronización', action: 'RETIRO' as const }]
      }));

    const finalEmployees = [...importedEmployees, ...retired];

    dataService.saveRestaurants(Array.from(newStoresMap.values()));
    dataService.saveEmployees(finalEmployees);
  }
};

import React, { useState, useMemo } from 'react';
import { Employee, Restaurant, JobHierarchy, User, UserRole } from '../types';
import { Search, ChevronRight, Edit3, Filter, Users, ShieldOff } from 'lucide-react';
import GradeEditor from './GradeEditor';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { dataService } from '../dataService';

interface EmployeeListProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
  onUpdate: () => void;
}

const EmployeeList: React.FC<EmployeeListProps> = ({ employees, restaurants, selectedMonth, user, onUpdate }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedRestaurant, setSelectedRestaurant] = useState<string>('all');
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  const filteredAndSorted = useMemo(() => {
    let result = employees.filter(e => {
      // Regla: Especialistas SOLO ven activos. Admin ve todo.
      if (user.role === UserRole.SPECIALIST && !e.active) return false;

      const matchSearch = searchTerm === '' || e.name.toLowerCase().includes(searchTerm.toLowerCase()) || e.id.includes(searchTerm);
      const matchStore = selectedRestaurant === 'all' || e.restaurantId === selectedRestaurant;

      return matchSearch && matchStore;
    });

    return result.sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));
  }, [employees, searchTerm, selectedRestaurant, user]);

  const allGrades = useMemo(() => dataService.getGrades().filter(g => g.month === selectedMonth), [selectedMonth, editingEmployee]);

  const getStatus = (employeeId: string) => {
    const grades = allGrades.filter(g => g.employeeId === employeeId);
    if (grades.length === 0) return 'PENDING';
    const sum = grades.reduce((s, g) => s + g.score, 0);
    const avg = sum / TOTAL_CATEGORIES_COUNT;
    return avg >= APPROVAL_THRESHOLD ? 'APPROVED' : 'FAILED';
  };

  return (
    <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
      <div className="p-8 border-b border-slate-50 flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h2 className="text-2xl font-black text-slate-800 tracking-tight flex items-center">
            <Users className="w-6 h-6 mr-3 text-red-600" /> Personal KFC
          </h2>
          <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">
            {user.role === UserRole.ADMIN ? 'Gestión Global de Nómina' : 'Gestión de Tiendas Asignadas'}
          </p>
        </div>

        <div className="flex flex-col md:flex-row items-center gap-4">
          <div className="relative w-full md:w-72">
            <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <input
              type="text" placeholder="Buscar por nombre o ID..."
              className="w-full pl-12 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 transition-all outline-none placeholder:text-slate-300"
              value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="relative w-full md:w-64">
            <Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <select
              className="w-full pl-12 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 outline-none appearance-none cursor-pointer"
              value={selectedRestaurant} onChange={(e) => setSelectedRestaurant(e.target.value)}
            >
              <option value="all">Todas las Tiendas</option>
              {restaurants.filter(r => user.role === 'ADMIN' || user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone)).map(r => (
                <option key={r.id} value={r.id}>{r.name}</option>
              ))}
            </select>
          </div>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50/50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Cargo</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">ID</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Tienda</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Certificación</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {filteredAndSorted.map(emp => {
              const status = getStatus(emp.id);
              return (
                <tr key={emp.id} className={`hover:bg-slate-50/50 transition-colors group ${!emp.active ? 'opacity-50' : ''}`}>
                  <td className="px-8 py-5">
                    <div className="font-black text-slate-800 group-hover:text-red-600 transition-colors flex items-center">
                      {emp.name}
                      {!emp.active && <ShieldOff className="w-3 h-3 ml-2 text-slate-400" title="Inactivo" />}
                    </div>
                    <div className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Ingreso: {emp.joinDate}</div>
                  </td>
                  <td className="px-8 py-5">
                    <span className="px-3 py-1.5 bg-white border border-slate-200 text-slate-600 rounded-lg text-[9px] font-black uppercase tracking-widest whitespace-nowrap inline-block shadow-sm min-w-[120px] text-center">
                      {emp.title}
                    </span>
                  </td>
                  <td className="px-8 py-5 text-sm font-bold text-slate-500 tabular-nums">{emp.id}</td>
                  <td className="px-8 py-5">
                    <div className="text-sm font-black text-slate-700">{restaurants.find(r => r.id === emp.restaurantId)?.name}</div>
                    <div className="text-[10px] font-bold text-slate-400 uppercase">{emp.zone}</div>
                  </td>
                  <td className="px-8 py-5">
                    {status === 'APPROVED' && <span className="inline-flex items-center px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[9px] font-black uppercase">✓ Aprobado</span>}
                    {status === 'FAILED' && <span className="inline-flex items-center px-3 py-1 bg-red-50 text-red-600 rounded-full text-[9px] font-black uppercase">✗ Reprobado</span>}
                    {status === 'PENDING' && <span className="inline-flex items-center px-3 py-1 bg-slate-50 text-slate-400 rounded-full text-[9px] font-black uppercase">○ Pendiente</span>}
                  </td>
                  <td className="px-8 py-5 text-center">
                    <button 
                      onClick={() => setEditingEmployee(emp)}
                      disabled={!emp.active && user.role === UserRole.SPECIALIST}
                      className="p-3 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-2xl transition-all active:scale-90 disabled:opacity-20"
                    >
                      <Edit3 className="w-5 h-5" />
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {filteredAndSorted.length === 0 && (
        <div className="p-20 text-center">
          <Users className="w-16 h-16 text-slate-100 mx-auto mb-4" />
          <p className="text-slate-400 font-black uppercase text-xs tracking-widest">No se encontraron trabajadores en esta selección</p>
        </div>
      )}

      {editingEmployee && (
        <GradeEditor 
          employee={editingEmployee}
          month={selectedMonth}
          onClose={() => { setEditingEmployee(null); onUpdate(); }}
        />
      )}
    </div>
  );
};

export default EmployeeList;

