                       </div>
                    </div>

                    {employee.history?.map((h, i) => (
                      <div key={i} className="relative pl-10 md:pl-12">
                         <div className="absolute left-1 md:left-1.5 top-2 w-3 h-3 md:w-4 md:h-4 bg-slate-200 rounded-full border-4 border-white z-10" />
                         <p className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{h.action} - {h.date}</p>
                         <div className="bg-slate-50/50 p-4 md:p-5 rounded-2xl md:rounded-3xl border-2 border-slate-50">
                            <p className="text-sm md:text-md font-black text-slate-600 tracking-tight">{h.restaurantName}</p>
                         </div>
                      </div>
                    ))}

                    {(!employee.history || employee.history.length === 0) && (
                      <div className="pl-10 md:pl-12 py-10">
                        <div className="p-6 md:p-8 border-2 border-slate-50 border-dashed rounded-3xl text-center">
                          <History className="w-8 h-8 text-slate-100 mx-auto mb-3" />
                          <p className="text-xs font-bold text-slate-300 italic">No se registran traslados históricos.</p>
                        </div>
                      </div>
                    )}
                 </div>
              </div>
            ) : (
              <div className="animate-in slide-in-from-left-4 duration-300">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 md:gap-x-14 gap-y-8 md:gap-y-12">
                  {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                    const score = getScore(activeGroup, cat);
                    return (
                      <div key={cat} className="space-y-4 md:space-y-5">
                        <div className="flex justify-between items-end px-1">
                          <label className="text-[10px] md:text-[11px] font-black text-slate-800 uppercase tracking-widest line-clamp-1">{cat}</label>
                          <span className={`text-[9px] font-black px-2 py-0.5 rounded ${score >= APPROVAL_THRESHOLD ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                            {score >= APPROVAL_THRESHOLD ? 'APROBADO' : 'PENDIENTE'}
                          </span>
                        </div>
                        <div className="flex items-center space-x-6 md:space-x-8">
                          <div className="relative shrink-0">
                            <input 
                              type="number" 
                              min="0" 
                              max="100" 
                              value={score === 0 ? '' : score}
                              placeholder="0"
                              onChange={e => handleScoreChange(activeGroup, cat, e.target.value)} 
                              onFocus={e => e.target.select()} 
                              className={`w-20 md:w-28 px-3 md:px-5 py-3 md:py-5 bg-white border-2 md:border-4 rounded-xl md:rounded-[28px] text-xl md:text-2xl font-black text-slate-900 text-center outline-none transition-all ${score >= APPROVAL_THRESHOLD ? 'border-emerald-100 focus:border-emerald-400' : 'border-slate-100 focus:border-red-500'}`} 
                            />
                            <span className="absolute -top-3 left-1/2 -translate-x-1/2 bg-white px-2 text-[8px] md:text-[10px] font-black text-slate-300 uppercase tracking-widest border border-slate-100 rounded-full shadow-sm">%</span>
                          </div>
                          <div className="flex-1 space-y-2 md:space-y-3">
                            <div className="h-2 md:h-2.5 bg-slate-50 rounded-full overflow-hidden shadow-inner ring-1 ring-slate-100">
                              <div className={`h-full transition-all duration-700 ease-out ${score >= APPROVAL_THRESHOLD ? 'bg-emerald-500' : 'bg-red-600'}`} style={{width: `${score}%`}} />
                            </div>
                            <div className="flex justify-between text-[8px] font-black text-slate-300 tracking-tighter uppercase">
                               <span>Puntaje</span>
                               <span>Máx: 100</span>
                            </div>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}
            <div className="h-28" />
          </div>
        </div>

        {/* Footer */}
        <div className="p-4 md:p-8 border-t border-slate-100 bg-slate-50 flex flex-col md:flex-row justify-end gap-3 md:gap-5 shrink-0 px-6 md:px-14">
          <button 
            onClick={onClose} 
            className="px-6 md:px-8 font-black text-slate-400 text-[10px] md:text-[11px] uppercase tracking-[0.2em] hover:text-slate-800 transition py-4 md:py-0"
          >
            DESCARTAR
          </button>
          <button 
            onClick={saveGrades} 
            className="px-8 md:px-16 py-4 md:py-6 bg-slate-900 text-white font-black rounded-2xl md:rounded-[28px] shadow-2xl shadow-slate-200 hover:bg-black transition-all active:scale-95 text-[10px] md:text-[11px] uppercase tracking-[0.2em] flex items-center justify-center ring-4 ring-slate-100"
          >
            <Save className="w-4 h-4 mr-3" /> CONFIRMAR NOTAS
          </button>
        </div>
      </div>
    </div>
  );
};

export default GradeEditor;

