import React, { useMemo, useState } from 'react';
import { Employee, GradeEntry, User, Restaurant, UserRole } from '../types';
import { dataService } from '../dataService';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, INITIAL_ZONES, INITIAL_REGIONS, TOTAL_CATEGORIES_COUNT } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, LineChart, Line, LabelList } from 'recharts';
import { XCircle, Users, Award, TrendingUp, Search, MapPin, Filter, Calendar, Download, ListFilter } from 'lucide-react';
import * as XLSX from 'xlsx';

interface DashboardProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ employees: initialEmployees, restaurants, selectedMonth, user }) => {
  const [searchPerson, setSearchPerson] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterStore, setFilterStore] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [selectedChartGroups, setSelectedChartGroups] = useState<string[]>(Object.keys(EVALUATION_GROUPS));

  const allGrades = useMemo(() => dataService.getGrades(), []);
  const currentGrades = useMemo(() => allGrades.filter(g => g.month === selectedMonth), [allGrades, selectedMonth]);

  const relevantEmployees = useMemo(() => {
    const idsWithGrades = new Set(currentGrades.map(g => g.employeeId));
    return initialEmployees.filter(e => e.active || idsWithGrades.has(e.id));
  }, [initialEmployees, currentGrades]);

  const filteredData = useMemo(() => {
    return relevantEmployees.filter(e => {
      const store = restaurants.find(r => r.id === e.restaurantId);
      const matchPerson = searchPerson === '' || e.name.toLowerCase().includes(searchPerson.toLowerCase()) || e.id.includes(searchPerson);
      const matchStore = filterStore === 'all' || e.restaurantId === filterStore;
      const matchZone = filterZone === 'all' || e.zone === filterZone;
      const matchRegion = filterRegion === 'all' || store?.region === filterRegion;
      return matchPerson && matchStore && matchZone && matchRegion;
    });
  }, [relevantEmployees, searchPerson, filterStore, filterZone, filterRegion, restaurants]);

  const stats = useMemo(() => {
    const totalEmployees = filteredData.length;
    let approvedCount = 0;

    const groupAvgs = Object.keys(EVALUATION_GROUPS).map(groupId => {
      const groupData = (EVALUATION_GROUPS as any)[groupId];
      const groupGrades = currentGrades.filter(g => g.group === groupId && filteredData.some(e => e.id === g.employeeId));

      const totalPossibleCategories = filteredData.length * groupData.categories.length;
      const sumScores = groupGrades.reduce((sum, g) => sum + g.score, 0);
      const avg = totalPossibleCategories > 0 ? sumScores / totalPossibleCategories : 0;

      return {
        id: groupId,
        name: groupData.name,
        avg: Math.round(avg)
      };
    });

    filteredData.forEach(emp => {
      const empGrades = currentGrades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        const sum = empGrades.reduce((sum, g) => sum + g.score, 0);
        const avg = sum / TOTAL_CATEGORIES_COUNT;
        if (avg >= APPROVAL_THRESHOLD) approvedCount++;
      }
    });

    return { totalEmployees, approvedCount, groupAvgs };
  }, [filteredData, currentGrades]);

  const filteredGroupAvgs = useMemo(() => {
    return stats.groupAvgs.filter(g => selectedChartGroups.includes(g.id));
  }, [stats.groupAvgs, selectedChartGroups]);

  const trendData = useMemo(() => {
    const months = Array.from(new Set(allGrades.map(g => g.month))).sort();
    return months.map(m => {
      const monthGrades = allGrades.filter(g => g.month === m);
      const filteredMonthGrades = monthGrades.filter(g => selectedChartGroups.includes(g.group));
      const empIds = new Set(filteredMonthGrades.map(g => g.employeeId));

      const totalCategoriesInSelectedGroups = selectedChartGroups.reduce((acc, gid) => acc + (EVALUATION_GROUPS as any)[gid].categories.length, 0);
      const totalPossible = empIds.size * totalCategoriesInSelectedGroups;
      const sum = filteredMonthGrades.reduce((s, g) => s + g.score, 0);

      return {
        month: m,
        score: totalPossible > 0 ? Math.round(sum / totalPossible) : 0
      };
    });
  }, [allGrades, selectedChartGroups]);

  const handleExport = () => {
    const exportData = filteredData.map(emp => {
      const empStore = restaurants.find(r => r.id === emp.restaurantId);
      const empGrades = currentGrades.filter(g => g.employeeId === emp.id);

      const groupData: any = {};
      Object.keys(EVALUATION_GROUPS).forEach(gid => {
        const gGrades = empGrades.filter(g => g.group === gid);
        const gConfig = (EVALUATION_GROUPS as any)[gid];
        const sum = gGrades.reduce((s, g) => s + g.score, 0);
        const avg = gConfig.categories.length > 0 ? Math.round(sum / gConfig.categories.length) : 0;
        groupData[gConfig.name] = `${avg}%`;
      });

      const totalSum = empGrades.reduce((s, g) => s + g.score, 0);
      const totalAvg = Math.round(totalSum / TOTAL_CATEGORIES_COUNT);

      return {
        "Documento": emp.id,
        "Nombre completo": emp.name,
        "Estado": emp.active ? "Activo" : "Retirado",
        "Fecha de ingreso": emp.joinDate,
        "Cargo": emp.title,
        "Nombre_Ceco": empStore?.name || emp.restaurantId,
        "Jefe de area": emp.zone,
        "Region": empStore?.region || 'N/A',
        "Mes Reporte": selectedMonth,
        "Promedio General": `${totalAvg}%`,
        ...groupData
      };
    });

    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Reporte_Akademia");
    XLSX.writeFile(wb, `Reporte_Akademia_${selectedMonth}.xlsx`);
  };

  const toggleChartGroup = (id: string) => {
    setSelectedChartGroups(prev => 
      prev.includes(id) ? prev.filter(g => g !== id) : [...prev, id]
    );
  };

  return (
    <div className="space-y-6">
      {/* Filters & Export */}
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6 items-end">
        {user.role === UserRole.ADMIN && (
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
            <div className="relative">
              <select 
                value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 transition-all outline-none appearance-none"
              >
                <option value="all">Todas las Regiones</option>
                {INITIAL_REGIONS.map(r => <option key={r} value={r}>{r}</option>)}
              </select>
              <MapPin className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
          </div>
        )}

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
          <div className="relative">
            <select 
              value={filterZone} onChange={(e) => setFilterZone(e.target.value)}
              className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 transition-all outline-none appearance-none"
            >
              <option value="all">Todas las Zonas</option>
              {INITIAL_ZONES.filter(z => user.role === UserRole.ADMIN || user.assignedZones.includes(z)).map(z => (
                <option key={z} value={z}>{z}</option>
              ))}
            </select>
            <Filter className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Tienda</label>
          <div className="relative">
            <select 
              value={filterStore} onChange={(e) => setFilterStore(e.target.value)}
              className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 transition-all outline-none appearance-none"
            >
              <option value="all">Todas las Tiendas</option>
              {restaurants.filter(r => user.role === UserRole.ADMIN || user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone)).map(r => (
                <option key={r.id} value={r.id}>{r.name}</option>
              ))}
            </select>
            <Filter className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Persona</label>
          <div className="relative">
            <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <input 
              type="text" placeholder="Nombre o ID..." value={searchPerson} onChange={(e) => setSearchPerson(e.target.value)}
              className="w-full pl-11 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 outline-none transition-all placeholder:text-slate-300"
            />
          </div>
        </div>

        <button 
          onClick={handleExport}
          className="w-full flex items-center justify-center space-x-2 px-4 py-3.5 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-black transition-all shadow-lg active:scale-95"
        >
          <Download className="w-4 h-4" />
          <span>Exportar Excel</span>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard icon={<Users className="w-6 h-6" />} label="Equipo Evaluado" value={stats.totalEmployees} subValue="Incluye Inactivos con Nota" />
        <StatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approvedCount} subValue="Nivel de Excelencia" color="green" />
        <StatCard icon={<TrendingUp className="w-6 h-6" />} label="Promedio" value={`${stats.groupAvgs.length > 0 ? Math.round(stats.groupAvgs.reduce((s, g) => s + g.avg, 0) / stats.groupAvgs.length) : 0}%`} subValue="General del Periodo" color="blue" />
        <StatCard icon={<XCircle className="w-6 h-6" />} label="Faltantes" value={Math.max(0, stats.totalEmployees - stats.approvedCount)} subValue="Brecha de Calidad" color="red" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Desempeño por Grupo */}
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
          <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
            <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center">
              <TrendingUp className="w-4 h-4 mr-2 text-red-500" /> Desempeño por Grupo Evaluativo
            </h3>
            <div className="flex flex-wrap gap-2">
              {Object.keys(EVALUATION_GROUPS).map(id => (
                <button
                  key={id}
                  onClick={() => toggleChartGroup(id)}
                  className={`px-3 py-1.5 rounded-lg text-[9px] font-black uppercase tracking-tighter transition-all border-2 ${selectedChartGroups.includes(id) ? 'bg-slate-900 text-white border-slate-900 shadow-md' : 'bg-white text-slate-400 border-slate-100'}`}
                >
                  {(EVALUATION_GROUPS as any)[id].name}
                </button>
              ))}
            </div>
          </div>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={filteredGroupAvgs} margin={{ top: 20, right: 0, left: -25, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                <YAxis domain={[0, 100]} axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                <Tooltip cursor={{ fill: '#f8fafc' }} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', fontWeight: '900', fontSize: '12px' }} />
                <Bar dataKey="avg" radius={[10, 10, 0, 0]} barSize={45}>
                  <LabelList dataKey="avg" position="top" formatter={(v: any) => `${v}%`} style={{ fontSize: '10px', fontWeight: '900', fill: '#64748b' }} />
                  {filteredGroupAvgs.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.avg >= APPROVAL_THRESHOLD ? '#10b981' : '#ef4444'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Tendencia Mensual */}
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
          <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
