import React, { useState, useEffect, useMemo } from 'react';
import { User, UserRole, AuthState, Employee, Restaurant } from './types';
import { dataService } from './dataService';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import EmployeeList from './components/EmployeeList';
import AdminPanel from './components/AdminPanel';
import Header from './components/Header';
import MyStores from './components/MyStores';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({ user: null, isAuthenticated: false });
  const [activeTab, setActiveTab] = useState<'dashboard' | 'my-stores' | 'employees' | 'admin'>('dashboard');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [selectedMonth, setSelectedMonth] = useState<string>(new Date().toISOString().slice(0, 7));
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const refreshData = () => {
    setEmployees(dataService.getEmployees());
    setRestaurants(dataService.getRestaurants());
  };

  useEffect(() => {
    refreshData();
  }, []);

  const handleLogin = (user: User) => {
    setAuth({ user, isAuthenticated: true });
    setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
  };

  const filteredEmployees = useMemo(() => {
    if (!auth.user) return [];
    if (auth.user.role === UserRole.ADMIN) return employees;

    return employees.filter(e => 
      auth.user?.assignedZones.includes(e.zone) || 
      auth.user?.assignedRestaurants.includes(e.restaurantId)
    );
  }, [employees, auth.user]);

  if (!auth.isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden relative">
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 lg:hidden" 
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={(tab) => {
          setActiveTab(tab);
          setIsSidebarOpen(false);
        }} 
        role={auth.user!.role}
        onLogout={handleLogout}
        isOpen={isSidebarOpen}
        setIsOpen={setIsSidebarOpen}
      />

      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header 
          user={auth.user!} 
          selectedMonth={selectedMonth} 
          onMonthChange={setSelectedMonth}
          onMenuClick={() => setIsSidebarOpen(true)}
        />

        <main className="flex-1 overflow-x-hidden overflow-y-auto p-4 md:p-6">
          {activeTab === 'dashboard' && (
            <Dashboard 
              employees={filteredEmployees} 
              restaurants={restaurants}
              selectedMonth={selectedMonth}
              user={auth.user!}
            />
          )}

          {activeTab === 'my-stores' && (
            <MyStores 
              user={auth.user!}
              restaurants={restaurants}
              employees={employees}
              selectedMonth={selectedMonth}
              onUpdate={refreshData}
            />
          )}

          {activeTab === 'employees' && (
            <EmployeeList 
              employees={filteredEmployees}
              restaurants={restaurants}
              selectedMonth={selectedMonth}
              user={auth.user!}
              onUpdate={refreshData}
            />
          )}

          {activeTab === 'admin' && auth.user?.role === UserRole.ADMIN && (
            <AdminPanel 
              onEmployeesImported={refreshData}
            />
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

export const EVALUATION_GROUPS = {
  'A': {
    name: 'Básicos',
    categories: ['Introducción', 'SST', 'Seguridad de alimentos']
  },
  'B': {
    name: 'Star',
    categories: ['Equipos', 'Producción', 'Servicio', 'Ensamble', 'Domicilios', 'Heladería']
  },
  'C': {
    name: 'All-Star',
    categories: ['Equipos', 'Producción', 'Servicio', 'Ensamble', 'Domicilios', 'Heladería']
  },
  'D': {
    name: 'Plan de Capacitación y SST',
    categories: ['Control y prevención de plagas', 'Manejo de sustancias químicas']
  },
  'E': {
    name: 'The Vault',
    categories: ['Fundamentos básicos', 'FOH', 'BOH', 'MOH', 'Delivery']
  }
};

export const TOTAL_CATEGORIES_COUNT = Object.values(EVALUATION_GROUPS).reduce(
  (acc, group) => acc + group.categories.length, 0
);

export const APPROVAL_THRESHOLD = 90;

export const INITIAL_RESTAURANTS = [];

import React, { useMemo, useState } from 'react';
import { Employee, GradeEntry, User, Restaurant, UserRole } from '../types';
import { dataService } from '../dataService';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, LineChart, Line, LabelList } from 'recharts';
import { XCircle, Users, Award, TrendingUp, Search, MapPin, Filter, Calendar, Download, X, Check, FileText } from 'lucide-react';
import * as XLSX from 'xlsx';

interface DashboardProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ employees: initialEmployees, restaurants, selectedMonth, user }) => {
  const [searchPerson, setSearchPerson] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterStore, setFilterStore] = useState('all');
  const [filterZone, setFilterZone] = useState('all');

  // Export Modal State
  const [showExportModal, setShowExportModal] = useState(false);
  const [exportGroups, setExportGroups] = useState<string[]>(Object.keys(EVALUATION_GROUPS));
  const [includeSubNotes, setIncludeSubNotes] = useState(false);

  const allGrades = useMemo(() => dataService.getGrades(), []);
  const currentGrades = useMemo(() => allGrades.filter(g => g.month === selectedMonth), [allGrades, selectedMonth]);

  // Derive dynamic filters from current restaurants data
  const dynamicRegions = useMemo(() => {
    const regions = Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort();
    return regions;
  }, [restaurants]);

  const dynamicZones = useMemo(() => {
    let zones = Array.from(new Set(restaurants.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) {
      zones = zones.filter(z => user.assignedZones.includes(z));
    }
    return zones;
  }, [restaurants, user]);

  const relevantEmployees = useMemo(() => {
    const idsWithGrades = new Set(currentGrades.map(g => g.employeeId));
    return initialEmployees.filter(e => e.active || idsWithGrades.has(e.id));
  }, [initialEmployees, currentGrades]);

  const filteredData = useMemo(() => {
    return relevantEmployees.filter(e => {
      const store = restaurants.find(r => r.id === e.restaurantId);
      const matchPerson = searchPerson === '' || e.name.toLowerCase().includes(searchPerson.toLowerCase()) || e.id.includes(searchPerson);
      const matchStore = filterStore === 'all' || e.restaurantId === filterStore;
      const matchZone = filterZone === 'all' || e.zone === filterZone;
      const matchRegion = filterRegion === 'all' || store?.region === filterRegion;
      return matchPerson && matchStore && matchZone && matchRegion;
    });
  }, [relevantEmployees, searchPerson, filterStore, filterZone, filterRegion, restaurants]);

  const stats = useMemo(() => {
    const totalEmployees = filteredData.length;
    let approvedCount = 0;

    const groupAvgs = Object.keys(EVALUATION_GROUPS).map(groupId => {
      const groupData = (EVALUATION_GROUPS as any)[groupId];
      const groupGrades = currentGrades.filter(g => g.group === groupId && filteredData.some(e => e.id === g.employeeId));

      const totalPossibleCategories = filteredData.length * groupData.categories.length;
      const sumScores = groupGrades.reduce((sum, g) => sum + g.score, 0);
      const avg = totalPossibleCategories > 0 ? sumScores / totalPossibleCategories : 0;

      return {
        id: groupId,
        name: groupData.name,
        avg: Math.round(avg)
      };
    });

    filteredData.forEach(emp => {
      const empGrades = currentGrades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        const sum = empGrades.reduce((sum, g) => sum + g.score, 0);
        const avg = sum / TOTAL_CATEGORIES_COUNT;
        if (avg >= APPROVAL_THRESHOLD) approvedCount++;
      }
    });

    return { totalEmployees, approvedCount, groupAvgs };
  }, [filteredData, currentGrades]);

  const trendData = useMemo(() => {
    const months = Array.from(new Set(allGrades.map(g => g.month))).sort();
    return months.map(m => {
      const monthGrades = allGrades.filter(g => g.month === m);
      const empIds = new Set(monthGrades.map(g => g.employeeId));
      const totalPossible = empIds.size * TOTAL_CATEGORIES_COUNT;
      const sum = monthGrades.reduce((s, g) => s + g.score, 0);
      return {
        month: m,
        score: totalPossible > 0 ? Math.round(sum / totalPossible) : 0
      };
    });
  }, [allGrades]);

  const handleExportFinal = () => {
    const exportData = filteredData.map(emp => {
      const empStore = restaurants.find(r => r.id === emp.restaurantId);
      const empGrades = currentGrades.filter(g => g.employeeId === emp.id);

      const dynamicColumns: any = {};

      exportGroups.forEach(gid => {
        const gConfig = (EVALUATION_GROUPS as any)[gid];
        const gGrades = empGrades.filter(g => g.group === gid);

        if (includeSubNotes) {
          gConfig.categories.forEach((cat: string) => {
            const grade = gGrades.find(g => g.category === cat);
            dynamicColumns[`${gConfig.name} - ${cat}`] = grade ? `${grade.score}%` : '0%';
          });
        } else {
          const sum = gGrades.reduce((s, g) => s + g.score, 0);
          const avg = gConfig.categories.length > 0 ? Math.round(sum / gConfig.categories.length) : 0;
          dynamicColumns[`${gConfig.name} %`] = `${avg}%`;
        }
      });

      const totalSum = empGrades.reduce((s, g) => s + g.score, 0);
      const totalAvg = Math.round(totalSum / TOTAL_CATEGORIES_COUNT);

      return {
        "Documento": emp.id,
        "Nombre completo": emp.name,
        "Estado": emp.active ? "Activo" : "Retirado",
        "Fecha de ingreso": emp.joinDate,
        "Cargo": emp.title,
        "Nombre_Ceco": empStore?.name || emp.restaurantId,
        "Jefe de area": emp.zone,
        "Region": empStore?.region || 'N/A',
        "Mes Reporte": selectedMonth,
        "Promedio General": `${totalAvg}%`,
        ...dynamicColumns
      };
    });

    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Reporte_Akademia");
    XLSX.writeFile(wb, `Reporte_Akademia_${selectedMonth}.xlsx`);
    setShowExportModal(false);
  };

  const toggleExportGroup = (id: string) => {
    setExportGroups(prev => 
      prev.includes(id) ? prev.filter(g => g !== id) : [...prev, id]
    );
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6 items-end">
        {user.role === UserRole.ADMIN && (
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
            <div className="relative">
              <select 
                value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 transition-all outline-none appearance-none"
              >
                <option value="all">Todas las Regiones</option>
                {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
              </select>
              <MapPin className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
          </div>
        )}

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
          <div className="relative">
            <select 
              value={filterZone} onChange={(e) => setFilterZone(e.target.value)}
