import React, { useState, useMemo } from 'react';
import { Employee, Restaurant, JobHierarchy, User, UserRole } from '../types';
import { Search, ChevronRight, Edit3, Filter, Users, ShieldOff, MapPin } from 'lucide-react';
import GradeEditor from './GradeEditor';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { dataService } from '../dataService';

interface EmployeeListProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
  onUpdate: () => void;
}

const EmployeeList: React.FC<EmployeeListProps> = ({ employees, restaurants, selectedMonth, user, onUpdate }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [filterStore, setFilterStore] = useState('all');
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  const dynamicRegions = useMemo(() => {
    return Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort();
  }, [restaurants]);

  const dynamicZones = useMemo(() => {
    let zones = Array.from(new Set(restaurants.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) {
      zones = zones.filter(z => user.assignedZones.includes(z));
    }
    return zones;
  }, [restaurants, user]);

  const filteredAndSorted = useMemo(() => {
    let result = employees.filter(e => {
      if (user.role === UserRole.SPECIALIST && !e.active) return false;

      const store = restaurants.find(r => r.id === e.restaurantId);
      const matchSearch = searchTerm === '' || e.name.toLowerCase().includes(searchTerm.toLowerCase()) || e.id.includes(searchTerm);
      const matchRegion = filterRegion === 'all' || store?.region === filterRegion;
      const matchZone = filterZone === 'all' || e.zone === filterZone;
      const matchStore = filterStore === 'all' || e.restaurantId === filterStore;

      return matchSearch && matchRegion && matchZone && matchStore;
    });

    return result.sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));
  }, [employees, searchTerm, filterRegion, filterZone, filterStore, user, restaurants]);

  const allGrades = useMemo(() => dataService.getGrades().filter(g => g.month === selectedMonth), [selectedMonth, editingEmployee]);

  const getStatus = (employeeId: string) => {
    const grades = allGrades.filter(g => g.employeeId === employeeId);
    if (grades.length === 0) return 'PENDING';
    const sum = grades.reduce((s, g) => s + g.score, 0);
    const avg = sum / TOTAL_CATEGORIES_COUNT;
    return avg >= APPROVAL_THRESHOLD ? 'APPROVED' : 'FAILED';
  };

  return (
    <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
      <div className="p-8 border-b border-slate-50 flex flex-col space-y-6">
        <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
          <div>
            <h2 className="text-2xl font-black text-slate-800 tracking-tight flex items-center">
              <Users className="w-6 h-6 mr-3 text-red-600" /> Personal KFC
            </h2>
            <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">
              {user.role === UserRole.ADMIN ? 'Gestión Global de Nómina' : 'Gestión de Tiendas Asignadas'}
            </p>
          </div>

          <div className="relative w-full md:w-96">
            <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <input
              type="text" placeholder="Buscar por nombre o ID..."
              className="w-full pl-12 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 transition-all outline-none placeholder:text-slate-300"
              value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        {user.role === UserRole.ADMIN && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="relative">
              <MapPin className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
              <select
                className="w-full pl-12 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 outline-none appearance-none cursor-pointer"
                value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)}
              >
                <option value="all">Todas las Regiones</option>
                {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
              </select>
            </div>

            <div className="relative">
              <Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
              <select
                className="w-full pl-12 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 outline-none appearance-none cursor-pointer"
                value={filterZone} onChange={(e) => setFilterZone(e.target.value)}
              >
                <option value="all">Todas las Zonas</option>
                {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
              </select>
            </div>

            <div className="relative">
              <Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
              <select
                className="w-full pl-12 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 outline-none appearance-none cursor-pointer"
                value={filterStore} onChange={(e) => setFilterStore(e.target.value)}
              >
                <option value="all">Todas las Tiendas</option>
                {restaurants.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
              </select>
            </div>
          </div>
        )}
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50/50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Cargo</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">ID</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Tienda</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Certificación</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {filteredAndSorted.map(emp => {
              const status = getStatus(emp.id);
              return (
                <tr key={emp.id} className={`hover:bg-slate-50/50 transition-colors group ${!emp.active ? 'opacity-50' : ''}`}>
                  <td className="px-8 py-5">
                    <div className="font-black text-slate-800 group-hover:text-red-600 transition-colors flex items-center">
                      {emp.name}
                      {!emp.active && <ShieldOff className="w-3 h-3 ml-2 text-slate-400" title="Inactivo" />}
                    </div>
                    <div className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Ingreso: {emp.joinDate}</div>
                  </td>
                  <td className="px-8 py-5">
                    <span className="px-3 py-1.5 bg-white border border-slate-200 text-slate-600 rounded-lg text-[9px] font-black uppercase tracking-widest whitespace-nowrap inline-block shadow-sm min-w-[120px] text-center">
                      {emp.title}
                    </span>
                  </td>
                  <td className="px-8 py-5 text-sm font-bold text-slate-500 tabular-nums">{emp.id}</td>
                  <td className="px-8 py-5">
                    <div className="text-sm font-black text-slate-700">{restaurants.find(r => r.id === emp.restaurantId)?.name}</div>
                    <div className="text-[10px] font-bold text-slate-400 uppercase">{emp.zone}</div>
                  </td>
                  <td className="px-8 py-5">
                    {status === 'APPROVED' && <span className="inline-flex items-center px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[9px] font-black uppercase">✓ Aprobado</span>}
                    {status === 'FAILED' && <span className="inline-flex items-center px-3 py-1 bg-red-50 text-red-600 rounded-full text-[9px] font-black uppercase">✗ Reprobado</span>}
                    {status === 'PENDING' && <span className="inline-flex items-center px-3 py-1 bg-slate-50 text-slate-400 rounded-full text-[9px] font-black uppercase">○ Pendiente</span>}
                  </td>
                  <td className="px-8 py-5 text-center">
                    <button 
                      onClick={() => setEditingEmployee(emp)}
                      disabled={!emp.active && user.role === UserRole.SPECIALIST}
                      className="p-3 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-2xl transition-all active:scale-90 disabled:opacity-20"
                    >
                      <Edit3 className="w-5 h-5" />
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {filteredAndSorted.length === 0 && (
        <div className="p-20 text-center">
          <Users className="w-16 h-16 text-slate-100 mx-auto mb-4" />
          <p className="text-slate-400 font-black uppercase text-xs tracking-widest">No se encontraron trabajadores en esta selección</p>
        </div>
      )}

      {editingEmployee && (
        <GradeEditor 
          employee={editingEmployee}
          month={selectedMonth}
          onClose={() => { setEditingEmployee(null); onUpdate(); }}
        />
      )}
    </div>
  );
};

export default EmployeeList;

