  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsImporting(true);
    setImportStatus('Procesando archivo...');

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws);

        if (data.length === 0) {
           throw new Error("El archivo está vacío");
        }

        dataService.importMonthlyExcel(data);

        setIsImporting(false);
        setImportStatus(`Carga exitosa: ${data.length} registros procesados.`);
        onEmployeesImported();
        setTimeout(() => setImportStatus(null), 5000);
      } catch (err) {
        setIsImporting(false);
        setImportStatus('Error: Formato de archivo no válido o vacío.');
        console.error(err);
      }
    };
    reader.readAsBinaryString(file);
  };

  const handleSaveUser = () => {
    if (!newUserData.username) return;
    const users = dataService.getUsers();

    if (editingUserId) {
      const updatedUser: User = {
        id: editingUserId,
        username: newUserData.username,
        password: newUserData.password || '123',
        role: newUserData.role,
        assignedZones: newUserData.assignedZones,
        assignedRestaurants: []
      };
      dataService.updateUser(updatedUser);
    } else {
      const newUser: User = {
        id: `u-${Date.now()}`,
        username: newUserData.username,
        password: newUserData.password || '123',
        role: newUserData.role,
        assignedZones: newUserData.assignedZones,
        assignedRestaurants: []
      };
      localStorage.setItem('la_akademia_users', JSON.stringify([...users, newUser]));
    }

    setShowUserModal(false);
    setEditingUserId(null);
    setNewUserData({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [] });
  };

  const startEdit = (user: User) => {
    setEditingUserId(user.id);
    setNewUserData({
      username: user.username,
      password: '',
      role: user.role,
      assignedZones: user.assignedZones
    });
    setShowUserModal(true);
  };

  const deleteUser = (userId: string) => {
    if (userId === 'admin1') return;
    if (!confirm('¿Seguro que desea eliminar este usuario?')) return;
    const users = dataService.getUsers().filter(u => u.id !== userId);
    localStorage.setItem('la_akademia_users', JSON.stringify(users));
    onEmployeesImported(); // trigger refresh
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-10 rounded-3xl md:rounded-[40px] shadow-sm border border-slate-100">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
          <div className="flex items-center space-x-6">
            <div className="p-4 md:p-5 bg-red-600 text-white rounded-2xl md:rounded-[24px] shadow-xl shadow-red-100">
              <Shield className="w-8 h-8 md:w-10 md:h-10" />
            </div>
            <div>
              <h2 className="text-2xl md:text-3xl font-black text-slate-800 tracking-tighter">Administración KFC</h2>
              <p className="text-slate-500 font-bold uppercase tracking-widest text-[9px] md:text-[10px]">Importación de Datos y Usuarios</p>
            </div>
          </div>

          <div className="flex gap-4">
            <button 
              onClick={() => {
                if(confirm('¿Seguro que desea eliminar TODOS los datos (Trabajadores, Notas, Tiendas)?')) {
                  dataService.clearAllData();
                  onEmployeesImported();
                }
              }}
              className="flex items-center justify-center space-x-3 px-6 py-4 bg-red-50 text-red-600 text-[10px] font-black rounded-2xl hover:bg-red-100 transition shadow-sm uppercase tracking-widest"
            >
              <Trash2 className="w-4 h-4" />
              <span>Limpiar Data</span>
            </button>
            <button 
              onClick={downloadTemplate}
              className="flex items-center justify-center space-x-3 px-6 py-4 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-black transition shadow-lg shadow-slate-100 uppercase tracking-widest"
            >
              <Download className="w-4 h-4" />
              <span>Plantilla Excel</span>
            </button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
          <div className="p-6 md:p-8 border-2 border-slate-50 rounded-[32px] bg-slate-50/30 flex flex-col justify-between relative overflow-hidden">
            {isImporting && (
              <div className="absolute inset-0 bg-white/60 backdrop-blur-sm z-10 flex flex-col items-center justify-center">
                <div className="w-12 h-12 border-4 border-red-600 border-t-transparent rounded-full animate-spin mb-4"></div>
                <p className="text-xs font-black text-slate-800 uppercase tracking-widest">Sincronizando...</p>
              </div>
            )}
            <div>
              <h3 className="text-lg font-black text-slate-800 mb-4 flex items-center tracking-tight">
                <FileSpreadsheet className="w-5 h-5 mr-3 text-red-600" /> Sincronización Mensual
              </h3>
              <p className="text-sm text-slate-500 font-bold leading-relaxed mb-8">
                Cargue el archivo .xlsx para actualizar automáticamente tiendas, jefes de área y la base de personal.
              </p>
              <label className="flex flex-col items-center justify-center w-full h-44 border-4 border-slate-100 border-dashed rounded-[32px] cursor-pointer bg-white hover:border-red-200 transition-all group mb-6">
                <Upload className="w-12 h-12 text-slate-200 group-hover:text-red-500 transition-colors mb-3" />
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Subir Archivo (.xlsx / .csv)</span>
                <input type="file" className="hidden" accept=".xlsx, .csv" onChange={handleFileUpload} />
              </label>
            </div>
            {importStatus ? (
              <div className={`p-4 rounded-2xl border flex items-center justify-center space-x-3 ${importStatus.includes('Error') ? 'bg-red-50 border-red-100 text-red-600' : 'bg-emerald-50 border-emerald-100 text-emerald-600'}`}>
                <Check className="w-4 h-4" />
                <p className="text-[10px] font-black uppercase tracking-widest">{importStatus}</p>
              </div>
            ) : (
              <p className="text-[9px] text-slate-400 font-bold text-center italic uppercase">Al subir, se actualizarán los datos de base.</p>
            )}
          </div>

          <div className="p-6 md:p-8 border-2 border-slate-50 rounded-[32px] bg-slate-50/30">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-lg font-black text-slate-800 flex items-center tracking-tight">
                <UserPlus className="w-5 h-5 mr-3 text-red-600" /> Gestión de Accesos
              </h3>
              <button 
                onClick={() => { setEditingUserId(null); setNewUserData({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [] }); setShowUserModal(true); }} 
                className="px-4 py-2 bg-red-600 text-white text-[10px] font-black rounded-xl hover:bg-red-700 transition shadow-lg shadow-red-100 uppercase tracking-widest"
              >
                + Nueva
              </button>
            </div>
            <div className="space-y-4 max-h-72 overflow-y-auto pr-2 scrollbar-thin">
              {dataService.getUsers().map(u => (
                <div key={u.id} className="bg-white p-5 rounded-2xl border border-slate-100 flex items-center justify-between shadow-sm group">
                  <div>
                    <p className="text-sm font-black text-slate-800 leading-none">{u.username}</p>
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">
                      {u.role} • {u.assignedZones.length ? `${u.assignedZones.length} Zonas` : 'Global'}
                    </p>
                  </div>
                  <div className="flex items-center space-x-2">
                    <button onClick={() => startEdit(u)} className="p-2 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-lg transition">
                      <Edit2 className="w-4 h-4" />
                    </button>
                    {u.id !== 'admin1' && (
                      <button onClick={() => deleteUser(u.id)} className="p-2 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-lg transition">
                        <Trash2 className="w-4 h-4" />
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {showUserModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/95 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-200 ring-2 ring-slate-800">
            <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
              <h2 className="text-2xl font-black tracking-tighter uppercase italic">{editingUserId ? 'Editar Usuario' : 'Nuevo Usuario'}</h2>
              <button onClick={() => setShowUserModal(false)} className="p-3 hover:bg-white/10 rounded-2xl transition"><X className="w-7 h-7"/></button>
            </div>
            <div className="p-10 space-y-8">
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Usuario</label>
                  <input type="text" placeholder="kfc.admin" value={newUserData.username} onChange={e => setNewUserData({...newUserData, username: e.target.value})} className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold text-slate-900 focus:border-red-500 outline-none" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Password</label>
                  <input type="password" placeholder="••••••••" value={newUserData.password} onChange={e => setNewUserData({...newUserData, password: e.target.value})} className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold text-slate-900 focus:border-red-500 outline-none" />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Rol Operativo</label>
                <div className="relative">
                  <select 
                    value={newUserData.role} 
                    onChange={e => setNewUserData({...newUserData, role: e.target.value as UserRole})} 
                    className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-black text-slate-900 appearance-none outline-none focus:border-red-500 cursor-pointer"
                  >
                    <option value={UserRole.SPECIALIST}>ESPECIALISTA</option>
                    <option value={UserRole.ADMIN}>ADMINISTRADOR</option>
                  </select>
                  <ChevronDown className="w-5 h-5 absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
                </div>
              </div>

              {newUserData.role === UserRole.SPECIALIST && (
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zonas Asignadas</label>
                  <div className="bg-slate-50 border-2 border-slate-100 rounded-2xl p-2 overflow-hidden">
                    <select 
                      multiple 
                      value={newUserData.assignedZones} 
                      onChange={e => {
                        const options = Array.from(e.target.selectedOptions, option => (option as HTMLOptionElement).value);
                        setNewUserData({...newUserData, assignedZones: options});
                      }} 
                      className="w-full px-3 py-2 bg-transparent font-bold text-slate-800 h-32 outline-none"
                    >
                      {availableZones.map(z => (
                        <option key={z} value={z} className="py-2 px-2 hover:bg-red-50 rounded-lg mb-1 cursor-pointer font-black text-xs uppercase">{z}</option>
                      ))}
                      {availableZones.length === 0 && <option disabled>Cargue tiendas primero</option>}
                    </select>
                  </div>
                  <p className="text-[9px] text-slate-400 font-bold italic mt-1">Mantenga presionado Ctrl (o Cmd) para seleccionar múltiples zonas.</p>
                </div>
              )}
            </div>
            <div className="p-8 bg-slate-50 flex justify-end gap-4 border-t border-slate-100">
              <button onClick={() => setShowUserModal(false)} className="px-8 font-black text-slate-400 text-xs uppercase tracking-widest hover:text-slate-600 transition">Cancelar</button>
              <button onClick={handleSaveUser} className="px-10 py-5 bg-red-600 text-white font-black rounded-3xl shadow-2xl shadow-red-100 hover:bg-red-700 transition-all active:scale-95 uppercase tracking-widest text-xs">{editingUserId ? 'Guardar Cambios' : 'Crear Usuario'}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useMemo, useState } from 'react';
import { Employee, Restaurant } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, Cell } from 'recharts';
import { ArrowUpCircle, ArrowDownCircle, Search, Filter, MapPin, Users, Calendar, ArrowRight } from 'lucide-react';

interface EntriesExitsReportProps {
  employees: Employee[];
  restaurants: Restaurant[];
}

const EntriesExitsReport: React.FC<EntriesExitsReportProps> = ({ employees, restaurants }) => {
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [filterStore, setFilterStore] = useState('all');
  const [viewDetail, setViewDetail] = useState<'entries' | 'exits' | 'none'>('none');

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => Array.from(new Set(restaurants.map(r => r.zone))).filter(Boolean).sort(), [restaurants]);

  const historyEvents = useMemo(() => {
    const events: any[] = [];
    employees.forEach(emp => {
      emp.history?.forEach(h => {
        if (h.action === 'INGRESO' || h.action === 'RETIRO') {
          // Check if event restaurant matches filters
          const store = restaurants.find(r => r.id === h.restaurantName || r.name === h.restaurantName);
          const matchRegion = filterRegion === 'all' || store?.region === filterRegion;
          const matchZone = filterZone === 'all' || store?.zone === filterZone;
          const matchStore = filterStore === 'all' || store?.id === filterStore || store?.name === filterStore;

          if (matchRegion && matchZone && matchStore) {
            events.push({
              ...h,
              employeeName: emp.name,
              employeeId: emp.id,
              month: h.date.slice(0, 7) // YYYY-MM
            });
          }
        }
      });
    });
    return events;
  }, [employees, restaurants, filterRegion, filterZone, filterStore]);

  const chartData = useMemo(() => {
    const months = Array.from(new Set(historyEvents.map(e => e.month))).sort();
    return months.map(m => {
      const entries = historyEvents.filter(e => e.month === m && e.action === 'INGRESO').length;
      const exits = historyEvents.filter(e => e.month === m && e.action === 'RETIRO').length;
      return { month: m, entries, exits };
    }).slice(-12); // Show last 12 active months
  }, [historyEvents]);

  const totals = useMemo(() => {
    const entries = historyEvents.filter(e => e.action === 'INGRESO').length;
    const exits = historyEvents.filter(e => e.action === 'RETIRO').length;
    return { entries, exits };
  }, [historyEvents]);

  const detailList = useMemo(() => {
    if (viewDetail === 'none') return [];
    const action = viewDetail === 'entries' ? 'INGRESO' : 'RETIRO';
    return historyEvents.filter(e => e.action === action).sort((a, b) => b.date.localeCompare(a.date));
  }, [historyEvents, viewDetail]);

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
          <div className="relative">
            <MapPin className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <select
              className="w-full pl-12 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 outline-none appearance-none cursor-pointer"
              value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)}
            >
              <option value="all">Todas las Regiones</option>
              {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
            </select>
          </div>

          <div className="relative">
            <Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <select
              className="w-full pl-12 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 outline-none appearance-none cursor-pointer"
              value={filterZone} onChange={(e) => setFilterZone(e.target.value)}
            >
              <option value="all">Todas las Zonas</option>
              {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
            </select>
          </div>

          <div className="relative">
            <Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <select
              className="w-full pl-12 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 outline-none appearance-none cursor-pointer"
              value={filterStore} onChange={(e) => setFilterStore(e.target.value)}
            >
              <option value="all">Todas las Tiendas</option>
              {restaurants.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
            </select>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="space-y-6">
            <div className="grid grid-cols-2 gap-4">
              <button 
                onClick={() => setViewDetail(viewDetail === 'entries' ? 'none' : 'entries')}
                className={`p-6 rounded-[32px] border-2 transition-all flex flex-col items-center text-center ${viewDetail === 'entries' ? 'bg-emerald-50 border-emerald-500 shadow-lg scale-105' : 'bg-slate-50 border-transparent hover:bg-emerald-50'}`}
              >
                <ArrowUpCircle className={`w-10 h-10 mb-2 ${viewDetail === 'entries' ? 'text-emerald-600' : 'text-slate-400'}`} />
                <p className="text-[10px] font-black uppercase text-slate-400 mb-1">Total Ingresos</p>
                <p className="text-3xl font-black text-slate-800">{totals.entries}</p>
                <span className="text-[9px] font-black text-emerald-600 mt-2">VER DETALLE</span>
              </button>

              <button 
                onClick={() => setViewDetail(viewDetail === 'exits' ? 'none' : 'exits')}
                className={`p-6 rounded-[32px] border-2 transition-all flex flex-col items-center text-center ${viewDetail === 'exits' ? 'bg-red-50 border-red-500 shadow-lg scale-105' : 'bg-slate-50 border-transparent hover:bg-red-50'}`}
              >
                <ArrowDownCircle className={`w-10 h-10 mb-2 ${viewDetail === 'exits' ? 'text-red-600' : 'text-slate-400'}`} />
                <p className="text-[10px] font-black uppercase text-slate-400 mb-1">Total Retiros</p>
                <p className="text-3xl font-black text-slate-800">{totals.exits}</p>
                <span className="text-[9px] font-black text-red-600 mt-2">VER DETALLE</span>
              </button>
            </div>

            <div className="bg-slate-900 p-8 rounded-[40px] text-white overflow-hidden relative">
              <div className="absolute top-0 right-0 p-4 opacity-10">
                <Users className="w-24 h-24" />
              </div>
              <h4 className="text-sm font-black uppercase tracking-widest mb-4">Análisis de Movimientos</h4>
              <p className="text-slate-400 text-xs leading-relaxed font-bold">
                Este dashboard visualiza la fluctuación de la nómina en base a los registros históricos capturados durante las importaciones mensuales.
              </p>
            </div>
          </div>

          <div className="bg-white p-8 rounded-[32px] border border-slate-100 flex flex-col justify-center">
             <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-6">Tendencia Mensual</h4>
             <div className="h-[250px]">
               <ResponsiveContainer width="100%" height="100%">
                 <BarChart data={chartData} margin={{ top: 0, right: 0, left: -20, bottom: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{ fontSize: 9, fontWeight: 900, fill: '#94a3b8' }} />
                    <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 9, fontWeight: 900, fill: '#94a3b8' }} />
                    <Tooltip contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontWeight: '900', fontSize: '11px' }} />
                    <Legend iconType="circle" />
                    <Bar name="Ingresos" dataKey="entries" fill="#10b981" radius={[4, 4, 0, 0]} />
                    <Bar name="Retiros" dataKey="exits" fill="#ef4444" radius={[4, 4, 0, 0]} />
                 </BarChart>
               </ResponsiveContainer>
             </div>
          </div>
        </div>
      </div>

      {viewDetail !== 'none' && (
        <div className="bg-white rounded-3xl shadow-sm border border-slate-100 animate-in slide-in-from-top-4 duration-300">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center">
            <div>
              <h3 className="text-xl font-black text-slate-800 tracking-tight flex items-center">
                 {viewDetail === 'entries' ? <ArrowUpCircle className="w-5 h-5 mr-3 text-emerald-500" /> : <ArrowDownCircle className="w-5 h-5 mr-3 text-red-500" />}
                 Detalle de {viewDetail === 'entries' ? 'Ingresos' : 'Retiros'}
              </h3>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Registros Filtrados: {detailList.length}</p>
            </div>
            <button onClick={() => setViewDetail('none')} className="text-[9px] font-black text-slate-400 uppercase tracking-widest hover:text-red-600">Cerrar Detalle</button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  <th className="px-8 py-4">Fecha</th>
                  <th className="px-8 py-4">Colaborador</th>
                  <th className="px-8 py-4">ID</th>
                  <th className="px-8 py-4">Tienda / CECO</th>
                  <th className="px-8 py-4 text-center">Acción</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {detailList.map((e, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-8 py-4 text-sm font-black text-slate-500 tabular-nums">{e.date}</td>
                    <td className="px-8 py-4 text-sm font-black text-slate-800 uppercase">{e.employeeName}</td>
                    <td className="px-8 py-4 text-sm font-bold text-slate-400">{e.employeeId}</td>
                    <td className="px-8 py-4">
                      <p className="text-sm font-black text-slate-600">{e.restaurantName}</p>
                    </td>
                    <td className="px-8 py-4 text-center">
                      <span className={`inline-block px-3 py-1 rounded-full text-[9px] font-black uppercase ${e.action === 'INGRESO' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                        {e.action}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          {detailList.length === 0 && (
            <div className="p-20 text-center">
              <Calendar className="w-12 h-12 text-slate-100 mx-auto mb-4" />
              <p className="text-slate-300 font-black italic text-sm">No se encontraron registros para este criterio.</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

