import { Employee, GradeEntry, User, UserRole, JobTitle, Restaurant } from './types';
import * as XLSX from 'xlsx';

const STORAGE_KEY_EMPLOYEES = 'la_akademia_employees';
const STORAGE_KEY_GRADES = 'la_akademia_grades';
const STORAGE_KEY_USERS = 'la_akademia_users';
const STORAGE_KEY_STORES = 'la_akademia_stores';

const parseExcelDate = (serial: any) => {
  if (!serial) return '';
  if (typeof serial === 'string') return serial;
  try {
    const date = XLSX.SSF.parse_date_code(serial);
    const month = String(date.m).padStart(2, '0');
    const day = String(date.d).padStart(2, '0');
    return `${date.y}-${month}-${day}`;
  } catch (e) {
    return String(serial);
  }
};

/**
 * Normalizes names to "First Name First Surname".
 * Groups "JUAN PEREZ" and "PEREZ JUAN" as the same entity.
 */
const normalizeJefeName = (rawName: string): string => {
  if (!rawName) return 'Sin Zona';

  // Basic cleaning
  let clean = rawName.replace(/,/g, ' ').replace(/\s+/g, ' ').trim().toUpperCase();
  let tokens = clean.split(' ').filter(t => t.length > 2); // Avoid 'DE', 'LA', etc.

  if (tokens.length === 0) return clean || 'Sin Zona';

  const toTitleCase = (str: string) => str.charAt(0).toUpperCase() + str.slice(1).toLowerCase();

  // Heuristic for standard Latin American HR format: SURNAMES NAMES or NAMES SURNAMES
  // We'll take the first and third token if 4 tokens, or 1st and 2nd if 2 tokens.
  // To ensure the SAME string is always returned for the same set of tokens:
  const sortedTokens = [...tokens].sort();
  // We'll use the sorted tokens to generate a "canonical" display name 
  // so that "Perez Juan" and "Juan Perez" both become "Juan Perez" (canonical)

  // Heuristic: If we have multiple tokens, pick two distinct ones to represent the person.
  // We use the sorted list to pick the "first" name and "first" last name in a stable way.
  return `${toTitleCase(sortedTokens[0])} ${toTitleCase(sortedTokens[sortedTokens.length - 1])}`;
};

export const dataService = {
  clearAllData: () => {
    localStorage.removeItem(STORAGE_KEY_EMPLOYEES);
    localStorage.removeItem(STORAGE_KEY_GRADES);
    localStorage.removeItem(STORAGE_KEY_STORES);
  },

  getEmployees: (): Employee[] => {
    const data = localStorage.getItem(STORAGE_KEY_EMPLOYEES);
    return data ? JSON.parse(data) : [];
  },

  getRestaurants: (): Restaurant[] => {
    const data = localStorage.getItem(STORAGE_KEY_STORES);
    return data ? JSON.parse(data) : [];
  },

  getGrades: (): GradeEntry[] => {
    const data = localStorage.getItem(STORAGE_KEY_GRADES);
    return data ? JSON.parse(data) : [];
  },

  saveEmployees: (employees: Employee[]) => {
    localStorage.setItem(STORAGE_KEY_EMPLOYEES, JSON.stringify(employees));
  },

  saveRestaurants: (stores: Restaurant[]) => {
    localStorage.setItem(STORAGE_KEY_STORES, JSON.stringify(stores));
  },

  saveGrades: (grades: GradeEntry[]) => {
    localStorage.setItem(STORAGE_KEY_GRADES, JSON.stringify(grades));
  },

  getUsers: (): User[] => {
    const data = localStorage.getItem(STORAGE_KEY_USERS);
    if (!data) {
      const seed: User[] = [
        { id: 'admin1', username: 'admin', password: '123', role: UserRole.ADMIN, assignedZones: [], assignedRestaurants: [] },
        { id: 'spec1', username: 'especialista1', password: '123', role: UserRole.SPECIALIST, assignedZones: [], assignedRestaurants: [] }
      ];
      localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(seed));
      return seed;
    }
    return JSON.parse(data);
  },

  updateUser: (updatedUser: User) => {
    const users = dataService.getUsers();
    const index = users.findIndex(u => u.id === updatedUser.id);
    if (index !== -1) {
      users[index] = updatedUser;
      localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(users));
    }
  },

  importMonthlyExcel: (rawData: any[]) => {
    const currentEmployees = dataService.getEmployees();
    const currentStores = dataService.getRestaurants();
    const today = new Date().toISOString().split('T')[0];
    let heladeriasSkipped = false;

    const newStoresMap = new Map<string, Restaurant>();
    currentStores.forEach(s => newStoresMap.set(s.id, s));

    const importedIds = new Set();

    const filteredRawData = rawData.filter(item => {
      const storeId = String(item.Nombre_Ceco || item.nombre_ceco || '').trim().toUpperCase();
      if (storeId.startsWith('H')) {
        heladeriasSkipped = true;
        return false;
      }
      return true;
    });

    const importedEmployees = filteredRawData.map(item => {
      const storeId = String(item.Nombre_Ceco || item.nombre_ceco || 'SIN_CECO').trim();
      const docId = String(item.Documento || item.documento || '').trim();
      if (!docId) return null;

      importedIds.add(docId);

      const normalizedZone = normalizeJefeName(item["Jefe de area"] || item.jefe_de_area || '');

      if (!newStoresMap.has(storeId)) {
        newStoresMap.set(storeId, {
          id: storeId,
          name: storeId,
          zone: normalizedZone,
          region: item.region || 'Sin Región'
        });
      } else {
        const s = newStoresMap.get(storeId)!;
        s.zone = normalizedZone;
        s.region = item.region || s.region;
      }

      const existing = currentEmployees.find(e => e.id === docId);
      const isActive = String(item.Estado || item.estado || '').toLowerCase().includes('activo');

      const emp: Employee = {
        id: docId,
        name: item["Nombre completo"] || item.nombre || 'Sin Nombre',
        joinDate: parseExcelDate(item["Fecha de ingreso"] || item.fecha_de_ingreso),
        title: (item.Cargo || item.cargo) as JobTitle,
        restaurantId: storeId,
        zone: normalizedZone,
        active: isActive,
        history: existing?.history || []
      };

      if (existing) {
        if (existing.restaurantId !== storeId) {
          emp.history = [...(existing.history || []), {
            date: today,
            restaurantName: existing.restaurantId,
            action: 'TRASLADO'
          }];
        }
        // User requested: "si en el estado del colaborador dice que es inactivo debes contarlo como retiro"
        if (existing.active && !isActive) {
           emp.history = [...(existing.history || []), {
            date: today,
            restaurantName: storeId,
            action: 'RETIRO'
          }];
        }
      } else {
        emp.history = [{ date: emp.joinDate || today, restaurantName: storeId, action: 'INGRESO' }];
        // If they enter as inactive, we also mark the withdrawal immediately in history
        if (!isActive) {
          emp.history.push({ date: today, restaurantName: storeId, action: 'RETIRO' });
        }
      }

      return emp;
    }).filter(e => e !== null) as Employee[];

    const retired = currentEmployees
      .filter(e => !importedIds.has(e.id) && e.active)
      .map(e => ({
        ...e,
        active: false,
        history: [...(e.history || []), { date: today, restaurantName: e.restaurantId, action: 'RETIRO' as const }]
      }));

    const finalEmployees = [...importedEmployees, ...retired];

    dataService.saveRestaurants(Array.from(newStoresMap.values()));
    dataService.saveEmployees(finalEmployees);

    return { heladeriasSkipped, count: importedEmployees.length };
  }
};

import React, { useMemo, useState, useEffect } from 'react';
import { Employee, GradeEntry, User, Restaurant, UserRole } from '../types';
import { dataService } from '../dataService';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, LineChart, Line, LabelList } from 'recharts';
import { XCircle, Users, Award, TrendingUp, Search, MapPin, Filter, Calendar, Download, X, Check, FileText } from 'lucide-react';
import * as XLSX from 'xlsx';

interface DashboardProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ employees: initialEmployees, restaurants, selectedMonth, user }) => {
  const [searchPerson, setSearchPerson] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [filterStore, setFilterStore] = useState('all');

  // Reset child filters when parent filter changes
  useEffect(() => {
    setFilterZone('all');
    setFilterStore('all');
  }, [filterRegion]);

  useEffect(() => {
    setFilterStore('all');
  }, [filterZone]);

  // Export Modal State
  const [showExportModal, setShowExportModal] = useState(false);
  const [exportGroups, setExportGroups] = useState<string[]>(Object.keys(EVALUATION_GROUPS));
  const [includeSubNotes, setIncludeSubNotes] = useState(false);

  const allGrades = useMemo(() => dataService.getGrades(), []);
  const currentGrades = useMemo(() => allGrades.filter(g => g.month === selectedMonth), [allGrades, selectedMonth]);

  // Derive cascading dynamic filters
  const dynamicRegions = useMemo(() => {
    return Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort();
  }, [restaurants]);

  const dynamicZones = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') {
      baseStores = baseStores.filter(r => r.region === filterRegion);
    }
    let zones = Array.from(new Set(baseStores.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) {
      zones = zones.filter(z => user.assignedZones.includes(z));
    }
    return zones;
  }, [restaurants, filterRegion, user]);

  const dynamicStores = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') {
      baseStores = baseStores.filter(r => r.region === filterRegion);
    }
    if (filterZone !== 'all') {
      baseStores = baseStores.filter(r => r.zone === filterZone);
    }
    if (user.role === UserRole.SPECIALIST) {
      baseStores = baseStores.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));
    }
    return baseStores.sort((a, b) => a.name.localeCompare(b.name));
  }, [restaurants, filterRegion, filterZone, user]);

  const relevantEmployees = useMemo(() => {
    const idsWithGrades = new Set(currentGrades.map(g => g.employeeId));
    return initialEmployees.filter(e => e.active || idsWithGrades.has(e.id));
  }, [initialEmployees, currentGrades]);

  const filteredData = useMemo(() => {
    return relevantEmployees.filter(e => {
      const store = restaurants.find(r => r.id === e.restaurantId);
      const matchPerson = searchPerson === '' || e.name.toLowerCase().includes(searchPerson.toLowerCase()) || e.id.includes(searchPerson);
      const matchRegion = filterRegion === 'all' || store?.region === filterRegion;
      const matchZone = filterZone === 'all' || e.zone === filterZone;
      const matchStore = filterStore === 'all' || e.restaurantId === filterStore;
      return matchPerson && matchStore && matchZone && matchRegion;
    });
  }, [relevantEmployees, searchPerson, filterStore, filterZone, filterRegion, restaurants]);

  const stats = useMemo(() => {
    const totalEmployees = filteredData.length;
    let approvedCount = 0;

    const groupAvgs = Object.keys(EVALUATION_GROUPS).map(groupId => {
      const groupData = (EVALUATION_GROUPS as any)[groupId];
      const groupGrades = currentGrades.filter(g => g.group === groupId && filteredData.some(e => e.id === g.employeeId));

      const totalPossibleCategories = filteredData.length * groupData.categories.length;
      const sumScores = groupGrades.reduce((sum, g) => sum + g.score, 0);
      const avg = totalPossibleCategories > 0 ? sumScores / totalPossibleCategories : 0;

      return {
        id: groupId,
        name: groupData.name,
        avg: Math.round(avg)
      };
    });

    filteredData.forEach(emp => {
      const empGrades = currentGrades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        const sum = empGrades.reduce((sum, g) => sum + g.score, 0);
        const avg = sum / TOTAL_CATEGORIES_COUNT;
        if (avg >= APPROVAL_THRESHOLD) approvedCount++;
      }
    });

    return { totalEmployees, approvedCount, groupAvgs };
  }, [filteredData, currentGrades]);

  const trendData = useMemo(() => {
    const months = Array.from(new Set(allGrades.map(g => g.month))).sort();
    return months.map(m => {
      const monthGrades = allGrades.filter(g => g.month === m);
      const empIdsInScope = new Set(filteredData.map(e => e.id));
      const filteredMonthGrades = monthGrades.filter(g => empIdsInScope.has(g.employeeId));

      const totalPossible = empIdsInScope.size * TOTAL_CATEGORIES_COUNT;
      const sum = filteredMonthGrades.reduce((s, g) => s + g.score, 0);
      return {
        month: m,
        score: totalPossible > 0 ? Math.round(sum / totalPossible) : 0
      };
    });
  }, [allGrades, filteredData]);

  const handleExportFinal = () => {
    const exportData = filteredData.map(emp => {
      const empStore = restaurants.find(r => r.id === emp.restaurantId);
      const empGrades = currentGrades.filter(g => g.employeeId === emp.id);

      const dynamicColumns: any = {};

      exportGroups.forEach(gid => {
        const gConfig = (EVALUATION_GROUPS as any)[gid];
        const gGrades = empGrades.filter(g => g.group === gid);

        if (includeSubNotes) {
          gConfig.categories.forEach((cat: string) => {
            const grade = gGrades.find(g => g.category === cat);
            dynamicColumns[`${gConfig.name} - ${cat}`] = grade ? `${grade.score}%` : '0%';
          });
        } else {
          const sum = gGrades.reduce((s, g) => s + g.score, 0);
          const avg = gConfig.categories.length > 0 ? Math.round(sum / gConfig.categories.length) : 0;
          dynamicColumns[`${gConfig.name} %`] = `${avg}%`;
        }
      });

      const totalSum = empGrades.reduce((s, g) => s + g.score, 0);
      const totalAvg = Math.round(totalSum / TOTAL_CATEGORIES_COUNT);

      return {
        "Documento": emp.id,
        "Nombre completo": emp.name,
        "Estado": emp.active ? "Activo" : "Retirado",
        "Fecha de ingreso": emp.joinDate,
        "Cargo": emp.title,
        "Nombre_Ceco": empStore?.name || emp.restaurantId,
        "Jefe de area": emp.zone,
        "Region": empStore?.region || 'N/A',
        "Mes Reporte": selectedMonth,
        "Promedio General": `${totalAvg}%`,
        ...dynamicColumns
      };
    });

    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Reporte_Akademia");
    XLSX.writeFile(wb, `Reporte_Akademia_${selectedMonth}.xlsx`);
    setShowExportModal(false);
  };

  const toggleExportGroup = (id: string) => {
    setExportGroups(prev => 
      prev.includes(id) ? prev.filter(g => g !== id) : [...prev, id]
    );
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6 items-end">
        {user.role === UserRole.ADMIN && (
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
            <div className="relative">
              <select 
                value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 transition-all outline-none appearance-none"
              >
                <option value="all">Todas las Regiones</option>
                {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
              </select>
              <MapPin className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
          </div>
        )}

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
          <div className="relative">
            <select 
              value={filterZone} onChange={(e) => setFilterZone(e.target.value)}
              className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 transition-all outline-none appearance-none"
            >
              <option value="all">Todas las Zonas</option>
              {dynamicZones.map(z => (
                <option key={z} value={z}>{z}</option>
              ))}
            </select>
            <Filter className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Tienda</label>
          <div className="relative">
            <select 
              value={filterStore} onChange={(e) => setFilterStore(e.target.value)}
              className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-sm font-black text-slate-900 focus:bg-white focus:border-red-500 transition-all outline-none appearance-none"
