            <div className="space-y-4 max-h-72 overflow-y-auto pr-2 scrollbar-thin">
              {dataService.getUsers().map(u => (
                <div key={u.id} className="bg-white p-5 rounded-2xl border border-slate-100 flex items-center justify-between shadow-sm group">
