import React, { useMemo, useState, useEffect } from 'react';
import { Employee, Restaurant } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, Cell, PieChart, Pie } from 'recharts';
import { ArrowUpCircle, ArrowDownCircle, Search, Filter, MapPin, Users, Calendar, ArrowRight, TrendingUp, ChevronDown } from 'lucide-react';

interface EntriesExitsReportProps {
  employees: Employee[];
  restaurants: Restaurant[];
}

const EntriesExitsReport: React.FC<EntriesExitsReportProps> = ({ employees, restaurants }) => {
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [filterStore, setFilterStore] = useState('all');

  const currentYear = new Date().getFullYear();
  const currentMonth = (new Date().getMonth() + 1).toString().padStart(2, '0');

  const [selectedYear, setSelectedYear] = useState<string>(currentYear.toString());
  const [selectedMonthPart, setSelectedMonthPart] = useState<string>(currentMonth);

  const [viewDetail, setViewDetail] = useState<'entries' | 'exits' | 'none'>('none');

  const selectedMonth = `${selectedYear}-${selectedMonthPart}`;

  // Cascading reset
  useEffect(() => {
    setFilterZone('all');
    setFilterStore('all');
  }, [filterRegion]);

  useEffect(() => {
    setFilterStore('all');
  }, [filterZone]);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);

  const dynamicZones = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') {
      baseStores = baseStores.filter(r => r.region === filterRegion);
    }
    return Array.from(new Set(baseStores.map(r => r.zone))).filter(Boolean).sort();
  }, [restaurants, filterRegion]);

  const dynamicStores = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') {
      baseStores = baseStores.filter(r => r.region === filterRegion);
    }
    if (filterZone !== 'all') {
      baseStores = baseStores.filter(r => r.zone === filterZone);
    }
    return baseStores.sort((a, b) => a.name.localeCompare(b.name));
  }, [restaurants, filterRegion, filterZone]);

  const historyEvents = useMemo(() => {
    const events: any[] = [];
    employees.forEach(emp => {
      emp.history?.forEach(h => {
        if (h.action === 'INGRESO' || h.action === 'RETIRO') {
          const store = restaurants.find(r => r.id === h.restaurantName || r.name === h.restaurantName);
          const matchRegion = filterRegion === 'all' || store?.region === filterRegion;
          const matchZone = filterZone === 'all' || store?.zone === filterZone;
          const matchStore = filterStore === 'all' || store?.id === filterStore || store?.name === filterStore;

          if (matchRegion && matchZone && matchStore) {
            events.push({
              ...h,
              employeeName: emp.name,
              employeeId: emp.id,
              month: h.date.slice(0, 7),
              year: h.date.slice(0, 4)
            });
          }
        }
      });
    });
    return events;
  }, [employees, restaurants, filterRegion, filterZone, filterStore]);

  const monthStats = useMemo(() => {
    const entries = historyEvents.filter(e => e.month === selectedMonth && e.action === 'INGRESO').length;
    const exits = historyEvents.filter(e => e.month === selectedMonth && e.action === 'RETIRO').length;
    return { entries, exits };
  }, [historyEvents, selectedMonth]);

  const yearStats = useMemo(() => {
    const entries = historyEvents.filter(e => e.year === selectedYear && e.action === 'INGRESO').length;
    const exits = historyEvents.filter(e => e.year === selectedYear && e.action === 'RETIRO').length;
    return { entries, exits };
  }, [historyEvents, selectedYear]);

  const detailList = useMemo(() => {
    if (viewDetail === 'none') return [];
    const action = viewDetail === 'entries' ? 'INGRESO' : 'RETIRO';
    return historyEvents.filter(e => e.month === selectedMonth && e.action === action).sort((a, b) => b.date.localeCompare(a.date));
  }, [historyEvents, viewDetail, selectedMonth]);

  const chartData = [
    { name: 'Mensual', ingresos: monthStats.entries, retiros: monthStats.exits },
    { name: 'Anual', ingresos: yearStats.entries, retiros: yearStats.exits }
  ];

  const years = [currentYear.toString(), (currentYear - 1).toString(), (currentYear - 2).toString()];
  const monthsList = [
    { val: '01', label: 'Enero' }, { val: '02', label: 'Febrero' }, { val: '03', label: 'Marzo' },
    { val: '04', label: 'Abril' }, { val: '05', label: 'Mayo' }, { val: '06', label: 'Junio' },
    { val: '07', label: 'Julio' }, { val: '08', label: 'Agosto' }, { val: '09', label: 'Septiembre' },
    { val: '10', label: 'Octubre' }, { val: '11', label: 'Noviembre' }, { val: '12', label: 'Diciembre' }
  ];

  const selectStyle = "w-full pl-10 pr-10 py-3 bg-white border-2 border-slate-200 rounded-2xl text-[12px] font-black text-slate-800 outline-none appearance-none cursor-pointer shadow-sm hover:border-red-400 focus:border-red-500 focus:ring-4 focus:ring-red-50 transition-all uppercase tracking-tighter";

  return (
    <div className="space-y-6">
      <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
        <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6 mb-8">
          <div className="grid grid-cols-1 md:grid-cols-5 gap-4 flex-1">

            <div className="relative">
              <Calendar className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
              <select
                className={selectStyle}
                value={selectedYear}
                onChange={(e) => setSelectedYear(e.target.value)}
              >
                {years.map(y => <option key={y} value={y}>{y}</option>)}
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>

            <div className="relative">
              <Calendar className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
              <select
                className={selectStyle}
                value={selectedMonthPart}
                onChange={(e) => setSelectedMonthPart(e.target.value)}
              >
                {monthsList.map(m => <option key={m.val} value={m.val}>{m.label}</option>)}
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>

            <div className="relative">
              <MapPin className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
              <select
                className={selectStyle}
                value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)}
              >
                <option value="all">Todas las Regiones</option>
                {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>

            <div className="relative">
              <Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
              <select
                className={selectStyle}
                value={filterZone} onChange={(e) => setFilterZone(e.target.value)}
              >
                <option value="all">Todas las Zonas</option>
                {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>

            <div className="relative">
              <Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
              <select
                className={selectStyle}
                value={filterStore} onChange={(e) => setFilterStore(e.target.value)}
              >
                <option value="all">Todas las Tiendas</option>
                {dynamicStores.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="space-y-6">
            <div className="grid grid-cols-2 gap-4">
