      {viewDetail !== 'none' && (
        <div className="bg-white rounded-[40px] shadow-2xl border border-slate-100 animate-in slide-in-from-top-4 duration-300 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
            <div>
              <h3 className="text-xl font-black text-slate-800 tracking-tight flex items-center">
                 {viewDetail === 'entries' ? <ArrowUpCircle className="w-5 h-5 mr-3 text-emerald-500" /> : <ArrowDownCircle className="w-5 h-5 mr-3 text-red-500" />}
                 {viewDetail === 'entries' ? 'Listado de Ingresos' : 'Listado de Retiros'}
              </h3>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Registros de {selectedMonth}</p>
            </div>
            <button onClick={() => setViewDetail('none')} className="text-[9px] font-black text-slate-400 uppercase tracking-widest hover:text-red-600 transition-colors">Cerrar Detalle</button>
