              </thead>
              <tbody className="divide-y divide-slate-50">
                {detailList.map((e, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/30 transition-colors group">
                    <td className="px-8 py-5 text-sm font-black text-slate-500 tabular-nums">{e.date}</td>
                    <td className="px-8 py-5 text-sm font-black text-slate-800 uppercase tracking-tighter">{e.employeeName}</td>
                    <td className="px-8 py-5 text-sm font-bold text-slate-400">{e.employeeId}</td>
