                    <td className="px-8 py-5 text-center">
                      <span className={`inline-block px-4 py-1.5 rounded-full text-[9px] font-black uppercase shadow-sm ${e.action === 'INGRESO' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
