            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default EntriesExitsReport;

import React, { useMemo, useState, useEffect } from 'react';
import { Employee, GradeEntry, User, Restaurant, UserRole } from '../types';
import { dataService } from '../dataService';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, LineChart, Line, LabelList } from 'recharts';
import { XCircle, Users, Award, TrendingUp, Search, MapPin, Filter, Calendar, Download, X, Check, FileText, ChevronDown } from 'lucide-react';
import * as XLSX from 'xlsx';

interface DashboardProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ employees: initialEmployees, restaurants, selectedMonth, user }) => {
  const [searchPerson, setSearchPerson] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [filterStore, setFilterStore] = useState('all');

  // Reset child filters when parent filter changes
  useEffect(() => {
    setFilterZone('all');
    setFilterStore('all');
  }, [filterRegion]);

  useEffect(() => {
    setFilterStore('all');
  }, [filterZone]);

  // Export Modal State
  const [showExportModal, setShowExportModal] = useState(false);
  const [exportGroups, setExportGroups] = useState<string[]>(Object.keys(EVALUATION_GROUPS));
  const [includeSubNotes, setIncludeSubNotes] = useState(false);

  const allGrades = useMemo(() => dataService.getGrades(), []);
  const currentGrades = useMemo(() => allGrades.filter(g => g.month === selectedMonth), [allGrades, selectedMonth]);

  // Derive cascading dynamic filters
  const dynamicRegions = useMemo(() => {
    return Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort();
  }, [restaurants]);

  const dynamicZones = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') {
      baseStores = baseStores.filter(r => r.region === filterRegion);
    }
    let zones = Array.from(new Set(baseStores.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) {
      zones = zones.filter(z => user.assignedZones.includes(z));
    }
    return zones;
  }, [restaurants, filterRegion, user]);

  const dynamicStores = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') {
      baseStores = baseStores.filter(r => r.region === filterRegion);
    }
    if (filterZone !== 'all') {
      baseStores = baseStores.filter(r => r.zone === filterZone);
    }
    if (user.role === UserRole.SPECIALIST) {
      baseStores = baseStores.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));
    }
    return baseStores.sort((a, b) => a.name.localeCompare(b.name));
  }, [restaurants, filterRegion, filterZone, user]);

  const relevantEmployees = useMemo(() => {
    const idsWithGrades = new Set(currentGrades.map(g => g.employeeId));
    return initialEmployees.filter(e => e.active || idsWithGrades.has(e.id));
  }, [initialEmployees, currentGrades]);

  const filteredData = useMemo(() => {
    return relevantEmployees.filter(e => {
      const store = restaurants.find(r => r.id === e.restaurantId);
      const matchPerson = searchPerson === '' || e.name.toLowerCase().includes(searchPerson.toLowerCase()) || e.id.includes(searchPerson);
      const matchRegion = filterRegion === 'all' || store?.region === filterRegion;
      const matchZone = filterZone === 'all' || e.zone === filterZone;
      const matchStore = filterStore === 'all' || e.restaurantId === filterStore;
      return matchPerson && matchStore && matchZone && matchRegion;
    });
  }, [relevantEmployees, searchPerson, filterStore, filterZone, filterRegion, restaurants]);

  const stats = useMemo(() => {
    const totalEmployees = filteredData.length;
    let approvedCount = 0;

    const groupAvgs = Object.keys(EVALUATION_GROUPS).map(groupId => {
      const groupData = (EVALUATION_GROUPS as any)[groupId];
      const groupGrades = currentGrades.filter(g => g.group === groupId && filteredData.some(e => e.id === g.employeeId));

      const totalPossibleCategories = filteredData.length * groupData.categories.length;
      const sumScores = groupGrades.reduce((sum, g) => sum + g.score, 0);
      const avg = totalPossibleCategories > 0 ? sumScores / totalPossibleCategories : 0;

      return {
        id: groupId,
        name: groupData.name,
        avg: Math.round(avg)
      };
    });

    filteredData.forEach(emp => {
      const empGrades = currentGrades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        const sum = empGrades.reduce((sum, g) => sum + g.score, 0);
        const avg = sum / TOTAL_CATEGORIES_COUNT;
        if (avg >= APPROVAL_THRESHOLD) approvedCount++;
      }
    });

    return { totalEmployees, approvedCount, groupAvgs };
  }, [filteredData, currentGrades]);

  const trendData = useMemo(() => {
    const months = Array.from(new Set(allGrades.map(g => g.month))).sort();
    return months.map(m => {
      const monthGrades = allGrades.filter(g => g.month === m);
      const empIdsInScope = new Set(filteredData.map(e => e.id));
      const filteredMonthGrades = monthGrades.filter(g => empIdsInScope.has(g.employeeId));

      const totalPossible = empIdsInScope.size * TOTAL_CATEGORIES_COUNT;
      const sum = filteredMonthGrades.reduce((s, g) => s + g.score, 0);
      return {
        month: m,
        score: totalPossible > 0 ? Math.round(sum / totalPossible) : 0
      };
    });
  }, [allGrades, filteredData]);

  const handleExportFinal = () => {
    const exportData = filteredData.map(emp => {
      const empStore = restaurants.find(r => r.id === emp.restaurantId);
      const empGrades = currentGrades.filter(g => g.employeeId === emp.id);

      const dynamicColumns: any = {};

      exportGroups.forEach(gid => {
        const gConfig = (EVALUATION_GROUPS as any)[gid];
        const gGrades = empGrades.filter(g => g.group === gid);

        if (includeSubNotes) {
          gConfig.categories.forEach((cat: string) => {
            const grade = gGrades.find(g => g.category === cat);
            dynamicColumns[`${gConfig.name} - ${cat}`] = grade ? `${grade.score}%` : '0%';
          });
        } else {
          const sum = gGrades.reduce((s, g) => s + g.score, 0);
          const avg = gConfig.categories.length > 0 ? Math.round(sum / gConfig.categories.length) : 0;
          dynamicColumns[`${gConfig.name} %`] = `${avg}%`;
        }
      });

      const totalSum = empGrades.reduce((s, g) => s + g.score, 0);
      const totalAvg = Math.round(totalSum / TOTAL_CATEGORIES_COUNT);

      return {
        "Documento": emp.id,
        "Nombre completo": emp.name,
        "Estado": emp.active ? "Activo" : "Retirado",
        "Fecha de ingreso": emp.joinDate,
        "Cargo": emp.title,
        "Nombre_Ceco": empStore?.name || emp.restaurantId,
        "Jefe de area": emp.zone,
        "Region": empStore?.region || 'N/A',
        "Mes Reporte": selectedMonth,
        "Promedio General": `${totalAvg}%`,
        ...dynamicColumns
      };
    });

    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Reporte_Akademia");
    XLSX.writeFile(wb, `Reporte_Akademia_${selectedMonth}.xlsx`);
    setShowExportModal(false);
  };

  const toggleExportGroup = (id: string) => {
    setExportGroups(prev => 
      prev.includes(id) ? prev.filter(g => g !== id) : [...prev, id]
    );
  };

  const selectStyle = "w-full pl-4 pr-10 py-3 bg-white border-2 border-slate-100 rounded-xl text-xs font-black text-slate-900 focus:border-red-500 hover:border-slate-300 transition-all outline-none appearance-none cursor-pointer uppercase shadow-sm";

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6 items-end">
        {user.role === UserRole.ADMIN && (
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1 flex items-center">
              <MapPin className="w-3 h-3 mr-1" /> Región
            </label>
            <div className="relative">
              <select 
                value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)}
                className={selectStyle}
              >
                <option value="all">Todas las Regiones</option>
                {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
          </div>
        )}

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1 flex items-center">
            <Filter className="w-3 h-3 mr-1" /> Zona
          </label>
          <div className="relative">
            <select 
              value={filterZone} onChange={(e) => setFilterZone(e.target.value)}
              className={selectStyle}
            >
              <option value="all">Todas las Zonas</option>
              {dynamicZones.map(z => (
                <option key={z} value={z}>{z}</option>
              ))}
            </select>
            <ChevronDown className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1 flex items-center">
            <Filter className="w-3 h-3 mr-1" /> Tienda
          </label>
          <div className="relative">
            <select 
              value={filterStore} onChange={(e) => setFilterStore(e.target.value)}
              className={selectStyle}
            >
              <option value="all">Todas las Tiendas</option>
              {dynamicStores.map(r => (
                <option key={r.id} value={r.id}>{r.name}</option>
              ))}
            </select>
            <ChevronDown className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1 flex items-center">
            <Search className="w-3 h-3 mr-1" /> Persona
          </label>
          <div className="relative">
            <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <input 
              type="text" placeholder="Nombre o ID..." value={searchPerson} onChange={(e) => setSearchPerson(e.target.value)}
              className="w-full pl-11 pr-4 py-3 bg-white border-2 border-slate-100 rounded-xl text-xs font-black text-slate-900 focus:border-red-500 hover:border-slate-300 outline-none transition-all placeholder:text-slate-300 shadow-sm"
            />
          </div>
        </div>

        <button 
          onClick={() => setShowExportModal(true)}
          className="w-full flex items-center justify-center space-x-2 px-4 py-3.5 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-black transition-all shadow-lg active:scale-95"
        >
          <Download className="w-4 h-4" />
          <span>Exportar Excel</span>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard icon={<Users className="w-6 h-6" />} label="Equipo Evaluado" value={stats.totalEmployees} subValue="Personal en Periodo" />
        <StatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approvedCount} subValue="Nivel de Excelencia" color="green" />
        <StatCard icon={<TrendingUp className="w-6 h-6" />} label="Promedio" value={`${stats.groupAvgs.length > 0 ? Math.round(stats.groupAvgs.reduce((s, g) => s + g.avg, 0) / stats.groupAvgs.length) : 0}%`} subValue="General del Periodo" color="blue" />
        <StatCard icon={<XCircle className="w-6 h-6" />} label="Faltantes" value={Math.max(0, stats.totalEmployees - stats.approvedCount)} subValue="Brecha de Calidad" color="red" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
          <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center mb-8">
            <TrendingUp className="w-4 h-4 mr-2 text-red-500" /> Desempeño por Grupo Evaluativo
          </h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.groupAvgs} margin={{ top: 20, right: 0, left: -25, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                <YAxis domain={[0, 100]} axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                <Tooltip cursor={{ fill: '#f8fafc' }} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', fontWeight: '900', fontSize: '12px' }} />
                <Bar dataKey="avg" radius={[10, 10, 0, 0]} barSize={45}>
                  <LabelList dataKey="avg" position="top" formatter={(v: any) => `${v}%`} style={{ fontSize: '10px', fontWeight: '900', fill: '#64748b' }} />
                  {stats.groupAvgs.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.avg >= APPROVAL_THRESHOLD ? '#10b981' : '#ef4444'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
          <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center mb-8">
            <Calendar className="w-4 h-4 mr-2 text-red-500" /> Tendencia de Desempeño Mensual
          </h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={trendData} margin={{ top: 5, right: 20, left: -20, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                <YAxis domain={[0, 100]} axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                <Tooltip contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', fontWeight: '900' }} />
                <Line type="monotone" dataKey="score" stroke="#ef4444" strokeWidth={4} dot={{ r: 6, fill: '#ef4444', strokeWidth: 2, stroke: '#fff' }} activeDot={{ r: 8 }} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {showExportModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/80 backdrop-blur-md p-4 animate-in fade-in duration-200">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-lg overflow-hidden border-2 border-slate-100">
            <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
              <div>
                <h3 className="text-2xl font-black uppercase tracking-tighter italic flex items-center">
                  <FileText className="w-6 h-6 mr-3 text-red-500" /> Configurar Exportación
                </h3>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Seleccione los datos para el reporte Excel</p>
              </div>
              <button onClick={() => setShowExportModal(false)} className="p-3 hover:bg-white/10 rounded-2xl transition">
                <X className="w-6 h-6"/>
              </button>
            </div>

            <div className="p-10 space-y-8">
              <div className="space-y-4">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Grupos Evaluativos</label>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                  {Object.entries(EVALUATION_GROUPS).map(([id, group]) => (
                    <button
                      key={id}
                      onClick={() => toggleExportGroup(id)}
                      className={`flex items-center justify-between px-4 py-3 rounded-2xl border-2 transition-all ${exportGroups.includes(id) ? 'bg-red-50 border-red-500 text-red-700' : 'bg-slate-50 border-slate-100 text-slate-400'}`}
                    >
                      <span className="text-[11px] font-black uppercase tracking-tight">{group.name}</span>
                      {exportGroups.includes(id) ? <Check className="w-4 h-4" /> : <div className="w-4 h-4" />}
                    </button>
                  ))}
                </div>
