import { Employee, GradeEntry, User, UserRole, JobTitle, Restaurant, HierarchyData } from './types';
import * as XLSX from 'xlsx';

const STORAGE_KEY_EMPLOYEES = 'la_akademia_employees';
const STORAGE_KEY_GRADES = 'la_akademia_grades';
const STORAGE_KEY_USERS = 'la_akademia_users';
const STORAGE_KEY_STORES = 'la_akademia_stores';
const STORAGE_KEY_HIERARCHY = 'la_akademia_hierarchy';

const parseExcelDate = (serial: any) => {
  if (!serial) return '';
  if (typeof serial === 'string') return serial;
  try {
    const date = XLSX.SSF.parse_date_code(serial);
    const month = String(date.m).padStart(2, '0');
    const day = String(date.d).padStart(2, '0');
    return `${date.y}-${month}-${day}`;
  } catch (e) {
    return String(serial);
  }
};

export const dataService = {
  clearAllData: () => {
    localStorage.removeItem(STORAGE_KEY_EMPLOYEES);
    localStorage.removeItem(STORAGE_KEY_GRADES);
    localStorage.removeItem(STORAGE_KEY_STORES);
  },

  getEmployees: (): Employee[] => {
    const data = localStorage.getItem(STORAGE_KEY_EMPLOYEES);
    return data ? JSON.parse(data) : [];
  },

  getRestaurants: (): Restaurant[] => {
    const data = localStorage.getItem(STORAGE_KEY_STORES);
    return data ? JSON.parse(data) : [];
  },

  getHierarchy: (): HierarchyData => {
    const data = localStorage.getItem(STORAGE_KEY_HIERARCHY);
    return data ? JSON.parse(data) : { regions: [] };
  },

  saveHierarchy: (hierarchy: HierarchyData) => {
    localStorage.setItem(STORAGE_KEY_HIERARCHY, JSON.stringify(hierarchy));
    // When saving hierarchy, we also need to update the restaurants mapping
    const restaurants = dataService.getRestaurants();
    const updatedRestaurants = restaurants.map(r => {
      let foundZone = 'Sin Clasificar';
      let foundRegion = 'Sin Clasificar';

      hierarchy.regions.forEach(reg => {
        reg.zones.forEach(zone => {
          if (zone.restaurantIds.includes(r.id)) {
            foundZone = zone.name;
            foundRegion = reg.name;
          }
        });
      });

      return { ...r, zone: foundZone, region: foundRegion };
    });
    dataService.saveRestaurants(updatedRestaurants);

    // Also update employees current zone view
    const employees = dataService.getEmployees();
    const updatedEmployees = employees.map(emp => {
      const store = updatedRestaurants.find(s => s.id === emp.restaurantId);
      return { ...emp, zone: store?.zone || 'Sin Clasificar' };
    });
    dataService.saveEmployees(updatedEmployees);
  },

  getGrades: (): GradeEntry[] => {
    const data = localStorage.getItem(STORAGE_KEY_GRADES);
    return data ? JSON.parse(data) : [];
  },

  saveEmployees: (employees: Employee[]) => {
    localStorage.setItem(STORAGE_KEY_EMPLOYEES, JSON.stringify(employees));
  },

  saveRestaurants: (stores: Restaurant[]) => {
    localStorage.setItem(STORAGE_KEY_STORES, JSON.stringify(stores));
  },

  saveGrades: (grades: GradeEntry[]) => {
    localStorage.setItem(STORAGE_KEY_GRADES, JSON.stringify(grades));
  },

  getUsers: (): User[] => {
    const data = localStorage.getItem(STORAGE_KEY_USERS);
    if (!data) {
      const seed: User[] = [
        { id: 'admin1', username: 'admin', password: '123', role: UserRole.ADMIN, assignedZones: [], assignedRestaurants: [] },
        { id: 'spec1', username: 'especialista1', password: '123', role: UserRole.SPECIALIST, assignedZones: [], assignedRestaurants: [] }
      ];
      localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(seed));
      return seed;
    }
    return JSON.parse(data);
  },

  updateUser: (updatedUser: User) => {
    const users = dataService.getUsers();
    const index = users.findIndex(u => u.id === updatedUser.id);
    if (index !== -1) {
      users[index] = updatedUser;
      localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(users));
    }
  },

  importMonthlyExcel: (rawData: any[]) => {
    const currentEmployees = dataService.getEmployees();
    const currentStores = dataService.getRestaurants();
    const hierarchy = dataService.getHierarchy();
    const today = new Date().toISOString().split('T')[0];
    let heladeriasSkipped = false;

    // Updated validation: removed "Jefe de area" as it is now determined by hierarchy
    const requiredFields = ["Documento", "Nombre completo", "Cargo", "Nombre_Ceco"];
    const missingDataRows: number[] = [];

    rawData.forEach((item, index) => {
      const missing = requiredFields.filter(field => {
        const val = item[field] || item[field.toLowerCase()];
        return val === undefined || val === null || String(val).trim() === "";
      });
      if (missing.length > 0) {
        missingDataRows.push(index + 2);
      }
    });

    if (missingDataRows.length > 0) {
      throw new Error(`Datos incompletos detectados en las filas: ${missingDataRows.slice(0, 5).join(", ")}${missingDataRows.length > 5 ? "..." : ""}. Verifique que 'Documento', 'Nombre completo', 'Cargo' y 'Nombre_Ceco' no estén vacíos.`);
    }

    const newStoresMap = new Map<string, Restaurant>();
    currentStores.forEach(s => newStoresMap.set(s.id, s));

    const importedIds = new Set();
    const filteredRawData = rawData.filter(item => {
      const storeId = String(item.Nombre_Ceco || item.nombre_ceco || '').trim().toUpperCase();
      if (storeId.startsWith('H')) {
        heladeriasSkipped = true;
        return false;
      }
      return true;
    });

    const importedEmployees = filteredRawData.map(item => {
      const storeId = String(item.Nombre_Ceco || item.nombre_ceco || 'SIN_CECO').trim();
      const docId = String(item.Documento || item.documento || '').trim();
      if (!docId) return null;

      importedIds.add(docId);

      // Determine Zone and Region from Hierarchy
      let assignedZone = 'Sin Clasificar';
      let assignedRegion = 'Sin Clasificar';
      hierarchy.regions.forEach(reg => {
        reg.zones.forEach(zone => {
          if (zone.restaurantIds.includes(storeId)) {
            assignedZone = zone.name;
            assignedRegion = reg.name;
          }
        });
      });

      if (!newStoresMap.has(storeId)) {
        newStoresMap.set(storeId, {
          id: storeId,
          name: storeId,
          zone: assignedZone,
          region: assignedRegion
        });
      } else {
        const s = newStoresMap.get(storeId)!;
        s.zone = assignedZone;
        s.region = assignedRegion;
      }

      const existing = currentEmployees.find(e => e.id === docId);
      const rawStatus = String(item.Estado || item.estado || '').trim().toUpperCase();
      const isActive = rawStatus.startsWith('ACTIVO');

      const emp: Employee = {
        id: docId,
        name: item["Nombre completo"] || item.nombre || 'Sin Nombre',
        joinDate: parseExcelDate(item["Fecha de ingreso"] || item.fecha_de_ingreso),
        title: (item.Cargo || item.cargo) as JobTitle,
        restaurantId: storeId,
        zone: assignedZone,
        active: isActive,
        history: existing?.history || []
      };

      if (existing) {
        if (existing.restaurantId !== storeId) {
          emp.history = [...(existing.history || []), {
            date: today,
            restaurantName: existing.restaurantId,
            action: 'TRASLADO'
          }];
        }
        if (existing.active && !isActive) {
           emp.history = [...(existing.history || []), {
            date: today,
            restaurantName: storeId,
            action: 'RETIRO'
          }];
        }
      } else {
        emp.history = [{ date: emp.joinDate || today, restaurantName: storeId, action: 'INGRESO' }];
        if (!isActive) {
          emp.history.push({ date: today, restaurantName: storeId, action: 'RETIRO' });
        }
      }

      return emp;
    }).filter(e => e !== null) as Employee[];

    const retired = currentEmployees
      .filter(e => !importedIds.has(e.id) && e.active)
      .map(e => ({
        ...e,
        active: false,
        history: [...(e.history || []), { date: today, restaurantName: e.restaurantId, action: 'RETIRO' as const }]
      }));

    const finalEmployees = [...importedEmployees, ...retired];
    dataService.saveRestaurants(Array.from(newStoresMap.values()));
    dataService.saveEmployees(finalEmployees);

    return { heladeriasSkipped, count: importedEmployees.length };
  }
};

import React, { useState, useMemo, useEffect } from 'react';
import { Upload, UserPlus, Database, Search, X, Check, ChevronDown, Lock, Shield, FileSpreadsheet, Download, Edit2, Trash2, AlertCircle, Network, MapPin, Layers, Plus, Trash } from 'lucide-react';
import { dataService } from '../dataService';
import { UserRole, User, JobTitle, HierarchyData } from '../types';
import * as XLSX from 'xlsx';

interface AdminPanelProps {
  onEmployeesImported: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onEmployeesImported }) => {
  const [activeSubTab, setActiveSubTab] = useState<'import' | 'users' | 'hierarchy'>('import');
  const [importStatus, setImportStatus] = useState<string | null>(null);
  const [importError, setImportError] = useState<string | null>(null);
  const [heladeriaWarning, setHeladeriaWarning] = useState<boolean>(false);
  const [isImporting, setIsImporting] = useState(false);
  const [showUserModal, setShowUserModal] = useState(false);
  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [newUserData, setNewUserData] = useState({
    username: '',
    password: '',
    role: UserRole.SPECIALIST,
    assignedZones: [] as string[],
  });

  // Hierarchy State
  const [hierarchy, setHierarchy] = useState<HierarchyData>(dataService.getHierarchy());
  const allRestaurants = useMemo(() => dataService.getRestaurants(), [activeSubTab]);

  const availableZones = useMemo(() => {
    return Array.from(new Set(dataService.getRestaurants().map(r => r.zone))).filter(Boolean).sort();
  }, [showUserModal, isImporting, activeSubTab]);

  const downloadTemplate = () => {
    // Template updated to remove redundant fields
    const headers = [["Documento", "Nombre completo", "Estado", "Fecha de ingreso", "Cargo", "Nombre_Ceco"]];
    const ws = XLSX.utils.aoa_to_sheet(headers);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Plantilla");
    XLSX.writeFile(wb, "plantilla_akademia_kfc.xlsx");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsImporting(true);
    setImportStatus('Procesando archivo...');
    setImportError(null);
    setHeladeriaWarning(false);

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws);

        if (data.length === 0) {
           throw new Error("El archivo está vacío");
        }

        const result = dataService.importMonthlyExcel(data);

        setIsImporting(false);
        setImportStatus(`Carga exitosa: ${result.count} registros procesados.`);
        if (result.heladeriasSkipped) {
          setHeladeriaWarning(true);
        }
        onEmployeesImported();
        setTimeout(() => setImportStatus(null), 8000);
      } catch (err: any) {
        setIsImporting(false);
        setImportStatus(null);
        setImportError(err.message || 'Error: Formato de archivo no válido o vacío.');
        console.error(err);
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; // Reset input
  };

  const handleSaveUser = () => {
    if (!newUserData.username) return;
    const users = dataService.getUsers();

    if (editingUserId) {
      const updatedUser: User = {
        id: editingUserId,
        username: newUserData.username,
        password: newUserData.password || '123',
        role: newUserData.role,
        assignedZones: newUserData.assignedZones,
        assignedRestaurants: []
      };
      dataService.updateUser(updatedUser);
    } else {
      const newUser: User = {
        id: `u-${Date.now()}`,
        username: newUserData.username,
        password: newUserData.password || '123',
        role: newUserData.role,
        assignedZones: newUserData.assignedZones,
        assignedRestaurants: []
      };
      localStorage.setItem('la_akademia_users', JSON.stringify([...users, newUser]));
    }

    setShowUserModal(false);
    setEditingUserId(null);
    setNewUserData({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [] });
  };

  const startEdit = (user: User) => {
    setEditingUserId(user.id);
    setNewUserData({
      username: user.username,
      password: '',
      role: user.role,
      assignedZones: user.assignedZones
    });
    setShowUserModal(true);
  };

  const deleteUser = (userId: string) => {
    if (userId === 'admin1') return;
    if (!confirm('¿Seguro que desea eliminar este usuario?')) return;
    const users = dataService.getUsers().filter(u => u.id !== userId);
    localStorage.setItem('la_akademia_users', JSON.stringify(users));
    onEmployeesImported(); 
  };

  // Hierarchy Handlers
  const addRegion = () => {
    const name = prompt('Nombre de la nueva región:');
    if (!name) return;
    const newHierarchy = { ...hierarchy, regions: [...hierarchy.regions, { name, zones: [] }] };
    setHierarchy(newHierarchy);
    dataService.saveHierarchy(newHierarchy);
  };

  const removeRegion = (index: number) => {
    if (!confirm('¿Desea eliminar esta región y todas sus zonas?')) return;
    const newRegions = [...hierarchy.regions];
    newRegions.splice(index, 1);
    const newHierarchy = { ...hierarchy, regions: newRegions };
    setHierarchy(newHierarchy);
    dataService.saveHierarchy(newHierarchy);
  };

  const addZone = (regionIndex: number) => {
    const name = prompt('Nombre de la nueva zona:');
    if (!name) return;
    const newHierarchy = { ...hierarchy };
    newHierarchy.regions[regionIndex].zones.push({ name, restaurantIds: [] });
    setHierarchy(newHierarchy);
    dataService.saveHierarchy(newHierarchy);
  };

  const removeZone = (regionIndex: number, zoneIndex: number) => {
    if (!confirm('¿Desea eliminar esta zona?')) return;
    const newHierarchy = { ...hierarchy };
    newHierarchy.regions[regionIndex].zones.splice(zoneIndex, 1);
    setHierarchy(newHierarchy);
    dataService.saveHierarchy(newHierarchy);
  };

  const toggleRestaurantInZone = (regionIndex: number, zoneIndex: number, restaurantId: string) => {
    const newHierarchy = { ...hierarchy };
    const currentZone = newHierarchy.regions[regionIndex].zones[zoneIndex];

    // Remove from any other zone first
    newHierarchy.regions.forEach(reg => {
      reg.zones.forEach(zone => {
        zone.restaurantIds = zone.restaurantIds.filter(id => id !== restaurantId);
      });
    });

