    currentZone.restaurantIds.push(restaurantId);

    setHierarchy(newHierarchy);
    dataService.saveHierarchy(newHierarchy);
  };

  const unassignedRestaurants = useMemo(() => {
    const assignedIds = new Set<string>();
    hierarchy.regions.forEach(reg => {
      reg.zones.forEach(zone => {
        zone.restaurantIds.forEach(id => assignedIds.add(id));
      });
    });
    return allRestaurants.filter(r => !assignedIds.has(r.id));
  }, [hierarchy, allRestaurants]);

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-10 rounded-3xl md:rounded-[40px] shadow-sm border border-slate-100">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
          <div className="flex items-center space-x-6">
            <div className="p-4 md:p-5 bg-red-600 text-white rounded-2xl md:rounded-[24px] shadow-xl shadow-red-100">
              <Shield className="w-8 h-8 md:w-10 md:h-10" />
            </div>
            <div>
              <h2 className="text-2xl md:text-3xl font-black text-slate-800 tracking-tighter">Panel Administrador</h2>
              <div className="flex gap-4 mt-2">
                <button 
                  onClick={() => setActiveSubTab('import')}
                  className={`text-[9px] font-black uppercase tracking-widest px-3 py-1 rounded-full transition ${activeSubTab === 'import' ? 'bg-red-600 text-white' : 'bg-slate-100 text-slate-400 hover:bg-slate-200'}`}
                >
                  Importación
                </button>
                <button 
                  onClick={() => setActiveSubTab('users')}
                  className={`text-[9px] font-black uppercase tracking-widest px-3 py-1 rounded-full transition ${activeSubTab === 'users' ? 'bg-red-600 text-white' : 'bg-slate-100 text-slate-400 hover:bg-slate-200'}`}
                >
                  Usuarios
                </button>
                <button 
                  onClick={() => setActiveSubTab('hierarchy')}
                  className={`text-[9px] font-black uppercase tracking-widest px-3 py-1 rounded-full transition ${activeSubTab === 'hierarchy' ? 'bg-red-600 text-white' : 'bg-slate-100 text-slate-400 hover:bg-slate-200'}`}
                >
                  Jerarquía
                </button>
              </div>
            </div>
          </div>

          <div className="flex gap-4">
            <button 
              onClick={downloadTemplate}
              className="flex items-center justify-center space-x-3 px-6 py-4 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-black transition shadow-lg shadow-slate-100 uppercase tracking-widest"
            >
              <Download className="w-4 h-4" />
              <span>Plantilla Excel</span>
            </button>
          </div>
        </div>

        {activeSubTab === 'import' && (
          <div className="grid grid-cols-1 md:grid-cols-1 gap-10">
            <div className="p-6 md:p-8 border-2 border-slate-50 rounded-[32px] bg-slate-50/30 flex flex-col justify-between relative overflow-hidden">
              {isImporting && (
