              </div>

              {/* Stores to Assign */}
              <div className="bg-white border border-slate-100 rounded-[32px] p-8 space-y-6 flex flex-col h-fit sticky top-24">
                <div>
                  <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Tiendas por Clasificar</h4>
                  <p className="text-xs text-slate-500 leading-relaxed font-bold">Seleccione una tienda y luego la zona de destino.</p>
