                        <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{r.id}</p>
                      </div>

                      <div className="relative group/menu">
                        <button className="p-2 bg-white border border-slate-200 rounded-xl text-slate-400 hover:text-red-600 hover:border-red-600 transition shadow-sm">
