import React, { useState, useEffect } from 'react';
import { Employee, GradeEntry, JobTitle } from '../types';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { dataService } from '../dataService';
import { X, Save, User, Calendar, MapPin, Briefcase, History, ChevronRight, GraduationCap, Star, Trophy, ClipboardCheck, Vault, Layers } from 'lucide-react';

interface GradeEditorProps {
  employee: Employee;
  month: string;
  onClose: () => void;
}

const GroupIcons: Record<string, React.ReactNode> = {
  'A': <GraduationCap className="w-5 h-5" />,
  'B': <Star className="w-5 h-5" />,
  'C': <Trophy className="w-5 h-5" />,
  'D': <ClipboardCheck className="w-5 h-5" />,
  'E': <Vault className="w-5 h-5" />,
};

const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('A');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const restaurants = dataService.getRestaurants();

  useEffect(() => {
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    setFormGrades(existing);
  }, [employee, month]);

  const handleScoreChange = (group: string, category: string, scoreStr: string) => {
    if (scoreStr === '') {
      setFormGrades(prev => prev.filter(g => !(g.group === group && g.category === category)));
      return;
    }
    let score = parseInt(scoreStr);
    if (isNaN(score)) return;
    const sanitizedScore = Math.max(0, Math.min(100, score));
    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) {
        const next = [...prev];
        next[idx] = { ...next[idx], score: sanitizedScore };
        return next;
      }
      return [...prev, { employeeId: employee.id, month, group, category, score: sanitizedScore }];
    });
  };

  const saveGrades = () => {
    const allGrades = dataService.getGrades();
    const filtered = allGrades.filter(g => !(g.employeeId === employee.id && g.month === month));
    dataService.saveGrades([...filtered, ...formGrades]);
    onClose();
  };

  const getScore = (group: string, category: string) => {
    return formGrades.find(g => g.group === group && g.category === category)?.score ?? 0;
  };

  const currentStore = restaurants.find(r => r.id === employee.restaurantId);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-0 md:p-4 animate-in fade-in duration-200">
      <div className="bg-white rounded-none md:rounded-[40px] shadow-[0_0_100px_rgba(0,0,0,0.5)] w-full max-w-6xl h-full md:h-auto md:max-h-[95vh] flex flex-col overflow-hidden border-0 md:border-4 border-white ring-1 ring-slate-800 relative">

        {/* Profile Header */}
        <div className="p-6 md:p-8 bg-slate-900 text-white shrink-0 relative overflow-hidden">
          <button 
            onClick={onClose} 
            className="absolute top-6 right-6 p-3 bg-white/10 hover:bg-red-600 rounded-2xl transition-all z-50 backdrop-blur-xl border border-white/10"
          >
            <X className="w-6 h-6"/>
          </button>

          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 relative z-10">
            <div className="flex items-center space-x-6">
              <div className="w-16 h-16 md:w-20 md:h-20 bg-gradient-to-br from-red-500 to-red-700 rounded-[28px] flex items-center justify-center border-4 border-slate-800 shadow-xl shrink-0">
                <User className="w-8 h-8 md:w-10 md:h-10 text-white" />
              </div>
              <div>
                <div className="flex flex-col md:flex-row md:items-center gap-3 mb-2">
                   <h2 className="text-xl md:text-3xl font-black tracking-tighter uppercase italic">{employee.name}</h2>
                   <div className="px-3 py-1 bg-red-600 text-[9px] font-black rounded-full uppercase tracking-[0.2em]">{employee.title}</div>
                </div>
                <div className="flex flex-wrap gap-x-6 gap-y-2 opacity-60">
                  <span className="flex items-center text-[10px] font-bold uppercase tracking-widest"><MapPin className="w-3.5 h-3.5 mr-2 text-red-500"/> {currentStore?.name || 'Tienda'}</span>
                  <span className="flex items-center text-[10px] font-bold uppercase tracking-widest"><Calendar className="w-3.5 h-3.5 mr-2 text-red-500"/> Ingreso: {employee.joinDate}</span>
                </div>
              </div>
            </div>

            <button 
              onClick={() => setShowHistory(!showHistory)}
              className={`px-5 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center transition-all ${showHistory ? 'bg-red-600 text-white shadow-lg' : 'bg-slate-800 text-slate-400 hover:text-white border border-slate-700'}`}
            >
              <History className="w-4 h-4 mr-2" /> Movimientos
            </button>
          </div>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
          {/* Navigation Sidebar (Evaluation Groups) */}
          <div className="w-full md:w-80 bg-slate-50 border-b md:border-b-0 md:border-r border-slate-200 flex flex-col shrink-0">
            <div className="p-6 md:p-8 flex-1 overflow-x-auto md:overflow-y-auto no-scrollbar">
               <div className="flex items-center space-x-2 mb-6 px-1">
                  <Layers className="w-4 h-4 text-slate-400" />
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Secciones Evaluativas</p>
               </div>
               <div className="flex md:flex-col space-x-3 md:space-x-0 md:space-y-3 pb-2 md:pb-0">
                {Object.entries(EVALUATION_GROUPS).map(([id, group]) => {
                  const isActive = activeGroup === id && !showHistory;
                  const groupGrades = formGrades.filter(g => g.group === id);
                  const totalInGroup = group.categories.length;
                  const sumScores = groupGrades.reduce((s, g) => s + g.score, 0);
                  const avg = sumScores / totalInGroup;

                  return (
                    <button 
                      key={id} 
                      onClick={() => { setActiveGroup(id); setShowHistory(false); }} 
                      className={`min-w-[160px] md:min-w-0 p-5 rounded-3xl text-left transition-all relative overflow-hidden flex flex-col justify-between h-28 md:h-auto border-2 ${isActive ? 'bg-white border-red-600 shadow-xl shadow-red-100/50 scale-[1.02] z-10' : 'bg-white/40 border-slate-100 hover:border-slate-300 opacity-70 hover:opacity-100'}`}
                    >
                      <div className="flex items-start justify-between mb-2">
                        <div className={`p-2 rounded-xl ${isActive ? 'bg-red-600 text-white' : 'bg-slate-200 text-slate-500'}`}>
                          {GroupIcons[id]}
                        </div>
                        <span className={`text-[11px] font-black tabular-nums px-2 py-1 rounded-lg ${avg >= APPROVAL_THRESHOLD ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                          {Math.round(avg)}%
                        </span>
                      </div>
                      <div>
                        <p className={`text-[12px] font-black uppercase tracking-tight ${isActive ? 'text-slate-900' : 'text-slate-500'}`}>{group.name}</p>
                        <div className="mt-2 h-1 bg-slate-100 rounded-full overflow-hidden">
                           <div className={`h-full transition-all duration-700 ${avg >= APPROVAL_THRESHOLD ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${avg}%`}}/>
                        </div>
                      </div>
                    </button>
                  );
                })}
               </div>
            </div>
          </div>

          {/* Main Content Area (Sub-notes / Categories) */}
          <div className="flex-1 overflow-y-auto bg-white p-8 md:p-14 relative scroll-smooth">
            {showHistory ? (
              <div className="max-w-3xl mx-auto animate-in slide-in-from-right-4 duration-300">
                 <div className="mb-10">
                    <h3 className="text-2xl font-black text-slate-800 tracking-tighter uppercase italic flex items-center">
                       <History className="w-7 h-7 mr-4 text-red-600" /> Registro Histórico
                    </h3>
                    <div className="h-1 w-20 bg-red-600 mt-2" />
                 </div>

                 <div className="space-y-6 relative before:absolute before:left-4 before:top-4 before:bottom-4 before:w-1 before:bg-slate-100">
                    <div className="relative pl-12">
                       <div className="absolute left-0 top-1 w-8 h-8 bg-red-600 rounded-2xl flex items-center justify-center border-4 border-white shadow-lg z-10">
                          <div className="w-2 h-2 rounded-full bg-white" />
                       </div>
                       <p className="text-[10px] font-black text-red-600 uppercase tracking-widest mb-1">Punto de Venta Actual</p>
                       <div className="bg-slate-50 p-6 rounded-[32px] border-2 border-slate-100">
                          <p className="text-lg font-black text-slate-800 tracking-tight uppercase italic">{currentStore?.name || 'CECO SIN ASIGNAR'}</p>
                          <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mt-1">{employee.zone}</p>
                       </div>
                    </div>

                    {employee.history?.map((h, i) => (
                      <div key={i} className="relative pl-12">
                         <div className="absolute left-1 top-2 w-6 h-6 bg-slate-200 rounded-xl border-4 border-white z-10" />
                         <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{h.action} — {h.date}</p>
                         <div className="bg-white p-5 rounded-[28px] border border-slate-100 shadow-sm">
                            <p className="text-sm font-black text-slate-600 uppercase italic tracking-tight">{h.restaurantName}</p>
                         </div>
                      </div>
                    ))}
                 </div>
              </div>
            ) : (
              <div className="max-w-4xl mx-auto animate-in fade-in duration-300">
                <div className="mb-12 flex flex-col md:flex-row md:items-center justify-between gap-4">
                  <div>
                    <div className="flex items-center space-x-3 mb-2">
                       <div className="p-2 bg-slate-100 text-slate-600 rounded-lg">{GroupIcons[activeGroup]}</div>
                       <h3 className="text-2xl font-black text-slate-800 tracking-tighter uppercase italic">{(EVALUATION_GROUPS as any)[activeGroup].name}</h3>
                    </div>
                    <p className="text-sm text-slate-400 font-bold uppercase tracking-widest ml-12">Sub-notas y criterios de evaluación técnica</p>
                  </div>
                  <div className="bg-slate-50 px-6 py-4 rounded-3xl border border-slate-100 flex items-center space-x-4">
                     <TrendingUp className="w-5 h-5 text-red-600" />
                     <div>
                        <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">Promedio Sección</p>
                        <p className="text-xl font-black text-slate-800 tabular-nums">
                          {Math.round(formGrades.filter(g => g.group === activeGroup).reduce((s, g) => s + g.score, 0) / (EVALUATION_GROUPS as any)[activeGroup].categories.length)}%
                        </p>
                     </div>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-1 gap-6">
                  {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                    const score = getScore(activeGroup, cat);
                    return (
                      <div key={cat} className="group bg-slate-50/50 hover:bg-white border-2 border-slate-100 hover:border-red-500 rounded-[32px] p-6 md:p-8 transition-all hover:shadow-2xl hover:shadow-red-500/10 flex flex-col md:flex-row items-center gap-8">
                        <div className="flex-1 w-full space-y-4">
                          <div className="flex justify-between items-center">
                            <label className="text-[12px] font-black text-slate-800 uppercase tracking-widest">{cat}</label>
                            <span className={`text-[9px] font-black px-3 py-1 rounded-full border ${score >= APPROVAL_THRESHOLD ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-red-50 text-red-600 border-red-100'}`}>
                              {score >= APPROVAL_THRESHOLD ? '✓ ACEPTABLE' : '✗ REFUERZO NECESARIO'}
                            </span>
                          </div>
                          <div className="space-y-3">
                            <div className="h-3 bg-white rounded-full overflow-hidden shadow-inner border border-slate-200">
                              <div className={`h-full transition-all duration-700 ease-out ${score >= APPROVAL_THRESHOLD ? 'bg-emerald-500' : 'bg-red-600'}`} style={{width: `${score}%`}} />
                            </div>
                            <div className="flex justify-between px-1">
                               <div className="flex gap-1">
                                  {[20, 40, 60, 80, 100].map(mark => (
                                    <div key={mark} className={`h-1.5 w-6 rounded-full ${score >= mark ? (score >= 90 ? 'bg-emerald-200' : 'bg-red-200') : 'bg-slate-200'}`} />
                                  ))}
                               </div>
                               <span className="text-[9px] font-black text-slate-300 uppercase">Target: 90%</span>
                            </div>
                          </div>
                        </div>

                        <div className="shrink-0 relative">
                          <input 
                            type="number" 
                            min="0" 
                            max="100" 
                            value={score === 0 ? '' : score}
                            placeholder="0"
                            onChange={e => handleScoreChange(activeGroup, cat, e.target.value)} 
                            onFocus={e => e.target.select()} 
                            className={`w-24 md:w-32 px-4 py-6 bg-white border-4 rounded-[32px] text-3xl font-black text-slate-900 text-center outline-none transition-all shadow-sm ${score >= APPROVAL_THRESHOLD ? 'border-emerald-200 focus:border-emerald-500' : 'border-slate-200 focus:border-red-600'}`} 
                          />
                          <span className="absolute -bottom-3 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-3 py-1 text-[10px] font-black rounded-full shadow-lg ring-4 ring-white">%</span>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}
            <div className="h-20" />
          </div>
        </div>

        {/* Action Footer */}
        <div className="p-6 md:p-10 border-t border-slate-100 bg-slate-50 flex flex-col md:flex-row justify-between items-center gap-6 shrink-0">
          <div className="hidden md:flex items-center space-x-3 text-slate-400">
             <Info className="w-5 h-5" />
             <p className="text-[10px] font-bold uppercase tracking-widest">Los cambios se guardarán permanentemente en la base de datos central</p>
          </div>

          <div className="flex w-full md:w-auto gap-4">
            <button 
              onClick={onClose} 
              className="flex-1 md:flex-none px-8 py-5 font-black text-slate-400 text-[11px] uppercase tracking-[0.2em] hover:text-slate-800 transition"
            >
              Cancelar
            </button>
            <button 
              onClick={saveGrades} 
              className="flex-1 md:flex-none px-12 py-5 bg-red-600 text-white font-black rounded-3xl shadow-2xl shadow-red-500/20 hover:bg-red-700 transition-all active:scale-95 text-[11px] uppercase tracking-[0.2em] flex items-center justify-center ring-8 ring-white"
            >
              <Save className="w-5 h-5 mr-3" /> Registrar Notas
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

