import React, { useState, useEffect } from 'react';
import { Employee, GradeEntry, JobTitle } from '../types';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { dataService } from '../dataService';
// Added missing TrendingUp and Info imports
import { X, Save, User, Calendar, MapPin, Briefcase, History, ChevronRight, GraduationCap, Star, Trophy, ClipboardCheck, Vault, Layers, TrendingUp, Info } from 'lucide-react';

interface GradeEditorProps {
  employee: Employee;
  month: string;
  onClose: () => void;
}

const GroupIcons: Record<string, React.ReactNode> = {
  'A': <GraduationCap className="w-5 h-5" />,
  'B': <Star className="w-5 h-5" />,
