                     <h3 className="text-lg md:text-xl font-black text-slate-800 tracking-tight uppercase italic">{(EVALUATION_GROUPS as any)[activeGroup].name}</h3>
                  </div>
                  <div className="bg-slate-900 px-4 py-2 rounded-xl text-white flex items-center space-x-3 w-fit">
                     <TrendingUp className="w-3.5 h-3.5 text-red-500" />
                     <p className="text-[9px] font-black uppercase tracking-widest">Promedio: <span className="text-red-500 ml-1">{Math.round(formGrades.filter(g => g.group === activeGroup).reduce((s, g) => s + g.score, 0) / (EVALUATION_GROUPS as any)[activeGroup].categories.length)}%</span></p>
                  </div>
                </div>

                <div className="space-y-3">
                  {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                    const score = getScore(activeGroup, cat);
                    return (
                      <div key={cat} className="group bg-slate-50/40 hover:bg-white border-2 border-slate-100 hover:border-red-400 rounded-2xl p-4 md:p-5 transition-all flex flex-col sm:flex-row items-center gap-4 md:gap-8">
                        <div className="flex-1 w-full">
                          <div className="flex justify-between items-center mb-2">
                            <label className="text-[10px] md:text-[11px] font-black text-slate-600 uppercase tracking-wide truncate">{cat}</label>
                            <span className={`text-[8px] font-black px-2 py-0.5 rounded border ${score >= APPROVAL_THRESHOLD ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-red-50 text-red-600 border-red-100'}`}>
                              {score >= APPROVAL_THRESHOLD ? 'ACEPTADO' : 'REFUERZO'}
                            </span>
                          </div>
                          <div className="h-2 bg-slate-100 rounded-full overflow-hidden border border-slate-200/50">
                            <div className={`h-full transition-all duration-700 ${score >= APPROVAL_THRESHOLD ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${score}%`}} />
                          </div>
                        </div>

                        <div className="shrink-0 flex items-center space-x-2">
                          <div className="relative">
                            <input 
                              type="number" 
                              min="0" 
                              max="100" 
                              value={score === 0 ? '' : score}
                              placeholder="0"
                              onChange={e => handleScoreChange(activeGroup, cat, e.target.value)} 
                              onFocus={e => e.target.select()} 
                              className={`w-16 md:w-20 px-2 py-3 md:py-4 bg-white border-2 rounded-xl text-lg md:text-xl font-black text-slate-900 text-center outline-none transition-all ${score >= APPROVAL_THRESHOLD ? 'border-emerald-200 focus:border-emerald-500' : 'border-slate-200 focus:border-red-500'}`} 
                            />
                            <span className="absolute -right-2 -top-1 bg-slate-800 text-white text-[7px] font-black px-1 rounded-sm shadow">%</span>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}
            <div className="h-10 md:h-20" />
          </div>
        </div>

        {/* Action Footer - Slimmer */}
        <div className="p-4 md:p-6 border-t border-slate-100 bg-slate-50 flex flex-col md:flex-row justify-between items-center gap-4 shrink-0">
          <div className="hidden md:flex items-center space-x-2 text-slate-400">
             <Info className="w-4 h-4" />
             <p className="text-[9px] font-bold uppercase tracking-widest">Guardado persistente en base de datos central</p>
          </div>

          <div className="flex w-full md:w-auto gap-3">
            <button 
              onClick={onClose} 
              className="flex-1 md:flex-none px-6 py-3 font-black text-slate-400 text-[10px] uppercase tracking-widest hover:text-slate-600 transition"
            >
              Cancelar
            </button>
            <button 
              onClick={saveGrades} 
              className="flex-1 md:flex-none px-8 py-3.5 bg-red-600 text-white font-black rounded-xl shadow-lg shadow-red-500/10 hover:bg-red-700 transition-all active:scale-95 text-[10px] uppercase tracking-widest flex items-center justify-center"
            >
              <Save className="w-4 h-4 mr-2" /> Registrar
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

