  const monthStats = useMemo(() => {
    const entries = historyEvents.filter(e => e.month === selectedMonth && e.action === 'INGRESO').length;
    const exits = historyEvents.filter(e => e.month === selectedMonth && e.action === 'RETIRO').length;
    return { entries, exits };
