  const selectStyle = "w-full pl-10 pr-10 py-3 bg-white border-2 border-slate-200 rounded-2xl text-[12px] font-black text-slate-800 outline-none appearance-none cursor-pointer shadow-sm hover:border-red-400 focus:border-red-500 transition-all uppercase tracking-tighter";

  return (
