                    <div className="space-y-3 pl-3 md:pl-4">
                      {region.zones.map((zone, zIdx) => (
                        <div key={zIdx} className="bg-slate-50 border border-slate-100 rounded-2xl p-4">
                           <h5 className="text-[10px] md:text-[11px] font-black text-slate-600 uppercase mb-3">{zone.name}</h5>
                           <div className="flex flex-wrap gap-2">
                             {zone.restaurantIds.map(id => (
                               <div key={id} className="px-2 py-1 bg-white border border-slate-200 rounded-lg text-[8px] md:text-[9px] font-black text-slate-500 uppercase">{id}</div>
                             ))}
                           </div>
                        </div>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {activeSubTab === 'users' && (
          <div className="p-6 md:p-10 border-2 border-slate-50 rounded-[32px] md:rounded-[40px] bg-slate-50/30 animate-in fade-in duration-300">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-8 gap-4">
              <h3 className="text-lg font-black text-slate-800 flex items-center tracking-tight">
                <UserPlus className="w-5 h-5 mr-3 text-red-600" /> Control de Accesos
              </h3>
              <button 
                onClick={() => { setEditingUserId(null); setNewUserData({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [] }); setShowUserModal(true); }} 
                className="w-full sm:w-auto px-6 py-3.5 bg-red-600 text-white text-[10px] font-black rounded-2xl hover:bg-red-700 transition shadow-xl shadow-red-100 uppercase tracking-widest"
              >
                + Crear Acceso
              </button>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 md:gap-6">
              {dataService.getUsers().map(u => (
                <div key={u.id} className="bg-white p-5 md:p-6 rounded-2xl md:rounded-3xl border border-slate-100 flex items-center justify-between shadow-sm group hover:border-red-100 transition-all">
                  <div className="flex items-center space-x-3 md:space-x-4 min-w-0">
                    <div className="w-10 h-10 md:w-12 md:h-12 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 shrink-0">
                      <Lock className="w-5 h-5 md:w-6 md:h-6" />
                    </div>
                    <div className="min-w-0">
                      <p className="text-sm font-black text-slate-800 leading-none truncate">{u.username}</p>
                      <p className="text-[9px] text-slate-400 font-black uppercase tracking-widest mt-2">
                        {u.role === UserRole.ADMIN ? 'SUPERADMIN' : 'ESPECIALISTA'} • {u.assignedZones.length} Zonas
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center space-x-1 shrink-0">
                    <button onClick={() => { setEditingUserId(u.id); setNewUserData({ username: u.username, password: '', role: u.role, assignedZones: u.assignedZones }); setShowUserModal(true); }} className="p-2 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-lg transition"><Edit2 className="w-4 h-4" /></button>
                    {u.id !== 'admin1' && <button onClick={() => deleteUser(u.id)} className="p-2 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-lg transition"><Trash2 className="w-4 h-4" /></button>}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {showUserModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/95 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[32px] md:rounded-[40px] shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-6 md:p-8 bg-slate-900 text-white flex justify-between items-center">
              <h2 className="text-xl font-black tracking-tighter uppercase italic">{editingUserId ? 'Actualizar Usuario' : 'Nuevo Usuario'}</h2>
              <button onClick={() => setShowUserModal(false)}><X className="w-6 h-6"/></button>
            </div>
            <div className="p-6 md:p-10 space-y-6">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <input type="text" placeholder="Usuario" value={newUserData.username} onChange={e => setNewUserData({...newUserData, username: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl font-bold text-sm outline-none focus:border-red-500" />
                <input type="password" placeholder="Password" value={newUserData.password} onChange={e => setNewUserData({...newUserData, password: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl font-bold text-sm outline-none focus:border-red-500" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Áreas Asignadas</label>
                <div className="bg-slate-50 border-2 border-slate-200 rounded-xl p-1 overflow-hidden">
                  <select multiple value={newUserData.assignedZones} onChange={e => setNewUserData({...newUserData, assignedZones: Array.from(e.target.selectedOptions, option => option.value)})} className="w-full px-3 py-2 bg-transparent font-bold text-slate-800 h-36 outline-none">
                    {availableZones.map(z => <option key={z} value={z} className="py-2 px-2 hover:bg-red-50 rounded-lg mb-1 cursor-pointer font-black text-[10px] uppercase">{z}</option>)}
                  </select>
                </div>
              </div>
            </div>
            <div className="p-6 bg-slate-50 flex justify-end gap-3 border-t border-slate-100">
              <button onClick={() => setShowUserModal(false)} className="px-6 py-3 font-black text-slate-400 text-[10px] uppercase tracking-widest">Cancelar</button>
              <button onClick={handleSaveUser} className="px-10 py-3.5 bg-red-600 text-white font-black rounded-2xl shadow-xl shadow-red-100 uppercase tracking-widest text-[10px]">Guardar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useMemo, useState, useEffect } from 'react';
import { User, Restaurant, Employee, UserRole, JobHierarchy } from '../types';
import { Store, MapPin, Users, Award, ChevronRight, ArrowLeft, User as UserIcon, Edit3, TrendingUp, BarChart as ChartIcon, Filter, Search, ChevronDown } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import GradeEditor from './GradeEditor';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
  onUpdate: () => void;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth, onUpdate }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [searchStore, setSearchStore] = useState('');

  useEffect(() => {
    setFilterZone('all');
  }, [filterRegion]);

  const assigned = useMemo(() => {
    let base = user.role === UserRole.ADMIN 
      ? restaurants 
      : restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));

    return base.filter(r => {
      const matchRegion = filterRegion === 'all' || r.region === filterRegion;
      const matchZone = filterZone === 'all' || r.zone === filterZone;
      const matchSearch = searchStore === '' || r.name.toLowerCase().includes(searchStore.toLowerCase()) || r.id.toLowerCase().includes(searchStore.toLowerCase());
      return matchRegion && matchZone && matchSearch;
    });
  }, [user, restaurants, filterRegion, filterZone, searchStore]);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    return Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
  }, [restaurants, filterRegion]);

  const allGrades = useMemo(() => dataService.getGrades(), [selectedMonth, editingEmployee]);
  const currentGrades = useMemo(() => allGrades.filter(g => g.month === selectedMonth), [allGrades, selectedMonth]);

  const getStoreStats = (storeId: string, month: string) => {
    const monthGrades = allGrades.filter(g => g.month === month);
    const storeEmpsAtMonth = employees.filter(e => e.restaurantId === storeId);
    if (storeEmpsAtMonth.length === 0) return { total: 0, approved: 0, percent: 0 };
    let approved = 0;
    storeEmpsAtMonth.forEach(emp => {
      const empGrades = monthGrades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        const sum = empGrades.reduce((sum, g) => sum + g.score, 0);
        const avg = sum / TOTAL_CATEGORIES_COUNT;
        if (avg >= APPROVAL_THRESHOLD) approved++;
      }
    });
    return { total: storeEmpsAtMonth.length, approved, percent: Math.round((approved / storeEmpsAtMonth.length) * 100) };
  };

  const storeHistoryData = useMemo(() => {
    if (!selectedStore) return [];
    const months = Array.from(new Set(allGrades.map(g => g.month))).sort() as string[];
    return months.map((m: string) => ({ month: m, percent: getStoreStats(selectedStore.id, m).percent })).slice(-6);
  }, [selectedStore, allGrades, employees]);

  const selectStyle = "w-full pl-10 pr-10 py-3 bg-white border-2 border-slate-100 rounded-xl text-[11px] font-black text-slate-800 outline-none appearance-none cursor-pointer hover:border-red-400 transition-all uppercase tracking-tighter";

  if (selectedStore) {
    const stats = getStoreStats(selectedStore.id, selectedMonth);
    const storeEmps = employees
      .filter(e => e.restaurantId === selectedStore.id && (user.role === UserRole.ADMIN ? true : e.active))
      .sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));

    return (
      <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
        <div className="flex items-center space-x-4">
          <button onClick={() => setSelectedStore(null)} className="p-3 bg-white border-2 border-slate-100 rounded-2xl text-slate-400 hover:text-red-600 transition-all shadow-sm"><ArrowLeft className="w-5 h-5" /></button>
          <div>
            <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tighter uppercase italic">{selectedStore.name}</h2>
            <p className="text-slate-400 text-[9px] font-black uppercase tracking-widest flex items-center mt-1"><MapPin className="w-3 h-3 mr-1.5" /> {selectedStore.zone}</p>
          </div>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <DetailStatCard icon={<Users className="w-5 h-5" />} label="Equipo" value={stats.total} color="blue" />
          <DetailStatCard icon={<Award className="w-5 h-5" />} label="Certificados" value={stats.approved} color="green" />
          <DetailStatCard icon={<TrendingUp className="w-5 h-5" />} label="Progreso" value={`${stats.percent}%`} color="red" />
          <div className="bg-white p-5 rounded-[24px] border border-slate-100 shadow-sm flex flex-col justify-center h-24 overflow-hidden">
             <div className="h-full">
               <ResponsiveContainer width="100%" height="100%">
                 <BarChart data={storeHistoryData}><Bar dataKey="percent" radius={[4, 4, 0, 0]}>{storeHistoryData.map((e, i) => <Cell key={i} fill={e.percent >= 90 ? '#10b981' : '#ef4444'} fillOpacity={0.8}/>)}</Bar></BarChart>
               </ResponsiveContainer>
             </div>
          </div>
        </div>
        <div className="bg-white rounded-[32px] shadow-sm border border-slate-100 overflow-hidden">
          <div className="p-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/20">
            <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">Colaboradores</h3>
          </div>
          <div className="md:hidden space-y-3 p-4">
            {storeEmps.map(emp => {
               const empGrades = currentGrades.filter(g => g.employeeId === emp.id);
               const avg = empGrades.length > 0 ? empGrades.reduce((s, g) => s + g.score, 0) / TOTAL_CATEGORIES_COUNT : 0;
               return (
                 <div key={emp.id} className="p-4 bg-white border border-slate-200 rounded-[20px] space-y-4">
                   <div className="flex items-center space-x-3">
                     <div className="w-10 h-10 bg-slate-100 rounded-lg flex items-center justify-center"><UserIcon className="w-5 h-5 text-slate-400" /></div>
                     <div className="min-w-0">
                       <p className="font-black text-slate-800 text-sm truncate uppercase tracking-tighter">{emp.name}</p>
                       <p className="text-[9px] font-bold text-slate-400 uppercase">{emp.title}</p>
                     </div>
                   </div>
                   <div className="flex items-center justify-between gap-4">
                     <div className="flex-1 h-2 bg-slate-100 rounded-full overflow-hidden">
                       <div className={`h-full ${avg >= APPROVAL_THRESHOLD ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${avg}%`}} />
                     </div>
                     <span className={`text-xs font-black ${avg >= APPROVAL_THRESHOLD ? 'text-emerald-600' : 'text-red-600'}`}>{Math.round(avg)}%</span>
                   </div>
                   <button onClick={() => setEditingEmployee(emp)} className="w-full py-3 bg-slate-900 text-white text-[9px] font-black rounded-xl uppercase tracking-[0.2em] active:scale-95 transition-all">Editar Notas</button>
                 </div>
               );
            })}
          </div>
          <div className="hidden md:block overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50">
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Progreso</th>
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {storeEmps.map(emp => {
                  const empGrades = currentGrades.filter(g => g.employeeId === emp.id);
                  const avg = empGrades.length > 0 ? empGrades.reduce((s, g) => s + g.score, 0) / TOTAL_CATEGORIES_COUNT : 0;
                  return (
                    <tr key={emp.id} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-8 py-4"><p className="font-black text-slate-800 text-sm">{emp.name}</p><p className="text-[9px] text-slate-400 font-black uppercase">{emp.title}</p></td>
                      <td className="px-8 py-4"><div className="flex items-center space-x-3"><div className="w-32 h-2 bg-slate-100 rounded-full overflow-hidden"><div className={`h-full ${avg >= APPROVAL_THRESHOLD ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${avg}%`}} /></div><span className={`text-[10px] font-black ${avg >= APPROVAL_THRESHOLD ? 'text-emerald-600' : 'text-red-600'}`}>{Math.round(avg)}%</span></div></td>
                      <td className="px-8 py-4 text-center"><button onClick={() => setEditingEmployee(emp)} className="px-6 py-2 bg-slate-900 text-white text-[9px] font-black rounded-xl hover:bg-red-600 transition-all uppercase tracking-widest">Editar</button></td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
        {editingEmployee && <GradeEditor employee={editingEmployee} month={selectedMonth} onClose={() => { setEditingEmployee(null); onUpdate(); }} />}
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm flex flex-col gap-6">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
          <div>
            <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tighter uppercase italic">Mis Tiendas</h2>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Supervisión y gestión técnica</p>
          </div>
          <div className="bg-slate-900 px-5 py-2.5 rounded-xl text-white flex items-center space-x-3 w-fit shrink-0">
            <Store className="w-4 h-4 text-red-500" /><span className="text-[11px] font-black uppercase tracking-widest">{assigned.length} Activas</span>
          </div>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="relative">
            <MapPin className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
            <select className={selectStyle} value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)}>
              <option value="all">Region: Todas</option>
              {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
            </select>
            <ChevronDown className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
          </div>
          <div className="relative">
            <Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
