import React, { useState, useMemo, useEffect } from 'react';
import { Employee, Restaurant, JobHierarchy, User, UserRole } from '../types';
import { Search, ChevronRight, Edit3, Filter, Users, ShieldOff, MapPin, ChevronDown, User as UserIcon } from 'lucide-react';
import GradeEditor from './GradeEditor';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { dataService } from '../dataService';

interface EmployeeListProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
  onUpdate: () => void;
}

const EmployeeList: React.FC<EmployeeListProps> = ({ employees, restaurants, selectedMonth, user, onUpdate }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [filterStore, setFilterStore] = useState('all');
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  useEffect(() => {
    setFilterZone('all');
    setFilterStore('all');
  }, [filterRegion]);

  useEffect(() => {
    setFilterStore('all');
  }, [filterZone]);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    let zones = Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) zones = zones.filter(z => user.assignedZones.includes(z));
    return zones;
  }, [restaurants, filterRegion, user]);

  const dynamicStores = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    if (filterZone !== 'all') base = base.filter(r => r.zone === filterZone);
    if (user.role === UserRole.SPECIALIST) base = base.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));
    return base.sort((a, b) => a.name.localeCompare(b.name));
  }, [restaurants, filterRegion, filterZone, user]);

  const filteredAndSorted = useMemo(() => {
    let result = employees.filter(e => {
      if (user.role === UserRole.SPECIALIST && !e.active) return false;
      const store = restaurants.find(r => r.id === e.restaurantId);
      const matchSearch = searchTerm === '' || e.name.toLowerCase().includes(searchTerm.toLowerCase()) || e.id.includes(searchTerm);
      const matchRegion = filterRegion === 'all' || store?.region === filterRegion;
      const matchZone = filterZone === 'all' || e.zone === filterZone;
      const matchStore = filterStore === 'all' || e.restaurantId === filterStore;
      return matchSearch && matchRegion && matchZone && matchStore;
    });
    return result.sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));
  }, [employees, searchTerm, filterRegion, filterZone, filterStore, user, restaurants]);

  const allGrades = useMemo(() => dataService.getGrades().filter(g => g.month === selectedMonth), [selectedMonth, editingEmployee]);

  const getStatus = (employeeId: string) => {
    const grades = allGrades.filter(g => g.employeeId === employeeId);
    if (grades.length === 0) return 'PENDING';
    const sum = grades.reduce((s, g) => s + g.score, 0);
    const avg = sum / TOTAL_CATEGORIES_COUNT;
    return avg >= APPROVAL_THRESHOLD ? 'APPROVED' : 'FAILED';
  };

  const selectStyle = "w-full pl-10 pr-10 py-3 bg-white border-2 border-slate-100 rounded-2xl text-[10px] font-black text-slate-800 outline-none appearance-none cursor-pointer hover:border-red-400 transition-all uppercase tracking-tighter shadow-sm";

  return (
    <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
      <div className="p-6 md:p-8 border-b border-slate-50 flex flex-col space-y-6">
        <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
          <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tight flex items-center uppercase italic shrink-0"><Users className="w-5 h-5 mr-3 text-red-600" /> Personal KFC</h2>
          <div className="relative flex-1 max-w-lg">
            <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <input type="text" placeholder="Buscar personal..." className="w-full pl-12 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-xs font-black text-slate-900 focus:bg-white focus:border-red-500 outline-none transition-all uppercase placeholder:text-slate-300" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
          </div>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
          <div className="relative"><MapPin className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" /><select className={selectStyle} value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)}><option value="all">Region: Todas</option>{dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}</select><ChevronDown className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" /></div>
          <div className="relative"><Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" /><select className={selectStyle} value={filterZone} onChange={(e) => setFilterZone(e.target.value)}><option value="all">Zona: Todas</option>{dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}</select><ChevronDown className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" /></div>
          <div className="relative"><Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" /><select className={selectStyle} value={filterStore} onChange={(e) => setFilterStore(e.target.value)}><option value="all">Tienda: Todas</option>{dynamicStores.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}</select><ChevronDown className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" /></div>
        </div>
      </div>

      <div className="md:hidden p-4 space-y-4">
        {filteredAndSorted.map(emp => {
          const status = getStatus(emp.id);
          const store = restaurants.find(r => r.id === emp.restaurantId);
          return (
            <div key={emp.id} className="p-5 bg-white border border-slate-200 rounded-[24px] space-y-4 shadow-sm">
              <div className="flex justify-between items-start">
                <div className="flex items-center space-x-3">
                  <div className="w-10 h-10 bg-slate-50 rounded-xl flex items-center justify-center text-slate-300"><UserIcon className="w-6 h-6" /></div>
                  <div className="min-w-0">
                    <p className="font-black text-slate-800 text-sm truncate uppercase tracking-tight">{emp.name}</p>
                    <p className="text-[9px] font-bold text-slate-400 uppercase">{emp.title} • {store?.name || emp.restaurantId}</p>
                  </div>
                </div>
                <div className="shrink-0">
                  {status === 'APPROVED' && <span className="text-[8px] font-black text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full">CERTIFICADO</span>}
                  {status === 'FAILED' && <span className="text-[8px] font-black text-red-600 bg-red-50 px-2 py-0.5 rounded-full">FALLIDO</span>}
                  {status === 'PENDING' && <span className="text-[8px] font-black text-slate-400 bg-slate-50 px-2 py-0.5 rounded-full">PENDIENTE</span>}
                </div>
              </div>
              <button onClick={() => setEditingEmployee(emp)} className="w-full py-3 bg-slate-900 text-white text-[10px] font-black rounded-xl uppercase tracking-widest shadow-md">Editar Notas</button>
            </div>
          );
        })}
      </div>

      <div className="hidden md:block overflow-x-auto">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50/50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Tienda</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Certificación</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {filteredAndSorted.map(emp => {
              const status = getStatus(emp.id);
              return (
                <tr key={emp.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-8 py-4"><p className="font-black text-slate-800 text-sm">{emp.name}</p><p className="text-[9px] text-slate-400 font-black uppercase tracking-widest">{emp.title}</p></td>
                  <td className="px-8 py-4 text-xs font-black text-slate-600 uppercase">{restaurants.find(r => r.id === emp.restaurantId)?.name}</td>
                  <td className="px-8 py-4">
                    <span className={`px-3 py-1 text-[9px] font-black uppercase rounded-full ${status === 'APPROVED' ? 'bg-emerald-50 text-emerald-600' : status === 'FAILED' ? 'bg-red-50 text-red-600' : 'bg-slate-50 text-slate-400'}`}>
                      {status === 'APPROVED' ? 'Aprobado' : status === 'FAILED' ? 'Reprobado' : 'Pendiente'}
                    </span>
                  </td>
                  <td className="px-8 py-4 text-center"><button onClick={() => setEditingEmployee(emp)} className="p-3 text-slate-300 hover:text-red-600 transition-all"><Edit3 className="w-5 h-5" /></button></td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
      {editingEmployee && <GradeEditor employee={editingEmployee} month={selectedMonth} onClose={() => { setEditingEmployee(null); onUpdate(); }} />}
    </div>
  );
};

export default EmployeeList;

import React, { useState, useMemo, useEffect } from 'react';
import { Upload, UserPlus, Search, X, Check, ChevronDown, Lock, Shield, FileSpreadsheet, Download, Edit2, Trash2, AlertCircle, Network, MapPin, Layers, Plus, Trash } from 'lucide-react';
import { dataService } from '../dataService';
import { UserRole, User, HierarchyData } from '../types';
import * as XLSX from 'xlsx';

interface AdminPanelProps {
  onEmployeesImported: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onEmployeesImported }) => {
  const [activeSubTab, setActiveSubTab] = useState<'import' | 'users' | 'hierarchy'>('import');
  const [importStatus, setImportStatus] = useState<string | null>(null);
  const [importError, setImportError] = useState<string | null>(null);
  const [heladeriaWarning, setHeladeriaWarning] = useState<boolean>(false);
  const [isImporting, setIsImporting] = useState(false);

  const [showUserModal, setShowUserModal] = useState(false);
  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [newUserData, setNewUserData] = useState({
    username: '',
    password: '',
    role: UserRole.SPECIALIST,
    assignedZones: [] as string[],
  });

  const [hierarchy, setHierarchy] = useState<HierarchyData>(dataService.getHierarchy());
  const allRestaurants = useMemo(() => dataService.getRestaurants(), [activeSubTab, importStatus]);

  useEffect(() => {
    setHierarchy(dataService.getHierarchy());
  }, [activeSubTab, importStatus]);

  const availableZones = useMemo(() => {
    return Array.from(new Set(dataService.getRestaurants().map(r => r.zone))).filter(Boolean).sort();
  }, [showUserModal, isImporting, activeSubTab, importStatus]);

  const downloadEmployeesTemplate = () => {
    const headers = [["Documento", "Nombre completo", "Estado", "Fecha de ingreso", "Cargo", "Nombre_Ceco"]];
    const ws = XLSX.utils.aoa_to_sheet(headers);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Plantilla_Trabajadores");
    XLSX.writeFile(wb, "plantilla_akademia_trabajadores.xlsx");
  };

  const downloadHierarchyTemplate = () => {
    const headers = [["Nombre de tienda", "Jefe de area", "Region"]];
    const ws = XLSX.utils.aoa_to_sheet(headers);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Plantilla_Jerarquia");
    XLSX.writeFile(wb, "plantilla_akademia_jerarquia.xlsx");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'employees' | 'hierarchy') => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsImporting(true);
    setImportStatus('Procesando archivo...');
    setImportError(null);
    setHeladeriaWarning(false);

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws);

        if (data.length === 0) throw new Error("El archivo está vacío");

        if (type === 'employees') {
          const result = dataService.importMonthlyExcel(data);
          setImportStatus(`Carga exitosa: ${result.count} trabajadores procesados.`);
          if (result.heladeriasSkipped) setHeladeriaWarning(true);
        } else {
          const count = dataService.importHierarchyExcel(data);
          setImportStatus(`Carga exitosa: Jerarquía actualizada con ${count} tiendas.`);
        }

        setIsImporting(false);
        onEmployeesImported();
        setTimeout(() => setImportStatus(null), 8000);
      } catch (err: any) {
        setIsImporting(false);
        setImportStatus(null);
        setImportError(err.message || 'Error en el formato del archivo.');
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = '';
  };

  const handleSaveUser = () => {
    if (!newUserData.username) return;
    const users = dataService.getUsers();

    if (editingUserId) {
      const updatedUser: User = {
        id: editingUserId,
        username: newUserData.username,
        password: newUserData.password || '123',
        role: UserRole.SPECIALIST,
        assignedZones: newUserData.assignedZones,
        assignedRestaurants: []
      };
      dataService.updateUser(updatedUser);
    } else {
      const newUser: User = {
        id: `u-${Date.now()}`,
        username: newUserData.username,
        password: newUserData.password || '123',
        role: UserRole.SPECIALIST,
        assignedZones: newUserData.assignedZones,
        assignedRestaurants: []
      };
      localStorage.setItem('la_akademia_users', JSON.stringify([...users, newUser]));
    }

    setShowUserModal(false);
    setEditingUserId(null);
    setNewUserData({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [] });
    onEmployeesImported();
  };

  const deleteUser = (userId: string) => {
    if (userId === 'admin1') return;
    if (!confirm('¿Desea eliminar este usuario?')) return;
    const users = dataService.getUsers().filter(u => u.id !== userId);
    localStorage.setItem('la_akademia_users', JSON.stringify(users));
    onEmployeesImported(); 
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-10 rounded-3xl md:rounded-[40px] shadow-sm border border-slate-100">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
          <div className="flex items-center space-x-6">
            <div className="p-4 md:p-5 bg-red-600 text-white rounded-2xl md:rounded-[24px] shadow-xl shadow-red-100 hidden sm:block">
              <Shield className="w-8 h-8 md:w-10 md:h-10" />
            </div>
            <div className="min-w-0">
              <h2 className="text-xl md:text-3xl font-black text-slate-800 tracking-tighter truncate">Administración KFC</h2>
              <div className="flex gap-2 mt-3 overflow-x-auto no-scrollbar pb-1">
                {[
                  { id: 'import', label: 'Importación' },
                  { id: 'hierarchy', label: 'Jerarquía' },
                  { id: 'users', label: 'Usuarios' }
                ].map(tab => (
                  <button 
                    key={tab.id}
                    onClick={() => setActiveSubTab(tab.id as any)}
                    className={`whitespace-nowrap text-[9px] font-black uppercase tracking-widest px-4 py-2 rounded-full transition shrink-0 ${activeSubTab === tab.id ? 'bg-red-600 text-white shadow-md' : 'bg-slate-100 text-slate-400 hover:bg-slate-200'}`}
                  >
                    {tab.label}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        {activeSubTab === 'import' && (
          <div className="grid grid-cols-1 gap-6 md:gap-10 animate-in fade-in duration-300">
            <div className="p-6 md:p-10 border-2 border-slate-50 rounded-[32px] md:rounded-[40px] bg-slate-50/30 relative overflow-hidden">
               <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
                  <div>
                    <h3 className="text-lg font-black text-slate-800 flex items-center tracking-tight">
                      <FileSpreadsheet className="w-5 h-5 mr-3 text-red-600" /> Carga de Trabajadores
                    </h3>
                  </div>
                  <button onClick={downloadEmployeesTemplate} className="w-full md:w-auto flex items-center justify-center space-x-3 px-6 py-3.5 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-black transition shadow-lg uppercase tracking-widest">
                    <Download className="w-4 h-4" />
                    <span>Plantilla Trabajadores</span>
                  </button>
               </div>
               <label className="flex flex-col items-center justify-center w-full h-44 md:h-56 border-4 border-slate-200 border-dashed rounded-[32px] md:rounded-[40px] cursor-pointer bg-white hover:border-red-400 hover:bg-red-50/10 transition-all group mb-8">
                <Upload className="w-12 h-12 md:w-16 md:h-16 text-slate-200 group-hover:text-red-600 mb-4" />
                <span className="text-[10px] md:text-[11px] font-black text-slate-400 uppercase tracking-widest group-hover:text-red-700 text-center px-4">Subir Base de Personal (.xlsx)</span>
                <input type="file" className="hidden" accept=".xlsx" onChange={(e) => handleFileUpload(e, 'employees')} />
               </label>
               <div className="space-y-4">
                {importStatus && <div className="p-4 rounded-2xl border-2 flex items-center justify-center bg-emerald-50 border-emerald-100 text-emerald-600 text-[10px] font-black uppercase tracking-widest">{importStatus}</div>}
                {importError && <div className="p-4 rounded-2xl border-2 flex items-center bg-red-50 border-red-100 text-red-600 text-[10px] font-black uppercase tracking-widest">{importError}</div>}
              </div>
            </div>
          </div>
        )}

        {activeSubTab === 'hierarchy' && (
          <div className="space-y-10 animate-in fade-in duration-300">
            <div className="p-6 md:p-10 border-2 border-slate-50 rounded-[32px] md:rounded-[40px] bg-slate-50/30">
               <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
                  <h3 className="text-lg font-black text-slate-800 flex items-center tracking-tight">
                    <Network className="w-5 h-5 mr-3 text-red-600" /> Sincronización de Jerarquía
                  </h3>
                  <button onClick={downloadHierarchyTemplate} className="w-full md:w-auto flex items-center justify-center space-x-3 px-6 py-3.5 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-black transition shadow-lg uppercase tracking-widest">
                    <Download className="w-4 h-4" />
                    <span>Plantilla Jerarquía</span>
                  </button>
               </div>
               <label className="flex flex-col items-center justify-center w-full h-36 md:h-44 border-4 border-slate-200 border-dashed rounded-[32px] md:rounded-[40px] cursor-pointer bg-white hover:border-red-400 hover:bg-red-50/10 transition-all group">
                <Upload className="w-10 h-10 md:w-12 md:h-12 text-slate-200 group-hover:text-red-600 mb-3" />
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest group-hover:text-red-700 text-center px-4">Subir Jerarquía de Tiendas (.xlsx)</span>
                <input type="file" className="hidden" accept=".xlsx" onChange={(e) => handleFileUpload(e, 'hierarchy')} />
               </label>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-6">
                <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2">Vista Estructural</h4>
