      {showUserModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/95 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[32px] md:rounded-[40px] shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-6 md:p-8 bg-slate-900 text-white flex justify-between items-center">
              <h2 className="text-xl font-black tracking-tighter uppercase italic">{editingUserId ? 'Actualizar Usuario' : 'Nuevo Usuario'}</h2>
              <button onClick={() => setShowUserModal(false)}><X className="w-6 h-6"/></button>
            </div>
            <div className="p-6 md:p-10 space-y-6">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <input type="text" placeholder="Usuario" value={newUserData.username} onChange={e => setNewUserData({...newUserData, username: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl font-bold text-sm outline-none focus:border-red-500" />
                <input type="password" placeholder="Password" value={newUserData.password} onChange={e => setNewUserData({...newUserData, password: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl font-bold text-sm outline-none focus:border-red-500" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Áreas Asignadas</label>
                <div className="bg-slate-50 border-2 border-slate-200 rounded-xl p-1 overflow-hidden">
                  {/* Added explicit type casting to HTMLOptionElement for option.value */}
                  <select multiple value={newUserData.assignedZones} onChange={e => setNewUserData({...newUserData, assignedZones: Array.from(e.target.selectedOptions, (option: any) => option.value)})} className="w-full px-3 py-2 bg-transparent font-bold text-slate-800 h-36 outline-none">
                    {availableZones.map(z => <option key={z} value={z} className="py-2 px-2 hover:bg-red-50 rounded-lg mb-1 cursor-pointer font-black text-[10px] uppercase">{z}</option>)}
                  </select>
