            </div>
            <div className="p-6 bg-slate-50 flex justify-end gap-3 border-t border-slate-100">
              <button onClick={() => setShowUserModal(false)} className="px-6 py-3 font-black text-slate-400 text-[10px] uppercase tracking-widest">Cancelar</button>
