import React, { useMemo, useState, useEffect } from 'react';
import { Employee, Restaurant, JobTitle } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, Cell } from 'recharts';
import { ArrowUpCircle, ArrowDownCircle, Search, Filter, MapPin, Users, Calendar, ArrowRight, TrendingUp, ChevronDown, Briefcase } from 'lucide-react';

interface EntriesExitsReportProps {
  employees: Employee[];
  restaurants: Restaurant[];
}

const EntriesExitsReport: React.FC<EntriesExitsReportProps> = ({ employees, restaurants }) => {
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [filterStore, setFilterStore] = useState('all');

  const currentYear = new Date().getFullYear();
  const currentMonth = (new Date().getMonth() + 1).toString().padStart(2, '0');

  const [selectedYear, setSelectedYear] = useState<string>(currentYear.toString());
  const [selectedMonthPart, setSelectedMonthPart] = useState<string>(currentMonth);

  const [viewDetail, setViewDetail] = useState<'entries' | 'exits' | 'none'>('none');

  const selectedMonth = `${selectedYear}-${selectedMonthPart}`;

  useEffect(() => {
    setFilterZone('all');
    setFilterStore('all');
  }, [filterRegion]);

  useEffect(() => {
    setFilterStore('all');
  }, [filterZone]);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);

  const dynamicZones = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') {
      baseStores = baseStores.filter(r => r.region === filterRegion);
    }
    return Array.from(new Set(baseStores.map(r => r.zone))).filter(Boolean).sort();
  }, [restaurants, filterRegion]);

  const dynamicStores = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') {
      baseStores = baseStores.filter(r => r.region === filterRegion);
    }
    if (filterZone !== 'all') {
      baseStores = baseStores.filter(r => r.zone === filterZone);
    }
    return baseStores.sort((a, b) => a.name.localeCompare(b.name));
  }, [restaurants, filterRegion, filterZone]);

  const historyEvents = useMemo(() => {
    const events: any[] = [];
    employees.forEach(emp => {
      emp.history?.forEach(h => {
        if (h.action === 'INGRESO' || h.action === 'RETIRO') {
          const store = restaurants.find(r => r.id === h.restaurantName || r.name === h.restaurantName);
          const matchRegion = filterRegion === 'all' || store?.region === filterRegion;
          const matchZone = filterZone === 'all' || store?.zone === filterZone;
          const matchStore = filterStore === 'all' || store?.id === filterStore || store?.name === filterStore;

          if (matchRegion && matchZone && matchStore) {
            events.push({
              ...h,
              employeeName: emp.name,
              employeeId: emp.id,
              employeeTitle: emp.title,
              month: h.date.slice(0, 7),
              year: h.date.slice(0, 4)
            });
          }
        }
      });
    });
    return events;
  }, [employees, restaurants, filterRegion, filterZone, filterStore]);

  const monthStats = useMemo(() => {
    const entries = historyEvents.filter(e => e.month === selectedMonth && e.action === 'INGRESO').length;
    const exits = historyEvents.filter(e => e.month === selectedMonth && e.action === 'RETIRO').length;
    return { entries, exits };
  }, [historyEvents, selectedMonth]);

  const yearStats = useMemo(() => {
    const entries = historyEvents.filter(e => e.year === selectedYear && e.action === 'INGRESO').length;
    const exits = historyEvents.filter(e => e.year === selectedYear && e.action === 'RETIRO').length;
    return { entries, exits };
  }, [historyEvents, selectedYear]);

  const statsByCargo = useMemo(() => {
    const monthEvents = historyEvents.filter(e => e.month === selectedMonth);
    const cargoMap: Record<string, { cargo: string, ingresos: number, retiros: number }> = {};

    Object.values(JobTitle).forEach(title => {
      cargoMap[title] = { cargo: title, ingresos: 0, retiros: 0 };
    });

    monthEvents.forEach(e => {
      if (cargoMap[e.employeeTitle]) {
        if (e.action === 'INGRESO') cargoMap[e.employeeTitle].ingresos++;
        if (e.action === 'RETIRO') cargoMap[e.employeeTitle].retiros++;
      }
    });

    return Object.values(cargoMap).filter(c => c.ingresos > 0 || c.retiros > 0);
  }, [historyEvents, selectedMonth]);

  {/* Defined detailList memo to fix "Cannot find name 'detailList'" error */}
  const detailList = useMemo(() => {
    if (viewDetail === 'none') return [];
    const action = viewDetail === 'entries' ? 'INGRESO' : 'RETIRO';
    return historyEvents.filter(e => e.month === selectedMonth && e.action === action);
  }, [historyEvents, selectedMonth, viewDetail]);

  const chartData = [
    { name: 'Mensual', ingresos: monthStats.entries, retiros: monthStats.exits },
    { name: 'Anual', ingresos: yearStats.entries, retiros: yearStats.exits }
  ];

  const years = [currentYear.toString(), (currentYear - 1).toString(), (currentYear - 2).toString()];
  const monthsList = [
    { val: '01', label: 'Enero' }, { val: '02', label: 'Febrero' }, { val: '03', label: 'Marzo' },
    { val: '04', label: 'Abril' }, { val: '05', label: 'Mayo' }, { val: '06', label: 'Junio' },
    { val: '07', label: 'Julio' }, { val: '08', label: 'Agosto' }, { val: '09', label: 'Septiembre' },
    { val: '10', label: 'Octubre' }, { val: '11', label: 'Noviembre' }, { val: '12', label: 'Diciembre' }
  ];

  const selectStyle = "w-full pl-10 pr-10 py-3 bg-white border-2 border-slate-200 rounded-2xl text-[12px] font-black text-slate-800 outline-none appearance-none cursor-pointer shadow-sm hover:border-red-400 focus:border-red-500 transition-all uppercase tracking-tighter";

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-8 rounded-3xl shadow-sm border border-slate-100">
        <div className="flex flex-col gap-6 mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
            <div className="relative">
              <Calendar className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
              <select className={selectStyle} value={selectedYear} onChange={(e) => setSelectedYear(e.target.value)}>
                {years.map(y => <option key={y} value={y}>{y}</option>)}
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
            <div className="relative">
              <Calendar className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
              <select className={selectStyle} value={selectedMonthPart} onChange={(e) => setSelectedMonthPart(e.target.value)}>
                {monthsList.map(m => <option key={m.val} value={m.val}>{m.label}</option>)}
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
            <div className="relative">
              <MapPin className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
              <select className={selectStyle} value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)}>
                <option value="all">Todas las Regiones</option>
                {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
            <div className="relative">
              <Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
              <select className={selectStyle} value={filterZone} onChange={(e) => setFilterZone(e.target.value)}>
                <option value="all">Todas las Zonas</option>
                {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
            <div className="relative">
              <Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
              <select className={selectStyle} value={filterStore} onChange={(e) => setFilterStore(e.target.value)}>
                <option value="all">Todas las Tiendas</option>
                {dynamicStores.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <button 
              onClick={() => setViewDetail(viewDetail === 'entries' ? 'none' : 'entries')}
              className={`p-6 rounded-[32px] border-2 transition-all flex flex-col items-center text-center ${viewDetail === 'entries' ? 'bg-emerald-50 border-emerald-500 shadow-lg scale-105' : 'bg-slate-50 border-transparent hover:bg-emerald-50 shadow-sm'}`}
            >
              <ArrowUpCircle className={`w-8 h-8 mb-2 ${viewDetail === 'entries' ? 'text-emerald-600' : 'text-slate-400'}`} />
              <p className="text-[10px] font-black uppercase text-slate-400 mb-1">Ingresos</p>
              <p className="text-2xl font-black text-slate-800">{monthStats.entries}</p>
            </button>
            <button 
              onClick={() => setViewDetail(viewDetail === 'exits' ? 'none' : 'exits')}
              className={`p-6 rounded-[32px] border-2 transition-all flex flex-col items-center text-center ${viewDetail === 'exits' ? 'bg-red-50 border-red-500 shadow-lg scale-105' : 'bg-slate-50 border-transparent hover:bg-red-50 shadow-sm'}`}
            >
              <ArrowDownCircle className={`w-8 h-8 mb-2 ${viewDetail === 'exits' ? 'text-red-600' : 'text-slate-400'}`} />
              <p className="text-[10px] font-black uppercase text-slate-400 mb-1">Retiros</p>
              <p className="text-2xl font-black text-slate-800">{monthStats.exits}</p>
            </button>
          </div>
          <div className="bg-white p-6 rounded-[32px] border border-slate-100 flex flex-col shadow-sm min-h-[300px]">
             <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-6">Comparativa Temporal</h4>
             <div className="flex-1">
               <ResponsiveContainer width="100%" height="100%">
                 <BarChart data={chartData} margin={{ top: 20, right: 30, left: -20, bottom: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                    <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                    <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontWeight: '900', fontSize: '12px' }} />
                    <Bar name="Ingresos" dataKey="ingresos" fill="#10b981" radius={[8, 8, 0, 0]} barSize={40} />
                    <Bar name="Retiros" dataKey="retiros" fill="#ef4444" radius={[8, 8, 0, 0]} barSize={40} />
                 </BarChart>
               </ResponsiveContainer>
             </div>
          </div>
        </div>

        <div className="bg-slate-50/50 p-6 md:p-8 rounded-[40px] border border-slate-100">
           <div className="flex items-center space-x-3 mb-8">
              <div className="p-3 bg-red-600 text-white rounded-2xl shadow-lg">
                <Briefcase className="w-5 h-5" />
              </div>
              <div>
                <h4 className="text-lg font-black text-slate-800 tracking-tighter">Desglose por Cargo</h4>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Distribución del mes seleccionado</p>
              </div>
           </div>
           <div className="h-[300px] bg-white p-6 rounded-[32px] shadow-sm">
             <ResponsiveContainer width="100%" height="100%">
               <BarChart data={statsByCargo} margin={{ top: 20, right: 30, left: -20, bottom: 0 }}>
                 <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                 <XAxis dataKey="cargo" axisLine={false} tickLine={false} tick={{ fontSize: 9, fontWeight: 900, fill: '#64748b' }} />
                 <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                 <Tooltip cursor={{fill: '#f1f5f9'}} contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontWeight: '900', fontSize: '11px' }} />
                 <Bar name="Ingresos" dataKey="ingresos" fill="#10b981" radius={[8, 8, 0, 0]} barSize={30} />
                 <Bar name="Retiros" dataKey="retiros" fill="#ef4444" radius={[8, 8, 0, 0]} barSize={30} />
               </BarChart>
             </ResponsiveContainer>
           </div>
        </div>
      </div>

      {viewDetail !== 'none' && (
        <div className="bg-white rounded-[40px] shadow-2xl border border-slate-100 animate-in slide-in-from-top-4 duration-300 overflow-hidden">
          <div className="p-6 md:p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
            <h3 className="text-lg font-black text-slate-800 tracking-tight flex items-center">
               {viewDetail === 'entries' ? <ArrowUpCircle className="w-5 h-5 mr-3 text-emerald-500" /> : <ArrowDownCircle className="w-5 h-5 mr-3 text-red-500" />}
               Listado de {viewDetail === 'entries' ? 'Ingresos' : 'Retiros'}
            </h3>
            <button onClick={() => setViewDetail('none')} className="text-[9px] font-black text-slate-400 uppercase hover:text-red-600 transition-colors">Cerrar</button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  <th className="px-6 md:px-8 py-5">Fecha</th>
                  <th className="px-6 md:px-8 py-5">Colaborador</th>
                  <th className="px-6 md:px-8 py-5">Tienda</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {detailList.map((e, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/30 transition-colors">
                    <td className="px-6 md:px-8 py-4 text-xs font-black text-slate-500">{e.date}</td>
                    <td className="px-6 md:px-8 py-4 text-xs font-black text-slate-800 uppercase">{e.employeeName}</td>
                    <td className="px-6 md:px-8 py-4 text-xs font-black text-slate-600 uppercase">{e.restaurantName}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
};

