interface EntriesExitsReportProps {
  employees: Employee[];
  restaurants: Restaurant[];
}

const EntriesExitsReport: React.FC<EntriesExitsReportProps> = ({ employees, restaurants }) => {
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [filterStore, setFilterStore] = useState('all');

  const currentYear = new Date().getFullYear();
  const currentMonthNum = (new Date().getMonth() + 1).toString().padStart(2, '0');

  const [selectedYear, setSelectedYear] = useState<string>(currentYear.toString());
  const [selectedMonthPart, setSelectedMonthPart] = useState<string>(currentMonthNum);

  const [viewDetail, setViewDetail] = useState<'entries' | 'exits' | 'none'>('none');

  const selectedMonthStr = `${selectedYear}-${selectedMonthPart}`;

  useEffect(() => {
    setFilterZone('all');
    setFilterStore('all');
  }, [filterRegion]);

  useEffect(() => {
    setFilterStore('all');
  }, [filterZone]);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);

  const dynamicZones = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') {
      baseStores = baseStores.filter(r => r.region === filterRegion);
    }
    return Array.from(new Set(baseStores.map(r => r.zone))).filter(Boolean).sort();
  }, [restaurants, filterRegion]);

  const dynamicStores = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') baseStores = baseStores.filter(r => r.region === filterRegion);
    if (filterZone !== 'all') baseStores = baseStores.filter(r => r.zone === filterZone);
    return baseStores.sort((a, b) => a.name.localeCompare(b.name));
  }, [restaurants, filterRegion, filterZone]);

  const historyEvents = useMemo(() => {
    const events: any[] = [];
    employees.forEach(emp => {
      emp.history?.forEach(h => {
        if (h.action === 'INGRESO' || h.action === 'RETIRO') {
          const store = restaurants.find(r => r.id === h.restaurantName || r.name === h.restaurantName);
          const matchRegion = filterRegion === 'all' || store?.region === filterRegion;
          const matchZone = filterZone === 'all' || store?.zone === filterZone;
          const matchStore = filterStore === 'all' || store?.id === filterStore || store?.name === filterStore;

          if (matchRegion && matchZone && matchStore) {
            events.push({
              ...h,
              employeeName: emp.name,
              employeeId: emp.id,
              employeeTitle: emp.title,
              month: h.date.slice(0, 7),
              year: h.date.slice(0, 4)
            });
          }
        }
      });
    });
    return events;
  }, [employees, restaurants, filterRegion, filterZone, filterStore]);

  const monthStats = useMemo(() => {
    const entries = historyEvents.filter(e => e.month === selectedMonthStr && e.action === 'INGRESO').length;
    const exits = historyEvents.filter(e => e.month === selectedMonthStr && e.action === 'RETIRO').length;
    return { entries, exits };
  }, [historyEvents, selectedMonthStr]);

  const statsByCargo = useMemo(() => {
    const monthEvents = historyEvents.filter(e => e.month === selectedMonthStr);
    const cargoMap: Record<string, { cargo: string, ingresos: number, retiros: number }> = {};

    monthEvents.forEach(e => {
      const title = e.employeeTitle || 'Otro';
      if (!cargoMap[title]) {
        cargoMap[title] = { cargo: title, ingresos: 0, retiros: 0 };
      }
      if (e.action === 'INGRESO') cargoMap[title].ingresos++;
      if (e.action === 'RETIRO') cargoMap[title].retiros++;
    });

    return Object.values(cargoMap).sort((a, b) => (b.ingresos + b.retiros) - (a.ingresos + a.retiros));
  }, [historyEvents, selectedMonthStr]);

  const yearChartData = useMemo(() => {
    const months = ['01','02','03','04','05','06','07','08','09','10','11','12'];
    const monthLabels = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];

    return months.map((m, idx) => {
      const targetMonth = `${selectedYear}-${m}`;
      const entries = historyEvents.filter(e => e.month === targetMonth && e.action === 'INGRESO').length;
      const exits = historyEvents.filter(e => e.month === targetMonth && e.action === 'RETIRO').length;
      return {
        name: monthLabels[idx],
        ingresos: entries,
        retiros: exits
      };
    });
  }, [historyEvents, selectedYear]);

  const detailList = useMemo(() => {
    if (viewDetail === 'none') return [];
    const action = viewDetail === 'entries' ? 'INGRESO' : 'RETIRO';
    return historyEvents.filter(e => e.month === selectedMonthStr && e.action === action);
  }, [historyEvents, selectedMonthStr, viewDetail]);

  const years = [currentYear.toString(), (currentYear - 1).toString()];
