    { val: '04', label: 'Abril' }, { val: '05', label: 'Mayo' }, { val: '06', label: 'Junio' },
    { val: '07', label: 'Julio' }, { val: '08', label: 'Agosto' }, { val: '09', label: 'Septiembre' },
    { val: '10', label: 'Octubre' }, { val: '11', label: 'Noviembre' }, { val: '12', label: 'Diciembre' }
  ];

  const selectStyle = "w-full pl-10 pr-10 py-2.5 bg-white border-2 border-slate-200 rounded-xl text-[11px] font-black text-slate-800 outline-none appearance-none cursor-pointer shadow-sm hover:border-red-400 focus:border-red-500 transition-all uppercase tracking-tighter";

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-8 rounded-[32px] shadow-sm border border-slate-100">
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 mb-8">
          <div className="relative">
            <Calendar className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
            <select className={selectStyle} value={selectedYear} onChange={(e) => setSelectedYear(e.target.value)}>
              {years.map(y => <option key={y} value={y}>{y}</option>)}
            </select>
          </div>
          <div className="relative">
            <Calendar className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
            <select className={selectStyle} value={selectedMonthPart} onChange={(e) => setSelectedMonthPart(e.target.value)}>
              {monthsList.map(m => <option key={m.val} value={m.val}>{m.label}</option>)}
            </select>
          </div>
          <div className="relative">
            <MapPin className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
            <select className={selectStyle} value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)}>
              <option value="all">Region: Todas</option>
              {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
            </select>
          </div>
          <div className="relative">
            <Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
            <select className={selectStyle} value={filterZone} onChange={(e) => setFilterZone(e.target.value)}>
              <option value="all">Zona: Todas</option>
              {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
            </select>
          </div>
          <div className="relative">
            <Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
            <select className={selectStyle} value={filterStore} onChange={(e) => setFilterStore(e.target.value)}>
              <option value="all">Tienda: Todas</option>
              {dynamicStores.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
            </select>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-1 space-y-4">
             <div className="grid grid-cols-2 gap-4">
                <button 
                  onClick={() => setViewDetail(viewDetail === 'entries' ? 'none' : 'entries')}
                  className={`p-4 rounded-3xl border-2 transition-all flex flex-col items-center ${viewDetail === 'entries' ? 'bg-emerald-50 border-emerald-500 shadow-lg' : 'bg-slate-50 border-transparent hover:bg-emerald-50'}`}
                >
                  <ArrowUpCircle className={`w-6 h-6 mb-2 ${viewDetail === 'entries' ? 'text-emerald-600' : 'text-slate-400'}`} />
                  <p className="text-[10px] font-black uppercase text-slate-400 mb-1">Ingresos</p>
                  <p className="text-2xl font-black text-slate-800">{monthStats.entries}</p>
                </button>
                <button 
                  onClick={() => setViewDetail(viewDetail === 'exits' ? 'none' : 'exits')}
                  className={`p-4 rounded-3xl border-2 transition-all flex flex-col items-center ${viewDetail === 'exits' ? 'bg-red-50 border-red-500 shadow-lg' : 'bg-slate-50 border-transparent hover:bg-red-50'}`}
                >
                  <ArrowDownCircle className={`w-6 h-6 mb-2 ${viewDetail === 'exits' ? 'text-red-600' : 'text-slate-400'}`} />
                  <p className="text-[10px] font-black uppercase text-slate-400 mb-1">Retiros</p>
                  <p className="text-2xl font-black text-slate-800">{monthStats.exits}</p>
                </button>
             </div>
             <div className="bg-slate-50/50 p-6 rounded-[32px] border border-slate-100">
               <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-6">Desglose por Cargo</h4>
               <div className="h-[250px]">
                 <ResponsiveContainer width="100%" height="100%">
                   <BarChart data={statsByCargo} layout="vertical" margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                      <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f1f5f9" />
                      <XAxis type="number" hide />
                      <YAxis dataKey="cargo" type="category" axisLine={false} tickLine={false} width={80} tick={{ fontSize: 9, fontWeight: 900, fill: '#64748b' }} />
                      <Tooltip cursor={{fill: '#f1f5f9'}} contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontWeight: '900', fontSize: '11px' }} />
                      <Bar name="Ingresos" dataKey="ingresos" fill="#10b981" radius={[0, 4, 4, 0]} barSize={12} />
                      <Bar name="Retiros" dataKey="retiros" fill="#ef4444" radius={[0, 4, 4, 0]} barSize={12} />
                   </BarChart>
                 </ResponsiveContainer>
               </div>
             </div>
          </div>
          <div className="lg:col-span-2 bg-white p-6 rounded-[32px] border border-slate-100 flex flex-col shadow-sm">
             <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-6">Comparativa Temporal (12 Meses)</h4>
             <div className="flex-1 min-h-[400px]">
               <ResponsiveContainer width="100%" height="100%">
                 <BarChart data={yearChartData} margin={{ top: 20, right: 0, left: -20, bottom: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                    <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                    <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontWeight: '900', fontSize: '11px' }} />
                    <Bar name="Ingresos" dataKey="ingresos" fill="#10b981" radius={[4, 4, 0, 0]} barSize={18} />
                    <Bar name="Retiros" dataKey="retiros" fill="#ef4444" radius={[4, 4, 0, 0]} barSize={18} />
                 </BarChart>
               </ResponsiveContainer>
             </div>
          </div>
        </div>
      </div>

      {viewDetail !== 'none' && (
        <div className="bg-white rounded-[32px] shadow-2xl border border-slate-100 animate-in slide-in-from-top-4 duration-300 overflow-hidden">
          <div className="p-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
