import React, { useState, useEffect, useMemo } from 'react';
import { Employee, GradeEntry, JobTitle } from '../types';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { dataService } from '../dataService';
import { X, Save, User, Calendar, MapPin, Briefcase, History, ChevronRight, GraduationCap, Star, Trophy, ClipboardCheck, Vault, Layers, TrendingUp, Info, Clock } from 'lucide-react';

interface GradeEditorProps {
  employee: Employee;
  month: string;
  onClose: () => void;
}

const GroupIcons: Record<string, React.ReactNode> = {
  'A': <GraduationCap className="w-4 h-4" />,
  'B': <Star className="w-4 h-4" />,
  'C': <Trophy className="w-4 h-4" />,
  'D': <ClipboardCheck className="w-4 h-4" />,
  'E': <Vault className="w-4 h-4" />,
};

const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('A');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const restaurants = dataService.getRestaurants();

  useEffect(() => {
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    setFormGrades(existing);
  }, [employee, month]);

  const seniority = useMemo(() => {
    if (!employee.joinDate) return "N/A";
    const start = new Date(employee.joinDate);
    const now = new Date();
    let diffInMonths = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth());
    if (diffInMonths < 0) return "0 meses";
    const years = Math.floor(diffInMonths / 12);
    const months = diffInMonths % 12;
    if (years === 0) return `${months} m`;
    return `${years}a ${months}m`;
  }, [employee.joinDate]);

  const handleScoreChange = (group: string, category: string, scoreStr: string) => {
    if (scoreStr === '') {
      setFormGrades(prev => prev.filter(g => !(g.group === group && g.category === category)));
      return;
    }
    let score = parseInt(scoreStr);
    if (isNaN(score)) return;
    const sanitizedScore = Math.max(0, Math.min(100, score));
    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) {
        const next = [...prev];
        next[idx] = { ...next[idx], score: sanitizedScore };
        return next;
      }
      return [...prev, { employeeId: employee.id, month, group, category, score: sanitizedScore }];
    });
  };

  const saveGrades = () => {
    const allGrades = dataService.getGrades();
    const filtered = allGrades.filter(g => !(g.employeeId === employee.id && g.month === month));
    dataService.saveGrades([...filtered, ...formGrades]);
    onClose();
  };

  const getScore = (group: string, category: string) => {
    return formGrades.find(g => g.group === group && g.category === category)?.score ?? 0;
  };

  const currentStore = restaurants.find(r => r.id === employee.restaurantId);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/95 backdrop-blur-md p-0 md:p-4 animate-in fade-in duration-200">
      <div className="bg-white rounded-none md:rounded-[40px] shadow-2xl w-full max-w-5xl h-full md:h-auto md:max-h-[92vh] flex flex-col overflow-hidden border-0 md:border-4 border-white ring-1 ring-slate-800 relative">

        <div className="p-5 md:p-8 bg-slate-900 text-white shrink-0 relative overflow-hidden">
          <button onClick={onClose} className="absolute top-4 right-4 md:top-6 md:right-6 p-2 md:p-3 bg-white/10 hover:bg-red-600 rounded-xl transition-all z-50 backdrop-blur-xl border border-white/10"><X className="w-5 h-5 md:w-6 md:h-6"/></button>

          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 relative z-10">
            <div className="flex items-center space-x-4 md:space-x-6">
              <div className="w-12 h-12 md:w-16 md:h-16 bg-gradient-to-br from-red-500 to-red-700 rounded-[18px] md:rounded-[24px] flex items-center justify-center border-2 border-slate-800 shadow-xl shrink-0"><User className="w-6 h-6 md:w-8 md:h-8 text-white" /></div>
              <div>
                <div className="flex flex-col md:flex-row md:items-center gap-1 md:gap-3">
