import React, { useState, useMemo, useEffect } from 'react';
import { Upload, UserPlus, Search, X, Check, ChevronDown, Lock, Shield, FileSpreadsheet, Download, Edit2, Trash2, AlertCircle, Network, MapPin, Layers, Plus, Trash } from 'lucide-react';
import { dataService } from '../dataService';
import { UserRole, User, HierarchyData } from '../types';
import * as XLSX from 'xlsx';

interface AdminPanelProps {
  onEmployeesImported: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onEmployeesImported }) => {
  const [activeSubTab, setActiveSubTab] = useState<'import' | 'users' | 'hierarchy'>('import');
  const [importStatus, setImportStatus] = useState<string | null>(null);
  const [importError, setImportError] = useState<string | null>(null);
  const [heladeriaWarning, setHeladeriaWarning] = useState<boolean>(false);
  const [isImporting, setIsImporting] = useState(false);

  const [showUserModal, setShowUserModal] = useState(false);
  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [newUserData, setNewUserData] = useState({
    username: '',
    password: '',
    role: UserRole.SPECIALIST,
    assignedZones: [] as string[],
  });

  const [hierarchy, setHierarchy] = useState<HierarchyData>(dataService.getHierarchy());

  useEffect(() => {
    setHierarchy(dataService.getHierarchy());
  }, [activeSubTab, importStatus]);

  const availableZones = useMemo(() => {
    return Array.from(new Set(dataService.getRestaurants().map(r => r.zone))).filter(Boolean).sort();
  }, [showUserModal, activeSubTab, importStatus]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'employees' | 'hierarchy') => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsImporting(true);
    setImportStatus('Procesando archivo...');
    setImportError(null);

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws);

        if (data.length === 0) throw new Error("El archivo está vacío");

        if (type === 'employees') {
          const result = dataService.importMonthlyExcel(data);
          setImportStatus(`Carga exitosa: ${result.count} trabajadores.`);
          if (result.heladeriasSkipped) setHeladeriaWarning(true);
        } else {
          const count = dataService.importHierarchyExcel(data);
          setImportStatus(`Éxito: ${count} tiendas sincronizadas.`);
        }

        setIsImporting(false);
        onEmployeesImported();
        setTimeout(() => setImportStatus(null), 5000);
      } catch (err: any) {
        setIsImporting(false);
        setImportError(err.message || 'Error en el archivo.');
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = '';
  };

  const handleSaveUser = () => {
    if (!newUserData.username) return;
    const users = dataService.getUsers();

    if (editingUserId) {
      const updatedUser: User = { id: editingUserId, username: newUserData.username, password: newUserData.password || '123', role: newUserData.role, assignedZones: newUserData.assignedZones, assignedRestaurants: [] };
      dataService.updateUser(updatedUser);
    } else {
      const newUser: User = { id: `u-${Date.now()}`, username: newUserData.username, password: newUserData.password || '123', role: newUserData.role, assignedZones: newUserData.assignedZones, assignedRestaurants: [] };
      localStorage.setItem('la_akademia_users', JSON.stringify([...users, newUser]));
    }

    setShowUserModal(false);
    onEmployeesImported();
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-8 rounded-[32px] shadow-sm border border-slate-100">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
          <div className="flex items-center space-x-4">
            <div className="p-3 bg-red-600 text-white rounded-2xl shadow-lg"><Shield className="w-6 h-6" /></div>
            <div>
              <h2 className="text-xl font-black text-slate-800 tracking-tight uppercase italic">Admin KFC</h2>
              <div className="flex gap-2 mt-2">
                {['import', 'hierarchy', 'users'].map(tab => (
                  <button 
                    key={tab} onClick={() => setActiveSubTab(tab as any)}
                    className={`text-[8px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full transition ${activeSubTab === tab ? 'bg-slate-900 text-white shadow-md' : 'bg-slate-100 text-slate-400 hover:bg-slate-200'}`}
                  >
                    {tab === 'import' ? 'Carga' : tab === 'hierarchy' ? 'Jerarquía' : 'Usuarios'}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        {activeSubTab === 'import' && (
          <div className="p-8 border-2 border-dashed border-slate-200 rounded-[32px] bg-slate-50/30 text-center animate-in fade-in duration-300">
            <label className="cursor-pointer block">
              <Upload className="w-12 h-12 text-slate-200 mx-auto mb-4" />
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Subir Base Personal (.xlsx)</p>
              <input type="file" className="hidden" accept=".xlsx" onChange={(e) => handleFileUpload(e, 'employees')} />
            </label>
            {importStatus && <p className="mt-4 text-[9px] font-black text-emerald-600 uppercase">{importStatus}</p>}
            {importError && <p className="mt-4 text-[9px] font-black text-red-600 uppercase">{importError}</p>}
          </div>
        )}

        {activeSubTab === 'hierarchy' && (
          <div className="space-y-6 animate-in fade-in duration-300">
            <label className="p-6 border-2 border-dashed border-slate-200 rounded-[32px] bg-slate-50/30 text-center cursor-pointer block">
              <Network className="w-10 h-10 text-slate-200 mx-auto mb-2" />
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sincronizar Estructura (.xlsx)</p>
              <input type="file" className="hidden" accept=".xlsx" onChange={(e) => handleFileUpload(e, 'hierarchy')} />
            </label>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {hierarchy.regions.map((region, rIdx) => (
                <div key={rIdx} className="bg-white border-2 border-slate-100 rounded-[24px] p-4 space-y-3">
                  <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest flex items-center border-b border-slate-50 pb-2"><MapPin className="w-3 h-3 mr-2 text-red-600" /> {region.name}</h4>
                  <div className="space-y-2">
                    {region.zones.map((zone, zIdx) => (
                      <div key={zIdx} className="text-[9px] font-bold text-slate-500 bg-slate-50 px-3 py-2 rounded-xl flex justify-between">
                         <span className="truncate">{zone.name}</span>
                         <span className="text-red-500 ml-2">{zone.restaurantIds.length} tnd</span>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeSubTab === 'users' && (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 animate-in fade-in duration-300">
            <button 
              onClick={() => { setEditingUserId(null); setNewUserData({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [] }); setShowUserModal(true); }}
              className="p-5 border-2 border-dashed border-slate-200 rounded-3xl flex flex-col items-center justify-center text-slate-400 hover:text-red-600 hover:border-red-200 transition-all"
            >
              <Plus className="w-8 h-8 mb-2" />
              <span className="text-[9px] font-black uppercase tracking-widest">Nuevo Usuario</span>
            </button>
            {dataService.getUsers().map(u => (
              <div key={u.id} className="bg-white p-4 rounded-3xl border border-slate-100 flex items-center justify-between shadow-sm">
                <div className="min-w-0">
                  <p className="text-xs font-black text-slate-800 truncate uppercase tracking-tighter">{u.username}</p>
                  <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mt-1">{u.role} • {u.assignedZones.length} áreas</p>
                </div>
                <div className="flex">
                  <button onClick={() => { setEditingUserId(u.id); setNewUserData({ username: u.username, password: '', role: u.role, assignedZones: u.assignedZones }); setShowUserModal(true); }} className="p-2 text-slate-200 hover:text-red-600 transition-all"><Edit2 className="w-3.5 h-3.5" /></button>
                  {u.id !== 'admin1' && <button onClick={() => { if(confirm('¿Eliminar?')) { localStorage.setItem('la_akademia_users', JSON.stringify(dataService.getUsers().filter(user => user.id !== u.id))); onEmployeesImported(); } }} className="p-2 text-slate-200 hover:text-red-600 transition-all"><Trash2 className="w-3.5 h-3.5" /></button>}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {showUserModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/95 backdrop-blur-xl p-4">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-6 bg-slate-900 text-white flex justify-between items-center"><h2 className="text-xl font-black uppercase italic tracking-tighter">Acceso KFC</h2><button onClick={() => setShowUserModal(false)}><X className="w-6 h-6"/></button></div>
            <div className="p-8 space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <input type="text" placeholder="Usuario" value={newUserData.username} onChange={e => setNewUserData({...newUserData, username: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl font-bold text-sm outline-none focus:border-red-500" />
                <input type="password" placeholder="Password" value={newUserData.password} onChange={e => setNewUserData({...newUserData, password: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl font-bold text-sm outline-none focus:border-red-500" />
              </div>
              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Zonas Asignadas</label>
                <select multiple value={newUserData.assignedZones} onChange={e => setNewUserData({...newUserData, assignedZones: Array.from(e.target.selectedOptions, (option: any) => option.value)})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl h-40 outline-none text-[10px] font-black uppercase tracking-tight">
                  {availableZones.map(z => <option key={z} value={z} className="py-2 px-1 hover:bg-red-50 rounded-lg">{z}</option>)}
                </select>
              </div>
            </div>
            <div className="p-6 bg-slate-50 flex justify-end gap-3 border-t border-slate-100">
              <button onClick={() => setShowUserModal(false)} className="px-6 py-3 font-black text-slate-400 text-[10px] uppercase tracking-widest">Cerrar</button>
              <button onClick={handleSaveUser} className="px-10 py-3 bg-red-600 text-white font-black rounded-xl uppercase tracking-widest text-[10px]">Guardar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

