import React, { useMemo, useState, useEffect } from 'react';
import { User, Restaurant, Employee, UserRole, JobHierarchy } from '../types';
import { Store, MapPin, Users, Award, ChevronRight, ArrowLeft, User as UserIcon, Edit3, TrendingUp, BarChart as ChartIcon, Filter, Search, ChevronDown } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import GradeEditor from './GradeEditor';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
  onUpdate: () => void;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth, onUpdate }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [searchStore, setSearchStore] = useState('');
  const [searchEmployee, setSearchEmployee] = useState('');

  useEffect(() => {
    setFilterZone('all');
  }, [filterRegion]);

  const assigned = useMemo(() => {
    let base = user.role === UserRole.ADMIN 
      ? restaurants 
      : restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));

    return base.filter(r => {
      const matchRegion = filterRegion === 'all' || r.region === filterRegion;
      const matchZone = filterZone === 'all' || r.zone === filterZone;
      const matchSearch = searchStore === '' || r.name.toLowerCase().includes(searchStore.toLowerCase()) || r.id.toLowerCase().includes(searchStore.toLowerCase());
      return matchRegion && matchZone && matchSearch;
    });
  }, [user, restaurants, filterRegion, filterZone, searchStore]);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    return Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
  }, [restaurants, filterRegion]);

  const allGrades = useMemo(() => dataService.getGrades(), [selectedMonth, editingEmployee]);
  const currentGrades = useMemo(() => allGrades.filter(g => g.month === selectedMonth), [allGrades, selectedMonth]);

  const getStoreStats = (storeId: string, month: string) => {
    const monthGrades = allGrades.filter(g => g.month === month);
    const storeEmpsAtMonth = employees.filter(e => e.restaurantId === storeId);
    if (storeEmpsAtMonth.length === 0) return { total: 0, approved: 0, percent: 0 };
    let approved = 0;
    storeEmpsAtMonth.forEach(emp => {
      const empGrades = monthGrades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        const sum = empGrades.reduce((sum, g) => sum + g.score, 0);
        const avg = sum / TOTAL_CATEGORIES_COUNT;
        if (avg >= APPROVAL_THRESHOLD) approved++;
      }
    });
    return { total: storeEmpsAtMonth.length, approved, percent: Math.round((approved / storeEmpsAtMonth.length) * 100) };
  };

  const storeHistoryData = useMemo(() => {
    if (!selectedStore) return [];
    const months = Array.from(new Set(allGrades.map(g => g.month))).sort() as string[];
    return months.map((m: string) => ({ month: m, percent: getStoreStats(selectedStore.id, m).percent })).slice(-6);
  }, [selectedStore, allGrades, employees]);

