import React, { useMemo, useState, useEffect } from 'react';
import { Employee, Restaurant, JobTitle } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { ArrowUpCircle, ArrowDownCircle, MapPin, Filter, Calendar, Briefcase, ChevronDown } from 'lucide-react';

interface EntriesExitsReportProps {
  employees: Employee[];
  restaurants: Restaurant[];
}

const EntriesExitsReport: React.FC<EntriesExitsReportProps> = ({ employees, restaurants }) => {
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [filterStore, setFilterStore] = useState('all');

  const currentYear = new Date().getFullYear();
  const currentMonthNum = (new Date().getMonth() + 1).toString().padStart(2, '0');

  const [selectedYear, setSelectedYear] = useState<string>(currentYear.toString());
  const [selectedMonthPart, setSelectedMonthPart] = useState<string>(currentMonthNum);
  const [viewDetail, setViewDetail] = useState<'entries' | 'exits' | 'none'>('none');

  const selectedMonthStr = `${selectedYear}-${selectedMonthPart}`;

  useEffect(() => {
    setFilterZone('all');
    setFilterStore('all');
  }, [filterRegion]);

  useEffect(() => {
    setFilterStore('all');
  }, [filterZone]);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    return Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
  }, [restaurants, filterRegion]);

  const dynamicStores = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    if (filterZone !== 'all') base = base.filter(r => r.zone === filterZone);
    return base.sort((a, b) => a.name.localeCompare(b.name));
  }, [restaurants, filterRegion, filterZone]);

  const historyEvents = useMemo(() => {
    const events: any[] = [];
    employees.forEach(emp => {
      emp.history?.forEach(h => {
        if (h.action === 'INGRESO' || h.action === 'RETIRO') {
          const store = restaurants.find(r => r.id === h.restaurantName || r.name === h.restaurantName);
          const matchRegion = filterRegion === 'all' || store?.region === filterRegion;
          const matchZone = filterZone === 'all' || store?.zone === filterZone;
          const matchStore = filterStore === 'all' || store?.id === filterStore || store?.name === filterStore;

          if (matchRegion && matchZone && matchStore) {
            events.push({
              ...h,
              employeeName: emp.name,
              employeeId: emp.id,
              employeeTitle: emp.title,
              month: h.date.slice(0, 7),
              year: h.date.slice(0, 4)
            });
          }
        }
      });
    });
    return events;
  }, [employees, restaurants, filterRegion, filterZone, filterStore]);

  const statsByCargo = useMemo(() => {
    const cargoMap: Record<string, { cargo: string, ingresos: number, retiros: number }> = {};
    // Inicializar con todos los cargos conocidos
    Object.values(JobTitle).forEach(t => {
      cargoMap[t] = { cargo: t, ingresos: 0, retiros: 0 };
    });

    historyEvents.filter(e => e.month === selectedMonthStr).forEach(e => {
      const title = e.employeeTitle || 'Miembro de equipo';
      if (!cargoMap[title]) cargoMap[title] = { cargo: title, ingresos: 0, retiros: 0 };
      if (e.action === 'INGRESO') cargoMap[title].ingresos++;
      if (e.action === 'RETIRO') cargoMap[title].retiros++;
    });

    return Object.values(cargoMap).sort((a, b) => (b.ingresos + b.retiros) - (a.ingresos + a.retiros));
  }, [historyEvents, selectedMonthStr]);

  const yearChartData = useMemo(() => {
    const monthLabels = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
    return monthLabels.map((name, idx) => {
      const mStr = `${selectedYear}-${String(idx + 1).padStart(2, '0')}`;
      const entries = historyEvents.filter(e => e.month === mStr && e.action === 'INGRESO').length;
      const exits = historyEvents.filter(e => e.month === mStr && e.action === 'RETIRO').length;
      return { name, ingresos: entries, retiros: exits };
    });
  }, [historyEvents, selectedYear]);

  const monthStats = useMemo(() => {
    const entries = historyEvents.filter(e => e.month === selectedMonthStr && e.action === 'INGRESO').length;
    const exits = historyEvents.filter(e => e.month === selectedMonthStr && e.action === 'RETIRO').length;
    return { entries, exits };
  }, [historyEvents, selectedMonthStr]);

  const detailList = useMemo(() => {
    if (viewDetail === 'none') return [];
    return historyEvents.filter(e => e.month === selectedMonthStr && e.action === (viewDetail === 'entries' ? 'INGRESO' : 'RETIRO'));
  }, [historyEvents, selectedMonthStr, viewDetail]);

  const selectStyle = "w-full pl-10 pr-10 py-2.5 bg-white border-2 border-slate-200 rounded-xl text-[11px] font-black text-slate-800 outline-none appearance-none cursor-pointer shadow-sm hover:border-red-400 focus:border-red-500 transition-all uppercase tracking-tighter";

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-8 rounded-[32px] shadow-sm border border-slate-100">
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 mb-8">
          <div className="relative">
            <Calendar className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
            <select className={selectStyle} value={selectedYear} onChange={(e) => setSelectedYear(e.target.value)}>
              {[currentYear, currentYear-1].map(y => <option key={y} value={y}>{y}</option>)}
            </select>
          </div>
          <div className="relative">
            <Calendar className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
            <select className={selectStyle} value={selectedMonthPart} onChange={(e) => setSelectedMonthPart(e.target.value)}>
              {['01','02','03','04','05','06','07','08','09','10','11','12'].map(m => <option key={m} value={m}>{m}</option>)}
            </select>
          </div>
          <div className="relative"><MapPin className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" /><select className={selectStyle} value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)}><option value="all">Region: Todas</option>{dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}</select></div>
          <div className="relative"><Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" /><select className={selectStyle} value={filterZone} onChange={(e) => setFilterZone(e.target.value)}><option value="all">Zona: Todas</option>{dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}</select></div>
          <div className="relative"><Filter className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" /><select className={selectStyle} value={filterStore} onChange={(e) => setFilterStore(e.target.value)}><option value="all">Tienda: Todas</option>{dynamicStores.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}</select></div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-1 space-y-4">
             <div className="grid grid-cols-2 gap-4">
                <button onClick={() => setViewDetail('entries')} className={`p-4 rounded-3xl border-2 transition-all flex flex-col items-center ${viewDetail === 'entries' ? 'bg-emerald-50 border-emerald-500 shadow-lg' : 'bg-slate-50 border-transparent'}`}><ArrowUpCircle className="w-6 h-6 mb-1 text-emerald-600" /><p className="text-[10px] font-black uppercase text-slate-400">Ingresos</p><p className="text-2xl font-black text-slate-800">{monthStats.entries}</p></button>
                <button onClick={() => setViewDetail('exits')} className={`p-4 rounded-3xl border-2 transition-all flex flex-col items-center ${viewDetail === 'exits' ? 'bg-red-50 border-red-500 shadow-lg' : 'bg-slate-50 border-transparent'}`}><ArrowDownCircle className="w-6 h-6 mb-1 text-red-600" /><p className="text-[10px] font-black uppercase text-slate-400">Retiros</p><p className="text-2xl font-black text-slate-800">{monthStats.exits}</p></button>
             </div>
             <div className="bg-slate-50/50 p-6 rounded-[32px] border border-slate-100">
               <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-4 flex items-center"><Briefcase className="w-3 h-3 mr-2" /> Desglose por Cargo</h4>
               <div className="h-[250px]">
                 <ResponsiveContainer width="100%" height="100%">
                   <BarChart data={statsByCargo} layout="vertical" margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                      <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f1f5f9" />
                      <XAxis type="number" hide />
                      <YAxis dataKey="cargo" type="category" axisLine={false} tickLine={false} width={80} tick={{ fontSize: 8, fontWeight: 900, fill: '#64748b' }} />
                      <Tooltip cursor={{fill: '#f1f5f9'}} contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)', fontWeight: '900', fontSize: '10px' }} />
                      <Bar name="Ingresos" dataKey="ingresos" fill="#10b981" radius={[0, 4, 4, 0]} barSize={10} />
                      <Bar name="Retiros" dataKey="retiros" fill="#ef4444" radius={[0, 4, 4, 0]} barSize={10} />
                   </BarChart>
                 </ResponsiveContainer>
               </div>
             </div>
          </div>
          <div className="lg:col-span-2 bg-white p-6 rounded-[32px] border border-slate-100 flex flex-col shadow-sm">
             <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-6">Comparativa Temporal {selectedYear}</h4>
             <div className="flex-1 min-h-[400px]">
               <ResponsiveContainer width="100%" height="100%">
                 <BarChart data={yearChartData} margin={{ top: 20, right: 0, left: -20, bottom: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                    <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                    <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontWeight: '900', fontSize: '11px' }} />
                    <Bar name="Ingresos" dataKey="ingresos" fill="#10b981" radius={[4, 4, 0, 0]} barSize={15} />
                    <Bar name="Retiros" dataKey="retiros" fill="#ef4444" radius={[4, 4, 0, 0]} barSize={15} />
                 </BarChart>
               </ResponsiveContainer>
             </div>
          </div>
        </div>
      </div>

      {viewDetail !== 'none' && (
        <div className="bg-white rounded-[32px] shadow-2xl border border-slate-100 animate-in slide-in-from-top-4 duration-300 overflow-hidden">
          <div className="p-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
            <h3 className="text-lg font-black text-slate-800 tracking-tight uppercase italic">{viewDetail === 'entries' ? 'Ingresos' : 'Retiros'} - {selectedMonthStr}</h3>
            <button onClick={() => setViewDetail('none')} className="text-[9px] font-black text-slate-400 uppercase">Cerrar</button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead><tr className="bg-slate-50 text-[9px] font-black text-slate-400 uppercase tracking-widest"><th className="px-8 py-4">Fecha</th><th className="px-8 py-4">Colaborador</th><th className="px-8 py-4">Tienda</th></tr></thead>
              <tbody className="divide-y divide-slate-50">
                {detailList.map((e, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/30 transition-colors"><td className="px-8 py-3 text-xs font-black text-slate-500">{e.date}</td><td className="px-8 py-3 text-xs font-black text-slate-800 uppercase">{e.employeeName}</td><td className="px-8 py-3 text-xs font-black text-slate-600 uppercase">{e.restaurantName}</td></tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
};

