import { Employee, GradeEntry, User, UserRole, JobTitle, Restaurant, HierarchyData } from './types';
import * as XLSX from 'xlsx';

const STORAGE_KEY_CLOUD_CONFIG = 'la_akademia_cloud_config';

const parseExcelDate = (serial: any) => {
  if (!serial) return '';
  if (typeof serial === 'string') return serial;
  try {
    const date = XLSX.SSF.parse_date_code(serial);
    const month = String(date.m).padStart(2, '0');
    const day = String(date.d).padStart(2, '0');
    return `${date.y}-${month}-${day}`;
  } catch (e) {
    return String(serial);
  }
};

export const dataService = {
  getCloudConfig: () => {
    const config = localStorage.getItem(STORAGE_KEY_CLOUD_CONFIG);
    return config ? JSON.parse(config) : { url: '', key: '' };
  },

  setCloudConfig: (url: string, key: string) => {
    localStorage.setItem(STORAGE_KEY_CLOUD_CONFIG, JSON.stringify({ url, key }));
  },

  // Helper para peticiones a Supabase
  supabaseFetch: async (table: string, method: string = 'GET', body?: any) => {
    const { url, key } = dataService.getCloudConfig();
    if (!url || !key) return null;

    const options: any = {
      method,
      headers: {
        'apikey': key,
        'Authorization': `Bearer ${key}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation'
      }
    };
    if (body) options.body = JSON.stringify(body);

    const res = await fetch(`${url}/rest/v1/${table}`, options);
    return res.json();
  },

  getEmployees: (): Employee[] => {
    const data = localStorage.getItem('la_akademia_employees');
    return data ? JSON.parse(data) : [];
  },

  saveEmployees: (employees: Employee[]) => {
    localStorage.setItem('la_akademia_employees', JSON.stringify(employees));
    // Sincronizar con nube en segundo plano si hay config
    const { url } = dataService.getCloudConfig();
    if (url) {
      employees.forEach(emp => {
         dataService.supabaseFetch(`employees?id=eq.${emp.id}`, 'PATCH', emp);
      });
    }
  },

  getRestaurants: (): Restaurant[] => {
    const data = localStorage.getItem('la_akademia_stores');
    return data ? JSON.parse(data) : [];
  },

  saveRestaurants: (stores: Restaurant[]) => {
    localStorage.setItem('la_akademia_stores', JSON.stringify(stores));
  },

  getGrades: (): GradeEntry[] => {
    const data = localStorage.getItem('la_akademia_grades');
    return data ? JSON.parse(data) : [];
  },

  saveGrades: (grades: GradeEntry[]) => {
    localStorage.setItem('la_akademia_grades', JSON.stringify(grades));
  },

  getHierarchy: (): HierarchyData => {
    const data = localStorage.getItem('la_akademia_hierarchy');
    return data ? JSON.parse(data) : { regions: [] };
  },

  saveHierarchy: (hierarchy: HierarchyData) => {
    localStorage.setItem('la_akademia_hierarchy', JSON.stringify(hierarchy));
  },

  getUsers: (): User[] => {
    const data = localStorage.getItem('la_akademia_users');
    return data ? JSON.parse(data) : [{ id: 'admin1', username: 'admin', password: '123', role: UserRole.ADMIN, assignedZones: [], assignedRestaurants: [] }];
  },

  updateUser: (updatedUser: User) => {
    const users = dataService.getUsers();
    const index = users.findIndex(u => u.id === updatedUser.id);
    if (index !== -1) {
      users[index] = updatedUser;
      localStorage.setItem('la_akademia_users', JSON.stringify(users));
    }
  },

  importMonthlyExcel: (rawData: any[]) => {
    const currentEmployees = dataService.getEmployees();
    const currentStores = dataService.getRestaurants();
    const today = new Date().toISOString().split('T')[0];

    const importedIds = new Set();
    const filteredRawData = rawData.filter(item => {
      const storeId = String(item.Nombre_Ceco || item.nombre_ceco || '').trim().toUpperCase();
      return !storeId.startsWith('H');
    });

    const importedEmployees = filteredRawData.map(item => {
      const storeId = String(item.Nombre_Ceco || item.nombre_ceco || 'SIN_CECO').trim().toUpperCase();
      const docId = String(item.Documento || item.documento || '').trim();
      if (!docId) return null;
      importedIds.add(docId);

      let assignedZone = 'Sin Clasificar';
      const storeInfo = currentStores.find(s => s.id === storeId);
      if (storeInfo) assignedZone = storeInfo.zone;

      const existing = currentEmployees.find(e => e.id === docId);
      const rawStatus = String(item.Estado || item.estado || '').trim().toUpperCase();
      const isActive = rawStatus.startsWith('ACTIVO');

      const emp: Employee = {
        id: docId,
        name: item["Nombre completo"] || item.nombre || 'Sin Nombre',
        joinDate: parseExcelDate(item["Fecha de ingreso"] || item.fecha_de_ingreso),
        title: (item.Cargo || item.cargo) as JobTitle,
        restaurantId: storeId,
        zone: assignedZone,
        active: isActive,
        history: existing?.history || []
      };

      if (existing) {
        if (existing.restaurantId !== storeId) {
          emp.history = [...(existing.history || []), { date: today, restaurantName: existing.restaurantId, action: 'TRASLADO' }];
        }
        if (existing.active && !isActive) {
           emp.history = [...(existing.history || []), { date: today, restaurantName: storeId, action: 'RETIRO' }];
        }
      } else {
        emp.history = [{ date: emp.joinDate || today, restaurantName: storeId, action: 'INGRESO' }];
      }
      return emp;
    }).filter(e => e !== null) as Employee[];

    const retired = currentEmployees
      .filter(e => !importedIds.has(e.id) && e.active)
      .map(e => ({
        ...e,
        active: false,
        history: [...(e.history || []), { date: today, restaurantName: e.restaurantId, action: 'RETIRO' as const }]
      }));

    const finalEmployees = [...importedEmployees, ...retired];
    dataService.saveEmployees(finalEmployees);
    return { count: importedEmployees.length };
  },

  importHierarchyExcel: (rawData: any[]) => {
    const newHierarchy: HierarchyData = { regions: [] };
    const newRestaurants: Restaurant[] = [];
    rawData.forEach(item => {
      const storeName = String(item["Nombre de tienda"] || "").trim().toUpperCase();
      const zoneName = String(item["Jefe de area"] || "Sin Zona").trim();
      const regionName = String(item["Region"] || "Sin Region").trim();
      if (!storeName) return;
      let region = newHierarchy.regions.find(r => r.name === regionName);
      if (!region) {
        region = { name: regionName, zones: [] };
        newHierarchy.regions.push(region);
      }
      let zone = region.zones.find(z => z.name === zoneName);
      if (!zone) {
        zone = { name: zoneName, restaurantIds: [] };
        region.zones.push(zone);
      }
      zone.restaurantIds.push(storeName);
      newRestaurants.push({ id: storeName, name: storeName, zone: zoneName, region: regionName });
    });
    dataService.saveRestaurants(newRestaurants);
    dataService.saveHierarchy(newHierarchy);
    return newRestaurants.length;
  }
};

import React, { useMemo, useState, useEffect } from 'react';
import { Employee, Restaurant, JobTitle } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { ArrowUpCircle, ArrowDownCircle, MapPin, Filter, Calendar, Briefcase, ChevronDown } from 'lucide-react';

interface EntriesExitsReportProps {
  employees: Employee[];
  restaurants: Restaurant[];
}

const EntriesExitsReport: React.FC<EntriesExitsReportProps> = ({ employees, restaurants }) => {
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [filterStore, setFilterStore] = useState('all');
  const [selectedYear, setSelectedYear] = useState<string>(new Date().getFullYear().toString());
  const [selectedMonthPart, setSelectedMonthPart] = useState<string>((new Date().getMonth() + 1).toString().padStart(2, '0'));
  const [viewDetail, setViewDetail] = useState<'entries' | 'exits' | 'none'>('none');

  const selectedMonthStr = `${selectedYear}-${selectedMonthPart}`;

  useEffect(() => { setFilterZone('all'); setFilterStore('all'); }, [filterRegion]);
  useEffect(() => { setFilterStore('all'); }, [filterZone]);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    return Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
  }, [restaurants, filterRegion]);
  const dynamicStores = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    if (filterZone !== 'all') base = base.filter(r => r.zone === filterZone);
    return base.sort((a, b) => a.name.localeCompare(b.name));
  }, [restaurants, filterRegion, filterZone]);

  const historyEvents = useMemo(() => {
    const events: any[] = [];
    employees.forEach(emp => {
      emp.history?.forEach(h => {
        if (h.action === 'INGRESO' || h.action === 'RETIRO') {
          const store = restaurants.find(r => r.id === h.restaurantName || r.name === h.restaurantName);
          if ((filterRegion === 'all' || store?.region === filterRegion) && (filterZone === 'all' || store?.zone === filterZone) && (filterStore === 'all' || store?.id === filterStore)) {
            events.push({ ...h, employeeName: emp.name, employeeTitle: emp.title, month: h.date.slice(0, 7), year: h.date.slice(0, 4) });
          }
        }
      });
    });
    return events;
  }, [employees, restaurants, filterRegion, filterZone, filterStore]);

  const statsByCargo = useMemo(() => {
    const cargoMap: Record<string, { cargo: string, ingresos: number, retiros: number }> = {};
    historyEvents.filter(e => e.month === selectedMonthStr).forEach(e => {
      const title = e.employeeTitle || 'Otro';
      if (!cargoMap[title]) cargoMap[title] = { cargo: title, ingresos: 0, retiros: 0 };
      if (e.action === 'INGRESO') cargoMap[title].ingresos++;
      if (e.action === 'RETIRO') cargoMap[title].retiros++;
    });
    return Object.values(cargoMap).sort((a, b) => (b.ingresos + b.retiros) - (a.ingresos + a.retiros));
  }, [historyEvents, selectedMonthStr]);

  const yearChartData = useMemo(() => {
    const months = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
    return months.map((name, idx) => {
      const mStr = `${selectedYear}-${String(idx + 1).padStart(2, '0')}`;
      const entries = historyEvents.filter(e => e.month === mStr && e.action === 'INGRESO').length;
      const exits = historyEvents.filter(e => e.month === mStr && e.action === 'RETIRO').length;
      return { name, ingresos: entries, retiros: exits };
    });
  }, [historyEvents, selectedYear]);

  const monthStats = useMemo(() => ({
    entries: historyEvents.filter(e => e.month === selectedMonthStr && e.action === 'INGRESO').length,
    exits: historyEvents.filter(e => e.month === selectedMonthStr && e.action === 'RETIRO').length
  }), [historyEvents, selectedMonthStr]);

  const selectStyle = "w-full pl-8 pr-8 py-2 bg-white border border-slate-200 rounded-lg text-[10px] font-black uppercase tracking-widest outline-none";

  return (
    <div className="space-y-4">
      <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
        <div className="grid grid-cols-2 md:grid-cols-5 gap-3 mb-6">
          <select className={selectStyle} value={selectedYear} onChange={e => setSelectedYear(e.target.value)}>{[currentYear, currentYear-1].map(y => <option key={y} value={y}>{y}</option>)}</select>
          <select className={selectStyle} value={selectedMonthPart} onChange={e => setSelectedMonthPart(e.target.value)}>{['01','02','03','04','05','06','07','08','09','10','11','12'].map(m => <option key={m} value={m}>{m}</option>)}</select>
          <select className={selectStyle} value={filterRegion} onChange={e => setFilterRegion(e.target.value)}><option value="all">Región</option>{dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}</select>
          <select className={selectStyle} value={filterZone} onChange={e => setFilterZone(e.target.value)}><option value="all">Zona</option>{dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}</select>
          <select className={selectStyle} value={filterStore} onChange={e => setFilterStore(e.target.value)}><option value="all">Tienda</option>{dynamicStores.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}</select>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setViewDetail('entries')} className={`p-3 rounded-2xl border-2 transition-all flex flex-col items-center ${viewDetail === 'entries' ? 'bg-emerald-50 border-emerald-500 shadow-lg' : 'bg-slate-50 border-transparent'}`}><ArrowUpCircle className="w-5 h-5 text-emerald-600 mb-1" /><p className="text-[9px] font-black text-slate-400 uppercase">Ingresos</p><p className="text-xl font-black text-slate-800">{monthStats.entries}</p></button>
              <button onClick={() => setViewDetail('exits')} className={`p-3 rounded-2xl border-2 transition-all flex flex-col items-center ${viewDetail === 'exits' ? 'bg-red-50 border-red-500 shadow-lg' : 'bg-slate-50 border-transparent'}`}><ArrowDownCircle className="w-5 h-5 text-red-600 mb-1" /><p className="text-[9px] font-black text-slate-400 uppercase">Retiros</p><p className="text-xl font-black text-slate-800">{monthStats.exits}</p></button>
            </div>
            <div className="bg-slate-50/50 p-4 rounded-2xl border border-slate-100">
               <h4 className="text-[8px] font-black uppercase text-slate-400 tracking-[0.2em] mb-4 flex items-center"><Briefcase className="w-3 h-3 mr-2" /> Cargos Activos</h4>
               <div className="h-[200px]">
                 <ResponsiveContainer width="100%" height="100%">
                   <BarChart data={statsByCargo} layout="vertical" margin={{ left: 20 }}>
                      <XAxis type="number" hide /><YAxis dataKey="cargo" type="category" axisLine={false} tickLine={false} tick={{fontSize: 7, fontWeight: 900, fill: '#64748b'}} width={60} />
                      <Tooltip cursor={{fill: '#f1f5f9'}} contentStyle={{borderRadius: '10px', fontSize: '9px', fontWeight: '900'}} /><Bar name="Ing." dataKey="ingresos" fill="#10b981" barSize={8} radius={[0, 4, 4, 0]} /><Bar name="Ret." dataKey="retiros" fill="#ef4444" barSize={8} radius={[0, 4, 4, 0]} />
                   </BarChart>
                 </ResponsiveContainer>
               </div>
            </div>
          </div>
          <div className="lg:col-span-2 bg-white p-6 rounded-2xl border border-slate-100 min-h-[350px]">
             <h4 className="text-[9px] font-black uppercase text-slate-400 tracking-[0.2em] mb-6">Comparativa Anual {selectedYear}</h4>
             <ResponsiveContainer width="100%" height="100%">
               <BarChart data={yearChartData} margin={{ left: -25 }}>
                 <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                 <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 9, fontWeight: 900, fill: '#94a3b8'}} />
                 <YAxis axisLine={false} tickLine={false} tick={{fontSize: 9, fontWeight: 900, fill: '#94a3b8'}} />
                 <Tooltip contentStyle={{borderRadius: '12px', fontSize: '10px', fontWeight: '900'}} /><Bar name="Ingresos" dataKey="ingresos" fill="#10b981" radius={[4, 4, 0, 0]} barSize={12} /><Bar name="Retiros" dataKey="retiros" fill="#ef4444" radius={[4, 4, 0, 0]} barSize={12} />
               </BarChart>
             </ResponsiveContainer>
          </div>
        </div>
      </div>
      {viewDetail !== 'none' && (
        <div className="bg-white rounded-2xl shadow-xl border border-slate-100 overflow-hidden animate-in fade-in duration-300">
           <div className="p-4 border-b border-slate-50 flex justify-between items-center"><h3 className="text-xs font-black uppercase italic">{viewDetail === 'entries' ? 'Ingresos' : 'Retiros'} {selectedMonthStr}</h3><button onClick={() => setViewDetail('none')} className="text-[8px] font-black uppercase bg-slate-100 px-3 py-1 rounded-full">Cerrar</button></div>
           <div className="max-h-60 overflow-y-auto"><table className="w-full text-left text-[10px]"><thead className="bg-slate-50 font-black text-slate-400 uppercase tracking-widest"><tr className="border-b border-slate-100"><th className="p-3">Fecha</th><th className="p-3">Nombre</th><th className="p-3">Tienda</th></tr></thead><tbody className="divide-y divide-slate-50">{historyEvents.filter(e => e.month === selectedMonthStr && e.action === (viewDetail === 'entries' ? 'INGRESO' : 'RETIRO')).map((e, i) => <tr key={i}><td className="p-3 text-slate-400">{e.date}</td><td className="p-3 font-black uppercase italic">{e.employeeName}</td><td className="p-3 text-slate-600 uppercase">{e.restaurantName}</td></tr>)}</tbody></table></div>
        </div>
      )}
    </div>
  );
};

export default EntriesExitsReport;

import React, { useState, useEffect, useMemo } from 'react';
import { Employee, GradeEntry, JobTitle } from '../types';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { dataService } from '../dataService';
import { X, Save, User, Calendar, MapPin, Briefcase, History, GraduationCap, Star, Trophy, ClipboardCheck, Vault, Layers, TrendingUp, Clock, Info } from 'lucide-react';

interface GradeEditorProps {
  employee: Employee;
  month: string;
  onClose: () => void;
}

const GroupIcons: Record<string, React.ReactNode> = {
  'A': <GraduationCap className="w-4 h-4" />,
  'B': <Star className="w-4 h-4" />,
  'C': <Trophy className="w-4 h-4" />,
  'D': <ClipboardCheck className="w-4 h-4" />,
  'E': <Vault className="w-4 h-4" />,
};

const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('A');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  useEffect(() => {
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    setFormGrades(existing);
  }, [employee, month]);

  const seniority = useMemo(() => {
    if (!employee.joinDate) return "N/A";
    const start = new Date(employee.joinDate);
    const now = new Date();
    let diff = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth());
    if (diff < 0) return "Reciente";
    const years = Math.floor(diff / 12);
    const months = diff % 12;
    return years === 0 ? `${months} meses` : `${years} años ${months} meses`;
  }, [employee.joinDate]);

  const handleScoreChange = (group: string, category: string, scoreStr: string) => {
    let score = scoreStr === '' ? 0 : Math.max(0, Math.min(100, parseInt(scoreStr) || 0));
    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) { const next = [...prev]; next[idx] = { ...next[idx], score }; return next; }
      return [...prev, { employeeId: employee.id, month, group, category, score }];
    });
  };

  const saveGrades = () => {
    const all = dataService.getGrades().filter(g => !(g.employeeId === employee.id && g.month === month));
    dataService.saveGrades([...all, ...formGrades]);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/95 backdrop-blur-md p-0 md:p-6 animate-in fade-in duration-200">
      <div className="bg-white md:rounded-[40px] shadow-2xl w-full max-w-5xl h-full md:h-[90vh] flex flex-col overflow-hidden relative border-4 border-white">

        <div className="p-6 bg-slate-900 text-white shrink-0 relative">
          <button onClick={onClose} className="absolute top-6 right-6 p-2 bg-white/10 hover:bg-red-600 rounded-xl transition-all z-50"><X className="w-6 h-6"/></button>
          <div className="flex items-center space-x-4">
            <div className="w-14 h-14 bg-red-600 rounded-2xl flex items-center justify-center border-2 border-slate-800 shadow-xl"><User className="w-8 h-8 text-white" /></div>
            <div>
              <div className="flex items-center gap-3">
                 <h2 className="text-xl font-black tracking-tight uppercase italic">{employee.name}</h2>
                 <div className="px-3 py-1 bg-red-600 text-[8px] font-black rounded-full uppercase tracking-widest">{employee.title}</div>
              </div>
              <div className="flex gap-4 opacity-50 mt-1 text-[9px] font-bold uppercase tracking-widest">
                <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5" /> {employee.joinDate}</span>
                <span className="flex items-center"><Clock className="w-3 h-3 mr-1.5" /> Antigüedad: {seniority}</span>
              </div>
            </div>
          </div>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
          <div className="w-full md:w-60 bg-slate-50 border-r border-slate-200 flex flex-col shrink-0 overflow-hidden">
             <div className="p-4 overflow-x-auto md:overflow-y-auto no-scrollbar flex md:flex-col gap-2">
                {Object.entries(EVALUATION_GROUPS).map(([id, group]) => {
                  const isActive = activeGroup === id;
                  const groupGrades = formGrades.filter(g => g.group === id);
                  const avg = groupGrades.length > 0 ? Math.round(groupGrades.reduce((s, g) => s + g.score, 0) / group.categories.length) : 0;
                  return (
                    <button key={id} onClick={() => setActiveGroup(id)} className={`min-w-[110px] md:min-w-0 p-4 rounded-2xl text-left border-2 transition-all relative ${isActive ? 'bg-white border-red-600 shadow-lg' : 'bg-white/50 border-transparent opacity-60'}`}>
                      <div className={`p-1.5 rounded-lg w-fit mb-2 ${isActive ? 'bg-red-600 text-white' : 'bg-slate-200 text-slate-500'}`}>{GroupIcons[id]}</div>
                      <p className="text-[9px] font-black uppercase tracking-tight truncate">{group.name}</p>
                      <p className={`text-[10px] font-black ${avg >= 90 ? 'text-emerald-600' : 'text-red-600'}`}>{avg}%</p>
                    </button>
                  );
                })}
             </div>
          </div>

          <div className="flex-1 overflow-y-auto p-6 md:p-10 no-scrollbar">
            <div className="max-w-3xl mx-auto">
              <div className="flex items-center space-x-3 mb-8">
                 <div className="p-2 bg-slate-50 text-slate-400 rounded-lg">{GroupIcons[activeGroup]}</div>
                 <h3 className="text-xl font-black text-slate-800 tracking-tight uppercase italic">{(EVALUATION_GROUPS as any)[activeGroup].name}</h3>
              </div>
              <div className="space-y-2">
                {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                  const score = formGrades.find(g => g.group === activeGroup && g.category === cat)?.score ?? 0;
                  return (
                    <div key={cat} className="bg-slate-50/50 hover:bg-white border-2 border-slate-100 hover:border-red-400 rounded-2xl p-4 transition-all flex items-center justify-between gap-4">
                      <div className="flex-1">
                        <label className="text-[10px] font-black text-slate-600 uppercase mb-2 block truncate">{cat}</label>
                        <div className="h-1.5 bg-slate-100 rounded-full overflow-hidden"><div className={`h-full transition-all ${score >= 90 ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${score}%`}} /></div>
                      </div>
                      <div className="relative">
                        <input type="number" value={score === 0 ? '' : score} onChange={e => handleScoreChange(activeGroup, cat, e.target.value)} className="w-16 px-2 py-3 bg-white border-2 border-slate-200 rounded-xl text-lg font-black text-center outline-none focus:border-red-500" />
                        <span className="absolute -right-1 -top-1 text-[7px] font-black bg-slate-800 text-white px-1 rounded shadow">%</span>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>

        <div className="p-6 border-t border-slate-100 bg-slate-50 flex justify-between items-center shrink-0">
          <div className="hidden md:flex items-center text-[10px] font-bold text-slate-400 uppercase tracking-widest"><Info className="w-4 h-4 mr-2" /> Los datos se guardan en la nube automáticamente</div>
          <div className="flex gap-3 w-full md:w-auto">
            <button onClick={onClose} className="flex-1 px-8 py-3 text-[10px] font-black text-slate-400 uppercase tracking-widest">Cancelar</button>
            <button onClick={saveGrades} className="flex-1 px-10 py-3.5 bg-red-600 text-white text-[10px] font-black rounded-xl shadow-lg uppercase tracking-widest active:scale-95"><Save className="w-4 h-4 mr-2 inline" /> Registrar Notas</button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default GradeEditor;

import React, { useState, useMemo, useEffect } from 'react';
