const parseExcelDate = (serial: any) => {
  if (!serial) return '';
  if (typeof serial === 'string') return serial;
  try {
    const date = XLSX.SSF.parse_date_code(serial);
    const month = String(date.m).padStart(2, '0');
    const day = String(date.d).padStart(2, '0');
    return `${date.y}-${month}-${day}`;
  } catch (e) {
    return String(serial);
  }
};

export const dataService = {
  supabaseFetch: async (table: string, method: string = 'GET', body?: any) => {
    const options: any = {
      method,
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': method === 'POST' ? 'resolution=merge-duplicates' : ''
      }
    };
    if (body) options.body = JSON.stringify(body);

    try {
      const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}`, options);
      if (!res.ok) {
        if (res.status === 404) return null;
        return null;
      }
      if (method === 'GET') return await res.json();
      return true;
    } catch (e) {
      console.error(`Error de red en ${table}:`, e);
      return null;
    }
  },

  loadAllFromCloud: async () => {
    try {
      const cloudEmployees = await dataService.supabaseFetch('employees');
      const cloudRestaurants = await dataService.supabaseFetch('restaurants');
      const cloudGrades = await dataService.supabaseFetch('grades');
      const cloudHierarchy = await dataService.supabaseFetch('hierarchy');

      // Si hay datos en la nube, los guardamos localmente
      if (cloudEmployees && cloudEmployees.length > 0) localStorage.setItem('la_akademia_employees', JSON.stringify(cloudEmployees));
      if (cloudRestaurants && cloudRestaurants.length > 0) localStorage.setItem('la_akademia_stores', JSON.stringify(cloudRestaurants));
      if (cloudGrades && cloudGrades.length > 0) localStorage.setItem('la_akademia_grades', JSON.stringify(cloudGrades));
      if (cloudHierarchy && cloudHierarchy.length > 0) {
        localStorage.setItem('la_akademia_hierarchy', JSON.stringify(cloudHierarchy[0].data));
      }

      // SI LA NUBE ESTÁ VACÍA PERO TENEMOS DATOS LOCALES, LOS SUBIMOS DE UNA VEZ
      const localEmps = dataService.getEmployees();
      if ((!cloudEmployees || cloudEmployees.length === 0) && localEmps.length > 0) {
        console.log("Subiendo datos locales iniciales a la nube...");
        await dataService.saveEmployees(localEmps);
        await dataService.saveRestaurants(dataService.getRestaurants());
        await dataService.saveHierarchy(dataService.getHierarchy());
        await dataService.saveGrades(dataService.getGrades());
      }

      return true;
    } catch (e) {
      return false;
    }
  },

  getEmployees: (): Employee[] => {
    const data = localStorage.getItem('la_akademia_employees');
    return data ? JSON.parse(data) : [];
  },

  saveEmployees: async (employees: Employee[]) => {
    localStorage.setItem('la_akademia_employees', JSON.stringify(employees));
    await dataService.supabaseFetch('employees', 'POST', employees);
  },

  getRestaurants: (): Restaurant[] => {
    const data = localStorage.getItem('la_akademia_stores');
    return data ? JSON.parse(data) : [];
  },

  saveRestaurants: async (stores: Restaurant[]) => {
    localStorage.setItem('la_akademia_stores', JSON.stringify(stores));
    await dataService.supabaseFetch('restaurants', 'POST', stores);
  },

  getGrades: (): GradeEntry[] => {
    const data = localStorage.getItem('la_akademia_grades');
    return data ? JSON.parse(data) : [];
  },

  saveGrades: async (grades: GradeEntry[]) => {
    localStorage.setItem('la_akademia_grades', JSON.stringify(grades));
    // Subir notas (máximo 1000 a la vez por limites de API)
    await dataService.supabaseFetch('grades', 'POST', grades.slice(-2000));
  },

  getHierarchy: (): HierarchyData => {
    const data = localStorage.getItem('la_akademia_hierarchy');
    return data ? JSON.parse(data) : { regions: [] };
  },

  saveHierarchy: async (hierarchy: HierarchyData) => {
    localStorage.setItem('la_akademia_hierarchy', JSON.stringify(hierarchy));
    await dataService.supabaseFetch('hierarchy', 'POST', { id: 1, data: hierarchy });
  },

  getUsers: (): User[] => {
    const data = localStorage.getItem('la_akademia_users');
    return data ? JSON.parse(data) : [{ id: 'admin1', username: 'admin', password: '123', role: UserRole.ADMIN, assignedZones: [], assignedRestaurants: [] }];
  },

  updateUser: (updatedUser: User) => {
    const users = dataService.getUsers();
    const index = users.findIndex(u => u.id === updatedUser.id);
    if (index !== -1) {
      users[index] = updatedUser;
      localStorage.setItem('la_akademia_users', JSON.stringify(users));
    }
  },

  importMonthlyExcel: async (rawData: any[]) => {
    const currentEmployees = dataService.getEmployees();
    const currentStores = dataService.getRestaurants();
    const today = new Date().toISOString().split('T')[0];

    const importedIds = new Set();
    const filteredRawData = rawData.filter(item => {
      const storeId = String(item.Nombre_Ceco || item.nombre_ceco || '').trim().toUpperCase();
      return !storeId.startsWith('H');
    });

    const importedEmployees = filteredRawData.map(item => {
      const storeId = String(item.Nombre_Ceco || item.nombre_ceco || 'SIN_CECO').trim().toUpperCase();
      const docId = String(item.Documento || item.documento || '').trim();
      if (!docId) return null;
      importedIds.add(docId);

      let assignedZone = 'Sin Clasificar';
      const storeInfo = currentStores.find(s => s.id === storeId);
      if (storeInfo) assignedZone = storeInfo.zone;

      const existing = currentEmployees.find(e => e.id === docId);
      const rawStatus = String(item.Estado || item.estado || '').trim().toUpperCase();
      const isActive = rawStatus.startsWith('ACTIVO');

      const emp: Employee = {
        id: docId,
        name: item["Nombre completo"] || item.nombre || 'Sin Nombre',
        joinDate: parseExcelDate(item["Fecha de ingreso"] || item.fecha_de_get_ingreso),
        title: (item.Cargo || item.cargo) as JobTitle,
        restaurantId: storeId,
        zone: assignedZone,
        active: isActive,
        history: existing?.history || []
      };

      if (existing) {
        if (existing.restaurantId !== storeId) {
          emp.history = [...(existing.history || []), { date: today, restaurantName: existing.restaurantId, action: 'TRASLADO' }];
        }
        if (existing.active && !isActive) {
           emp.history = [...(existing.history || []), { date: today, restaurantName: storeId, action: 'RETIRO' }];
        }
      } else {
        emp.history = [{ date: emp.joinDate || today, restaurantName: storeId, action: 'INGRESO' }];
      }
      return emp;
    }).filter(e => e !== null) as Employee[];

    const retired = currentEmployees
      .filter(e => !importedIds.has(e.id) && e.active)
      .map(e => ({
        ...e,
        active: false,
        history: [...(e.history || []), { date: today, restaurantName: e.restaurantId, action: 'RETIRO' as const }]
      }));

    const finalEmployees = [...importedEmployees, ...retired];
    await dataService.saveEmployees(finalEmployees);
    return { count: importedEmployees.length };
  },

  importHierarchyExcel: async (rawData: any[]) => {
    const newHierarchy: HierarchyData = { regions: [] };
    const newRestaurants: Restaurant[] = [];
    rawData.forEach(item => {
      const storeName = String(item["Nombre de tienda"] || "").trim().toUpperCase();
      const zoneName = String(item["Jefe de area"] || "Sin Zona").trim();
      const regionName = String(item["Region"] || "Sin Region").trim();
      if (!storeName) return;
      let region = newHierarchy.regions.find(r => r.name === regionName);
      if (!region) {
        region = { name: regionName, zones: [] };
        newHierarchy.regions.push(region);
      }
      let zone = region.zones.find(z => z.name === zoneName);
      if (!zone) {
        zone = { name: zoneName, restaurantIds: [] };
        region.zones.push(zone);
      }
      zone.restaurantIds.push(storeName);
      newRestaurants.push({ id: storeName, name: storeName, zone: zoneName, region: regionName });
    });
    await dataService.saveRestaurants(newRestaurants);
    await dataService.saveHierarchy(newHierarchy);
    return newRestaurants.length;
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, UserRole, AuthState, Employee, Restaurant } from './types';
import { dataService } from './dataService';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import AdminPanel from './components/AdminPanel';
import Header from './components/Header';
import MyStores from './components/MyStores';
import EntriesExitsReport from './components/EntriesExitsReport';
import { Cloud, CloudOff, RefreshCw } from 'lucide-react';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({ user: null, isAuthenticated: false });
  const [activeTab, setActiveTab] = useState<'dashboard' | 'my-stores' | 'admin' | 'entries-exits'>('dashboard');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [selectedMonth, setSelectedMonth] = useState<string>(new Date().toISOString().slice(0, 7));
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [syncStatus, setSyncStatus] = useState<'syncing' | 'online' | 'offline'>('syncing');

  const refreshData = () => {
    setEmployees(dataService.getEmployees());
    setRestaurants(dataService.getRestaurants());
  };

  const initData = async () => {
    setSyncStatus('syncing');
    const success = await dataService.loadAllFromCloud();
    refreshData();
    setSyncStatus(success ? 'online' : 'offline');
  };

  useEffect(() => {
    initData();
    // Re-sincronizar cada 5 minutos automáticamente
    const interval = setInterval(initData, 5 * 60 * 1000);
    return () => clearInterval(interval);
  }, []);

  const handleLogin = (user: User) => {
    setAuth({ user, isAuthenticated: true });
    setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
  };

  const filteredEmployees = useMemo(() => {
    if (!auth.user) return [];
    if (auth.user.role === UserRole.ADMIN) return employees;

    return employees.filter(e => 
      auth.user?.assignedZones.includes(e.zone) || 
      auth.user?.assignedRestaurants.includes(e.restaurantId)
    );
  }, [employees, auth.user]);

  if (!auth.isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden relative">
      {/* Indicador de Estado de Nube */}
      <div className={`fixed bottom-6 right-6 z-[200] px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-widest shadow-2xl flex items-center gap-3 transition-all duration-500 border-2 ${
        syncStatus === 'syncing' ? 'bg-slate-900 border-red-500 text-white animate-pulse' :
        syncStatus === 'online' ? 'bg-white border-emerald-500 text-emerald-600' :
        'bg-white border-red-500 text-red-600'
      }`}>
        {syncStatus === 'syncing' ? <RefreshCw className="w-3 h-3 animate-spin" /> : 
         syncStatus === 'online' ? <Cloud className="w-3 h-3" /> : <CloudOff className="w-3 h-3" />}
        {syncStatus === 'syncing' ? 'Sincronizando...' : syncStatus === 'online' ? 'Nube Conectada' : 'Modo Offline'}
      </div>

      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 lg:hidden" 
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={(tab) => {
          setActiveTab(tab as any);
          setIsSidebarOpen(false);
        }} 
        role={auth.user!.role}
        onLogout={handleLogout}
        isOpen={isSidebarOpen}
        setIsOpen={setIsSidebarOpen}
      />

      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header 
          user={auth.user!} 
          selectedMonth={selectedMonth} 
          onMonthChange={setSelectedMonth}
          onMenuClick={() => setIsSidebarOpen(true)}
        />

        <main className="flex-1 overflow-x-hidden overflow-y-auto p-4 md:p-6">
          {activeTab === 'dashboard' && (
            <Dashboard 
              employees={filteredEmployees} 
              restaurants={restaurants}
              selectedMonth={selectedMonth}
              user={auth.user!}
            />
          )}

          {activeTab === 'my-stores' && (
            <MyStores 
              user={auth.user!}
              restaurants={restaurants}
              employees={employees}
              selectedMonth={selectedMonth}
              onUpdate={refreshData}
            />
          )}

          {activeTab === 'entries-exits' && auth.user?.role === UserRole.ADMIN && (
            <EntriesExitsReport 
              employees={employees}
              restaurants={restaurants}
            />
          )}

          {activeTab === 'admin' && auth.user?.role === UserRole.ADMIN && (
            <AdminPanel 
              onEmployeesImported={refreshData}
            />
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Upload, UserPlus, X, Shield, FileSpreadsheet, Network, MapPin, Plus, Edit2, RotateCcw } from 'lucide-react';
import { dataService } from '../dataService';
import { UserRole, User, HierarchyData } from '../types';
import * as XLSX from 'xlsx';

interface AdminPanelProps {
  onEmployeesImported: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onEmployeesImported }) => {
  const [activeSubTab, setActiveSubTab] = useState<'import' | 'users' | 'hierarchy'>('import');
  const [importStatus, setImportStatus] = useState<string | null>(null);
  const [hierarchy, setHierarchy] = useState<HierarchyData>(dataService.getHierarchy());

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'employees' | 'hierarchy') => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    // Fix: Made the onload callback async to correctly handle the Promises returned by dataService
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws);
        if (type === 'employees') {
          // Fix: Await the async importMonthlyExcel call to access the 'count' property from the resolved value
          const res = await dataService.importMonthlyExcel(data);
          setImportStatus(`Carga exitosa: ${res.count} trabajadores.`);
        } else {
          // Fix: Await the async importHierarchyExcel call to get the resolved number count
          const count = await dataService.importHierarchyExcel(data);
          setImportStatus(`Éxito: ${count} tiendas sincronizadas.`);
        }
        onEmployeesImported();
        setTimeout(() => setImportStatus(null), 5000);
      } catch (err: any) { alert("Error en el archivo"); }
    };
    reader.readAsBinaryString(file);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-8 rounded-[32px] shadow-sm border border-slate-100">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
          <div className="flex items-center space-x-4">
            <div className="p-3 bg-red-600 text-white rounded-2xl shadow-lg"><Shield className="w-6 h-6" /></div>
            <div>
              <h2 className="text-xl font-black text-slate-800 tracking-tight uppercase italic">Admin KFC</h2>
              <div className="flex gap-2 mt-2">
