export const dataService = {
  supabaseFetch: async (table: string, method: string = 'GET', body?: any) => {
    // Para POST (Upsert), Supabase prefiere saber sobre qué columna hay conflicto
    const url = method === 'POST' 
      ? `${SUPABASE_URL}/rest/v1/${table}?on_conflict=id` 
      : `${SUPABASE_URL}/rest/v1/${table}`;

    const options: any = {
      method,
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': method === 'POST' ? 'resolution=merge-duplicates' : ''
      }
    };

    if (body) {
      // Limpiamos el body de undefined para evitar errores de JSON
      options.body = JSON.stringify(body, (key, value) => value === undefined ? null : value);
    }

    try {
      const res = await fetch(url, options);
      if (!res.ok) {
        const errorText = await res.text();
        console.error(`❌ ERROR SUPABASE en tabla [${table}]:`, {
          status: res.status,
          statusText: res.statusText,
          details: errorText,
          url: url
        });
        throw new Error(`Error ${res.status}: ${errorText}`);
      }
      if (method === 'GET') return await res.json();
      return true;
    } catch (e: any) {
      console.error(`🚨 Fallo de red o servidor en ${table}:`, e.message);
      throw e;
    }
  },

  loadAllFromCloud: async () => {
    try {
      const [cloudEmployees, cloudRestaurants, cloudGrades, cloudHierarchy] = await Promise.all([
        dataService.supabaseFetch('employees').catch(() => []),
        dataService.supabaseFetch('restaurants').catch(() => []),
        dataService.supabaseFetch('grades').catch(() => []),
        dataService.supabaseFetch('hierarchy').catch(() => [])
      ]);

      if (cloudEmployees?.length > 0) localStorage.setItem('la_akademia_employees', JSON.stringify(cloudEmployees));
      if (cloudRestaurants?.length > 0) localStorage.setItem('la_akademia_stores', JSON.stringify(cloudRestaurants));
      if (cloudGrades?.length > 0) localStorage.setItem('la_akademia_grades', JSON.stringify(cloudGrades));
      if (cloudHierarchy?.length > 0 && cloudHierarchy[0]?.data) {
        localStorage.setItem('la_akademia_hierarchy', JSON.stringify(cloudHierarchy[0].data));
      }

      return true;
    } catch (e) {
      return false;
    }
  },

