      console.log(`✅ Lote ${Math.floor(i/chunkSize) + 1} subido.`);
    }
  },

  getRestaurants: (): Restaurant[] => {
    const data = localStorage.getItem('la_akademia_stores');
    return data ? JSON.parse(data) : [];
  },

  saveRestaurants: async (stores: Restaurant[]) => {
    localStorage.setItem('la_akademia_stores', JSON.stringify(stores));
    await dataService.supabaseFetch('restaurants', 'POST', stores);
  },

