        {activeSubTab === 'users' && (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 animate-in fade-in duration-300">
            <button className="p-6 border-2 border-dashed border-slate-200 rounded-3xl flex flex-col items-center justify-center text-slate-400 hover:bg-slate-50 transition-colors"><Plus className="w-6 h-6 mb-2" /><span className="text-[9px] font-black uppercase">Nuevo Usuario</span></button>
            {dataService.getUsers().map(u => (
              <div key={u.id} className="bg-white p-4 rounded-3xl border border-slate-100 flex items-center justify-between shadow-sm"><div className="min-w-0"><p className="text-xs font-black text-slate-800 truncate uppercase">{u.username}</p><p className="text-[8px] font-black text-slate-400 uppercase mt-1">{u.role} • {u.assignedZones.length} áreas</p></div><Edit2 className="w-4 h-4 text-slate-200" /></div>
            ))}
