import React, { useState, useMemo, useEffect } from 'react';
import { Employee, Restaurant, JobHierarchy, User, UserRole } from '../types';
import { Search, Edit3, Filter, Users, MapPin, ChevronDown, User as UserIcon } from 'lucide-react';
import GradeEditor from './GradeEditor';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { dataService } from '../dataService';

interface EmployeeListProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
  onUpdate: () => void;
}

const EmployeeList: React.FC<EmployeeListProps> = ({ employees, restaurants, selectedMonth, user, onUpdate }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [filterStore, setFilterStore] = useState('all');
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    let zones = Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) zones = zones.filter(z => user.assignedZones.includes(z));
    return zones;
  }, [restaurants, filterRegion, user]);

  const dynamicStores = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    if (filterZone !== 'all') base = base.filter(r => r.zone === filterZone);
    if (user.role === UserRole.SPECIALIST) base = base.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));
    return base.sort((a, b) => a.name.localeCompare(b.name));
  }, [restaurants, filterRegion, filterZone, user]);

  const filteredAndSorted = useMemo(() => {
    let result = employees.filter(e => {
      if (user.role === UserRole.SPECIALIST && !e.active) return false;
      const store = restaurants.find(r => r.id === e.restaurant_id);
      const matchSearch = searchTerm === '' || e.name.toLowerCase().includes(searchTerm.toLowerCase()) || e.id.includes(searchTerm);
      const matchRegion = filterRegion === 'all' || store?.region === filterRegion;
      const matchZone = filterZone === 'all' || e.zone === filterZone;
      const matchStore = filterStore === 'all' || e.restaurant_id === filterStore;
      return matchSearch && matchRegion && matchZone && matchStore;
    });
    return result.sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));
  }, [employees, searchTerm, filterRegion, filterZone, filterStore, user, restaurants]);

  const getStatus = (employeeId: string) => {
    const grades = dataService.getGrades().filter(g => g.employeeId === employeeId && g.month === selectedMonth);
    if (grades.length === 0) return 'PENDING';
    const sum = grades.reduce((s, g) => s + g.score, 0);
    const avg = sum / TOTAL_CATEGORIES_COUNT;
    return avg >= APPROVAL_THRESHOLD ? 'APPROVED' : 'FAILED';
  };

  return (
    <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
      <div className="p-6 md:p-8 border-b border-slate-50 flex flex-col space-y-6">
        <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
          <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tight flex items-center uppercase italic shrink-0"><Users className="w-5 h-5 mr-3 text-red-600" /> Personal KFC</h2>
          <div className="relative flex-1 max-w-lg">
            <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <input type="text" placeholder="Buscar personal..." className="w-full pl-12 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl text-xs font-black" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
          </div>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
           <select className="p-3 bg-white border-2 border-slate-100 rounded-xl text-[10px] font-black uppercase" value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)}><option value="all">Region: Todas</option>{dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}</select>
           <select className="p-3 bg-white border-2 border-slate-100 rounded-xl text-[10px] font-black uppercase" value={filterZone} onChange={(e) => setFilterZone(e.target.value)}><option value="all">Zona: Todas</option>{dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}</select>
           <select className="p-3 bg-white border-2 border-slate-100 rounded-xl text-[10px] font-black uppercase" value={filterStore} onChange={(e) => setFilterStore(e.target.value)}><option value="all">Tienda: Todas</option>{dynamicStores.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}</select>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50/50">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Tienda</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Certificación</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {filteredAndSorted.map(emp => {
              const status = getStatus(emp.id);
              return (
                <tr key={emp.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-8 py-4"><p className="font-black text-slate-800 text-sm uppercase">{emp.name}</p><p className="text-[9px] text-slate-400 font-black uppercase">{emp.title}</p></td>
                  <td className="px-8 py-4 text-xs font-black text-slate-600 uppercase">{restaurants.find(r => r.id === emp.restaurant_id)?.name}</td>
                  <td className="px-8 py-4">
                    <span className={`px-3 py-1 text-[9px] font-black uppercase rounded-full ${status === 'APPROVED' ? 'bg-emerald-50 text-emerald-600' : status === 'FAILED' ? 'bg-red-50 text-red-600' : 'bg-slate-50 text-slate-400'}`}>
                      {status === 'APPROVED' ? 'Aprobado' : status === 'FAILED' ? 'Reprobado' : 'Pendiente'}
                    </span>
                  </td>
                  <td className="px-8 py-4 text-center"><button onClick={() => setEditingEmployee(emp)} className="p-3 text-slate-300 hover:text-red-600 transition-all"><Edit3 className="w-5 h-5" /></button></td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
      {editingEmployee && <GradeEditor employee={editingEmployee} month={selectedMonth} onClose={() => { setEditingEmployee(null); onUpdate(); }} />}
    </div>
  );
};

export default EmployeeList;

import React, { useState, useEffect, useMemo } from 'react';
import { Employee, GradeEntry } from '../types';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { dataService } from '../dataService';
import { X, Save, User, Calendar, Clock, GraduationCap, Star, Trophy, ClipboardCheck, Vault, Info } from 'lucide-react';

interface GradeEditorProps {
  employee: Employee;
  month: string;
  onClose: () => void;
}

const GroupIcons: Record<string, React.ReactNode> = {
  'A': <GraduationCap className="w-4 h-4" />,
  'B': <Star className="w-4 h-4" />,
  'C': <Trophy className="w-4 h-4" />,
  'D': <ClipboardCheck className="w-4 h-4" />,
  'E': <Vault className="w-4 h-4" />,
};

const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('A');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);

  useEffect(() => {
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    setFormGrades(existing);
  }, [employee, month]);

  const seniority = useMemo(() => {
    if (!employee.join_date) return "N/A";
    const start = new Date(employee.join_date);
    const now = new Date();
    let diff = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth());
    if (diff < 0) return "Reciente";
    const years = Math.floor(diff / 12);
    const months = diff % 12;
    return years === 0 ? `${months} meses` : `${years} años ${months} meses`;
  }, [employee.join_date]);

  const handleScoreChange = (group: string, category: string, scoreStr: string) => {
    let score = scoreStr === '' ? 0 : Math.max(0, Math.min(100, parseInt(scoreStr) || 0));
    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) { const next = [...prev]; next[idx] = { ...next[idx], score }; return next; }
      return [...prev, { employeeId: employee.id, month, group, category, score }];
    });
  };

  const saveGrades = () => {
    const all = dataService.getGrades().filter(g => !(g.employeeId === employee.id && g.month === month));
    dataService.saveGrades([...all, ...formGrades]);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/95 backdrop-blur-md p-0 md:p-6 animate-in fade-in duration-200">
      <div className="bg-white md:rounded-[40px] shadow-2xl w-full max-w-5xl h-full md:h-[90vh] flex flex-col overflow-hidden relative border-4 border-white">
        <div className="p-6 bg-slate-900 text-white shrink-0 relative">
          <button onClick={onClose} className="absolute top-6 right-6 p-2 bg-white/10 hover:bg-red-600 rounded-xl transition-all z-50"><X className="w-6 h-6"/></button>
          <div className="flex items-center space-x-4">
            <div className="w-14 h-14 bg-red-600 rounded-2xl flex items-center justify-center"><User className="w-8 h-8 text-white" /></div>
            <div>
              <div className="flex items-center gap-3">
                 <h2 className="text-xl font-black tracking-tight uppercase italic">{employee.name}</h2>
                 <div className="px-3 py-1 bg-red-600 text-[8px] font-black rounded-full uppercase tracking-widest">{employee.title}</div>
              </div>
              <div className="flex gap-4 opacity-50 mt-1 text-[9px] font-bold uppercase tracking-widest">
                <span className="flex items-center"><Calendar className="w-3 h-3 mr-1.5" /> {employee.join_date}</span>
                <span className="flex items-center"><Clock className="w-3 h-3 mr-1.5" /> Antigüedad: {seniority}</span>
              </div>
            </div>
          </div>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
          <div className="w-full md:w-60 bg-slate-50 border-r border-slate-200 flex flex-col shrink-0 overflow-hidden p-4 gap-2">
            {Object.entries(EVALUATION_GROUPS).map(([id, group]) => {
              const isActive = activeGroup === id;
              return (
                <button key={id} onClick={() => setActiveGroup(id)} className={`p-4 rounded-2xl text-left border-2 transition-all ${isActive ? 'bg-white border-red-600 shadow-lg' : 'bg-white/50 border-transparent opacity-60'}`}>
                  <div className={`p-1.5 rounded-lg w-fit mb-2 ${isActive ? 'bg-red-600 text-white' : 'bg-slate-200 text-slate-500'}`}>{GroupIcons[id]}</div>
                  <p className="text-[9px] font-black uppercase tracking-tight truncate">{group.name}</p>
                </button>
              );
            })}
          </div>

          <div className="flex-1 overflow-y-auto p-6 md:p-10">
            <div className="max-w-3xl mx-auto space-y-2">
              {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                const score = formGrades.find(g => g.group === activeGroup && g.category === cat)?.score ?? 0;
                return (
                  <div key={cat} className="bg-slate-50/50 hover:bg-white border-2 border-slate-100 hover:border-red-400 rounded-2xl p-4 transition-all flex items-center justify-between gap-4">
                    <div className="flex-1">
                      <label className="text-[10px] font-black text-slate-600 uppercase mb-2 block truncate">{cat}</label>
                      <div className="h-1.5 bg-slate-100 rounded-full overflow-hidden"><div className={`h-full transition-all ${score >= 90 ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${score}%`}} /></div>
                    </div>
                    <div className="relative">
                      <input type="number" value={score === 0 ? '' : score} onChange={e => handleScoreChange(activeGroup, cat, e.target.value)} className="w-16 px-2 py-3 bg-white border-2 border-slate-200 rounded-xl text-lg font-black text-center outline-none focus:border-red-500" />
                      <span className="absolute -right-1 -top-1 text-[7px] font-black bg-slate-800 text-white px-1 rounded shadow">%</span>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        <div className="p-6 border-t border-slate-100 bg-slate-50 flex justify-between items-center shrink-0">
          <div className="hidden md:flex items-center text-[10px] font-bold text-slate-400 uppercase tracking-widest"><Info className="w-4 h-4 mr-2" /> Los datos se guardan en la nube</div>
          <button onClick={saveGrades} className="w-full md:w-auto px-10 py-3.5 bg-red-600 text-white text-[10px] font-black rounded-xl shadow-lg uppercase tracking-widest active:scale-95"><Save className="w-4 h-4 mr-2 inline" /> Registrar Notas</button>
        </div>
      </div>
    </div>
  );
};

export default GradeEditor;

import React, { useMemo, useState } from 'react';
import { User, Restaurant, Employee, UserRole, JobHierarchy } from '../types';
import { Store, MapPin, Users, Award, ArrowLeft, User as UserIcon, TrendingUp } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import GradeEditor from './GradeEditor';

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
  onUpdate: () => void;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth, onUpdate }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  const assigned = useMemo(() => {
    return user.role === UserRole.ADMIN 
      ? restaurants 
      : restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));
  }, [user, restaurants]);

  const getStoreStats = (storeId: string) => {
    const storeEmps = employees.filter(e => e.restaurant_id === storeId);
    if (storeEmps.length === 0) return { total: 0, approved: 0, percent: 0 };
    let approved = 0;
    const grades = dataService.getGrades().filter(g => g.month === selectedMonth);
    storeEmps.forEach(emp => {
      const empGrades = grades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        const sum = empGrades.reduce((sum, g) => sum + g.score, 0);
        const avg = sum / TOTAL_CATEGORIES_COUNT;
        if (avg >= APPROVAL_THRESHOLD) approved++;
