    }).filter(e => e !== null) as Employee[];

    // Marcar como retirados a los que no están en el Excel nuevo pero estaban activos
    const retired = currentEmployees
      .filter(e => !importedIds.has(e.id) && e.active)
      .map(e => {
        const hasRetiroThisMonth = e.history?.some(h => h.action === 'RETIRO' && h.date.startsWith(currentMonth));
        return {
          ...e,
          active: false,
          history: hasRetiroThisMonth 
            ? e.history 
            : [...(e.history || []), { date: today, restaurantName: e.restaurant_id, action: 'RETIRO' as const }]
        };
      });

    const finalEmployees = [...importedEmployees, ...retired];
    await dataService.saveEmployees(finalEmployees);
    return { count: importedEmployees.length };
  },

  importHierarchyExcel: async (rawData: any[]) => {
    const stores: Restaurant[] = [];
    const hierarchy: HierarchyData = { regions: [] };

    rawData.forEach(item => {
      const regionName = String(item.Region || item.region || 'Sin Region').trim();
      const zoneName = String(item.Zona || item.zona || 'Sin Zona').trim();
      const storeId = String(item.Ceco || item.ceco || '').trim().toUpperCase();
      const storeName = String(item.Nombre || item.nombre || 'Tienda Sin Nombre').trim();

      if (!storeId || storeId.startsWith('H')) return;

      stores.push({
        id: storeId,
        name: storeName,
        zone: zoneName,
        region: regionName
      });

      let region = hierarchy.regions.find(r => r.name === regionName);
      if (!region) {
        region = { name: regionName, zones: [] };
        hierarchy.regions.push(region);
      }

      let zone = region.zones.find(z => z.name === zoneName);
      if (!zone) {
        zone = { name: zoneName, restaurantIds: [] };
        region.zones.push(zone);
      }

      if (!zone.restaurantIds.includes(storeId)) {
        zone.restaurantIds.push(storeId);
      }
    });

    if (stores.length > 0) {
      await dataService.saveRestaurants(stores);
      await dataService.saveHierarchy(hierarchy);
    }

    return stores.length;
  }
};

