    if (confirm("¿Estás seguro de eliminar este usuario?")) {
      try {
        await dataService.deleteUser(id);
        setUsers(users.filter(u => u.id !== id));
      } catch (e) {
        alert("Error al eliminar usuario");
      }
    }
  };

