            {users.map(u => (
              <div key={u.id} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm group hover:border-red-200 transition-all relative overflow-hidden">
                <div className="absolute top-0 right-0 p-4 opacity-0 group-hover:opacity-100 transition-opacity">
                  {u.username !== 'admin' && (
                    <button onClick={() => handleDeleteUser(u.id)} className="p-2 text-slate-300 hover:text-red-600 bg-slate-50 rounded-lg">
                      <Trash2 className="w-4 h-4" />
