                  )}
                </div>
                <div className="min-w-0">
                  <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center mb-3 text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-all">
