          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-lg overflow-hidden flex flex-col">
            <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
              <div>
                <h3 className="font-black uppercase italic tracking-tighter text-xl">Crear Acceso</h3>
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">Nuevo Especialista de Zona</p>
              </div>
              <button onClick={() => setShowUserModal(false)} className="p-2 hover:bg-white/10 rounded-xl transition-all"><X className="w-6 h-6"/></button>
            </div>
            <div className="p-8 space-y-6 overflow-y-auto max-h-[70vh]">
              <div className="grid grid-cols-2 gap-4">
