                  <input type="text" value={newUser.username} onChange={e => setNewUser({...newUser, username: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-bold outline-none focus:border-red-500 transition-all" placeholder="Ej: kfc_norte" />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block px-1">Contraseña</label>
                  <input type="password" value={newUser.password} onChange={e => setNewUser({...newUser, password: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-bold outline-none focus:border-red-500 transition-all" placeholder="••••••••" />
                </div>
              </div>

              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block px-1">Asignar Zonas ({newUser.assignedZones?.length})</label>
                <div className="grid grid-cols-2 gap-2 max-h-48 overflow-y-auto p-1 no-scrollbar">
                  {allZones.map(zone => (
                    <button 
                      key={zone} 
                      onClick={() => toggleZone(zone)}
                      className={`px-4 py-2.5 rounded-xl text-[9px] font-black uppercase text-left transition-all border-2 ${newUser.assignedZones?.includes(zone) ? 'bg-red-50 border-red-500 text-red-600' : 'bg-slate-50 border-transparent text-slate-400 hover:bg-slate-100'}`}
                    >
                      {zone}
                    </button>
                  ))}
                </div>
              </div>

              <div className="pt-4 border-t border-slate-50">
                 <button 
                  onClick={handleCreateUser}
                  className="w-full py-4 bg-red-600 text-white font-black rounded-2xl hover:bg-red-700 shadow-xl shadow-red-100 transition-all uppercase tracking-widest text-xs flex items-center justify-center gap-2"
                >
                  <CheckCircle2 className="w-4 h-4" /> Crear y Guardar en Nube
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

