import React, { useState, useEffect } from 'react';
import { User, UserRole } from '../types';
import { dataService } from '../dataService';
import { LogIn, RefreshCw, GraduationCap } from 'lucide-react';

interface LoginProps {
  onLogin: (user: User) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      // Intentar sincronizar usuarios antes de loguear por si hay nuevos
      await dataService.loadAllFromCloud();
      const users = dataService.getUsers();
      const user = users.find(u => u.username.toLowerCase() === username.toLowerCase() && u.password === password);

      if (user) {
        onLogin(user);
      } else {
        setError('Credenciales incorrectas. Verifica tu usuario y clave.');
      }
    } catch (err) {
      setError('Error de conexión con el servidor. Reintente.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-900 p-4 relative overflow-hidden">
      {/* Background Decor */}
      <div className="absolute top-0 right-0 -translate-y-1/2 translate-x-1/2 w-96 h-96 bg-red-600 rounded-full blur-[120px] opacity-20" />
      <div className="absolute bottom-0 left-0 translate-y-1/2 -translate-x-1/2 w-96 h-96 bg-red-600 rounded-full blur-[120px] opacity-10" />

      <div className="bg-white p-8 md:p-12 rounded-[48px] shadow-2xl w-full max-w-md relative z-10 border border-white/20">
        <div className="flex flex-col items-center mb-10">
          <div className="w-20 h-20 bg-red-50 rounded-[28px] flex items-center justify-center mb-6 shadow-xl shadow-red-50 transition-transform hover:rotate-6">
            <GraduationCap className="text-red-600 w-10 h-10" />
          </div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tighter uppercase italic">La Akademia</h1>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.3em] mt-2">KFC Management System</p>
        </div>

        <form onSubmit={handleLogin} className="space-y-6">
          <div className="space-y-1">
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Usuario</label>
            <input
              type="text"
              className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:bg-white focus:border-red-500 outline-none transition-all font-bold text-slate-800 placeholder:text-slate-300"
              placeholder="Ingresa tu ID"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              required
            />
          </div>

          <div className="space-y-1">
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Contraseña</label>
            <input
              type="password"
              className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:bg-white focus:border-red-500 outline-none transition-all font-bold text-slate-800 placeholder:text-slate-300"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
          </div>

          {error && (
            <div className="p-4 bg-red-50 border border-red-100 rounded-2xl animate-in shake duration-300">
              <p className="text-red-600 text-[10px] font-black uppercase text-center">{error}</p>
            </div>
          )}

          <button
            type="submit"
            disabled={loading}
            className="w-full bg-red-600 text-white font-black py-5 rounded-2xl hover:bg-red-700 transition-all shadow-2xl shadow-red-100 active:scale-95 flex items-center justify-center gap-3 uppercase tracking-widest text-xs"
          >
            {loading ? <RefreshCw className="w-5 h-5 animate-spin" /> : <LogIn className="w-5 h-5" />}
            {loading ? 'Validando...' : 'Entrar al Sistema'}
          </button>
        </form>

        <div className="mt-12 pt-8 border-t border-slate-50 text-center">
          <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest">© 2024 La Akademia KFC - Cloud Core v2.0</p>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useMemo, useState, useEffect } from 'react';
import { Employee, Restaurant, JobTitle } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { ArrowUpCircle, ArrowDownCircle, MapPin, Filter, Calendar, Briefcase, ChevronDown, Search } from 'lucide-react';

interface EntriesExitsReportProps {
  employees: Employee[];
  restaurants: Restaurant[];
}

const EntriesExitsReport: React.FC<EntriesExitsReportProps> = ({ employees, restaurants }) => {
  const currentYear = new Date().getFullYear();
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [filterStore, setFilterStore] = useState('all');
  const [selectedYear, setSelectedYear] = useState<string>(currentYear.toString());
  const [selectedMonthPart, setSelectedMonthPart] = useState<string>((new Date().getMonth() + 1).toString().padStart(2, '0'));
  const [viewDetail, setViewDetail] = useState<'entries' | 'exits' | 'none'>('none');

  const selectedMonthStr = `${selectedYear}-${selectedMonthPart}`;

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    return Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
  }, [restaurants, filterRegion]);
  const dynamicStores = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    if (filterZone !== 'all') base = base.filter(r => r.zone === filterZone);
    return base.sort((a, b) => a.name.localeCompare(b.name));
  }, [restaurants, filterRegion, filterZone]);

  const historyEvents = useMemo(() => {
    const events: any[] = [];
    employees.forEach(emp => {
      emp.history?.forEach(h => {
        if (h.action === 'INGRESO' || h.action === 'RETIRO') {
          const store = restaurants.find(r => r.id === h.restaurantName || r.name === h.restaurantName);
          const matchRegion = filterRegion === 'all' || store?.region === filterRegion;
          const matchZone = filterZone === 'all' || store?.zone === filterZone;
          const matchStore = filterStore === 'all' || store?.id === filterStore;

          if (matchRegion && matchZone && matchStore) {
            events.push({ 
              ...h, 
              employeeName: emp.name, 
              employeeTitle: emp.title, 
              month: h.date.slice(0, 7), 
              year: h.date.slice(0, 4) 
            });
          }
        }
      });
    });
    return events;
  }, [employees, restaurants, filterRegion, filterZone, filterStore]);

  const statsByCargo = useMemo(() => {
    const cargoMap: Record<string, { cargo: string, ingresos: number, retiros: number }> = {};
    historyEvents.filter(e => e.month === selectedMonthStr).forEach(e => {
      const title = e.employeeTitle || 'Otro';
      if (!cargoMap[title]) cargoMap[title] = { cargo: title, ingresos: 0, retiros: 0 };
      if (e.action === 'INGRESO') cargoMap[title].ingresos++;
      if (e.action === 'RETIRO') cargoMap[title].retiros++;
    });
    return Object.values(cargoMap).sort((a, b) => (b.ingresos + b.retiros) - (a.ingresos + a.retiros));
  }, [historyEvents, selectedMonthStr]);

  const yearChartData = useMemo(() => {
    const months = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
    return months.map((name, idx) => {
      const mStr = `${selectedYear}-${String(idx + 1).padStart(2, '0')}`;
      const entries = historyEvents.filter(e => e.month === mStr && e.action === 'INGRESO').length;
      const exits = historyEvents.filter(e => e.month === mStr && e.action === 'RETIRO').length;
      return { name, ingresos: entries, retiros: exits };
    });
  }, [historyEvents, selectedYear]);

  const monthStats = useMemo(() => ({
    entries: historyEvents.filter(e => e.month === selectedMonthStr && e.action === 'INGRESO').length,
    exits: historyEvents.filter(e => e.month === selectedMonthStr && e.action === 'RETIRO').length
  }), [historyEvents, selectedMonthStr]);

  const selectStyle = "w-full px-4 py-2.5 bg-white border-2 border-slate-300 rounded-xl text-[11px] font-black text-slate-800 uppercase tracking-widest outline-none focus:border-red-500 transition-colors shadow-sm appearance-none cursor-pointer";

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-8 rounded-[32px] border border-slate-200 shadow-lg">
        <h3 className="text-sm font-black text-slate-900 uppercase tracking-[0.2em] mb-6 flex items-center">
          <Filter className="w-4 h-4 mr-2 text-red-600" /> Filtros de Reporte
        </h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-5 gap-4 mb-8">
          <div className="space-y-1.5">
            <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">Año</label>
            <div className="relative">
              <select className={selectStyle} value={selectedYear} onChange={e => setSelectedYear(e.target.value)}>
                {[currentYear, currentYear-1, currentYear-2].map(y => <option key={y} value={y}>{y}</option>)}
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
          </div>
          <div className="space-y-1.5">
            <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">Mes</label>
            <div className="relative">
              <select className={selectStyle} value={selectedMonthPart} onChange={e => setSelectedMonthPart(e.target.value)}>
                {['01','02','03','04','05','06','07','08','09','10','11','12'].map((m, idx) => (
                  <option key={m} value={m}>{['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'][idx]}</option>
                ))}
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
          </div>
          <div className="space-y-1.5">
            <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
            <div className="relative">
              <select className={selectStyle} value={filterRegion} onChange={e => setFilterRegion(e.target.value)}>
                <option value="all">Todas las Regiones</option>
                {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
          </div>
          <div className="space-y-1.5">
            <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
            <div className="relative">
              <select className={selectStyle} value={filterZone} onChange={e => setFilterZone(e.target.value)}>
                <option value="all">Todas las Zonas</option>
                {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
          </div>
          <div className="space-y-1.5">
            <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">Tienda</label>
            <div className="relative">
              <select className={selectStyle} value={filterStore} onChange={e => setFilterStore(e.target.value)}>
                <option value="all">Todas las Tiendas</option>
                {dynamicStores.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="space-y-6">
            <div className="grid grid-cols-2 gap-4">
              <button 
                onClick={() => setViewDetail('entries')} 
                className={`p-5 rounded-3xl border-2 transition-all flex flex-col items-center group ${viewDetail === 'entries' ? 'bg-emerald-50 border-emerald-500 shadow-xl scale-105' : 'bg-slate-50 border-transparent hover:border-slate-200'}`}
              >
                <div className={`p-2 rounded-xl mb-2 ${viewDetail === 'entries' ? 'bg-emerald-500 text-white' : 'bg-white text-emerald-600 shadow-sm'}`}>
                  <ArrowUpCircle className="w-6 h-6" />
                </div>
                <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Ingresos</p>
                <p className="text-3xl font-black text-slate-900 mt-1">{monthStats.entries}</p>
              </button>
              <button 
                onClick={() => setViewDetail('exits')} 
                className={`p-5 rounded-3xl border-2 transition-all flex flex-col items-center group ${viewDetail === 'exits' ? 'bg-red-50 border-red-500 shadow-xl scale-105' : 'bg-slate-50 border-transparent hover:border-slate-200'}`}
              >
                <div className={`p-2 rounded-xl mb-2 ${viewDetail === 'exits' ? 'bg-red-500 text-white' : 'bg-white text-red-600 shadow-sm'}`}>
                  <ArrowDownCircle className="w-6 h-6" />
                </div>
                <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Retiros</p>
                <p className="text-3xl font-black text-slate-900 mt-1">{monthStats.exits}</p>
              </button>
            </div>

            <div className="bg-slate-50/80 p-6 rounded-3xl border border-slate-100">
               <h4 className="text-[9px] font-black uppercase text-slate-600 tracking-[0.2em] mb-6 flex items-center">
                 <Briefcase className="w-4 h-4 mr-2 text-slate-400" /> Movimientos por Cargo
               </h4>
               <div className="h-[240px]">
                 <ResponsiveContainer width="100%" height="100%">
                   <BarChart data={statsByCargo} layout="vertical" margin={{ left: 20 }}>
                      <XAxis type="number" hide />
