             <span className="text-[10px] font-black bg-slate-100 px-4 py-1.5 rounded-full uppercase text-slate-400">Filtrado por Jerarquía</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50">
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
