                          <UserIcon className="w-5 h-5" />
                        </div>
                        <div>
                          <p className="font-black text-slate-800 text-[13px] uppercase italic leading-tight group-hover:text-red-600 transition-colors">{emp.name}</p>
                          <p className="text-[9px] text-slate-400 font-black uppercase tracking-widest mt-0.5">ID: {emp.id}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex items-center gap-2">
                        <div className="p-1.5 bg-slate-100 rounded-lg text-slate-400">
                          <Briefcase className="w-3.5 h-3.5" />
                        </div>
                        <span className="text-[11px] font-black text-slate-700 uppercase italic tracking-tight">{emp.title}</span>
                      </div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <button 
                        onClick={() => setEditingEmployee(emp)} 
