const parseExcelDate = (serial: any) => {
  if (!serial) return '';
  if (typeof serial === 'string') return serial;
  try {
    const date = XLSX.SSF.parse_date_code(serial);
    const month = String(date.m).padStart(2, '0');
    const day = String(date.d).padStart(2, '0');
    return `${date.y}-${month}-${day}`;
  } catch (e) {
    return String(serial);
  }
};

export const dataService = {
  supabaseFetch: async (table: string, method: string = 'GET', body?: any, queryParams: string = '') => {
    const url = `${SUPABASE_URL}/rest/v1/${table}${queryParams}`;
    const options: any = {
      method,
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': method === 'POST' ? 'resolution=merge-duplicates' : 'return=representation'
      }
    };
    if (body) options.body = JSON.stringify(body, (k, v) => v === undefined ? null : v);

    const res = await fetch(url, options);
    if (!res.ok) {
      const error = await res.text();
      throw new Error(`Supabase Error [${table}]: ${error}`);
    }
    return method === 'GET' || options.headers['Prefer'].includes('return=representation') ? await res.json() : true;
  },

  supabaseFetchAll: async (table: string): Promise<any[]> => {
    let allData: any[] = [];
    let from = 0;
    const step = 1000;
    let hasMore = true;
    while (hasMore) {
      const url = `${SUPABASE_URL}/rest/v1/${table}?select=*&offset=${from}&limit=${step}`;
      const res = await fetch(url, { headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` } });
      const data = await res.json();
      allData = [...allData, ...data];
      if (data.length < step) hasMore = false; else from += step;
    }
    return allData;
  },

  loadAllFromCloud: async () => {
    try {
      const [employees, restaurants, grades, hierarchy, users] = await Promise.all([
        dataService.supabaseFetchAll('employees'),
        dataService.supabaseFetchAll('restaurants'),
        dataService.supabaseFetchAll('grades'),
        dataService.supabaseFetch('hierarchy'),
        dataService.supabaseFetchAll('users').catch(() => [])
      ]);

      localStorage.setItem('la_akademia_employees', JSON.stringify(employees));
      localStorage.setItem('la_akademia_stores', JSON.stringify(restaurants));
      localStorage.setItem('la_akademia_grades', JSON.stringify(grades));
      localStorage.setItem('la_akademia_users', JSON.stringify(users));

      const defaultHierarchy = { lockedMonths: [], regions: [] };
      const cloudHierarchy = (hierarchy && hierarchy[0]?.data) ? hierarchy[0].data : defaultHierarchy;
      localStorage.setItem('la_akademia_hierarchy', JSON.stringify(cloudHierarchy));
      return true;
    } catch (e) {
      return false;
    }
  },

  getEmployees: (): Employee[] => JSON.parse(localStorage.getItem('la_akademia_employees') || '[]'),
  getRestaurants: (): Restaurant[] => JSON.parse(localStorage.getItem('la_akademia_stores') || '[]'),
  getGrades: (): GradeEntry[] => JSON.parse(localStorage.getItem('la_akademia_grades') || '[]'),
  getHierarchy: (): HierarchyData => JSON.parse(localStorage.getItem('la_akademia_hierarchy') || '{"lockedMonths":[], "regions":[]}'),
  getUsers: (): User[] => {
    const local = JSON.parse(localStorage.getItem('la_akademia_users') || '[]');
    if (local.length === 0) return [{ id: 'admin-master', username: 'admin', password: '123', role: UserRole.ADMIN, assignedZones: [], assignedRestaurants: [] }];
    return local;
  },

  saveEmployees: async (employees: Employee[]) => {
    localStorage.setItem('la_akademia_employees', JSON.stringify(employees));
    const chunkSize = 100;
    for (let i = 0; i < employees.length; i += chunkSize) {
      await dataService.supabaseFetch('employees', 'POST', employees.slice(i, i + chunkSize), '?on_conflict=id');
    }
  },

  saveRestaurants: async (stores: Restaurant[]) => {
    localStorage.setItem('la_akademia_stores', JSON.stringify(stores));
    await dataService.supabaseFetch('restaurants', 'POST', stores, '?on_conflict=id');
  },

  saveGrades: async (grades: GradeEntry[]) => {
    localStorage.setItem('la_akademia_grades', JSON.stringify(grades));
    const gradesWithId = grades.map(g => ({
      ...g,
      id: `${g.employeeId}_${g.month}_${g.group}_${g.category}`.replace(/\s+/g, '_')
    }));
    const chunkSize = 100;
    for (let i = 0; i < gradesWithId.length; i += chunkSize) {
      await dataService.supabaseFetch('grades', 'POST', gradesWithId.slice(i, i + chunkSize), '?on_conflict=id');
    }
  },

  saveHierarchy: async (hierarchy: HierarchyData) => {
    localStorage.setItem('la_akademia_hierarchy', JSON.stringify(hierarchy));
    await dataService.supabaseFetch('hierarchy', 'POST', { id: 1, data: hierarchy }, '?on_conflict=id');
  },

  saveUsers: async (users: User[]) => {
    localStorage.setItem('la_akademia_users', JSON.stringify(users));
    await dataService.supabaseFetch('users', 'POST', users, '?on_conflict=id');
  },

  deleteUser: async (userId: string) => {
    const url = `${SUPABASE_URL}/rest/v1/users?id=eq.${userId}`;
    const res = await fetch(url, {
      method: 'DELETE',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
    });
    if (!res.ok) throw new Error('No se pudo eliminar el usuario');
    const current = dataService.getUsers().filter(u => u.id !== userId);
    localStorage.setItem('la_akademia_users', JSON.stringify(current));
  },

  importMonthlyExcel: async (rawData: any[]) => {
    await dataService.loadAllFromCloud();
    const currentEmployees = dataService.getEmployees();
    const currentStores = dataService.getRestaurants();
    const today = new Date().toISOString().split('T')[0];

    const importedIds = new Set();
    const filteredRawData = rawData.filter(item => {
      const storeId = String(item.Nombre_Ceco || item.nombre_ceco || '').trim().toUpperCase();
      return storeId !== '' && !storeId.startsWith('H');
    });

    const importedEmployees = filteredRawData.map(item => {
      const storeId = String(item.Nombre_Ceco || item.nombre_ceco || 'SIN_CECO').trim().toUpperCase();
      const docId = String(item.Documento || item.documento || '').trim();
      if (!docId) return null;
      importedIds.add(docId);

      const existing = currentEmployees.find(e => e.id === docId);
      const rawStatus = String(item.Estado || item.estado || '').trim().toUpperCase();
      const isActive = rawStatus.startsWith('ACTIVO');

      const emp: Employee = {
        id: docId,
        name: String(item["Nombre completo"] || item.nombre || 'Sin Nombre').trim(),
        join_date: parseExcelDate(item["Fecha de ingreso"] || item.fecha_de_ingreso),
        title: (item.Cargo || item.cargo) as JobTitle,
        restaurant_id: storeId,
        zone: currentStores.find(s => s.id === storeId)?.zone || (existing?.zone || 'Sin Clasificar'),
        active: isActive,
        history: existing?.history || []
      };

      if (existing) {
        if (existing.restaurant_id !== storeId) {
           emp.history = [...(existing.history || []), { date: today, restaurantName: existing.restaurant_id, action: 'TRASLADO' }];
        }
        if (existing.active && !isActive) {
           emp.history = [...(existing.history || []), { date: today, restaurantName: storeId, action: 'RETIRO' }];
        }
        if (!existing.active && isActive) {
           emp.history = [...(existing.history || []), { date: today, restaurantName: storeId, action: 'INGRESO' }];
        }
      } else {
        emp.history = [{ date: emp.join_date || today, restaurantName: storeId, action: 'INGRESO' }];
      }
      return emp;
    }).filter(e => e !== null) as Employee[];

    // Retiros Implícitos: Si no están en el Excel y estaban activos, pasarlos a retirados
    const implicitRetires = currentEmployees
      .filter(e => !importedIds.has(e.id) && e.active)
      .map(e => ({
        ...e, 
        active: false, 
        history: [...(e.history || []), { date: today, restaurantName: e.restaurant_id, action: 'RETIRO' as const }]
      }));

    // Unir todo asegurando que no perdamos a los que ya estaban retirados de antes
    const allProcessed = [...importedEmployees];
    implicitRetires.forEach(ir => {
      if (!allProcessed.some(p => p.id === ir.id)) allProcessed.push(ir);
    });

    // Mantener a los retirados antiguos que no están en el Excel pero tampoco en los nuevos retiros implícitos
    currentEmployees.forEach(old => {
      if (!allProcessed.some(p => p.id === old.id)) {
        allProcessed.push(old);
      }
    });

    await dataService.saveEmployees(allProcessed);
    return { count: importedEmployees.length };
  },

  importHierarchyExcel: async (rawData: any[]) => {
    const current = dataService.getHierarchy();
    const stores: Restaurant[] = [];
    const hierarchy: HierarchyData = { lockedMonths: current.lockedMonths || [], regions: [] };

    rawData.forEach(item => {
      const regionName = String(item.Region || item.region || 'Sin Region').trim();
      const zoneName = String(item.Zona || item.zona || 'Sin Zona').trim();
      const storeId = String(item.Ceco || item.ceco || '').trim().toUpperCase();
      const storeName = String(item.Nombre || item.nombre || 'Tienda Sin Nombre').trim();
      if (!storeId || storeId.startsWith('H')) return;
      stores.push({ id: storeId, name: storeName, zone: zoneName, region: regionName });
      let r = hierarchy.regions.find(r => r.name === regionName);
      if (!r) { r = { name: regionName, zones: [] }; hierarchy.regions.push(r); }
      let z = r.zones.find(z => z.name === zoneName);
      if (!z) { z = { name: zoneName, restaurantIds: [] }; r.zones.push(z); }
      if (!z.restaurantIds.includes(storeId)) z.restaurantIds.push(storeId);
    });

    if (stores.length > 0) {
      await dataService.saveRestaurants(stores);
      await dataService.saveHierarchy(hierarchy);
    }
    return stores.length;
  }
};

import React, { useState, useMemo, useEffect } from 'react';
import { Upload, UserPlus, X, Shield, FileSpreadsheet, Network, MapPin, Plus, Edit2, RotateCcw, AlertCircle, Trash2, Key, CheckCircle2, Lock, Unlock } from 'lucide-react';
import { dataService } from '../dataService';
import { UserRole, User, HierarchyData } from '../types';
import * as XLSX from 'xlsx';

interface AdminPanelProps {
  onEmployeesImported: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onEmployeesImported }) => {
  const [activeSubTab, setActiveSubTab] = useState<'import' | 'users' | 'hierarchy' | 'periods'>('import');
  const [importStatus, setImportStatus] = useState<{message: string, isError: boolean} | null>(null);
  const [hierarchy, setHierarchy] = useState<HierarchyData>(dataService.getHierarchy());
  const [users, setUsers] = useState<User[]>(dataService.getUsers());
  const [showUserModal, setShowUserModal] = useState(false);

  const [newUser, setNewUser] = useState<Partial<User>>({
    username: '',
    password: '',
    role: UserRole.SPECIALIST,
    assignedZones: [],
    assignedRestaurants: []
  });

  const allZones = useMemo(() => {
    const zones = new Set<string>();
    hierarchy.regions.forEach(r => r.zones.forEach(z => zones.add(z.name)));
    return Array.from(zones).sort();
  }, [hierarchy]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'employees' | 'hierarchy') => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImportStatus({ message: 'Procesando archivo...', isError: false });
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws);
        if (type === 'employees') {
          const res = await dataService.importMonthlyExcel(data);
          setImportStatus({ message: `Carga exitosa: ${res.count} trabajadores sincronizados.`, isError: false });
        } else {
          const count = await dataService.importHierarchyExcel(data);
          setImportStatus({ message: `Éxito: ${count} tiendas sincronizadas correctamente.`, isError: false });
          setHierarchy(dataService.getHierarchy());
        }
        onEmployeesImported();
      } catch (err: any) { 
        setImportStatus({ message: `Error: ${err.message}`, isError: true }); 
      }
    };
    reader.readAsBinaryString(file);
  };

  const handleCreateUser = async () => {
    if (!newUser.username || !newUser.password) { alert("Usuario y contraseña requeridos"); return; }
    const userToSave: User = { id: `user_${Date.now()}`, username: newUser.username!, password: newUser.password!, role: newUser.role!, assignedZones: newUser.assignedZones || [], assignedRestaurants: newUser.assignedRestaurants || [] };
    try {
      const updatedUsers = [...users, userToSave];
      await dataService.saveUsers(updatedUsers);
      setUsers(updatedUsers);
      setShowUserModal(false);
      setNewUser({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [], assignedRestaurants: [] });
    } catch (e) { alert("Error al guardar en nube"); }
  };

  const handleDeleteUser = async (id: string) => {
    if (confirm("¿Eliminar usuario?")) {
      try { await dataService.deleteUser(id); setUsers(users.filter(u => u.id !== id)); } catch (e) { alert("Error al eliminar"); }
    }
  };

  const togglePeriodLock = async (month: string) => {
    const currentLocked = hierarchy.lockedMonths || [];
    const isLocked = currentLocked.includes(month);
    const updatedLocked = isLocked 
      ? currentLocked.filter(m => m !== month)
      : [...currentLocked, month];

    const updatedHierarchy = { ...hierarchy, lockedMonths: updatedLocked };
    await dataService.saveHierarchy(updatedHierarchy);
    setHierarchy(updatedHierarchy);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-8 rounded-[32px] shadow-sm border border-slate-100">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
          <div className="flex items-center space-x-4">
            <div className="p-3 bg-red-600 text-white rounded-2xl shadow-lg"><Shield className="w-6 h-6" /></div>
            <div>
              <h2 className="text-xl font-black text-slate-800 tracking-tight uppercase italic">Admin KFC</h2>
              <div className="flex flex-wrap gap-2 mt-2">
                {[
                  {id: 'import', label: 'Carga Excel'},
                  {id: 'hierarchy', label: 'Estructura'},
                  {id: 'users', label: 'Especialistas'},
                  {id: 'periods', label: 'Cierre de Mes'}
                ].map(tab => (
                  <button key={tab.id} onClick={() => setActiveSubTab(tab.id as any)} className={`text-[8px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full transition ${activeSubTab === tab.id ? 'bg-slate-900 text-white shadow-md' : 'bg-slate-100 text-slate-400'}`}>
                    {tab.label}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        {importStatus && (
          <div className={`mb-6 p-4 rounded-2xl flex items-center gap-3 animate-in slide-in-from-top-2 duration-300 ${importStatus.isError ? 'bg-red-50 text-red-700 border border-red-100' : 'bg-emerald-50 text-emerald-700 border border-emerald-100'}`}>
            {importStatus.isError ? <AlertCircle className="w-5 h-5 shrink-0" /> : <CheckCircle2 className="w-5 h-5 shrink-0" />}
            <p className="text-[10px] font-black uppercase tracking-widest">{importStatus.message}</p>
            <button onClick={() => setImportStatus(null)} className="ml-auto p-1 hover:bg-black/5 rounded-full"><X className="w-4 h-4"/></button>
          </div>
        )}

        {activeSubTab === 'import' && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-in fade-in">
            <label className="p-10 border-2 border-dashed border-slate-200 rounded-[32px] bg-slate-50/30 text-center cursor-pointer block hover:bg-red-50 hover:border-red-200 transition-all group">
              <FileSpreadsheet className="w-12 h-12 text-slate-200 mx-auto mb-4 group-hover:text-red-400 transition-colors" />
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sincronizar Trabajadores (.xlsx)</p>
              <input type="file" className="hidden" accept=".xlsx" onChange={e => handleFileUpload(e, 'employees')} />
            </label>
            <label className="p-10 border-2 border-dashed border-slate-200 rounded-[32px] bg-slate-50/30 text-center cursor-pointer block hover:bg-red-50 hover:border-red-200 transition-all group">
              <Network className="w-12 h-12 text-slate-200 mx-auto mb-4 group-hover:text-red-400 transition-colors" />
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sincronizar Estructura (.xlsx)</p>
              <input type="file" className="hidden" accept=".xlsx" onChange={e => handleFileUpload(e, 'hierarchy')} />
            </label>
          </div>
        )}

        {activeSubTab === 'periods' && (
          <div className="space-y-6 animate-in fade-in">
