const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('A');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);
  const [isSaving, setIsSaving] = useState(false);
  const [showHistory, setShowHistory] = useState(false);

  const hierarchy = dataService.getHierarchy();
  const isPeriodLocked = hierarchy.lockedMonths?.includes(month);

  useEffect(() => {
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    setFormGrades(existing);
  }, [employee, month]);

  const seniority = useMemo(() => {
    if (!employee.join_date) return "N/A";
    const start = new Date(employee.join_date);
    const now = new Date();
    let diff = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth());
    if (diff < 0) return "Reciente";
    const years = Math.floor(diff / 12);
    const months = diff % 12;
    return years === 0 ? `${months} meses` : `${years} años ${months} meses`;
  }, [employee.join_date]);

  const handleScoreChange = (group: string, category: string, scoreStr: string) => {
    if (isPeriodLocked) return;
    let score = scoreStr === '' ? 0 : Math.max(0, Math.min(100, parseInt(scoreStr) || 0));
    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) { 
        const next = [...prev]; 
        next[idx] = { ...next[idx], score }; 
        return next; 
      }
      return [...prev, { employeeId: employee.id, month, group, category, score }];
    });
  };

  const saveGrades = async () => {
    if (isPeriodLocked) return;
    setIsSaving(true);
    const all = dataService.getGrades().filter(g => !(g.employeeId === employee.id && g.month === month));
    await dataService.saveGrades([...all, ...formGrades]);
    setIsSaving(false);
    onClose();
