const parseExcelDate = (serial: any) => {
  if (!serial) return '';
  if (typeof serial === 'string') return serial;
  try {
    const date = XLSX.SSF.parse_date_code(serial);
    const month = String(date.m).padStart(2, '0');
    const day = String(date.d).padStart(2, '0');
    return `${date.y}-${month}-${day}`;
  } catch (e) {
    return String(serial);
  }
};

export const dataService = {
  supabaseFetch: async (table: string, method: string = 'GET', body?: any, queryParams: string = '') => {
    const url = `${SUPABASE_URL}/rest/v1/${table}${queryParams}`;
    const options: any = {
      method,
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': method === 'POST' ? 'resolution=merge-duplicates' : 'return=representation'
      }
    };
    if (body) options.body = JSON.stringify(body, (k, v) => v === undefined ? null : v);

    const res = await fetch(url, options);
    if (!res.ok) {
      const error = await res.text();
      throw new Error(`Supabase Error [${table}]: ${error}`);
    }

    // Corregido: Manejo de respuestas vacías (204) para evitar que el botón se quede en "guardando"
    if (res.status === 204) return true;
    const text = await res.text();
    return text ? JSON.parse(text) : true;
  },

  supabaseFetchAll: async (table: string): Promise<any[]> => {
    let allData: any[] = [];
    let from = 0;
    const step = 1000;
    let hasMore = true;
    while (hasMore) {
      const url = `${SUPABASE_URL}/rest/v1/${table}?select=*&offset=${from}&limit=${step}`;
      const res = await fetch(url, { headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` } });
      const data = await res.json();
      allData = [...allData, ...data];
      if (data.length < step) hasMore = false; else from += step;
    }
    return allData;
  },

  loadAllFromCloud: async () => {
    try {
      const [employees, restaurants, grades, hierarchy, users] = await Promise.all([
        dataService.supabaseFetchAll('employees'),
        dataService.supabaseFetchAll('restaurants'),
        dataService.supabaseFetchAll('grades'),
        dataService.supabaseFetch('hierarchy'),
        dataService.supabaseFetchAll('users').catch(() => [])
      ]);

      localStorage.setItem('la_akademia_employees', JSON.stringify(employees));
      localStorage.setItem('la_akademia_stores', JSON.stringify(restaurants));
      localStorage.setItem('la_akademia_grades', JSON.stringify(grades));
      localStorage.setItem('la_akademia_users', JSON.stringify(users));

      const defaultHierarchy = { lockedMonths: [], regions: [] };
      const cloudHierarchy = (hierarchy && hierarchy[0]?.data) ? hierarchy[0].data : defaultHierarchy;
      localStorage.setItem('la_akademia_hierarchy', JSON.stringify(cloudHierarchy));
      return true;
    } catch (e) {
      return false;
    }
  },

  getEmployees: (): Employee[] => JSON.parse(localStorage.getItem('la_akademia_employees') || '[]'),
  getRestaurants: (): Restaurant[] => JSON.parse(localStorage.getItem('la_akademia_stores') || '[]'),
  getGrades: (): GradeEntry[] => JSON.parse(localStorage.getItem('la_akademia_grades') || '[]'),
  getHierarchy: (): HierarchyData => JSON.parse(localStorage.getItem('la_akademia_hierarchy') || '{"lockedMonths":[], "regions":[]}'),
  getUsers: (): User[] => {
    const local = JSON.parse(localStorage.getItem('la_akademia_users') || '[]');
    if (local.length === 0) return [{ id: 'admin-master', username: 'admin', password: '123', role: UserRole.ADMIN, assignedZones: [], assignedRestaurants: [] }];
    return local;
  },

  saveEmployees: async (employees: Employee[]) => {
    localStorage.setItem('la_akademia_employees', JSON.stringify(employees));
    const chunkSize = 100;
    for (let i = 0; i < employees.length; i += chunkSize) {
      await dataService.supabaseFetch('employees', 'POST', employees.slice(i, i + chunkSize), '?on_conflict=id');
    }
  },

  clearEmployeesInCloud: async () => {
    // Eliminar todos los registros de trabajadores para re-importar de cero
    const url = `${SUPABASE_URL}/rest/v1/employees?id=neq.0`;
    await fetch(url, {
      method: 'DELETE',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
    });
    localStorage.setItem('la_akademia_employees', '[]');
  },

  saveRestaurants: async (stores: Restaurant[]) => {
    localStorage.setItem('la_akademia_stores', JSON.stringify(stores));
    await dataService.supabaseFetch('restaurants', 'POST', stores, '?on_conflict=id');
  },

  saveGrades: async (grades: GradeEntry[]) => {
    localStorage.setItem('la_akademia_grades', JSON.stringify(grades));
    const gradesWithId = grades.map(g => ({
      ...g,
      id: `${g.employeeId}_${g.month}_${g.group}_${g.category}`.replace(/\s+/g, '_')
    }));
    const chunkSize = 100;
    for (let i = 0; i < gradesWithId.length; i += chunkSize) {
      await dataService.supabaseFetch('grades', 'POST', gradesWithId.slice(i, i + chunkSize), '?on_conflict=id');
    }
  },

  saveHierarchy: async (hierarchy: HierarchyData) => {
    localStorage.setItem('la_akademia_hierarchy', JSON.stringify(hierarchy));
    await dataService.supabaseFetch('hierarchy', 'POST', { id: 1, data: hierarchy }, '?on_conflict=id');
  },

  saveUsers: async (users: User[]) => {
    localStorage.setItem('la_akademia_users', JSON.stringify(users));
    await dataService.supabaseFetch('users', 'POST', users, '?on_conflict=id');
  },

  deleteUser: async (userId: string) => {
    const url = `${SUPABASE_URL}/rest/v1/users?id=eq.${userId}`;
    const res = await fetch(url, {
      method: 'DELETE',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
    });
    if (!res.ok) throw new Error('No se pudo eliminar el usuario');
    const current = dataService.getUsers().filter(u => u.id !== userId);
    localStorage.setItem('la_akademia_users', JSON.stringify(current));
  },

  importMonthlyExcel: async (rawData: any[]) => {
    await dataService.loadAllFromCloud();
    const currentEmployees = dataService.getEmployees();
    const currentStores = dataService.getRestaurants();
    const today = new Date().toISOString().split('T')[0];

    const importedIds = new Set();
    const filteredRawData = rawData.filter(item => {
      const storeId = String(item.Nombre_Ceco || item.nombre_ceco || '').trim().toUpperCase();
      return storeId !== '' && !storeId.startsWith('H');
    });

    const importedEmployees = filteredRawData.map(item => {
      const storeId = String(item.Nombre_Ceco || item.nombre_ceco || 'SIN_CECO').trim().toUpperCase();
      const docId = String(item.Documento || item.documento || '').trim();
      if (!docId) return null;
      importedIds.add(docId);

      const existing = currentEmployees.find(e => e.id === docId);
      const rawStatus = String(item.Estado || item.estado || '').trim().toUpperCase();
      const isActiveInExcel = rawStatus.startsWith('ACTIVO');

      const emp: Employee = {
        id: docId,
        name: String(item["Nombre completo"] || item.nombre || 'Sin Nombre').trim(),
        join_date: parseExcelDate(item["Fecha de ingreso"] || item.fecha_de_ingreso),
        title: (item.Cargo || item.cargo) as JobTitle,
        restaurant_id: storeId,
        zone: currentStores.find(s => s.id === storeId)?.zone || (existing?.zone || 'Sin Clasificar'),
        active: isActiveInExcel,
        history: existing?.history || []
      };

      if (existing) {
        // Preservar historial antiguo
        emp.history = [...(existing.history || [])];

        // Traslado: Cambio de restaurante
        if (existing.restaurant_id !== storeId) {
           emp.history.push({ date: today, restaurantName: existing.restaurant_id, action: 'TRASLADO' });
        }

        // Retiro Explícito: Si en Excel dice "Retirado" y en DB estaba "Activo"
        if (existing.active && !isActiveInExcel) {
           emp.history.push({ date: today, restaurantName: storeId, action: 'RETIRO' });
        }

        // Reingreso: Si en Excel dice "Activo" y en DB estaba "Retirado"
        if (!existing.active && isActiveInExcel) {
           emp.history.push({ date: today, restaurantName: storeId, action: 'INGRESO' });
        }
      } else {
        // Nuevo Ingreso: Primer registro
        emp.history = [{ date: emp.join_date || today, restaurantName: storeId, action: 'INGRESO' }];
      }
      return emp;
    }).filter(e => e !== null) as Employee[];

    // Retiros Implícitos: No están en el Excel actual pero estaban activos en la base
    const implicitRetires = currentEmployees
      .filter(e => !importedIds.has(e.id) && e.active)
      .map(e => ({
        ...e, 
        active: false, 
        history: [...(e.history || []), { date: today, restaurantName: e.restaurant_id, action: 'RETIRO' as const }]
      }));

    // Unir todo: Los importados + los que se acaban de retirar implícitamente
    const allProcessed = [...importedEmployees];
    implicitRetires.forEach(ir => {
      if (!allProcessed.some(p => p.id === ir.id)) allProcessed.push(ir);
    });

    // Mantener a los retirados antiguos (los que ya estaban inactivos en la DB) para no borrarlos
    currentEmployees.forEach(old => {
      if (!allProcessed.some(p => p.id === old.id)) {
        allProcessed.push(old);
      }
    });

    await dataService.saveEmployees(allProcessed);
    return { count: importedEmployees.length };
  },

  importHierarchyExcel: async (rawData: any[]) => {
    const current = dataService.getHierarchy();
    const stores: Restaurant[] = [];
    const hierarchy: HierarchyData = { lockedMonths: current.lockedMonths || [], regions: [] };

    rawData.forEach(item => {
      const regionName = String(item.Region || item.region || 'Sin Region').trim();
      const zoneName = String(item.Zona || item.zona || 'Sin Zona').trim();
      const storeId = String(item.Ceco || item.ceco || '').trim().toUpperCase();
      const storeName = String(item.Nombre || item.nombre || 'Tienda Sin Nombre').trim();
      if (!storeId || storeId.startsWith('H')) return;
      stores.push({ id: storeId, name: storeName, zone: zoneName, region: regionName });
      let r = hierarchy.regions.find(r => r.name === regionName);
      if (!r) { r = { name: regionName, zones: [] }; hierarchy.regions.push(r); }
      let z = r.zones.find(z => z.name === zoneName);
      if (!z) { z = { name: zoneName, restaurantIds: [] }; r.zones.push(z); }
      if (!z.restaurantIds.includes(storeId)) z.restaurantIds.push(storeId);
    });

    if (stores.length > 0) {
      await dataService.saveRestaurants(stores);
      await dataService.saveHierarchy(hierarchy);
    }
    return stores.length;
  }
};

import { dataService } from '../dataService';
import { UserRole, User, HierarchyData } from '../types';
import * as XLSX from 'xlsx';

interface AdminPanelProps {
  onEmployeesImported: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onEmployeesImported }) => {
  const [activeSubTab, setActiveSubTab] = useState<'import' | 'users' | 'hierarchy' | 'periods'>('import');
  const [importStatus, setImportStatus] = useState<{message: string, isError: boolean} | null>(null);
  const [hierarchy, setHierarchy] = useState<HierarchyData>(dataService.getHierarchy());
  const [users, setUsers] = useState<User[]>(dataService.getUsers());
  const [showUserModal, setShowUserModal] = useState(false);
  const [isClearing, setIsClearing] = useState(false);

  const [newUser, setNewUser] = useState<Partial<User>>({
    username: '',
    password: '',
    role: UserRole.SPECIALIST,
    assignedZones: [],
    assignedRestaurants: []
  });

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'employees' | 'hierarchy') => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImportStatus({ message: 'Procesando archivo...', isError: false });
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws);
        if (type === 'employees') {
          const res = await dataService.importMonthlyExcel(data);
          setImportStatus({ message: `Carga exitosa: ${res.count} trabajadores sincronizados.`, isError: false });
        } else {
          const count = await dataService.importHierarchyExcel(data);
          setImportStatus({ message: `Éxito: ${count} tiendas sincronizadas correctamente.`, isError: false });
          setHierarchy(dataService.getHierarchy());
        }
        onEmployeesImported();
      } catch (err: any) { 
        setImportStatus({ message: `Error: ${err.message}`, isError: true }); 
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; // Limpiar input para permitir re-subida
  };

  const handleClearDatabase = async () => {
    if (!confirm("¿ESTÁS SEGURO? Esta acción eliminará a TODOS los trabajadores actuales para permitir una re-importación limpia. Las notas no se borrarán pero perderán el vínculo visual si no se re-importan los mismos IDs.")) return;
    setIsClearing(true);
    try {
      await dataService.clearEmployeesInCloud();
      setImportStatus({ message: "Base de datos de trabajadores reiniciada correctamente.", isError: false });
      onEmployeesImported();
    } catch (e) {
      setImportStatus({ message: "Error al reiniciar base de datos.", isError: true });
    } finally {
      setIsClearing(false);
    }
  };

  const handleCreateUser = async () => {
    if (!newUser.username || !newUser.password) { alert("Usuario y contraseña requeridos"); return; }
    const userToSave: User = { id: `user_${Date.now()}`, username: newUser.username!, password: newUser.password!, role: newUser.role!, assignedZones: newUser.assignedZones || [], assignedRestaurants: newUser.assignedRestaurants || [] };
    try {
      const updatedUsers = [...users, userToSave];
      await dataService.saveUsers(updatedUsers);
      setUsers(updatedUsers);
      setShowUserModal(false);
      setNewUser({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [], assignedRestaurants: [] });
    } catch (e) { alert("Error al guardar en nube"); }
  };

  const handleDeleteUser = async (id: string) => {
    if (confirm("¿Eliminar usuario?")) {
      try { await dataService.deleteUser(id); setUsers(users.filter(u => u.id !== id)); } catch (e) { alert("Error al eliminar"); }
    }
  };

  const togglePeriodLock = async (month: string) => {
    const currentLocked = hierarchy.lockedMonths || [];
    const isLocked = currentLocked.includes(month);
    const updatedLocked = isLocked 
      ? currentLocked.filter(m => m !== month)
      : [...currentLocked, month];

    const updatedHierarchy = { ...hierarchy, lockedMonths: updatedLocked };
    await dataService.saveHierarchy(updatedHierarchy);
    setHierarchy(updatedHierarchy);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-8 rounded-[32px] shadow-sm border border-slate-100">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
          <div className="flex items-center space-x-4">
            <div className="p-3 bg-red-600 text-white rounded-2xl shadow-lg"><Shield className="w-6 h-6" /></div>
            <div>
              <h2 className="text-xl font-black text-slate-800 tracking-tight uppercase italic">Admin KFC</h2>
              <div className="flex flex-wrap gap-2 mt-2">
                {[
                  {id: 'import', label: 'Carga Excel'},
                  {id: 'hierarchy', label: 'Estructura'},
                  {id: 'users', label: 'Especialistas'},
                  {id: 'periods', label: 'Cierre de Mes'}
                ].map(tab => (
                  <button key={tab.id} onClick={() => setActiveSubTab(tab.id as any)} className={`text-[8px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full transition ${activeSubTab === tab.id ? 'bg-slate-900 text-white shadow-md' : 'bg-slate-100 text-slate-400'}`}>
                    {tab.label}
                  </button>
                ))}
              </div>
            </div>
          </div>
          {activeSubTab === 'import' && (
            <button 
              onClick={handleClearDatabase} 
              disabled={isClearing}
              className="px-6 py-2.5 bg-red-50 text-red-600 border border-red-100 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-red-600 hover:text-white transition-all disabled:opacity-50"
            >
              {isClearing ? 'Reiniciando...' : 'Reiniciar Base de Datos'}
            </button>
          )}
        </div>

        {importStatus && (
          <div className={`mb-6 p-4 rounded-2xl flex items-center gap-3 animate-in slide-in-from-top-2 duration-300 ${importStatus.isError ? 'bg-red-50 text-red-700 border border-red-100' : 'bg-emerald-50 text-emerald-700 border border-emerald-100'}`}>
            {importStatus.isError ? <AlertCircle className="w-5 h-5 shrink-0" /> : <CheckCircle2 className="w-5 h-5 shrink-0" />}
            <p className="text-[10px] font-black uppercase tracking-widest">{importStatus.message}</p>
            <button onClick={() => setImportStatus(null)} className="ml-auto p-1 hover:bg-black/5 rounded-full"><X className="w-4 h-4"/></button>
          </div>
        )}

        {activeSubTab === 'import' && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-in fade-in">
            <label className="p-10 border-2 border-dashed border-slate-200 rounded-[32px] bg-slate-50/30 text-center cursor-pointer block hover:bg-red-50 hover:border-red-200 transition-all group">
              <FileSpreadsheet className="w-12 h-12 text-slate-200 mx-auto mb-4 group-hover:text-red-400 transition-colors" />
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sincronizar Trabajadores (.xlsx)</p>
              <input type="file" className="hidden" accept=".xlsx" onChange={e => handleFileUpload(e, 'employees')} />
            </label>
            <label className="p-10 border-2 border-dashed border-slate-200 rounded-[32px] bg-slate-50/30 text-center cursor-pointer block hover:bg-red-50 hover:border-red-200 transition-all group">
              <Network className="w-12 h-12 text-slate-200 mx-auto mb-4 group-hover:text-red-400 transition-colors" />
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sincronizar Estructura (.xlsx)</p>
              <input type="file" className="hidden" accept=".xlsx" onChange={e => handleFileUpload(e, 'hierarchy')} />
            </label>
          </div>
        )}

        {activeSubTab === 'periods' && (
          <div className="space-y-6 animate-in fade-in">
             <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
               <h3 className="text-xs font-black uppercase italic text-slate-900 mb-2">Control de Históricos Mes a Mes</h3>
               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Al cerrar un mes, los Especialistas ya no podrán modificar las notas registradas.</p>
             </div>
             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
               {Array.from({length: 6}).map((_, i) => {
                 const d = new Date(); d.setMonth(d.getMonth() - i);
                 const mStr = d.toISOString().slice(0, 7);
                 const isLocked = hierarchy.lockedMonths?.includes(mStr);
                 return (
                   <div key={mStr} className={`p-6 rounded-3xl border-2 transition-all flex flex-col items-center gap-4 ${isLocked ? 'border-red-500 bg-red-50/50' : 'border-slate-100 bg-white'}`}>
                      <div className={`p-4 rounded-2xl ${isLocked ? 'bg-red-600 text-white' : 'bg-emerald-500 text-white'}`}>
                        {isLocked ? <Lock className="w-5 h-5" /> : <Unlock className="w-5 h-5" />}
                      </div>
                      <p className="text-sm font-black uppercase italic text-slate-800">{mStr}</p>
                      <button 
                        onClick={() => togglePeriodLock(mStr)}
                        className={`w-full py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${isLocked ? 'bg-slate-900 text-white' : 'bg-red-600 text-white'}`}
                      >
                        {isLocked ? 'Abrir Periodo' : 'Cerrar Periodo'}
                      </button>
                   </div>
                 );
               })}
             </div>
          </div>
        )}

        {activeSubTab === 'users' && (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            <button onClick={() => setShowUserModal(true)} className="p-6 border-2 border-dashed border-slate-200 rounded-3xl flex flex-col items-center justify-center text-slate-400 hover:bg-slate-50 transition-colors">
              <UserPlus className="w-6 h-6 mb-2" />
              <span className="text-[9px] font-black uppercase">Nuevo Especialista</span>
            </button>
            {users.map(u => (
              <div key={u.id} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm group hover:border-red-200 transition-all relative">
                <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity">
                  {u.username !== 'admin' && <button onClick={() => handleDeleteUser(u.id)} className="p-2 text-slate-300 hover:text-red-600 bg-slate-50 rounded-lg"><Trash2 className="w-4 h-4" /></button>}
                </div>
                <div className="min-w-0">
                  <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center mb-3 text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-all"><Key className="w-5 h-5" /></div>
                  <p className="text-xs font-black text-slate-800 uppercase truncate italic">{u.username}</p>
                  <p className="text-[8px] font-black text-slate-400 uppercase mt-1 tracking-widest">{u.role}</p>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {showUserModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-4">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-lg flex flex-col overflow-hidden">
            <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
              <h3 className="font-black uppercase italic tracking-tighter text-xl">Crear Acceso</h3>
              <button onClick={() => setShowUserModal(false)}><X className="w-6 h-6"/></button>
            </div>
            <div className="p-8 space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <input type="text" value={newUser.username} onChange={e => setNewUser({...newUser, username: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-bold outline-none focus:border-red-500" placeholder="Usuario" />
                <input type="password" value={newUser.password} onChange={e => setNewUser({...newUser, password: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-bold outline-none focus:border-red-500" placeholder="Clave" />
              </div>
              <button onClick={handleCreateUser} className="w-full py-4 bg-red-600 text-white font-black rounded-2xl hover:bg-red-700 shadow-xl transition-all uppercase tracking-widest text-xs">Guardar Especialista</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useMemo, useState } from 'react';
import { User, Restaurant, Employee, UserRole, JobHierarchy } from '../types';
import { Store, MapPin, Users, Award, ArrowLeft, User as UserIcon, TrendingUp, Briefcase } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import GradeEditor from './GradeEditor';

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
  onUpdate: () => void;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth, onUpdate }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  const assigned = useMemo(() => {
    return user.role === UserRole.ADMIN 
      ? restaurants 
      : restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));
  }, [user, restaurants]);

  const getStoreStats = (storeId: string) => {
    const storeEmps = employees.filter(e => e.restaurant_id === storeId);
    if (storeEmps.length === 0) return { total: 0, approved: 0, percent: 0 };
    let approved = 0;
    const grades = dataService.getGrades().filter(g => g.month === selectedMonth);
    storeEmps.forEach(emp => {
      const empGrades = grades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        const sum = empGrades.reduce((sum, g) => sum + g.score, 0);
        const avg = sum / TOTAL_CATEGORIES_COUNT;
        if (avg >= APPROVAL_THRESHOLD) approved++;
      }
    });
    return { total: storeEmps.length, approved, percent: Math.round((approved / storeEmps.length) * 100) };
  };

  if (selectedStore) {
    const stats = getStoreStats(selectedStore.id);
    const storeEmps = employees
      .filter(e => e.restaurant_id === selectedStore.id && (user.role === UserRole.ADMIN ? true : e.active))
      .sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));

    return (
      <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
        <div className="flex items-center space-x-4">
          <button onClick={() => setSelectedStore(null)} className="p-3 bg-white border-2 border-slate-100 rounded-2xl text-slate-400 hover:text-red-600 transition-all shadow-sm"><ArrowLeft className="w-5 h-5" /></button>
          <div>
            <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tighter uppercase italic leading-none">{selectedStore.name}</h2>
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest flex items-center mt-2"><MapPin className="w-3.5 h-3.5 mr-1.5 text-red-500" /> {selectedStore.zone} • {selectedStore.region}</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <DetailStatCard icon={<Users className="w-6 h-6" />} label="Equipo Total" value={stats.total} color="blue" />
          <DetailStatCard icon={<Award className="w-6 h-6" />} label="Personal Aprobado" value={stats.approved} color="green" />
          <DetailStatCard icon={<TrendingUp className="w-6 h-6" />} label="Porcentaje Éxito" value={`${stats.percent}%`} color="red" />
        </div>

        <div className="bg-white rounded-[40px] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center">
             <h3 className="text-xs font-black uppercase italic tracking-widest flex items-center">
               <Users className="w-4 h-4 mr-2 text-red-600" /> Listado de Colaboradores
             </h3>
             <span className="text-[10px] font-black bg-slate-100 px-4 py-1.5 rounded-full uppercase text-slate-400">Filtrado por Jerarquía</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50">
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Cargo / Puesto</th>
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Acciones</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {storeEmps.map(emp => (
                  <tr key={emp.id} className="hover:bg-slate-50/80 transition-all group">
                    <td className="px-8 py-6">
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-colors">
                          <UserIcon className="w-5 h-5" />
                        </div>
                        <div>
                          <p className="font-black text-slate-800 text-[13px] uppercase italic leading-tight group-hover:text-red-600 transition-colors">{emp.name}</p>
                          <p className="text-[9px] text-slate-400 font-black uppercase tracking-widest mt-0.5">ID: {emp.id}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex items-center gap-2">
                        <div className="p-1.5 bg-slate-100 rounded-lg text-slate-400">
                          <Briefcase className="w-3.5 h-3.5" />
                        </div>
                        <span className="text-[11px] font-black text-slate-700 uppercase italic tracking-tight">{emp.title}</span>
                      </div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <button 
                        onClick={() => setEditingEmployee(emp)} 
                        className="px-8 py-3 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-red-600 shadow-lg shadow-slate-100 hover:shadow-red-100 transition-all uppercase tracking-widest"
                      >
                        Gestionar Notas
                      </button>
                    </td>
                  </tr>
                ))}
                {storeEmps.length === 0 && (
                  <tr>
                    <td colSpan={3} className="p-20 text-center">
                      <p className="text-[11px] font-black text-slate-400 uppercase italic tracking-[0.2em]">No se encontró personal activo en esta tienda</p>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
        {editingEmployee && <GradeEditor employee={editingEmployee} month={selectedMonth} onClose={() => { setEditingEmployee(null); onUpdate(); }} />}
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 animate-in fade-in duration-300">
      {assigned.map(store => {
        const stats = getStoreStats(store.id);
        return (
          <div key={store.id} onClick={() => setSelectedStore(store)} className="bg-white rounded-[32px] shadow-sm border-2 border-slate-50 overflow-hidden hover:border-red-500 hover:shadow-2xl hover:shadow-red-50 transition-all group cursor-pointer flex flex-col p-8">
            <div className="flex items-start justify-between mb-8">
              <div className="flex items-center space-x-4">
                <div className="w-14 h-14 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400 group-hover:bg-red-600 group-hover:text-white transition-all shadow-inner"><Store className="w-7 h-7" /></div>
                <div className="min-w-0">
                  <h3 className="font-black text-slate-800 text-lg truncate uppercase tracking-tighter leading-tight italic">{store.name}</h3>
                  <p className="text-[10px] text-slate-400 font-black uppercase truncate tracking-widest mt-1">{store.region} • {store.zone}</p>
                </div>
              </div>
            </div>
            <div className="mt-auto grid grid-cols-2 gap-4">
               <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[9px] font-black text-slate-400 uppercase mb-1 tracking-widest">Colaboradores</p><p className="text-2xl font-black text-slate-800 tracking-tighter">{stats.total}</p></div>
               <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[9px] font-black text-slate-400 uppercase mb-1 tracking-widest">Aprobación</p><p className={`text-2xl font-black tracking-tighter ${stats.percent >= 90 ? 'text-emerald-600' : 'text-red-600'}`}>{stats.percent}%</p></div>
            </div>
          </div>
        );
      })}
    </div>
  );
};

const DetailStatCard: React.FC<{ icon: React.ReactNode, label: string, value: string | number, color: string }> = ({ icon, label, value, color }) => {
  const colorMap: any = { 
    blue: 'bg-blue-50 text-blue-600 border-blue-100', 
    green: 'bg-emerald-50 text-emerald-600 border-emerald-100', 
    red: 'bg-red-50 text-red-600 border-red-100' 
  };
  return (
    <div className={`bg-white p-6 rounded-[32px] border-2 shadow-sm flex items-center space-x-5 transition-transform hover:scale-[1.03] ${colorMap[color]}`}>
      <div className={`p-4 rounded-2xl bg-white shadow-lg`}>{icon}</div>
      <div>
        <p className="text-[10px] font-black uppercase tracking-[0.2em] opacity-60">{label}</p>
        <h4 className="text-3xl font-black tracking-tighter leading-none mt-1">{value}</h4>
      </div>
    </div>
  );
};

export default MyStores;

// Import useState and React to resolve "Cannot find name 'useState'" and 'React' errors
import React, { useState } from 'react';
import { dataService } from '../dataService';
import { UserRole, User, HierarchyData } from '../types';
import * as XLSX from 'xlsx';
// Import missing icons from lucide-react to resolve "Cannot find name" errors
import { 
  Shield, 
  AlertCircle, 
  CheckCircle2, 
  X, 
  FileSpreadsheet, 
  Network, 
  Lock, 
  Unlock, 
  UserPlus, 
  Trash2, 
  Key,
  FileText
} from 'lucide-react';

interface AdminPanelProps {
  onEmployeesImported: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onEmployeesImported }) => {
  const [activeSubTab, setActiveSubTab] = useState<'import' | 'users' | 'hierarchy' | 'periods'>('import');
  const [importStatus, setImportStatus] = useState<{message: string, isError: boolean} | null>(null);
  const [hierarchy, setHierarchy] = useState<HierarchyData>(dataService.getHierarchy());
  const [users, setUsers] = useState<User[]>(dataService.getUsers());
  const [showUserModal, setShowUserModal] = useState(false);
  const [isClearing, setIsClearing] = useState(false);

  const [newUser, setNewUser] = useState<Partial<User>>({
    username: '',
    password: '',
    role: UserRole.SPECIALIST,
    assignedZones: [],
    assignedRestaurants: []
  });

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'employees' | 'hierarchy') => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImportStatus({ message: 'Procesando archivo...', isError: false });
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws);
        if (type === 'employees') {
          const res = await dataService.importMonthlyExcel(data);
          setImportStatus({ message: `Carga exitosa: ${res.count} trabajadores sincronizados.`, isError: false });
        } else {
          const count = await dataService.importHierarchyExcel(data);
          setImportStatus({ message: `Éxito: ${count} tiendas sincronizadas correctamente.`, isError: false });
          setHierarchy(dataService.getHierarchy());
        }
        onEmployeesImported();
      } catch (err: any) { 
        setImportStatus({ message: `Error: ${err.message}`, isError: true }); 
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; // Limpiar input para permitir re-subida
  };

  const handleClearDatabase = async () => {
    if (!confirm("¿ESTÁS SEGURO? Esta acción eliminará a TODOS los trabajadores actuales para permitir una re-importación limpia. Las notas no se borrarán pero perderán el vínculo visual si no se re-importan los mismos IDs.")) return;
    setIsClearing(true);
    try {
      await dataService.clearEmployeesInCloud();
      setImportStatus({ message: "Base de datos de trabajadores reiniciada correctamente.", isError: false });
      onEmployeesImported();
    } catch (e) {
      setImportStatus({ message: "Error al reiniciar base de datos.", isError: true });
    } finally {
      setIsClearing(false);
    }
  };

  const handleCreateUser = async () => {
    if (!newUser.username || !newUser.password) { alert("Usuario y contraseña requeridos"); return; }
    const userToSave: User = { id: `user_${Date.now()}`, username: newUser.username!, password: newUser.password!, role: newUser.role!, assignedZones: newUser.assignedZones || [], assignedRestaurants: newUser.assignedRestaurants || [] };
    try {
      const updatedUsers = [...users, userToSave];
      await dataService.saveUsers(updatedUsers);
      setUsers(updatedUsers);
      setShowUserModal(false);
      setNewUser({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [], assignedRestaurants: [] });
    } catch (e) { alert("Error al guardar en nube"); }
  };

  const handleDeleteUser = async (id: string) => {
    if (confirm("¿Eliminar usuario?")) {
      try { await dataService.deleteUser(id); setUsers(users.filter(u => u.id !== id)); } catch (e) { alert("Error al eliminar"); }
    }
  };

  const togglePeriodLock = async (month: string) => {
    const currentLocked = hierarchy.lockedMonths || [];
    const isLocked = currentLocked.includes(month);
    const updatedLocked = isLocked 
      ? currentLocked.filter(m => m !== month)
      : [...currentLocked, month];

    const updatedHierarchy = { ...hierarchy, lockedMonths: updatedLocked };
    await dataService.saveHierarchy(updatedHierarchy);
    setHierarchy(updatedHierarchy);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-8 rounded-[32px] shadow-sm border border-slate-100">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
          <div className="flex items-center space-x-4">
            <div className="p-3 bg-red-600 text-white rounded-2xl shadow-lg"><Shield className="w-6 h-6" /></div>
            <div>
              <h2 className="text-xl font-black text-slate-800 tracking-tight uppercase italic">Admin KFC</h2>
              <div className="flex flex-wrap gap-2 mt-2">
                {[
                  {id: 'import', label: 'Carga Excel'},
                  {id: 'hierarchy', label: 'Estructura'},
                  {id: 'users', label: 'Especialistas'},
                  {id: 'periods', label: 'Cierre de Mes'}
                ].map(tab => (
                  <button key={tab.id} onClick={() => setActiveSubTab(tab.id as any)} className={`text-[8px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full transition ${activeSubTab === tab.id ? 'bg-slate-900 text-white shadow-md' : 'bg-slate-100 text-slate-400'}`}>
                    {tab.label}
                  </button>
                ))}
              </div>
            </div>
          </div>
          {activeSubTab === 'import' && (
            <button 
              onClick={handleClearDatabase} 
              disabled={isClearing}
              className="px-6 py-2.5 bg-red-50 text-red-600 border border-red-100 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-red-600 hover:text-white transition-all disabled:opacity-50"
            >
              {isClearing ? 'Reiniciando...' : 'Reiniciar Base de Datos'}
            </button>
          )}
        </div>

        {importStatus && (
          <div className={`mb-6 p-4 rounded-2xl flex items-center gap-3 animate-in slide-in-from-top-2 duration-300 ${importStatus.isError ? 'bg-red-50 text-red-700 border border-red-100' : 'bg-emerald-50 text-emerald-700 border border-emerald-100'}`}>
            {importStatus.isError ? <AlertCircle className="w-5 h-5 shrink-0" /> : <CheckCircle2 className="w-5 h-5 shrink-0" />}
            <p className="text-[10px] font-black uppercase tracking-widest">{importStatus.message}</p>
            <button onClick={() => setImportStatus(null)} className="ml-auto p-1 hover:bg-black/5 rounded-full"><X className="w-4 h-4"/></button>
          </div>
        )}

        {activeSubTab === 'import' && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-in fade-in">
