              </div>
            )}
            {!isPeriodLocked && (
              <div className="flex items-center gap-2 bg-emerald-500/10 px-3 py-1.5 rounded-xl border border-emerald-500/20">
                <Cloud className="w-4 h-4 text-emerald-400" />
