const parseExcelDate = (serial: any) => {
  if (!serial) return '';
  if (typeof serial === 'string') return serial;
  try {
    const date = XLSX.SSF.parse_date_code(serial);
    const month = String(date.m).padStart(2, '0');
    const day = String(date.d).padStart(2, '0');
    return `${date.y}-${month}-${day}`;
  } catch (e) {
    return String(serial);
  }
};

export const dataService = {
  supabaseFetch: async (table: string, method: string = 'GET', body?: any, queryParams: string = '') => {
    const url = `${SUPABASE_URL}/rest/v1/${table}${queryParams}`;
    const options: any = {
      method,
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation'
      }
    };
    if (body) options.body = JSON.stringify(body, (k, v) => v === undefined ? null : v);

    const res = await fetch(url, options);
    if (!res.ok) {
      const error = await res.text();
      throw new Error(`Supabase Error [${table}]: ${error}`);
    }

    if (res.status === 204) return true;
    const text = await res.text();
    return text ? JSON.parse(text) : true;
  },

  supabaseFetchAll: async (table: string): Promise<any[]> => {
    let allData: any[] = [];
    let from = 0;
    const step = 1000;
    let hasMore = true;
    while (hasMore) {
      const url = `${SUPABASE_URL}/rest/v1/${table}?select=*&offset=${from}&limit=${step}`;
      const res = await fetch(url, { headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` } });
      const data = await res.json();
      allData = [...allData, ...data];
      if (data.length < step) hasMore = false; else from += step;
    }
    return allData;
  },

  loadAllFromCloud: async () => {
    try {
      const [employees, restaurants, rawGrades, hierarchy, users] = await Promise.all([
        dataService.supabaseFetchAll('employees'),
        dataService.supabaseFetchAll('restaurants'),
        dataService.supabaseFetchAll('grades'),
        dataService.supabaseFetch('hierarchy'),
        dataService.supabaseFetchAll('users').catch(() => [])
      ]);

      const grades = rawGrades.map((g: any) => ({
        employeeId: g.employee_id,
        month: g.month,
        group: g.group,
        category: g.category,
        score: g.score
      }));

      localStorage.setItem('la_akademia_employees', JSON.stringify(employees));
      localStorage.setItem('la_akademia_stores', JSON.stringify(restaurants));
      localStorage.setItem('la_akademia_grades', JSON.stringify(grades));
      localStorage.setItem('la_akademia_users', JSON.stringify(users));

      const defaultHierarchy = { lockedMonths: [], regions: [] };
      const cloudHierarchy = (hierarchy && hierarchy[0]?.data) ? hierarchy[0].data : defaultHierarchy;
      localStorage.setItem('la_akademia_hierarchy', JSON.stringify(cloudHierarchy));
      return true;
    } catch (e) {
      console.error(e);
      return false;
    }
  },

  getEmployees: (): Employee[] => JSON.parse(localStorage.getItem('la_akademia_employees') || '[]'),
  getRestaurants: (): Restaurant[] => JSON.parse(localStorage.getItem('la_akademia_stores') || '[]'),
  getGrades: (): GradeEntry[] => JSON.parse(localStorage.getItem('la_akademia_grades') || '[]'),
  getHierarchy: (): HierarchyData => JSON.parse(localStorage.getItem('la_akademia_hierarchy') || '{"lockedMonths":[], "regions":[]}'),
  getUsers: (): User[] => {
    const local = JSON.parse(localStorage.getItem('la_akademia_users') || '[]');
    if (local.length === 0) return [{ id: 'admin-master', username: 'admin', password: '123', role: UserRole.ADMIN, assignedZones: [], assignedRestaurants: [] }];
    return local;
  },

  saveEmployees: async (employees: Employee[]) => {
    localStorage.setItem('la_akademia_employees', JSON.stringify(employees));
    const chunkSize = 100;
    for (let i = 0; i < employees.length; i += chunkSize) {
      await dataService.supabaseFetch('employees', 'POST', employees.slice(i, i + chunkSize), '?on_conflict=id');
    }
  },

  // FIX: Added missing saveRestaurants method to allow persisting restaurant data both locally and in the cloud.
  saveRestaurants: async (restaurants: Restaurant[]) => {
    localStorage.setItem('la_akademia_stores', JSON.stringify(restaurants));
    await dataService.supabaseFetch('restaurants', 'POST', restaurants, '?on_conflict=id');
  },

  clearAllDataInCloud: async () => {
    await fetch(`${SUPABASE_URL}/rest/v1/employees?id=neq.0`, {
      method: 'DELETE',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
    });
    await fetch(`${SUPABASE_URL}/rest/v1/grades?employee_id=neq.0`, {
      method: 'DELETE',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
    });
    localStorage.setItem('la_akademia_employees', '[]');
    localStorage.setItem('la_akademia_grades', '[]');
  },

  saveEmployeeGrades: async (employeeId: string, month: string, grades: GradeEntry[]) => {
    // 1. Eliminar registros previos para evitar duplicados sin requerir índices UNIQUE
    const deleteUrl = `${SUPABASE_URL}/rest/v1/grades?employee_id=eq.${employeeId}&month=eq.${month}`;
    await fetch(deleteUrl, {
      method: 'DELETE',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
    });

    // 2. Insertar los nuevos registros
    if (grades.length > 0) {
      const payload = grades.map(g => ({
        employee_id: g.employeeId,
        month: g.month,
        group: g.group,
        category: g.category,
        score: g.score
      }));
      await dataService.supabaseFetch('grades', 'POST', payload);
    }

    // 3. Actualizar local storage
    const allGrades = dataService.getGrades().filter(g => !(g.employeeId === employeeId && g.month === month));
    const updated = [...allGrades, ...grades];
    localStorage.setItem('la_akademia_grades', JSON.stringify(updated));
  },

  saveGrades: async (grades: GradeEntry[]) => {
    // Método genérico usado para imports masivos (mantenido por compatibilidad)
    localStorage.setItem('la_akademia_grades', JSON.stringify(grades));
    const payload = grades.map(g => ({
      employee_id: g.employeeId,
      month: g.month,
      group: g.group,
      category: g.category,
      score: g.score
    }));

    const chunkSize = 100;
    for (let i = 0; i < payload.length; i += chunkSize) {
      await dataService.supabaseFetch('grades', 'POST', payload.slice(i, i + chunkSize));
    }
  },

