  importMonthlyExcel: async (rawData: any[]) => {
    await dataService.loadAllFromCloud();
    const currentEmployees = dataService.getEmployees();
    const currentStores = dataService.getRestaurants();
    const today = new Date().toISOString().split('T')[0];

    const importedIds = new Set();
    const filteredRawData = rawData.filter(item => {
      const storeId = String(item.Nombre_Ceco || item.nombre_ceco || '').trim().toUpperCase();
      return storeId !== '' && !storeId.startsWith('H');
    });

    const importedEmployees = filteredRawData.map(item => {
      const storeId = String(item.Nombre_Ceco || item.nombre_ceco || 'SIN_CECO').trim().toUpperCase();
      const docId = String(item.Documento || item.documento || '').trim();
      if (!docId) return null;
      importedIds.add(docId);

      const existing = currentEmployees.find(e => e.id === docId);
      const rawStatus = String(item.Estado || item.estado || '').trim().toUpperCase();
      const isActiveInExcel = rawStatus.startsWith('ACTIVO');

      const emp: Employee = {
        id: docId,
        name: String(item["Nombre completo"] || item.nombre || 'Sin Nombre').trim(),
        join_date: parseExcelDate(item["Fecha de ingreso"] || item.fecha_de_ingreso),
        title: (item.Cargo || item.cargo) as JobTitle,
        restaurant_id: storeId,
        zone: currentStores.find(s => s.id === storeId)?.zone || (existing?.zone || 'Sin Clasificar'),
        active: isActiveInExcel,
        history: existing?.history || []
      };

      if (existing) {
        emp.history = [...(existing.history || [])];
        if (existing.restaurant_id !== storeId) {
           emp.history.push({ date: today, restaurantName: existing.restaurant_id, action: 'TRASLADO' });
        }
        if (existing.active && !isActiveInExcel) {
           emp.history.push({ date: today, restaurantName: storeId, action: 'RETIRO' });
        }
        if (!existing.active && isActiveInExcel) {
           emp.history.push({ date: today, restaurantName: storeId, action: 'INGRESO' });
        }
      } else {
        emp.history = [{ date: emp.join_date || today, restaurantName: storeId, action: 'INGRESO' }];
      }
      return emp;
    }).filter(e => e !== null) as Employee[];

    const implicitRetires = currentEmployees
      .filter(e => !importedIds.has(e.id) && e.active)
      .map(e => ({
        ...e, 
        active: false, 
        history: [...(e.history || []), { date: today, restaurantName: e.restaurant_id, action: 'RETIRO' as const }]
      }));

    const allProcessed = [...importedEmployees];
    implicitRetires.forEach(ir => {
      if (!allProcessed.some(p => p.id === ir.id)) allProcessed.push(ir);
    });

    currentEmployees.forEach(old => {
      if (!allProcessed.some(p => p.id === old.id)) {
        allProcessed.push(old);
      }
    });

    await dataService.saveEmployees(allProcessed);
    return { count: importedEmployees.length };
  },

  importHierarchyExcel: async (rawData: any[]) => {
    const current = dataService.getHierarchy();
    const stores: Restaurant[] = [];
    const hierarchy: HierarchyData = { lockedMonths: current.lockedMonths || [], regions: [] };

    rawData.forEach(item => {
      const regionName = String(item.Region || item.region || 'Sin Region').trim();
      const zoneName = String(item.Zona || item.zona || 'Sin Zona').trim();
      const storeId = String(item.Ceco || item.ceco || '').trim().toUpperCase();
      const storeName = String(item.Nombre || item.nombre || 'Tienda Sin Nombre').trim();
      if (!storeId || storeId.startsWith('H')) return;
      stores.push({ id: storeId, name: storeName, zone: zoneName, region: regionName });
      let r = hierarchy.regions.find(r => r.name === regionName);
      if (!r) { r = { name: regionName, zones: [] }; hierarchy.regions.push(r); }
      let z = r.zones.find(z => z.name === zoneName);
      if (!z) { z = { name: zoneName, restaurantIds: [] }; r.zones.push(z); }
      if (!z.restaurantIds.includes(storeId)) z.restaurantIds.push(storeId);
    });

    if (stores.length > 0) {
      await dataService.saveRestaurants(stores);
      await dataService.saveHierarchy(hierarchy);
    }
    return stores.length;
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, UserRole, AuthState, Employee, Restaurant } from './types';
import { dataService } from './dataService';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import AdminPanel from './components/AdminPanel';
import Header from './components/Header';
import MyStores from './components/MyStores';
import EntriesExitsReport from './components/EntriesExitsReport';
import { Cloud, CloudOff, RefreshCw } from 'lucide-react';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({ user: null, isAuthenticated: false });
  const [activeTab, setActiveTab] = useState<'dashboard' | 'my-stores' | 'admin' | 'entries-exits'>('dashboard');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [selectedMonth, setSelectedMonth] = useState<string>(new Date().toISOString().slice(0, 7));
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [syncStatus, setSyncStatus] = useState<'syncing' | 'online' | 'offline'>('syncing');

  const refreshData = () => {
    setEmployees(dataService.getEmployees());
    setRestaurants(dataService.getRestaurants());
  };

  const initData = async () => {
    setSyncStatus('syncing');
    const success = await dataService.loadAllFromCloud();
    refreshData();
    setSyncStatus(success ? 'online' : 'offline');
  };

  useEffect(() => {
    initData();
    const interval = setInterval(initData, 5 * 60 * 1000);
    return () => clearInterval(interval);
  }, []);

  const handleLogin = (user: User) => {
    setAuth({ user, isAuthenticated: true });
    setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
  };

  const filteredEmployees = useMemo(() => {
    if (!auth.user) return [];
    if (auth.user.role === UserRole.ADMIN) return employees;

    return employees.filter(e => 
      auth.user?.assignedZones.includes(e.zone) || 
      auth.user?.assignedRestaurants.includes(e.restaurant_id)
    );
  }, [employees, auth.user]);

  if (!auth.isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden relative">
      {/* Moved to bottom-6 left-6 */}
      <div className={`fixed bottom-6 left-6 z-[200] px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-widest shadow-2xl flex items-center gap-3 transition-all duration-500 border-2 ${
        syncStatus === 'syncing' ? 'bg-slate-900 border-red-500 text-white animate-pulse' :
        syncStatus === 'online' ? 'bg-white border-emerald-500 text-emerald-600' :
        'bg-white border-red-500 text-red-600'
      }`}>
        {syncStatus === 'syncing' ? <RefreshCw className="w-3 h-3 animate-spin" /> : 
         syncStatus === 'online' ? <Cloud className="w-3 h-3" /> : <CloudOff className="w-3 h-3" />}
        {syncStatus === 'syncing' ? 'Sincronizando...' : syncStatus === 'online' ? 'Nube Conectada' : 'Modo Offline'}
      </div>

      {isSidebarOpen && (
        <div className="fixed inset-0 bg-black/50 z-40 lg:hidden" onClick={() => setIsSidebarOpen(false)} />
      )}

      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={(tab) => { setActiveTab(tab as any); setIsSidebarOpen(false); }} 
        role={auth.user!.role}
        onLogout={handleLogout}
        isOpen={isSidebarOpen}
        setIsOpen={setIsSidebarOpen}
      />

      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header user={auth.user!} selectedMonth={selectedMonth} onMonthChange={setSelectedMonth} onMenuClick={() => setIsSidebarOpen(true)} />
        <main className="flex-1 overflow-x-hidden overflow-y-auto p-4 md:p-6">
          {activeTab === 'dashboard' && <Dashboard employees={filteredEmployees} restaurants={restaurants} selectedMonth={selectedMonth} user={auth.user!} />}
          {activeTab === 'my-stores' && <MyStores user={auth.user!} restaurants={restaurants} employees={employees} selectedMonth={selectedMonth} onUpdate={refreshData} />}
          {activeTab === 'entries-exits' && auth.user?.role === UserRole.ADMIN && <EntriesExitsReport employees={employees} restaurants={restaurants} />}
          {activeTab === 'admin' && auth.user?.role === UserRole.ADMIN && <AdminPanel onEmployeesImported={refreshData} />}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useMemo, useState, useEffect } from 'react';
import { Employee, GradeEntry, User, Restaurant, UserRole } from '../types';
import { dataService } from '../dataService';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, LineChart, Line, LabelList } from 'recharts';
import { XCircle, Users, Award, TrendingUp, Search, MapPin, Filter, Calendar, Download, X, Check, FileText, ChevronDown } from 'lucide-react';
import * as XLSX from 'xlsx';

interface DashboardProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ employees: initialEmployees, restaurants, selectedMonth, user }) => {
  const [searchPerson, setSearchPerson] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [filterStore, setFilterStore] = useState('all');

  const allGrades = useMemo(() => dataService.getGrades(), []);
  const currentGrades = useMemo(() => allGrades.filter(g => g.month === selectedMonth), [allGrades, selectedMonth]);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);

  const dynamicZones = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') baseStores = baseStores.filter(r => r.region === filterRegion);
    let zones = Array.from(new Set(baseStores.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) zones = zones.filter(z => user.assignedZones.includes(z));
    return zones;
  }, [restaurants, filterRegion, user]);

  const dynamicStores = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') baseStores = baseStores.filter(r => r.region === filterRegion);
    if (filterZone !== 'all') baseStores = baseStores.filter(r => r.zone === filterZone);
    if (user.role === UserRole.SPECIALIST) baseStores = baseStores.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));
    return baseStores.sort((a, b) => a.name.localeCompare(b.name));
  }, [restaurants, filterRegion, filterZone, user]);

  const filteredData = useMemo(() => {
    return initialEmployees.filter(e => {
      const store = restaurants.find(r => r.id === e.restaurant_id);
      const matchPerson = searchPerson === '' || e.name.toLowerCase().includes(searchPerson.toLowerCase()) || e.id.includes(searchPerson);
      const matchRegion = filterRegion === 'all' || store?.region === filterRegion;
      const matchZone = filterZone === 'all' || e.zone === filterZone;
      const matchStore = filterStore === 'all' || e.restaurant_id === filterStore;
      return matchPerson && matchStore && matchZone && matchRegion;
    });
  }, [initialEmployees, searchPerson, filterStore, filterZone, filterRegion, restaurants]);

  const stats = useMemo(() => {
    const totalEmployees = filteredData.length;
    let approvedCount = 0;

    const groupAvgs = Object.keys(EVALUATION_GROUPS).map(groupId => {
      const groupData = (EVALUATION_GROUPS as any)[groupId];
      const groupGrades = currentGrades.filter(g => g.group === groupId && filteredData.some(e => e.id === g.employeeId));
      const totalPossibleCategories = filteredData.length * groupData.categories.length;
      const sumScores = groupGrades.reduce((sum, g) => sum + g.score, 0);
      const avg = totalPossibleCategories > 0 ? sumScores / totalPossibleCategories : 0;
      return { id: groupId, name: groupData.name, avg: Math.round(avg) };
    });

    filteredData.forEach(emp => {
      const empGrades = currentGrades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        const sum = empGrades.reduce((sum, g) => sum + g.score, 0);
        const avg = sum / TOTAL_CATEGORIES_COUNT;
        if (avg >= APPROVAL_THRESHOLD) approvedCount++;
      }
    });

    return { totalEmployees, approvedCount, groupAvgs };
  }, [filteredData, currentGrades]);

  const handleExportFinal = () => {
    const exportData = filteredData.map(emp => {
      const empStore = restaurants.find(r => r.id === emp.restaurant_id);
      const empGrades = currentGrades.filter(g => g.employeeId === emp.id);
      const dynamicColumns: any = {};

      Object.keys(EVALUATION_GROUPS).forEach(gid => {
        const gConfig = (EVALUATION_GROUPS as any)[gid];
        const gGrades = empGrades.filter(g => g.group === gid);
        const sum = gGrades.reduce((s, g) => s + g.score, 0);
        const avg = gConfig.categories.length > 0 ? Math.round(sum / gConfig.categories.length) : 0;
        dynamicColumns[`${gConfig.name} %`] = `${avg}%`;
      });

      const totalSum = empGrades.reduce((s, g) => s + g.score, 0);
      const totalAvg = Math.round(totalSum / TOTAL_CATEGORIES_COUNT);

      return {
        "Documento": emp.id,
        "Nombre completo": emp.name,
        "Estado": emp.active ? "Activo" : "Retirado",
        "Fecha de ingreso": emp.join_date,
        "Cargo": emp.title,
        "Nombre_Ceco": empStore?.name || emp.restaurant_id,
        "Jefe de area": emp.zone,
        "Mes Reporte": selectedMonth,
        "Promedio General": `${totalAvg}%`,
        ...dynamicColumns
      };
    });

    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Reporte_Akademia");
    XLSX.writeFile(wb, `Reporte_Akademia_${selectedMonth}.xlsx`);
  };

  const selectClasses = "w-full p-3 bg-white border-2 border-slate-100 rounded-xl text-xs font-black uppercase text-slate-800 outline-none focus:border-red-500 transition-all";

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6 items-end">
        {user.role === UserRole.ADMIN && (
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1"><MapPin className="w-3 h-3 mr-1 inline" /> Región</label>
            <select value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)} className={selectClasses}>
              <option value="all">Todas</option>
              {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
            </select>
          </div>
        )}
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1"><Filter className="w-3 h-3 mr-1 inline" /> Zona</label>
          <select value={filterZone} onChange={(e) => setFilterZone(e.target.value)} className={selectClasses}>
            <option value="all">Todas</option>
            {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1"><Filter className="w-3 h-3 mr-1 inline" /> Tienda</label>
          <select value={filterStore} onChange={(e) => setFilterStore(e.target.value)} className={selectClasses}>
            <option value="all">Todas</option>
            {dynamicStores.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1"><Search className="w-3 h-3 mr-1 inline" /> Persona</label>
          <input type="text" placeholder="Nombre o ID..." value={searchPerson} onChange={(e) => setSearchPerson(e.target.value)} className="w-full p-3 bg-white border-2 border-slate-100 rounded-xl text-xs font-black uppercase text-slate-800" />
        </div>
        <button onClick={handleExportFinal} className="w-full flex items-center justify-center space-x-2 px-4 py-3.5 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-black transition-all shadow-lg">
          <Download className="w-4 h-4" /> <span>Exportar Excel</span>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard icon={<Users className="w-6 h-6" />} label="Equipo" value={stats.totalEmployees} subValue="Personal en Periodo" />
        <StatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approvedCount} subValue="Nivel de Excelencia" color="green" />
        <StatCard icon={<TrendingUp className="w-6 h-6" />} label="Promedio" value={`${stats.groupAvgs.length > 0 ? Math.round(stats.groupAvgs.reduce((s, g) => s + g.avg, 0) / stats.groupAvgs.length) : 0}%`} subValue="General" color="blue" />
        <StatCard icon={<XCircle className="w-6 h-6" />} label="Faltantes" value={Math.max(0, stats.totalEmployees - stats.approvedCount)} subValue="Brecha de Calidad" color="red" />
      </div>

      <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
        <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center mb-8"><TrendingUp className="w-4 h-4 mr-2 text-red-500" /> Desempeño por Grupo</h3>
        <div className="h-[300px]">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={stats.groupAvgs} margin={{ top: 20, right: 0, left: -25, bottom: 0 }}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
              <YAxis domain={[0, 100]} axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
              <Tooltip cursor={{ fill: '#f8fafc' }} />
              <Bar dataKey="avg" radius={[10, 10, 0, 0]} barSize={45}>
                <LabelList dataKey="avg" position="top" formatter={(v: any) => `${v}%`} style={{ fontSize: '10px', fontWeight: '900', fill: '#64748b' }} />
                {stats.groupAvgs.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.avg >= APPROVAL_THRESHOLD ? '#10b981' : '#ef4444'} />)}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ icon: React.ReactNode, label: string, value: string | number, subValue: string, color?: string }> = ({ icon, label, value, subValue, color = 'gray' }) => {
  const colorMap: any = { red: 'bg-red-50 text-red-600', green: 'bg-emerald-50 text-emerald-600', blue: 'bg-blue-50 text-blue-600', gray: 'bg-slate-50 text-slate-600' };
  return (
    <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 transition-transform hover:scale-[1.02]">
      <div className="flex items-center space-x-5">
        <div className={`p-4 rounded-2xl ${colorMap[color]}`}>{icon}</div>
        <div>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-1">{label}</p>
          <h4 className="text-3xl font-black text-slate-800 tracking-tighter leading-none">{value}</h4>
          <p className="text-[10px] text-slate-400 font-bold mt-2">{subValue}</p>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { dataService } from '../dataService';
import { UserRole, User, HierarchyData, Restaurant } from '../types';
import * as XLSX from 'xlsx';
import { 
  Shield, 
  AlertCircle, 
  CheckCircle2, 
  X, 
  FileSpreadsheet, 
  Network, 
  Lock, 
  Unlock, 
  UserPlus, 
  Trash2, 
  Key,
  FileText,
  ChevronDown,
  MapPin,
  Store,
  ChevronRight
} from 'lucide-react';

interface AdminPanelProps {
  onEmployeesImported: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onEmployeesImported }) => {
  const [activeSubTab, setActiveSubTab] = useState<'import' | 'users' | 'hierarchy' | 'periods'>('import');
  const [importStatus, setImportStatus] = useState<{message: string, isError: boolean} | null>(null);
  const [hierarchy, setHierarchy] = useState<HierarchyData>(dataService.getHierarchy());
  const [users, setUsers] = useState<User[]>(dataService.getUsers());
  const [showUserModal, setShowUserModal] = useState(false);
  const [isClearing, setIsClearing] = useState(false);

  const [newUser, setNewUser] = useState<Partial<User>>({
    username: '',
    password: '',
    role: UserRole.SPECIALIST,
    assignedZones: [],
    assignedRestaurants: []
  });

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'employees' | 'hierarchy') => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImportStatus({ message: 'Procesando archivo...', isError: false });
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws);
        if (type === 'employees') {
          const res = await dataService.importMonthlyExcel(data);
          setImportStatus({ message: `Carga exitosa: ${res.count} trabajadores sincronizados.`, isError: false });
        } else {
          const count = await dataService.importHierarchyExcel(data);
          setImportStatus({ message: `Éxito: ${count} tiendas sincronizadas correctamente.`, isError: false });
          setHierarchy(dataService.getHierarchy());
        }
        onEmployeesImported();
      } catch (err: any) { 
        setImportStatus({ message: `Error: ${err.message}`, isError: true }); 
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; 
  };

  const handleClearDatabase = async () => {
    if (!confirm("¿ESTÁS TOTALMENTE SEGURO? Esta acción eliminará a TODOS los trabajadores y TODAS las notas actuales para un reinicio completo.")) return;
    setIsClearing(true);
    try {
      await dataService.clearAllDataInCloud();
      setImportStatus({ message: "Base de datos (Trabajadores y Notas) reiniciada correctamente.", isError: false });
      onEmployeesImported();
    } catch (e) {
      setImportStatus({ message: "Error al reiniciar base de datos.", isError: true });
    } finally {
      setIsClearing(false);
    }
  };

  const handleCreateUser = async () => {
    if (!newUser.username || !newUser.password) { alert("Usuario y contraseña requeridos"); return; }
    const userToSave: User = { id: `user_${Date.now()}`, username: newUser.username!, password: newUser.password!, role: newUser.role!, assignedZones: newUser.assignedZones || [], assignedRestaurants: newUser.assignedRestaurants || [] };
    try {
      const updatedUsers = [...users, userToSave];
      await dataService.saveUsers(updatedUsers);
      setUsers(updatedUsers);
      setShowUserModal(false);
      setNewUser({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [], assignedRestaurants: [] });
    } catch (e) { alert("Error al guardar en nube"); }
  };

  const handleDeleteUser = async (id: string) => {
    if (confirm("¿Eliminar usuario?")) {
      try { await dataService.deleteUser(id); setUsers(users.filter(u => u.id !== id)); } catch (e) { alert("Error al eliminar"); }
    }
  };

  const togglePeriodLock = async (month: string) => {
    const currentLocked = hierarchy.lockedMonths || [];
    const isLocked = currentLocked.includes(month);
    const updatedLocked = isLocked 
      ? currentLocked.filter(m => m !== month)
      : [...currentLocked, month];

    const updatedHierarchy = { ...hierarchy, lockedMonths: updatedLocked };
    await dataService.saveHierarchy(updatedHierarchy);
    setHierarchy(updatedHierarchy);
  };

  const allRestaurants = dataService.getRestaurants();

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-8 rounded-[32px] shadow-sm border border-slate-100">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
          <div className="flex items-center space-x-4">
            <div className="p-3 bg-red-600 text-white rounded-2xl shadow-lg"><Shield className="w-6 h-6" /></div>
            <div>
              <h2 className="text-xl font-black text-slate-800 tracking-tight uppercase italic">Admin KFC</h2>
              <div className="flex flex-wrap gap-2 mt-2">
                {[
                  {id: 'import', label: 'Carga Excel'},
                  {id: 'hierarchy', label: 'Estructura'},
                  {id: 'users', label: 'Especialistas'},
                  {id: 'periods', label: 'Cierre de Mes'}
                ].map(tab => (
                  <button key={tab.id} onClick={() => setActiveSubTab(tab.id as any)} className={`text-[8px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full transition ${activeSubTab === tab.id ? 'bg-slate-900 text-white shadow-md' : 'bg-slate-100 text-slate-400'}`}>
                    {tab.label}
                  </button>
                ))}
              </div>
            </div>
          </div>
          {activeSubTab === 'import' && (
            <button 
              onClick={handleClearDatabase} 
              disabled={isClearing}
              className="px-6 py-2.5 bg-red-50 text-red-600 border border-red-100 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-red-600 hover:text-white transition-all disabled:opacity-50"
            >
              {isClearing ? 'Reiniciando...' : 'Reiniciar Todo (Data y Notas)'}
            </button>
          )}
        </div>

        {importStatus && (
          <div className={`mb-6 p-4 rounded-2xl flex items-center gap-3 animate-in slide-in-from-top-2 duration-300 ${importStatus.isError ? 'bg-red-50 text-red-700 border border-red-100' : 'bg-emerald-50 text-emerald-700 border border-emerald-100'}`}>
            {importStatus.isError ? <AlertCircle className="w-5 h-5 shrink-0" /> : <CheckCircle2 className="w-5 h-5 shrink-0" />}
            <p className="text-[10px] font-black uppercase tracking-widest">{importStatus.message}</p>
            <button onClick={() => setImportStatus(null)} className="ml-auto p-1 hover:bg-black/5 rounded-full"><X className="w-4 h-4"/></button>
          </div>
        )}

        {activeSubTab === 'import' && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-in fade-in">
            <label className="p-10 border-2 border-dashed border-slate-200 rounded-[32px] bg-slate-50/30 text-center cursor-pointer block hover:bg-red-50 hover:border-red-200 transition-all group">
              <FileSpreadsheet className="w-12 h-12 text-slate-200 mx-auto mb-4 group-hover:text-red-400 transition-colors" />
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sincronizar Trabajadores (.xlsx)</p>
              <input type="file" className="hidden" accept=".xlsx" onChange={e => handleFileUpload(e, 'employees')} />
            </label>
            <label className="p-10 border-2 border-dashed border-slate-200 rounded-[32px] bg-slate-50/30 text-center cursor-pointer block hover:bg-red-50 hover:border-red-200 transition-all group">
              <Network className="w-12 h-12 text-slate-200 mx-auto mb-4 group-hover:text-red-400 transition-colors" />
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sincronizar Estructura (.xlsx)</p>
              <input type="file" className="hidden" accept=".xlsx" onChange={e => handleFileUpload(e, 'hierarchy')} />
            </label>
          </div>
        )}

        {activeSubTab === 'hierarchy' && (
          <div className="space-y-6 animate-in fade-in">
            <div className="flex flex-wrap gap-4">
               <div className="px-6 py-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-center gap-4">
                 <MapPin className="w-6 h-6 text-red-600" />
                 <div><p className="text-[10px] font-black text-slate-400 uppercase">Regiones</p><p className="text-lg font-black text-slate-900 leading-tight">{hierarchy.regions.length}</p></div>
               </div>
               <div className="px-6 py-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-center gap-4">
                 <AlertCircle className="w-6 h-6 text-slate-400" />
                 <div><p className="text-[10px] font-black text-slate-400 uppercase">Zonas</p><p className="text-lg font-black text-slate-900 leading-tight">{hierarchy.regions.reduce((acc, r) => acc + r.zones.length, 0)}</p></div>
               </div>
               <div className="px-6 py-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-center gap-4">
                 <Store className="w-6 h-6 text-slate-400" />
                 <div><p className="text-[10px] font-black text-slate-400 uppercase">Tiendas</p><p className="text-lg font-black text-slate-900 leading-tight">{allRestaurants.length}</p></div>
               </div>
            </div>

            <div className="space-y-4 max-h-[500px] overflow-y-auto pr-2 no-scrollbar">
              {hierarchy.regions.map(region => (
                <div key={region.name} className="bg-slate-50/50 rounded-3xl border border-slate-100 overflow-hidden">
                  <div className="p-5 bg-slate-900 text-white flex items-center gap-3">
                    <MapPin className="w-4 h-4 text-red-500" />
                    <span className="text-xs font-black uppercase italic tracking-widest">Región: {region.name}</span>
                  </div>
                  <div className="p-4 grid grid-cols-1 md:grid-cols-2 gap-4">
                    {region.zones.map(zone => (
                      <div key={zone.name} className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm">
                        <div className="flex items-center justify-between mb-3">
                          <p className="text-[11px] font-black text-slate-800 uppercase italic">Zona: {zone.name}</p>
                          <span className="text-[9px] font-black bg-slate-100 px-2 py-0.5 rounded text-slate-400">{zone.restaurantIds.length} Tiendas</span>
                        </div>
                        <div className="flex flex-wrap gap-2">
                          {zone.restaurantIds.map(rid => {
                            const rName = allRestaurants.find(r => r.id === rid)?.name || rid;
                            return (
                              <span key={rid} className="text-[8px] font-black bg-slate-50 border border-slate-100 px-2 py-1 rounded-md uppercase text-slate-500">
                                {rid} - {rName}
                              </span>
                            );
                          })}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
              {hierarchy.regions.length === 0 && (
                <div className="p-20 text-center border-2 border-dashed border-slate-100 rounded-3xl">
                  <p className="text-xs font-black text-slate-300 uppercase tracking-widest">Cargue un archivo de estructura para visualizar los datos</p>
                </div>
              )}
            </div>
          </div>
        )}

        {activeSubTab === 'periods' && (
          <div className="space-y-6 animate-in fade-in">
             <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
               <h3 className="text-xs font-black uppercase italic text-slate-900 mb-2">Control de Históricos Mes a Mes</h3>
               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Al cerrar un mes, los Especialistas ya no podrán modificar las notas registradas.</p>
             </div>
             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
               {Array.from({length: 6}).map((_, i) => {
                 const d = new Date(); d.setMonth(d.getMonth() - i);
                 const mStr = d.toISOString().slice(0, 7);
                 const isLocked = hierarchy.lockedMonths?.includes(mStr);
                 return (
                   <div key={mStr} className={`p-6 rounded-3xl border-2 transition-all flex flex-col items-center gap-4 ${isLocked ? 'border-red-500 bg-red-50/50' : 'border-slate-100 bg-white'}`}>
                      <div className={`p-4 rounded-2xl ${isLocked ? 'bg-red-600 text-white' : 'bg-emerald-500 text-white'}`}>
                        {isLocked ? <Lock className="w-5 h-5" /> : <Unlock className="w-5 h-5" />}
                      </div>
                      <p className="text-sm font-black uppercase italic text-slate-800">{mStr}</p>
                      <button 
                        onClick={() => togglePeriodLock(mStr)}
                        className={`w-full py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${isLocked ? 'bg-slate-900 text-white' : 'bg-red-600 text-white'}`}
                      >
                        {isLocked ? 'Abrir Periodo' : 'Cerrar Periodo'}
                      </button>
                   </div>
                 );
               })}
             </div>
          </div>
        )}

        {activeSubTab === 'users' && (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            <button onClick={() => setShowUserModal(true)} className="p-6 border-2 border-dashed border-slate-200 rounded-3xl flex flex-col items-center justify-center text-slate-400 hover:bg-slate-50 transition-colors">
              <UserPlus className="w-6 h-6 mb-2" />
              <span className="text-[9px] font-black uppercase">Nuevo Especialista</span>
            </button>
            {users.map(u => (
              <div key={u.id} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm group hover:border-red-200 transition-all relative">
                <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity">
                  {u.username !== 'admin' && <button onClick={() => handleDeleteUser(u.id)} className="p-2 text-slate-300 hover:text-red-600 bg-slate-50 rounded-lg"><Trash2 className="w-4 h-4" /></button>}
                </div>
                <div className="min-w-0">
                  <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center mb-3 text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-all"><Key className="w-5 h-5" /></div>
                  <p className="text-xs font-black text-slate-800 uppercase truncate italic">{u.username}</p>
                  <p className="text-[8px] font-black text-slate-400 uppercase mt-1 tracking-widest">{u.role}</p>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {showUserModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-4">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-lg flex flex-col overflow-hidden">
            <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
              <h3 className="font-black uppercase italic tracking-tighter text-xl">Crear Acceso</h3>
              <button onClick={() => setShowUserModal(false)}><X className="w-6 h-6"/></button>
            </div>
            <div className="p-8 space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <input type="text" value={newUser.username} onChange={e => setNewUser({...newUser, username: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-bold outline-none focus:border-red-500" placeholder="Usuario" />
                <input type="password" value={newUser.password} onChange={e => setNewUser({...newUser, password: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-bold outline-none focus:border-red-500" placeholder="Clave" />
              </div>
              <button onClick={handleCreateUser} className="w-full py-4 bg-red-600 text-white font-black rounded-2xl hover:bg-red-700 shadow-xl transition-all uppercase tracking-widest text-xs">Guardar Especialista</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

