import React, { useState, useEffect, useMemo } from 'react';
import { Employee, GradeEntry } from '../types';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { dataService } from '../dataService';
import { X, Save, User, Calendar, Clock, GraduationCap, Star, Trophy, ClipboardCheck, Vault, Info, ChevronRight, CheckCircle2, MapPin, Cloud, History, ArrowRight, Lock } from 'lucide-react';

interface GradeEditorProps {
  employee: Employee;
  month: string;
  onClose: () => void;
}

const GroupIcons: Record<string, React.ReactNode> = {
  'A': <GraduationCap className="w-5 h-5" />,
  'B': <Star className="w-5 h-5" />,
  'C': <Trophy className="w-5 h-5" />,
  'D': <ClipboardCheck className="w-5 h-5" />,
  'E': <Vault className="w-5 h-5" />,
};

const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('A');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);
  const [isSaving, setIsSaving] = useState(false);
  const [showHistory, setShowHistory] = useState(false);

  const hierarchy = dataService.getHierarchy();
  const isPeriodLocked = hierarchy.lockedMonths?.includes(month);

  useEffect(() => {
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    setFormGrades(existing);
  }, [employee, month]);

  const seniority = useMemo(() => {
    if (!employee.join_date) return "N/A";
    const start = new Date(employee.join_date);
    const now = new Date();
    let diff = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth());
    if (diff < 0) return "Reciente";
    const years = Math.floor(diff / 12);
    const months = diff % 12;
    return years === 0 ? `${months} meses` : `${years} años ${months} meses`;
  }, [employee.join_date]);

  const handleScoreChange = (group: string, category: string, scoreStr: string) => {
    if (isPeriodLocked) return;
    let score = scoreStr === '' ? 0 : Math.max(0, Math.min(100, parseInt(scoreStr) || 0));
    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) { 
        const next = [...prev]; 
        next[idx] = { ...next[idx], score }; 
        return next; 
      }
      return [...prev, { employeeId: employee.id, month, group, category, score }];
    });
  };

  const saveGrades = async () => {
    if (isPeriodLocked) return;
    setIsSaving(true);
    try {
      // Usamos el nuevo método optimizado que no requiere restricciones UNIQUE en la DB
      await dataService.saveEmployeeGrades(employee.id, month, formGrades);
      onClose();
    } catch (err: any) {
      console.error(err);
      alert(`Error al guardar notas: ${err.message || 'Error de base de datos'}`);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-950/90 backdrop-blur-xl p-0 md:p-6 animate-in fade-in duration-300">
      <div className="bg-white md:rounded-[48px] shadow-2xl w-full max-w-6xl h-full md:h-[92vh] flex flex-col overflow-hidden relative border-8 border-white/5">

        {/* Header Superior */}
        <div className="p-6 md:p-8 bg-slate-900 text-white shrink-0 relative flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
          <div className="absolute top-6 right-6 flex items-center gap-3 z-50">
            {isPeriodLocked && (
              <div className="flex items-center gap-2 bg-red-600 px-3 py-1.5 rounded-xl border border-red-500 shadow-lg">
                <Lock className="w-4 h-4 text-white" />
                <span className="text-[9px] font-black uppercase tracking-widest text-white">Periodo Cerrado</span>
              </div>
            )}
            <button 
              onClick={onClose} 
              className="p-2.5 bg-white/10 hover:bg-red-600 rounded-2xl transition-all group shadow-lg"
            >
              <X className="w-6 h-6 group-hover:scale-110 transition-transform" />
            </button>
          </div>

          <div className="flex items-center space-x-6">
            <div className="w-16 h-16 bg-red-600 rounded-3xl flex items-center justify-center shadow-2xl shadow-red-900/40 border-4 border-white/10">
              <User className="w-9 h-9 text-white" />
            </div>
            <div>
              <div className="flex flex-wrap items-center gap-4">
                 <h2 className="text-2xl font-black tracking-tight uppercase italic">{employee.name}</h2>
                 <span className="px-4 py-1.5 bg-red-600 text-[10px] font-black rounded-full uppercase tracking-[0.2em] shadow-lg">
                   {employee.title}
                 </span>
                 <button 
                   onClick={() => setShowHistory(!showHistory)}
                   className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest transition-all ${showHistory ? 'bg-white text-slate-900' : 'bg-white/10 text-white hover:bg-white/20'}`}
                 >
                   <History className="w-3.5 h-3.5" />
                   {showHistory ? 'Volver a Notas' : 'Ver Histórico'}
                 </button>
              </div>
              <div className="flex flex-wrap gap-5 opacity-70 mt-2 text-[10px] font-black uppercase tracking-widest">
                <span className="flex items-center text-emerald-400">
                  <Calendar className="w-3.5 h-3.5 mr-2" /> Ingreso: {employee.join_date}
                </span>
                <span className="flex items-center text-blue-400">
                  <Clock className="w-3.5 h-3.5 mr-2" /> Antigüedad: {seniority}
                </span>
                <span className="flex items-center text-slate-300">
                  <MapPin className="w-3.5 h-3.5 mr-2" /> CECO: {employee.restaurant_id}
                </span>
              </div>
            </div>
          </div>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">

          {/* Sidebar de Grupos */}
          <div className="w-full md:w-72 bg-slate-50 border-r border-slate-200 flex flex-col shrink-0 overflow-y-auto p-4 gap-3 no-scrollbar">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2 px-2">Certificaciones</p>
            {Object.entries(EVALUATION_GROUPS).map(([id, group]) => {
              const isActive = activeGroup === id && !showHistory;
              const groupGrades = formGrades.filter(g => g.group === id);
              const groupAvg = groupGrades.length > 0 ? Math.round(groupGrades.reduce((s, g) => s + g.score, 0) / (group as any).categories.length) : 0;

              return (
                <button 
                  key={id} 
                  disabled={showHistory}
                  onClick={() => { setActiveGroup(id); setShowHistory(false); }} 
                  className={`p-5 rounded-3xl text-left border-2 transition-all group flex items-center gap-4 ${isActive ? 'bg-white border-red-600 shadow-xl scale-[1.02]' : 'bg-transparent border-transparent opacity-50 hover:opacity-100 hover:bg-slate-100'} ${showHistory ? 'cursor-not-allowed grayscale' : ''}`}
                >
                  <div className={`p-3 rounded-2xl shrink-0 ${isActive ? 'bg-red-600 text-white shadow-lg' : 'bg-slate-200 text-slate-500'}`}>
                    {GroupIcons[id]}
                  </div>
                  <div className="min-w-0 flex-1">
                    <p className={`text-[11px] font-black uppercase tracking-tight leading-tight ${isActive ? 'text-slate-900' : 'text-slate-500'}`}>{group.name}</p>
                    <div className="mt-2 flex items-center gap-2">
                       <div className="flex-1 h-1.5 bg-slate-200 rounded-full overflow-hidden">
                          <div className={`h-full transition-all duration-500 ${groupAvg >= 90 ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${groupAvg}%`}} />
                       </div>
                       <span className={`text-[10px] font-black ${groupAvg >= 90 ? 'text-emerald-600' : 'text-slate-400'}`}>{groupAvg}%</span>
                    </div>
                  </div>
                  <ChevronRight className={`w-4 h-4 transition-transform ${isActive ? 'text-red-500 translate-x-1' : 'text-slate-300'}`} />
                </button>
              );
            })}
          </div>

          <div className="flex-1 overflow-y-auto p-6 md:p-12 bg-white">
            <div className="max-w-3xl mx-auto">
              {showHistory ? (
                <div className="animate-in slide-in-from-right-4 duration-300">
                  <div className="mb-10 border-b-2 border-slate-50 pb-6">
                    <h3 className="text-xl font-black text-slate-900 uppercase italic tracking-tight flex items-center gap-3"><History className="w-6 h-6 text-red-600" /> Registro de Movimientos</h3>
                    <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest mt-1">Historial completo del colaborador</p>
                  </div>
                  <div className="space-y-6 relative before:absolute before:left-6 before:top-2 before:bottom-2 before:w-0.5 before:bg-slate-100">
                    {employee.history && employee.history.length > 0 ? (
                      employee.history.sort((a,b) => b.date.localeCompare(a.date)).map((h, i) => (
                        <div key={i} className="relative pl-14 group">
                          <div className={`absolute left-0 top-1 w-12 h-12 rounded-2xl flex items-center justify-center z-10 shadow-lg border-4 border-white ${h.action === 'INGRESO' ? 'bg-emerald-500 text-white' : h.action === 'RETIRO' ? 'bg-red-500 text-white' : 'bg-blue-500 text-white'}`}>
                            {h.action === 'INGRESO' ? <CheckCircle2 className="w-5 h-5" /> : h.action === 'RETIRO' ? <X className="w-5 h-5" /> : <ArrowRight className="w-5 h-5" />}
                          </div>
                          <div className="bg-slate-50 p-6 rounded-[24px] border border-slate-100 group-hover:bg-white transition-all">
                             <div className="flex justify-between mb-1">
                               <p className={`text-[10px] font-black uppercase ${h.action === 'INGRESO' ? 'text-emerald-600' : h.action === 'RETIRO' ? 'text-red-600' : 'text-blue-600'}`}>{h.action}</p>
                               <span className="text-[10px] font-black text-slate-400">{h.date}</span>
                             </div>
                             <p className="text-sm font-black text-slate-800 uppercase italic flex items-center gap-2"><MapPin className="w-3.5 h-3.5" /> {h.restaurantName}</p>
                          </div>
                        </div>
                      ))
                    ) : (
                      <div className="p-10 text-center bg-slate-50 rounded-3xl border border-dashed border-slate-200">
                        <p className="text-[10px] font-black text-slate-400 uppercase italic">Sin eventos registrados</p>
                      </div>
                    )}
                  </div>
                </div>
              ) : (
                <div className="animate-in fade-in">
                  <div className="mb-10 flex items-center justify-between border-b-2 border-slate-50 pb-6">
                    <div>
                      <h3 className="text-xl font-black text-slate-900 uppercase italic tracking-tight">{(EVALUATION_GROUPS as any)[activeGroup].name}</h3>
                      <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest mt-1">Evaluación del periodo: {month}</p>
                    </div>
                  </div>
                  <div className="space-y-4">
                    {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                      const score = formGrades.find(g => g.group === activeGroup && g.category === cat)?.score ?? 0;
                      return (
                        <div key={cat} className={`bg-slate-50/50 border-2 rounded-[24px] p-6 transition-all flex items-center justify-between gap-8 ${isPeriodLocked ? 'opacity-70 grayscale cursor-not-allowed' : 'hover:bg-white hover:border-slate-200'} border-transparent`}>
                          <div className="flex-1">
                            <label className="text-xs font-black text-slate-900 uppercase mb-3 block">{cat}</label>
                            <div className="h-3 bg-slate-200 rounded-full overflow-hidden">
                              <div className={`h-full transition-all duration-700 ${score >= 90 ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${score}%`}} />
                            </div>
                          </div>
                          <div className="relative shrink-0">
                            <input 
                              type="number" 
                              disabled={isPeriodLocked}
                              placeholder="0"
                              value={score === 0 ? '' : score} 
                              onChange={e => handleScoreChange(activeGroup, cat, e.target.value)} 
                              className={`w-24 px-4 py-4 bg-white border-2 rounded-2xl text-2xl font-black text-center shadow-md outline-none ${isPeriodLocked ? 'border-slate-100 text-slate-300' : score >= 90 ? 'border-emerald-100 text-emerald-700 focus:border-emerald-500' : 'border-slate-200 text-slate-800 focus:border-red-500'}`} 
                            />
                            <span className="absolute -right-2 -top-2 text-[8px] font-black bg-slate-900 text-white px-2 py-1 rounded-lg uppercase shadow-lg">%</span>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="p-8 border-t border-slate-100 bg-slate-50 flex justify-between items-center shrink-0">
          {/* Moved Sync Badge to Bottom Left */}
          <div>
            {!isPeriodLocked && (
              <div className="flex items-center gap-2 bg-emerald-500/10 px-4 py-2 rounded-xl border border-emerald-500/20 shadow-sm animate-pulse">
                <Cloud className="w-4 h-4 text-emerald-500" />
                <span className="text-[10px] font-black uppercase tracking-widest text-emerald-600">Sincronización Activa</span>
              </div>
            )}
          </div>
          <div className="flex items-center gap-4">
            <button onClick={onClose} className="px-8 py-4 bg-white text-slate-400 font-black rounded-2xl border-2 border-slate-200 hover:bg-slate-100 uppercase text-[11px] transition-all">
              {isPeriodLocked ? 'Regresar' : 'Cancelar'}
            </button>
            {!isPeriodLocked && (
              <button onClick={saveGrades} disabled={isSaving} className="px-12 py-4 bg-red-600 text-white text-[11px] font-black rounded-2xl shadow-2xl hover:bg-red-700 active:scale-95 transition-all uppercase flex items-center gap-3 disabled:opacity-50">
                {isSaving ? <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" /> : <Save className="w-4 h-4" />}
                {isSaving ? 'Guardando...' : 'Guardar Evaluación'}
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

