                   className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest transition-all ${showHistory ? 'bg-white text-slate-900' : 'bg-white/10 text-white hover:bg-white/20'}`}
