                  <div className="flex items-center justify-between mb-8">
                    <h3 className="text-lg font-black uppercase italic tracking-tight">{(EVALUATION_GROUPS as any)[activeGroup].name}</h3>
                    {isPeriodLocked && <div className="flex items-center gap-1.5 bg-red-100 text-red-600 px-3 py-1 rounded-full text-[9px] font-black uppercase"><Lock className="w-3 h-3"/> Lectura</div>}
                  </div>
                  <div className="space-y-4">
                    {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                      const score = formGrades.find(g => g.group === activeGroup && g.category === cat)?.score ?? 0;
                      return (
                        <div key={cat} className="bg-slate-50/50 border-2 border-transparent rounded-[24px] p-5 flex items-center justify-between gap-6 transition-all hover:bg-white hover:border-slate-100">
                          <div className="flex-1">
                            <label className="text-[10px] font-black text-slate-900 uppercase mb-3 block">{cat}</label>
                            <div className="h-2 bg-slate-200 rounded-full overflow-hidden">
                              <div className={`h-full ${score >= 90 ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${score}%`}} />
                            </div>
                          </div>
                          <div className="relative">
                            <input 
                              type="number" 
                              disabled={isPeriodLocked}
                              value={score === 0 ? '' : score} 
                              onChange={e => handleScoreChange(activeGroup, cat, e.target.value)} 
                              className={`w-16 md:w-20 px-2 py-3 bg-white border-2 rounded-xl text-lg font-black text-center shadow-md outline-none ${isPeriodLocked ? 'text-slate-300' : score >= 90 ? 'border-emerald-100 text-emerald-700' : 'border-slate-200 text-slate-800 focus:border-red-500'}`} 
                            />
                            <span className="absolute -right-1 -top-1 text-[8px] font-black bg-slate-900 text-white px-1.5 py-0.5 rounded shadow">%</span>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="p-6 md:p-8 border-t border-slate-100 bg-slate-50 flex flex-col sm:flex-row gap-4 justify-between items-center shrink-0">
          <div className="hidden sm:block">
            {isPeriodLocked ? (
              <span className="text-[10px] font-black text-slate-400 uppercase italic">Registro histórico no editable</span>
            ) : (
              <div className="flex items-center gap-2 text-emerald-600 bg-emerald-50 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border border-emerald-100 shadow-sm animate-pulse">
                <Cloud className="w-4 h-4"/> Nube Activa
              </div>
            )}
          </div>
          <div className="flex items-center gap-4 w-full sm:w-auto">
            <button onClick={onClose} className="flex-1 sm:flex-none px-8 py-4 bg-white text-slate-400 font-black rounded-2xl border-2 border-slate-200 text-[10px] uppercase transition-all">Regresar</button>
            {!isPeriodLocked && (
              <button onClick={saveGrades} disabled={isSaving} className="flex-1 sm:flex-none px-10 py-4 bg-red-600 text-white text-[10px] font-black rounded-2xl shadow-xl hover:bg-red-700 transition-all uppercase flex items-center justify-center gap-2">
                {isSaving ? <RefreshCw className="w-4 h-4 animate-spin"/> : <Save className="w-4 h-4"/>}
                {isSaving ? 'Guardando...' : 'Guardar Notas'}
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default GradeEditor;

import React, { useState, useMemo } from 'react';
import { dataService } from '../dataService';
import { UserRole, User, HierarchyData, Restaurant } from '../types';
import * as XLSX from 'xlsx';
import { 
  Shield, 
  AlertCircle, 
  CheckCircle2, 
  X, 
  FileSpreadsheet, 
  Network, 
  UserPlus, 
  Trash2, 
  Key,
  Download,
  MapPin,
  Store,
  Layers,
  ChevronDown,
  Check
} from 'lucide-react';

interface AdminPanelProps {
  onEmployeesImported: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onEmployeesImported }) => {
  const [activeSubTab, setActiveSubTab] = useState<'import' | 'users' | 'hierarchy'>('import');
  const [importStatus, setImportStatus] = useState<{message: string, isError: boolean} | null>(null);
  const [hierarchy, setHierarchy] = useState<HierarchyData>(dataService.getHierarchy());
  const [users, setUsers] = useState<User[]>(dataService.getUsers());
  const [showUserModal, setShowUserModal] = useState(false);
  const [isClearing, setIsClearing] = useState(false);
  const [showZoneDropdown, setShowZoneDropdown] = useState(false);

  const [newUser, setNewUser] = useState<Partial<User>>({
    username: '',
    password: '',
    role: UserRole.SPECIALIST,
    assignedZones: [],
    assignedRestaurants: []
  });

  const availableZones = useMemo(() => {
    const zones = new Set<string>();
    hierarchy.regions.forEach(r => r.zones.forEach(z => zones.add(z.name)));
    return Array.from(zones).sort();
  }, [hierarchy]);

  const handleDownloadTemplate = (type: 'employees' | 'hierarchy') => {
    let data = [];
    let filename = "";
    if (type === 'hierarchy') {
      data = [{ "Nombre_Ceco": "1234", "Nombre": "TIENDA EJEMPLO", "Zona": "ZONA 1", "Regional": "REGION SUR" }];
      filename = "Plantilla_Jerarquia_KFC.xlsx";
    } else {
      data = [{ 
        "Documento": "1000222333", 
        "Nombre completo": "JUAN PEREZ", 
        "Fecha de ingreso": "2023-01-15", 
        "Cargo": "Miembro de equipo", 
        "Nombre_Ceco": "1234", 
        "Estado": "ACTIVO", 
        "Fecha fin": "" 
      }];
      filename = "Plantilla_Trabajadores_KFC.xlsx";
    }
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Plantilla");
    XLSX.writeFile(wb, filename);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'employees' | 'hierarchy') => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImportStatus({ message: 'Procesando archivo...', isError: false });
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws);
        if (type === 'employees') {
          const res = await dataService.importMonthlyExcel(data);
          setImportStatus({ message: `Carga exitosa: ${res.count} trabajadores sincronizados.`, isError: false });
        } else {
          const count = await dataService.importHierarchyExcel(data);
          setImportStatus({ message: `Éxito: ${count} tiendas sincronizadas correctamente.`, isError: false });
          setHierarchy(dataService.getHierarchy());
        }
        onEmployeesImported();
      } catch (err: any) { 
        setImportStatus({ message: `Error: ${err.message}`, isError: true }); 
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; 
  };

  const handleClearDatabase = async () => {
    if (!confirm("¿ESTÁS TOTALMENTE SEGURO? Esta acción eliminará a TODOS los trabajadores y TODAS las notas actuales.")) return;
    setIsClearing(true);
    try {
      await dataService.clearAllDataInCloud();
      setImportStatus({ message: "Base de datos reiniciada correctamente.", isError: false });
      onEmployeesImported();
    } catch (e) {
      setImportStatus({ message: "Error al reiniciar base de datos.", isError: true });
    } finally {
      setIsClearing(false);
    }
  };

  const handleCreateUser = async () => {
    if (!newUser.username || !newUser.password) { alert("Usuario y contraseña requeridos"); return; }
    const userToSave: User = { 
      id: `user_${Date.now()}`, 
      username: newUser.username!, 
      password: newUser.password!, 
      role: newUser.role!, 
      assignedZones: newUser.assignedZones || [], 
      assignedRestaurants: newUser.assignedRestaurants || [] 
    };
    try {
      const updatedUsers = [...users, userToSave];
      await dataService.saveUsers(updatedUsers);
      setUsers(updatedUsers);
      setShowUserModal(false);
      setNewUser({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [], assignedRestaurants: [] });
    } catch (e) { alert("Error al guardar en nube"); }
  };

  const toggleZone = (zone: string) => {
    const current = newUser.assignedZones || [];
    if (current.includes(zone)) {
      setNewUser({ ...newUser, assignedZones: current.filter(z => z !== zone) });
    } else {
      setNewUser({ ...newUser, assignedZones: [...current, zone] });
    }
  };

  const handleDeleteUser = async (id: string) => {
    if (confirm("¿Eliminar usuario?")) {
      try { await dataService.deleteUser(id); setUsers(users.filter(u => u.id !== id)); } catch (e) { alert("Error al eliminar"); }
    }
  };

  const allRestaurants = dataService.getRestaurants();

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-8 rounded-[32px] shadow-sm border border-slate-100">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
          <div className="flex items-center space-x-4">
            <div className="p-3 bg-red-600 text-white rounded-2xl shadow-lg"><Shield className="w-6 h-6" /></div>
            <div>
              <h2 className="text-xl font-black text-slate-800 tracking-tight uppercase italic">Admin KFC</h2>
              <div className="flex flex-wrap gap-2 mt-2">
                {[
                  {id: 'import', label: 'Carga Excel'},
                  {id: 'hierarchy', label: 'Estructura'},
                  {id: 'users', label: 'Especialistas'}
                ].map(tab => (
                  <button key={tab.id} onClick={() => setActiveSubTab(tab.id as any)} className={`text-[8px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full transition ${activeSubTab === tab.id ? 'bg-slate-900 text-white shadow-md' : 'bg-slate-100 text-slate-400'}`}>
                    {tab.label}
                  </button>
                ))}
              </div>
            </div>
          </div>
          {activeSubTab === 'import' && (
            <button 
              onClick={handleClearDatabase} 
              disabled={isClearing}
              className="px-6 py-2.5 bg-red-50 text-red-600 border border-red-100 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-red-600 hover:text-white transition-all disabled:opacity-50"
            >
              {isClearing ? 'Reiniciando...' : 'Reiniciar Todo (Data y Notas)'}
            </button>
          )}
        </div>

        {importStatus && (
          <div className={`mb-6 p-4 rounded-2xl flex items-center gap-3 animate-in slide-in-from-top-2 duration-300 ${importStatus.isError ? 'bg-red-50 text-red-700 border border-red-100' : 'bg-emerald-50 text-emerald-700 border border-emerald-100'}`}>
            {importStatus.isError ? <AlertCircle className="w-5 h-5 shrink-0" /> : <CheckCircle2 className="w-5 h-5 shrink-0" />}
            <p className="text-[10px] font-black uppercase tracking-widest">{importStatus.message}</p>
            <button onClick={() => setImportStatus(null)} className="ml-auto p-1 hover:bg-black/5 rounded-full"><X className="w-4 h-4"/></button>
          </div>
        )}

        {activeSubTab === 'import' && (
          <div className="space-y-6 animate-in fade-in">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-4">
                <label className="p-8 border-2 border-dashed border-slate-200 rounded-[32px] bg-slate-50/30 text-center cursor-pointer block hover:bg-red-50 hover:border-red-200 transition-all group">
                  <FileSpreadsheet className="w-10 h-10 text-slate-200 mx-auto mb-4 group-hover:text-red-400 transition-colors" />
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sincronizar Trabajadores (.xlsx)</p>
                  <input type="file" className="hidden" accept=".xlsx" onChange={e => handleFileUpload(e, 'employees')} />
                </label>
                <button onClick={() => handleDownloadTemplate('employees')} className="w-full flex items-center justify-center gap-2 py-3 bg-white border-2 border-slate-100 rounded-xl text-[9px] font-black uppercase tracking-widest text-slate-500 hover:bg-slate-50 transition-all">
                  <Download className="w-3 h-3" /> Descargar Plantilla Trabajadores
                </button>
              </div>

              <div className="space-y-4">
                <label className="p-8 border-2 border-dashed border-slate-200 rounded-[32px] bg-slate-50/30 text-center cursor-pointer block hover:bg-red-50 hover:border-red-200 transition-all group">
                  <Network className="w-10 h-10 text-slate-200 mx-auto mb-4 group-hover:text-red-400 transition-colors" />
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sincronizar Estructura (.xlsx)</p>
                  <input type="file" className="hidden" accept=".xlsx" onChange={e => handleFileUpload(e, 'hierarchy')} />
                </label>
                <button onClick={() => handleDownloadTemplate('hierarchy')} className="w-full flex items-center justify-center gap-2 py-3 bg-white border-2 border-slate-100 rounded-xl text-[9px] font-black uppercase tracking-widest text-slate-500 hover:bg-slate-50 transition-all">
                  <Download className="w-3 h-3" /> Descargar Plantilla Estructura
                </button>
              </div>
            </div>
            <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-relaxed">
                <AlertCircle className="w-3 h-3 inline mr-1 text-red-500" />
                El cierre de periodos es automático. Al iniciar un nuevo mes calendario, los meses anteriores se bloquean para edición para asegurar la integridad del histórico.
              </p>
            </div>
          </div>
        )}

        {activeSubTab === 'hierarchy' && (
          <div className="space-y-6 animate-in fade-in">
            <div className="flex flex-wrap gap-4">
               <div className="px-6 py-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-center gap-4">
                 <MapPin className="w-6 h-6 text-red-600" />
                 <div><p className="text-[10px] font-black text-slate-400 uppercase">Regiones</p><p className="text-lg font-black text-slate-900 leading-tight">{hierarchy.regions.length}</p></div>
               </div>
               <div className="px-6 py-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-center gap-4">
                 <AlertCircle className="w-6 h-6 text-slate-400" />
                 <div><p className="text-[10px] font-black text-slate-400 uppercase">Zonas</p><p className="text-lg font-black text-slate-900 leading-tight">{hierarchy.regions.reduce((acc, r) => acc + r.zones.length, 0)}</p></div>
               </div>
               <div className="px-6 py-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-center gap-4">
                 <Store className="w-6 h-6 text-slate-400" />
                 <div><p className="text-[10px] font-black text-slate-400 uppercase">Tiendas</p><p className="text-lg font-black text-slate-900 leading-tight">{allRestaurants.length}</p></div>
               </div>
            </div>

            <div className="space-y-4 max-h-[500px] overflow-y-auto pr-2 no-scrollbar">
              {hierarchy.regions.map(region => (
                <div key={region.name} className="bg-slate-50/50 rounded-3xl border border-slate-100 overflow-hidden">
                  <div className="p-5 bg-slate-900 text-white flex items-center gap-3">
                    <MapPin className="w-4 h-4 text-red-500" />
                    <span className="text-xs font-black uppercase italic tracking-widest">Región: {region.name}</span>
                  </div>
                  <div className="p-4 grid grid-cols-1 md:grid-cols-2 gap-4">
                    {region.zones.map(zone => (
                      <div key={zone.name} className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm">
                        <div className="flex items-center justify-between mb-3">
                          <p className="text-[11px] font-black text-slate-800 uppercase italic">Zona: {zone.name}</p>
                          <span className="text-[9px] font-black bg-slate-100 px-2 py-0.5 rounded text-slate-400">{zone.restaurantIds.length} Tiendas</span>
                        </div>
                        <div className="flex flex-wrap gap-2">
                          {zone.restaurantIds.map(rid => {
                            const rName = allRestaurants.find(r => r.id === rid)?.name || rid;
                            return (
                              <span key={rid} className="text-[8px] font-black bg-slate-50 border border-slate-100 px-2 py-1 rounded-md uppercase text-slate-500">
                                {rid} - {rName}
                              </span>
                            );
                          })}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
              {hierarchy.regions.length === 0 && (
                <div className="p-20 text-center border-2 border-dashed border-slate-100 rounded-3xl">
                  <p className="text-xs font-black text-slate-300 uppercase tracking-widest">Cargue un archivo de estructura para visualizar los datos</p>
                </div>
              )}
            </div>
          </div>
        )}

        {activeSubTab === 'users' && (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            <button onClick={() => setShowUserModal(true)} className="p-6 border-2 border-dashed border-slate-200 rounded-3xl flex flex-col items-center justify-center text-slate-400 hover:bg-slate-50 transition-colors">
              <UserPlus className="w-6 h-6 mb-2" />
              <span className="text-[9px] font-black uppercase">Nuevo Especialista</span>
            </button>
            {users.map(u => (
              <div key={u.id} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm group hover:border-red-200 transition-all relative">
                <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity">
                  {u.username !== 'admin' && <button onClick={() => handleDeleteUser(u.id)} className="p-2 text-slate-300 hover:text-red-600 bg-slate-50 rounded-lg"><Trash2 className="w-4 h-4" /></button>}
                </div>
                <div className="min-w-0">
                  <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center mb-3 text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-all"><Key className="w-5 h-5" /></div>
                  <p className="text-xs font-black text-slate-800 uppercase truncate italic">{u.username}</p>
                  <p className="text-[8px] font-black text-slate-400 uppercase mt-1 tracking-widest">{u.role}</p>
                  {u.role === UserRole.SPECIALIST && u.assignedZones.length > 0 && (
                    <div className="mt-3 flex flex-wrap gap-1">
                      {u.assignedZones.map(z => (
                        <span key={z} className="text-[7px] font-black bg-slate-50 px-1.5 py-0.5 rounded border border-slate-100 uppercase text-slate-400">{z}</span>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {showUserModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-4 animate-in fade-in duration-300">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-lg flex flex-col overflow-hidden border-2 border-white/20">
            <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
              <div className="flex items-center gap-4">
                <div className="p-3 bg-red-600 rounded-2xl shadow-xl shadow-red-900/20">
                  <UserPlus className="w-6 h-6 text-white" />
                </div>
                <h3 className="font-black uppercase italic tracking-tighter text-xl">Creación de Usuario</h3>
              </div>
              <button onClick={() => { setShowUserModal(false); setShowZoneDropdown(false); }} className="p-2 bg-white/10 hover:bg-white/20 rounded-xl transition-all">
                <X className="w-6 h-6" />
              </button>
            </div>
            <div className="p-8 space-y-6">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nombre de Usuario</label>
                  <input 
                    type="text" 
                    value={newUser.username} 
                    onChange={e => setNewUser({...newUser, username: e.target.value})} 
                    className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-black text-slate-900 outline-none focus:border-red-500 focus:bg-white transition-all placeholder:text-slate-300" 
                    placeholder="Ej: kfc_especialista" 
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Contraseña</label>
                  <input 
                    type="password" 
                    value={newUser.password} 
                    onChange={e => setNewUser({...newUser, password: e.target.value})} 
                    className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-black text-slate-900 outline-none focus:border-red-500 focus:bg-white transition-all placeholder:text-slate-300" 
                    placeholder="••••••••" 
                  />
                </div>
              </div>

              <div className="space-y-2 relative">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-1.5">
                  <Layers className="w-3 h-3" /> Asignar Zonas Activas
                </label>
                <div className="relative">
                  <button 
                    onClick={() => setShowZoneDropdown(!showZoneDropdown)}
                    className="w-full flex items-center justify-between px-4 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-xs font-black text-slate-900 shadow-sm transition-all hover:border-slate-300"
                  >
                    <span className="truncate">
                      {newUser.assignedZones && newUser.assignedZones.length > 0 
                        ? `${newUser.assignedZones.length} zonas seleccionadas` 
                        : 'Seleccionar zonas...'}
                    </span>
                    <ChevronDown className={`w-4 h-4 text-slate-400 transition-transform ${showZoneDropdown ? 'rotate-180' : ''}`} />
                  </button>

                  {showZoneDropdown && (
                    <div className="absolute top-full left-0 right-0 mt-2 bg-white border-2 border-slate-100 rounded-2xl shadow-2xl z-[210] overflow-hidden animate-in fade-in slide-in-from-top-2">
                      <div className="max-h-[180px] overflow-y-auto p-2 space-y-1 no-scrollbar">
                        {availableZones.map(zone => (
                          <button
                            key={zone}
                            onClick={() => toggleZone(zone)}
                            className={`w-full flex items-center justify-between px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${newUser.assignedZones?.includes(zone) ? 'bg-red-50 text-red-600' : 'text-slate-500 hover:bg-slate-50'}`}
                          >
                            <span>{zone}</span>
                            {newUser.assignedZones?.includes(zone) && <Check className="w-3.5 h-3.5" />}
                          </button>
                        ))}
                        {availableZones.length === 0 && (
                          <div className="py-4 text-center text-[9px] font-black text-slate-400 uppercase">Cargue la estructura primero</div>
