                </div>
              </div>

              <button 
                onClick={handleCreateUser} 
                className="w-full py-4 bg-red-600 text-white font-black rounded-2xl hover:bg-red-700 shadow-2xl shadow-red-100 transition-all uppercase tracking-widest text-xs flex items-center justify-center gap-2"
              >
                <Shield className="w-4 h-4" /> Guardar Perfil Especialista
              </button>
            </div>
            <div className="p-4 bg-slate-50 text-center border-t border-slate-100">
              <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest">Control de acceso administrado por KFC Cloud Core</p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useMemo } from 'react';
import { Employee, GradeEntry } from '../types';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { dataService } from '../dataService';
import { X, Save, User, Calendar, Clock, GraduationCap, Star, Trophy, ClipboardCheck, Vault, ChevronRight, CheckCircle2, MapPin, Cloud, History, ArrowRight, Lock, RefreshCw } from 'lucide-react';

interface GradeEditorProps {
  employee: Employee;
  month: string;
  onClose: () => void;
}

const GroupIcons: Record<string, React.ReactNode> = {
  'A': <GraduationCap className="w-5 h-5" />,
  'B': <Star className="w-5 h-5" />,
  'C': <Trophy className="w-5 h-5" />,
  'D': <ClipboardCheck className="w-5 h-5" />,
  'E': <Vault className="w-5 h-5" />,
};

const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('A');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);
  const [isSaving, setIsSaving] = useState(false);
  const [showHistory, setShowHistory] = useState(false);

  const currentMonthStr = new Date().toISOString().slice(0, 7);
  const isPeriodLocked = month < currentMonthStr;

  useEffect(() => {
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    setFormGrades(existing);
  }, [employee, month]);

  const seniority = useMemo(() => {
    if (!employee.join_date) return "N/A";
    const start = new Date(employee.join_date);
    const now = new Date();
    let diff = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth());
    if (diff < 0) return "Reciente";
    const years = Math.floor(diff / 12);
    const months = diff % 12;

    let result = "";
    if (years > 0) result += `${years} año${years > 1 ? 's' : ''} `;
    result += `${months} mes${months !== 1 ? 'es' : ''}`;
    return result;
  }, [employee.join_date]);

  const handleScoreChange = (group: string, category: string, scoreStr: string) => {
    if (isPeriodLocked) return;
    let score = scoreStr === '' ? 0 : Math.max(0, Math.min(100, parseInt(scoreStr) || 0));
    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) { 
        const next = [...prev]; 
        next[idx] = { ...next[idx], score }; 
        return next; 
      }
      return [...prev, { employeeId: employee.id, month, group, category, score }];
    });
  };

  const saveGrades = async () => {
    if (isPeriodLocked) return;
    setIsSaving(true);
    try {
      await dataService.saveEmployeeGrades(employee.id, month, formGrades);
      onClose();
    } catch (err: any) {
      console.error(err);
      alert(`Error al guardar notas: ${err.message || 'Error de base de datos'}`);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-950/90 backdrop-blur-xl animate-in fade-in duration-300">
      <div className="bg-white h-full w-full md:h-[92vh] md:max-w-6xl md:rounded-[48px] flex flex-col overflow-hidden relative shadow-2xl">

        {/* Header Responsivo */}
        <div className="p-5 md:p-8 bg-slate-900 text-white shrink-0 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div className="flex items-center space-x-4 md:space-x-6">
            <div className="w-12 h-12 md:w-16 md:h-16 bg-red-600 rounded-2xl md:rounded-3xl flex items-center justify-center shadow-lg border-4 border-white/10">
              <User className="w-6 h-6 md:w-9 md:h-9 text-white" />
            </div>
            <div>
              <div className="flex flex-wrap items-center gap-2 md:gap-4">
                 <h2 className="text-lg md:text-2xl font-black uppercase italic truncate max-w-[200px] md:max-w-none">{employee.name}</h2>
                 <span className="px-3 py-1 bg-red-600 text-[8px] md:text-[10px] font-black rounded-full uppercase tracking-widest">{employee.title}</span>
              </div>
              <div className="flex flex-wrap gap-3 mt-1 text-[9px] font-black uppercase tracking-widest opacity-60">
                <span className="flex items-center gap-1"><Clock className="w-3 h-3" /> {seniority}</span>
                <span className="flex items-center gap-1"><MapPin className="w-3 h-3" /> {employee.restaurant_id}</span>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-2 self-end md:self-auto">
            <button 
              onClick={() => setShowHistory(!showHistory)}
              className={`flex items-center gap-2 px-3 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${showHistory ? 'bg-white text-slate-900' : 'bg-white/10 text-white hover:bg-white/20'}`}
            >
              <History className="w-4 h-4" /> <span className="hidden sm:inline">Trayectoria</span>
            </button>
            <button onClick={onClose} className="p-2 bg-white/10 hover:bg-red-600 rounded-xl transition-all shadow-md"><X className="w-6 h-6"/></button>
          </div>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
          {/* Navegación de Grupos (Sidebar en MD, Horiz en SM) */}
          <div className="w-full md:w-72 bg-slate-50 border-r border-slate-200 flex md:flex-col overflow-x-auto md:overflow-y-auto p-4 gap-3 no-scrollbar shrink-0 sticky top-0 z-10 bg-slate-50 shadow-sm md:shadow-none">
            {Object.entries(EVALUATION_GROUPS).map(([id, group]) => {
              const isActive = activeGroup === id && !showHistory;
              const groupGrades = formGrades.filter(g => g.group === id);
              const groupAvg = groupGrades.length > 0 ? Math.round(groupGrades.reduce((s, g) => s + g.score, 0) / (group as any).categories.length) : 0;

              return (
                <button 
                  key={id} 
                  disabled={showHistory}
                  onClick={() => { setActiveGroup(id); setShowHistory(false); }} 
                  className={`p-3 md:p-5 rounded-2xl md:rounded-3xl text-left border-2 transition-all flex items-center gap-3 shrink-0 md:shrink ${isActive ? 'bg-white border-red-600 shadow-lg scale-105 md:scale-100' : 'bg-transparent border-transparent opacity-50'} ${showHistory ? 'cursor-not-allowed grayscale' : ''}`}
                >
                  <div className={`p-2 rounded-xl ${isActive ? 'bg-red-600 text-white' : 'bg-slate-200 text-slate-500'}`}>{GroupIcons[id]}</div>
                  <div className="hidden md:block flex-1 min-w-0">
                    <p className={`text-[10px] font-black uppercase tracking-tight ${isActive ? 'text-slate-900' : 'text-slate-500'}`}>{group.name}</p>
                    <div className="mt-2 flex items-center gap-2">
                       <div className="flex-1 h-1 bg-slate-200 rounded-full overflow-hidden">
                          <div className={`h-full ${groupAvg >= 90 ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${groupAvg}%`}} />
                       </div>
                       <span className="text-[9px] font-black text-slate-400">{groupAvg}%</span>
                    </div>
                  </div>
                </button>
              );
            })}
          </div>

          {/* Contenido Principal */}
          <div className="flex-1 overflow-y-auto p-4 md:p-12 bg-white no-scrollbar">
            <div className="max-w-2xl mx-auto">
              {showHistory ? (
                <div className="space-y-4">
                  <h3 className="text-lg font-black uppercase italic tracking-tight mb-6 flex items-center gap-3"><History className="w-5 h-5 text-red-600" /> Historial de Movimientos</h3>
                  {employee.history?.map((h, i) => (
                    <div key={i} className="bg-slate-50 p-5 rounded-3xl border border-slate-100 flex items-center justify-between">
                      <div>
                        <p className={`text-[9px] font-black uppercase ${h.action === 'INGRESO' ? 'text-emerald-600' : h.action === 'RETIRO' ? 'text-red-600' : 'text-blue-600'}`}>{h.action}</p>
                        <p className="text-sm font-black text-slate-800 uppercase italic mt-1">{h.restaurantName}</p>
                      </div>
                      <span className="text-[9px] font-black text-slate-400">{h.date}</span>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="space-y-6">
                  {/* Título de Grupo Visible en Móviles */}
                  <div className="md:hidden mb-2">
                    <div className="flex items-center gap-3 p-4 bg-slate-50 rounded-2xl border border-slate-100">
                      <div className="p-2 bg-red-600 text-white rounded-lg">{GroupIcons[activeGroup]}</div>
                      <div>
                        <p className="text-[11px] font-black text-slate-900 uppercase italic tracking-tight">{(EVALUATION_GROUPS as any)[activeGroup].name}</p>
                        <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">Grupo de Evaluación</p>
                      </div>
                    </div>
                  </div>

                  <div className="hidden md:flex items-center justify-between mb-8">
                    <h3 className="text-lg font-black uppercase italic tracking-tight">{(EVALUATION_GROUPS as any)[activeGroup].name}</h3>
                    {isPeriodLocked && <div className="flex items-center gap-1.5 bg-red-100 text-red-600 px-3 py-1 rounded-full text-[9px] font-black uppercase"><Lock className="w-3 h-3"/> Lectura</div>}
                  </div>

                  <div className="space-y-4">
                    {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                      const score = formGrades.find(g => g.group === activeGroup && g.category === cat)?.score ?? 0;
                      return (
                        <div key={cat} className="bg-slate-50/50 border-2 border-transparent rounded-[24px] p-5 flex items-center justify-between gap-6 transition-all hover:bg-white hover:border-slate-100">
                          <div className="flex-1">
                            <label className="text-[10px] font-black text-slate-900 uppercase mb-3 block">{cat}</label>
                            <div className="h-2 bg-slate-200 rounded-full overflow-hidden">
                              <div className={`h-full ${score >= 90 ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${score}%`}} />
                            </div>
                          </div>
                          <div className="relative">
                            <input 
                              type="number" 
                              disabled={isPeriodLocked}
                              value={score === 0 ? '' : score} 
                              onChange={e => handleScoreChange(activeGroup, cat, e.target.value)} 
                              className={`w-16 md:w-20 px-2 py-3 bg-white border-2 rounded-xl text-lg font-black text-center shadow-md outline-none ${isPeriodLocked ? 'text-slate-300' : score >= 90 ? 'border-emerald-100 text-emerald-700' : 'border-slate-200 text-slate-800 focus:border-red-500'}`} 
                            />
                            <span className="absolute -right-1 -top-1 text-[8px] font-black bg-slate-900 text-white px-1.5 py-0.5 rounded shadow">%</span>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="p-6 md:p-8 border-t border-slate-100 bg-slate-50 flex flex-col sm:flex-row gap-4 justify-between items-center shrink-0">
          <div className="hidden sm:block">
            {isPeriodLocked ? (
              <span className="text-[10px] font-black text-slate-400 uppercase italic">Registro histórico no editable</span>
            ) : (
              <div className="flex items-center gap-2 text-emerald-600 bg-emerald-50 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border border-emerald-100 shadow-sm animate-pulse">
                <Cloud className="w-4 h-4"/> Nube Activa
              </div>
            )}
          </div>
          <div className="flex items-center gap-4 w-full sm:w-auto">
            <button onClick={onClose} className="flex-1 sm:flex-none px-8 py-4 bg-white text-slate-400 font-black rounded-2xl border-2 border-slate-200 text-[10px] uppercase transition-all">Regresar</button>
            {!isPeriodLocked && (
              <button onClick={saveGrades} disabled={isSaving} className="flex-1 sm:flex-none px-10 py-4 bg-red-600 text-white text-[10px] font-black rounded-2xl shadow-xl hover:bg-red-700 transition-all uppercase flex items-center justify-center gap-2">
                {isSaving ? <RefreshCw className="w-4 h-4 animate-spin"/> : <Save className="w-4 h-4"/>}
                {isSaving ? 'Guardando...' : 'Guardar Notas'}
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default GradeEditor;

import React, { useMemo, useState } from 'react';
import { User, Restaurant, Employee, UserRole, JobHierarchy } from '../types';
import { Store, MapPin, Users, Award, ArrowLeft, User as UserIcon, TrendingUp, Briefcase, Search, Filter, Edit3, Clock } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import GradeEditor from './GradeEditor';

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
  onUpdate: () => void;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth, onUpdate }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [storeSearch, setStoreSearch] = useState('');
  const [empSearch, setEmpSearch] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');

  const calculateSeniority = (joinDate: string) => {
    if (!joinDate) return "N/A";
    const start = new Date(joinDate);
    const now = new Date();
    let diff = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth());
    if (diff < 0) return "Reciente";
    const years = Math.floor(diff / 12);
    const months = diff % 12;

    let result = "";
    if (years > 0) result += `${years} año${years > 1 ? 's' : ''} `;
    if (months > 0 || years === 0) result += `${months} mes${months !== 1 ? 'es' : ''}`;
    return result.trim();
  };

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    let zones = Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) zones = zones.filter(z => user.assignedZones.includes(z));
    return zones;
  }, [restaurants, filterRegion, user]);

  const assigned = useMemo(() => {
    let base = user.role === UserRole.ADMIN 
      ? restaurants 
      : restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));

    return base.filter(r => {
      const matchSearch = storeSearch === '' || r.name.toLowerCase().includes(storeSearch.toLowerCase()) || r.id.includes(storeSearch);
      const matchRegion = filterRegion === 'all' || r.region === filterRegion;
      const matchZone = filterZone === 'all' || r.zone === filterZone;
      return matchSearch && matchRegion && matchZone;
    });
  }, [user, restaurants, storeSearch, filterRegion, filterZone]);

  const getStoreStats = (storeId: string) => {
    const storeEmps = employees.filter(e => e.restaurant_id === storeId);
    if (storeEmps.length === 0) return { total: 0, approved: 0, percent: 0 };
    let approved = 0;
    const grades = dataService.getGrades().filter(g => g.month === selectedMonth);
    storeEmps.forEach(emp => {
      const empGrades = grades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        const sum = empGrades.reduce((sum, g) => sum + g.score, 0);
        const avg = sum / TOTAL_CATEGORIES_COUNT;
        if (avg >= APPROVAL_THRESHOLD) approved++;
      }
    });
    return { total: storeEmps.length, approved, percent: Math.round((approved / storeEmps.length) * 100) };
  };

  const selectClasses = "p-3 bg-white border-2 border-slate-100 rounded-xl text-[10px] font-black uppercase text-slate-800 outline-none focus:border-red-500 transition-all shadow-sm";

  if (selectedStore) {
    const stats = getStoreStats(selectedStore.id);
    const storeEmps = employees
      .filter(e => e.restaurant_id === selectedStore.id && (user.role === UserRole.ADMIN ? true : e.active))
      .filter(e => empSearch === '' || e.name.toLowerCase().includes(empSearch.toLowerCase()) || e.id.includes(empSearch))
      .sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));

    return (
      <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center space-x-4">
            <button onClick={() => { setSelectedStore(null); setEmpSearch(''); }} className="p-3 bg-white border-2 border-slate-100 rounded-2xl text-slate-400 hover:text-red-600 transition-all shadow-sm"><ArrowLeft className="w-5 h-5" /></button>
            <div className="min-w-0">
              <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tighter uppercase italic leading-none truncate">{selectedStore.name}</h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-widest flex items-center mt-2 truncate"><MapPin className="w-3 h-3 mr-1.5 text-red-500" /> {selectedStore.zone} • {selectedStore.region}</p>
            </div>
          </div>
          <div className="relative w-full md:w-72">
            <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <input 
              type="text" 
              placeholder="Buscar colaborador..." 
              value={empSearch}
              onChange={e => setEmpSearch(e.target.value)}
              className="w-full pl-12 pr-4 py-3.5 bg-white border-2 border-slate-100 rounded-2xl text-xs font-black shadow-sm outline-none focus:border-red-500 transition-all" 
            />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <DetailStatCard icon={<Users className="w-6 h-6" />} label="Equipo" value={stats.total} color="blue" />
          <DetailStatCard icon={<Award className="w-6 h-6" />} label="Aprobados" value={stats.approved} color="green" />
          <DetailStatCard icon={<TrendingUp className="w-6 h-6" />} label="Éxito" value={`${stats.percent}%`} color="red" />
        </div>

        <div className="bg-white rounded-[32px] md:rounded-[40px] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b border-slate-50 flex justify-between items-center">
             <h3 className="text-[10px] font-black uppercase italic tracking-widest flex items-center">
               <Users className="w-4 h-4 mr-2 text-red-600" /> Colaboradores
             </h3>
             <span className="text-[8px] font-black bg-slate-100 px-3 py-1.5 rounded-full uppercase text-slate-400 hidden sm:inline">Orden Jerárquico</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50">
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Antigüedad</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Cargo</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {storeEmps.map(emp => (
                  <tr key={emp.id} className="hover:bg-slate-50/80 transition-all group">
                    <td className="px-4 md:px-8 py-4 text-center">
                      <button 
                        onClick={() => setEditingEmployee(emp)} 
                        className="px-4 py-3 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-red-600 shadow-lg shadow-slate-100 hover:shadow-red-100 transition-all uppercase tracking-widest flex items-center justify-center gap-2 mx-auto"
                      >
                        <Edit3 className="w-4 h-4" />
                        <span className="hidden sm:inline">Notas</span>
                      </button>
                    </td>
                    <td className="px-4 md:px-8 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-9 h-9 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-colors hidden sm:flex">
                          <UserIcon className="w-4 h-4" />
                        </div>
                        <div>
                          <p className="font-black text-slate-800 text-[12px] uppercase italic leading-tight group-hover:text-red-600 transition-colors">{emp.name}</p>
                          <p className="text-[8px] text-slate-400 font-black uppercase tracking-widest mt-0.5">ID: {emp.id}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-4 md:px-8 py-4">
                      <div className="flex items-center gap-2 text-slate-500">
                        <Clock className="w-3 h-3 text-slate-300" />
                        <span className="text-[10px] font-black uppercase">{calculateSeniority(emp.join_date)}</span>
                      </div>
                    </td>
                    <td className="px-4 md:px-8 py-4">
                      <span className="text-[10px] font-black text-slate-700 uppercase italic tracking-tight">{emp.title}</span>
                    </td>
                  </tr>
                ))}
                {storeEmps.length === 0 && (
                  <tr>
                    <td colSpan={4} className="p-20 text-center">
                      <p className="text-[11px] font-black text-slate-400 uppercase italic tracking-[0.2em]">Sin resultados</p>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
        {editingEmployee && <GradeEditor employee={editingEmployee} month={selectedMonth} onClose={() => { setEditingEmployee(null); onUpdate(); }} />}
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
          <select value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
          <select value={filterZone} onChange={(e) => setFilterZone(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
          </select>
        </div>
        <div className="md:col-span-2 space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Buscar Tienda</label>
          <input 
            type="text" 
            placeholder="CECO o Nombre..." 
            value={storeSearch}
            onChange={e => setStoreSearch(e.target.value)}
            className="w-full p-3.5 bg-slate-50 border-2 border-slate-100 rounded-xl text-xs font-black uppercase shadow-inner outline-none focus:bg-white focus:border-red-500 transition-all" 
          />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {assigned.map(store => {
          const stats = getStoreStats(store.id);
          return (
            <div key={store.id} onClick={() => setSelectedStore(store)} className="bg-white rounded-[32px] shadow-sm border-2 border-slate-50 overflow-hidden hover:border-red-500 hover:shadow-2xl hover:shadow-red-50 transition-all group cursor-pointer flex flex-col p-8">
              <div className="flex items-start justify-between mb-8">
                <div className="flex items-center space-x-4">
                  <div className="w-14 h-14 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400 group-hover:bg-red-600 group-hover:text-white transition-all shadow-inner"><Store className="w-7 h-7" /></div>
                  <div className="min-w-0">
                    <h3 className="font-black text-slate-800 text-lg truncate uppercase tracking-tighter leading-tight italic">{store.name}</h3>
                    <p className="text-[9px] text-slate-400 font-black uppercase truncate tracking-widest mt-1">{store.region} • {store.zone}</p>
                  </div>
                </div>
              </div>
              <div className="mt-auto grid grid-cols-2 gap-4">
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Equipo</p><p className="text-xl font-black text-slate-800 tracking-tighter">{stats.total}</p></div>
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Éxito</p><p className={`text-xl font-black tracking-tighter ${stats.percent >= 90 ? 'text-emerald-600' : 'text-red-600'}`}>{stats.percent}%</p></div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

