import React, { useState, useMemo } from 'react';
import { dataService } from '../dataService';
import { UserRole, User, HierarchyData, Restaurant } from '../types';
import * as XLSX from 'xlsx';
import { 
  Shield, 
  AlertCircle, 
  CheckCircle2, 
  X, 
  FileSpreadsheet, 
  Network, 
  UserPlus, 
  Trash2, 
  Key,
  Download,
  MapPin,
  Store,
  Layers,
  ChevronDown,
  Check
} from 'lucide-react';

interface AdminPanelProps {
  onEmployeesImported: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onEmployeesImported }) => {
  const [activeSubTab, setActiveSubTab] = useState<'import' | 'users' | 'hierarchy'>('import');
  const [importStatus, setImportStatus] = useState<{message: string, isError: boolean} | null>(null);
  const [hierarchy, setHierarchy] = useState<HierarchyData>(dataService.getHierarchy());
  const [users, setUsers] = useState<User[]>(dataService.getUsers());
  const [showUserModal, setShowUserModal] = useState(false);
  const [isClearing, setIsClearing] = useState(false);
  const [showZoneDropdown, setShowZoneDropdown] = useState(false);

  const [newUser, setNewUser] = useState<Partial<User>>({
    username: '',
    password: '',
    role: UserRole.SPECIALIST,
    assignedZones: [],
    assignedRestaurants: []
  });

  const availableZones = useMemo(() => {
    const zones = new Set<string>();
    hierarchy.regions.forEach(r => r.zones.forEach(z => zones.add(z.name)));
    return Array.from(zones).sort();
  }, [hierarchy]);

  const handleDownloadTemplate = (type: 'employees' | 'hierarchy') => {
    let data = [];
    let filename = "";
    if (type === 'hierarchy') {
      data = [{ "Nombre_Ceco": "1234", "Nombre": "TIENDA EJEMPLO", "Zona": "ZONA 1", "Regional": "REGION SUR" }];
      filename = "Plantilla_Jerarquia_KFC.xlsx";
    } else {
      data = [{ 
        "Documento": "1000222333", 
        "Nombre completo": "JUAN PEREZ", 
        "Fecha de ingreso": "2023-01-15", 
        "Cargo": "Miembro de equipo", 
        "Nombre_Ceco": "1234", 
        "Estado": "ACTIVO", 
        "Fecha fin": "" 
      }];
      filename = "Plantilla_Trabajadores_KFC.xlsx";
    }
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Plantilla");
    XLSX.writeFile(wb, filename);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'employees' | 'hierarchy') => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImportStatus({ message: 'Procesando archivo...', isError: false });
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws);
        if (type === 'employees') {
          const res = await dataService.importMonthlyExcel(data);
          setImportStatus({ message: `Carga exitosa: ${res.count} trabajadores sincronizados.`, isError: false });
        } else {
          const count = await dataService.importHierarchyExcel(data);
          setImportStatus({ message: `Éxito: ${count} tiendas sincronizadas correctamente.`, isError: false });
          setHierarchy(dataService.getHierarchy());
        }
        onEmployeesImported();
      } catch (err: any) { 
        setImportStatus({ message: `Error: ${err.message}`, isError: true }); 
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; 
  };

  const handleClearDatabase = async () => {
    if (!confirm("¿ESTÁS TOTALMENTE SEGURO? Esta acción eliminará a TODOS los trabajadores y TODAS las notas actuales.")) return;
    setIsClearing(true);
    try {
      await dataService.clearAllDataInCloud();
      setImportStatus({ message: "Base de datos reiniciada correctamente.", isError: false });
      onEmployeesImported();
    } catch (e) {
      setImportStatus({ message: "Error al reiniciar base de datos.", isError: true });
    } finally {
      setIsClearing(false);
    }
  };

  const handleCreateUser = async () => {
    if (!newUser.username || !newUser.password) { alert("Usuario y contraseña requeridos"); return; }
    const userToSave: User = { 
      id: `user_${Date.now()}`, 
      username: newUser.username!, 
      password: newUser.password!, 
      role: newUser.role!, 
      assignedZones: newUser.assignedZones || [], 
      assignedRestaurants: newUser.assignedRestaurants || [] 
    };
    try {
      const updatedUsers = [...users, userToSave];
      await dataService.saveUsers(updatedUsers);
      setUsers(updatedUsers);
      setShowUserModal(false);
      setNewUser({ username: '', password: '', role: UserRole.SPECIALIST, assignedZones: [], assignedRestaurants: [] });
    } catch (e) { alert("Error al guardar en nube"); }
  };

  const toggleZone = (zone: string) => {
    const current = newUser.assignedZones || [];
    if (current.includes(zone)) {
      setNewUser({ ...newUser, assignedZones: current.filter(z => z !== zone) });
    } else {
      setNewUser({ ...newUser, assignedZones: [...current, zone] });
    }
  };

  const handleDeleteUser = async (id: string) => {
    if (confirm("¿Eliminar usuario?")) {
      try { await dataService.deleteUser(id); setUsers(users.filter(u => u.id !== id)); } catch (e) { alert("Error al eliminar"); }
    }
  };

  const allRestaurants = dataService.getRestaurants();

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 md:p-8 rounded-[32px] shadow-sm border border-slate-100">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
          <div className="flex items-center space-x-4">
            <div className="p-3 bg-red-600 text-white rounded-2xl shadow-lg"><Shield className="w-6 h-6" /></div>
            <div>
              <h2 className="text-xl font-black text-slate-800 tracking-tight uppercase italic">Admin KFC</h2>
              <div className="flex flex-wrap gap-2 mt-2">
                {[
                  {id: 'import', label: 'Carga Excel'},
                  {id: 'hierarchy', label: 'Estructura'},
                  {id: 'users', label: 'Especialistas'}
                ].map(tab => (
                  <button key={tab.id} onClick={() => setActiveSubTab(tab.id as any)} className={`text-[8px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full transition ${activeSubTab === tab.id ? 'bg-slate-900 text-white shadow-md' : 'bg-slate-100 text-slate-400'}`}>
                    {tab.label}
                  </button>
                ))}
              </div>
            </div>
          </div>
          {activeSubTab === 'import' && (
            <button 
              onClick={handleClearDatabase} 
              disabled={isClearing}
              className="px-6 py-2.5 bg-red-50 text-red-600 border border-red-100 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-red-600 hover:text-white transition-all disabled:opacity-50"
            >
              {isClearing ? 'Reiniciando...' : 'Reiniciar Todo (Data y Notas)'}
            </button>
          )}
        </div>

        {importStatus && (
          <div className={`mb-6 p-4 rounded-2xl flex items-center gap-3 animate-in slide-in-from-top-2 duration-300 ${importStatus.isError ? 'bg-red-50 text-red-700 border border-red-100' : 'bg-emerald-50 text-emerald-700 border border-emerald-100'}`}>
            {importStatus.isError ? <AlertCircle className="w-5 h-5 shrink-0" /> : <CheckCircle2 className="w-5 h-5 shrink-0" />}
            <p className="text-[10px] font-black uppercase tracking-widest">{importStatus.message}</p>
            <button onClick={() => setImportStatus(null)} className="ml-auto p-1 hover:bg-black/5 rounded-full"><X className="w-4 h-4"/></button>
          </div>
        )}

        {activeSubTab === 'import' && (
          <div className="space-y-6 animate-in fade-in">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-4">
                <label className="p-8 border-2 border-dashed border-slate-200 rounded-[32px] bg-slate-50/30 text-center cursor-pointer block hover:bg-red-50 hover:border-red-200 transition-all group">
                  <FileSpreadsheet className="w-10 h-10 text-slate-200 mx-auto mb-4 group-hover:text-red-400 transition-colors" />
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sincronizar Trabajadores (.xlsx)</p>
                  <input type="file" className="hidden" accept=".xlsx" onChange={e => handleFileUpload(e, 'employees')} />
                </label>
                <button onClick={() => handleDownloadTemplate('employees')} className="w-full flex items-center justify-center gap-2 py-3 bg-white border-2 border-slate-100 rounded-xl text-[9px] font-black uppercase tracking-widest text-slate-500 hover:bg-slate-50 transition-all">
                  <Download className="w-3 h-3" /> Descargar Plantilla Trabajadores
                </button>
              </div>

              <div className="space-y-4">
                <label className="p-8 border-2 border-dashed border-slate-200 rounded-[32px] bg-slate-50/30 text-center cursor-pointer block hover:bg-red-50 hover:border-red-200 transition-all group">
                  <Network className="w-10 h-10 text-slate-200 mx-auto mb-4 group-hover:text-red-400 transition-colors" />
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sincronizar Estructura (.xlsx)</p>
                  <input type="file" className="hidden" accept=".xlsx" onChange={e => handleFileUpload(e, 'hierarchy')} />
                </label>
                <button onClick={() => handleDownloadTemplate('hierarchy')} className="w-full flex items-center justify-center gap-2 py-3 bg-white border-2 border-slate-100 rounded-xl text-[9px] font-black uppercase tracking-widest text-slate-500 hover:bg-slate-50 transition-all">
                  <Download className="w-3 h-3" /> Descargar Plantilla Estructura
                </button>
              </div>
            </div>
            <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-relaxed">
                <AlertCircle className="w-3 h-3 inline mr-1 text-red-500" />
                El cierre de periodos es automático. Al iniciar un nuevo mes calendario, los meses anteriores se bloquean para edición para asegurar la integridad del histórico.
              </p>
            </div>
          </div>
        )}

        {activeSubTab === 'hierarchy' && (
          <div className="space-y-6 animate-in fade-in">
            <div className="flex flex-wrap gap-4">
               <div className="px-6 py-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-center gap-4">
                 <MapPin className="w-6 h-6 text-red-600" />
                 <div><p className="text-[10px] font-black text-slate-400 uppercase">Regiones</p><p className="text-lg font-black text-slate-900 leading-tight">{hierarchy.regions.length}</p></div>
               </div>
               <div className="px-6 py-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-center gap-4">
                 <AlertCircle className="w-6 h-6 text-slate-400" />
                 <div><p className="text-[10px] font-black text-slate-400 uppercase">Zonas</p><p className="text-lg font-black text-slate-900 leading-tight">{hierarchy.regions.reduce((acc, r) => acc + r.zones.length, 0)}</p></div>
               </div>
               <div className="px-6 py-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-center gap-4">
                 <Store className="w-6 h-6 text-slate-400" />
                 <div><p className="text-[10px] font-black text-slate-400 uppercase">Tiendas</p><p className="text-lg font-black text-slate-900 leading-tight">{allRestaurants.length}</p></div>
               </div>
            </div>

            <div className="space-y-4 max-h-[500px] overflow-y-auto pr-2 no-scrollbar">
              {hierarchy.regions.map(region => (
                <div key={region.name} className="bg-slate-50/50 rounded-3xl border border-slate-100 overflow-hidden">
                  <div className="p-5 bg-slate-900 text-white flex items-center gap-3">
                    <MapPin className="w-4 h-4 text-red-500" />
                    <span className="text-xs font-black uppercase italic tracking-widest">Región: {region.name}</span>
                  </div>
                  <div className="p-4 grid grid-cols-1 md:grid-cols-2 gap-4">
                    {region.zones.map(zone => (
                      <div key={zone.name} className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm">
                        <div className="flex items-center justify-between mb-3">
                          <p className="text-[11px] font-black text-slate-800 uppercase italic">Zona: {zone.name}</p>
                          <span className="text-[9px] font-black bg-slate-100 px-2 py-0.5 rounded text-slate-400">{zone.restaurantIds.length} Tiendas</span>
                        </div>
                        <div className="flex flex-wrap gap-2">
                          {zone.restaurantIds.map(rid => {
                            const rName = allRestaurants.find(r => r.id === rid)?.name || rid;
                            return (
                              <span key={rid} className="text-[8px] font-black bg-slate-50 border border-slate-100 px-2 py-1 rounded-md uppercase text-slate-500">
                                {rid} - {rName}
                              </span>
                            );
                          })}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
              {hierarchy.regions.length === 0 && (
                <div className="p-20 text-center border-2 border-dashed border-slate-100 rounded-3xl">
                  <p className="text-xs font-black text-slate-300 uppercase tracking-widest">Cargue un archivo de estructura para visualizar los datos</p>
                </div>
              )}
            </div>
          </div>
        )}

        {activeSubTab === 'users' && (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            <button onClick={() => setShowUserModal(true)} className="p-6 border-2 border-dashed border-slate-200 rounded-3xl flex flex-col items-center justify-center text-slate-400 hover:bg-slate-50 transition-colors">
              <UserPlus className="w-6 h-6 mb-2" />
              <span className="text-[9px] font-black uppercase">Nuevo Especialista</span>
            </button>
            {users.map(u => (
              <div key={u.id} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm group hover:border-red-200 transition-all relative">
                <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity">
                  {u.username !== 'admin' && <button onClick={() => handleDeleteUser(u.id)} className="p-2 text-slate-300 hover:text-red-600 bg-slate-50 rounded-lg"><Trash2 className="w-4 h-4" /></button>}
                </div>
                <div className="min-w-0">
                  <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center mb-3 text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-all"><Key className="w-5 h-5" /></div>
                  <p className="text-xs font-black text-slate-800 uppercase truncate italic">{u.username}</p>
                  <p className="text-[8px] font-black text-slate-400 uppercase mt-1 tracking-widest">{u.role}</p>
                  {u.role === UserRole.SPECIALIST && u.assignedZones.length > 0 && (
                    <div className="mt-3 flex flex-wrap gap-1">
                      {u.assignedZones.map(z => (
                        <span key={z} className="text-[7px] font-black bg-slate-50 px-1.5 py-0.5 rounded border border-slate-100 uppercase text-slate-400">{z}</span>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {showUserModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-4 animate-in fade-in duration-300">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-lg flex flex-col overflow-hidden border-2 border-white/20">
            <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
              <div className="flex items-center gap-4">
                <div className="p-3 bg-red-600 rounded-2xl shadow-xl shadow-red-900/20">
                  <UserPlus className="w-6 h-6 text-white" />
                </div>
                <h3 className="font-black uppercase italic tracking-tighter text-xl">Creación de Usuario</h3>
              </div>
              <button onClick={() => { setShowUserModal(false); setShowZoneDropdown(false); }} className="p-2 bg-white/10 hover:bg-white/20 rounded-xl transition-all">
                <X className="w-6 h-6" />
              </button>
            </div>
            <div className="p-8 space-y-6">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nombre de Usuario</label>
                  <input 
                    type="text" 
                    value={newUser.username} 
                    onChange={e => setNewUser({...newUser, username: e.target.value})} 
                    className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-black text-slate-900 outline-none focus:border-red-500 focus:bg-white transition-all placeholder:text-slate-300" 
                    placeholder="Ej: kfc_especialista" 
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Contraseña</label>
                  <input 
                    type="password" 
                    value={newUser.password} 
                    onChange={e => setNewUser({...newUser, password: e.target.value})} 
                    className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-black text-slate-900 outline-none focus:border-red-500 focus:bg-white transition-all placeholder:text-slate-300" 
                    placeholder="••••••••" 
                  />
                </div>
              </div>

              <div className="space-y-2 relative">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-1.5">
                  <Layers className="w-3 h-3" /> Asignar Zonas Activas
                </label>
                <div className="relative">
                  <button 
                    onClick={() => setShowZoneDropdown(!showZoneDropdown)}
                    className="w-full flex items-center justify-between px-4 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-xs font-black text-slate-900 shadow-sm transition-all hover:border-slate-300"
                  >
                    <span className="truncate">
                      {newUser.assignedZones && newUser.assignedZones.length > 0 
                        ? `${newUser.assignedZones.length} zonas seleccionadas` 
                        : 'Seleccionar zonas...'}
                    </span>
                    <ChevronDown className={`w-4 h-4 text-slate-400 transition-transform ${showZoneDropdown ? 'rotate-180' : ''}`} />
                  </button>

                  {showZoneDropdown && (
                    <div className="absolute top-full left-0 right-0 mt-2 bg-white border-2 border-slate-100 rounded-2xl shadow-2xl z-[210] overflow-hidden animate-in fade-in slide-in-from-top-2">
                      <div className="max-h-[180px] overflow-y-auto p-2 space-y-1 no-scrollbar">
                        {availableZones.map(zone => (
                          <button
                            key={zone}
                            onClick={() => toggleZone(zone)}
                            className={`w-full flex items-center justify-between px-4 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${newUser.assignedZones?.includes(zone) ? 'bg-red-50 text-red-600' : 'text-slate-500 hover:bg-slate-50'}`}
                          >
                            <span>{zone}</span>
                            {newUser.assignedZones?.includes(zone) && <Check className="w-3.5 h-3.5" />}
                          </button>
                        ))}
                        {availableZones.length === 0 && (
                          <div className="py-4 text-center text-[9px] font-black text-slate-400 uppercase">Cargue la estructura primero</div>
                        )}
                      </div>
                    </div>
                  )}
                </div>
              </div>

              <button 
                onClick={handleCreateUser} 
                className="w-full py-4 bg-red-600 text-white font-black rounded-2xl hover:bg-red-700 shadow-2xl shadow-red-100 transition-all uppercase tracking-widest text-xs flex items-center justify-center gap-2"
              >
                <Shield className="w-4 h-4" /> Guardar Perfil Especialista
              </button>
            </div>
            <div className="p-4 bg-slate-50 text-center border-t border-slate-100">
              <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest">Control de acceso administrado por KFC Cloud Core</p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useMemo } from 'react';
import { Employee, GradeEntry } from '../types';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { dataService } from '../dataService';
import { X, Save, User, Calendar, Clock, GraduationCap, Star, Trophy, ClipboardCheck, Vault, ChevronRight, CheckCircle2, MapPin, Cloud, History, ArrowRight, Lock, RefreshCw } from 'lucide-react';

interface GradeEditorProps {
  employee: Employee;
  month: string;
  onClose: () => void;
}

const GroupIcons: Record<string, React.ReactNode> = {
  'A': <GraduationCap className="w-5 h-5" />,
  'B': <Star className="w-5 h-5" />,
  'C': <Trophy className="w-5 h-5" />,
  'D': <ClipboardCheck className="w-5 h-5" />,
  'E': <Vault className="w-5 h-5" />,
};

const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('A');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);
  const [isSaving, setIsSaving] = useState(false);
  const [showHistory, setShowHistory] = useState(false);

  const currentMonthStr = new Date().toISOString().slice(0, 7);
  const isPeriodLocked = month < currentMonthStr;

  useEffect(() => {
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    setFormGrades(existing);
  }, [employee, month]);

  const seniority = useMemo(() => {
    if (!employee.join_date) return "N/A";
    const start = new Date(employee.join_date);
    const now = new Date();
    let diff = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth());
    if (diff < 0) return "Reciente";
    const years = Math.floor(diff / 12);
    const months = diff % 12;

    let result = "";
    if (years > 0) result += `${years} año${years > 1 ? 's' : ''} `;
    if (months > 0 || years === 0) result += `${months} mes${months !== 1 ? 'es' : ''}`;
    return result.trim();
  }, [employee.join_date]);

  const handleScoreChange = (group: string, category: string, scoreStr: string) => {
    if (isPeriodLocked) return;
    let score = scoreStr === '' ? 0 : Math.max(0, Math.min(100, parseInt(scoreStr) || 0));
    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) { 
        const next = [...prev]; 
        next[idx] = { ...next[idx], score }; 
        return next; 
      }
      return [...prev, { employeeId: employee.id, month, group, category, score }];
    });
  };

  const saveGrades = async () => {
    if (isPeriodLocked) return;
    setIsSaving(true);
    try {
      await dataService.saveEmployeeGrades(employee.id, month, formGrades);
      onClose();
    } catch (err: any) {
      console.error(err);
      alert(`Error al guardar notas: ${err.message || 'Error de base de datos'}`);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-950/90 backdrop-blur-xl animate-in fade-in duration-300">
      <div className="bg-white h-full w-full md:h-[92vh] md:max-w-6xl md:rounded-[48px] flex flex-col overflow-hidden relative shadow-2xl">

        {/* Header Responsivo */}
        <div className="p-5 md:p-8 bg-slate-900 text-white shrink-0 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div className="flex items-center space-x-4 md:space-x-6">
            <div className="w-12 h-12 md:w-16 md:h-16 bg-red-600 rounded-2xl md:rounded-3xl flex items-center justify-center shadow-lg border-4 border-white/10">
              <User className="w-6 h-6 md:w-9 md:h-9 text-white" />
            </div>
            <div>
              <div className="flex flex-wrap items-center gap-2 md:gap-4">
                 <h2 className="text-lg md:text-2xl font-black uppercase italic truncate max-w-[200px] md:max-w-none">{employee.name}</h2>
                 <span className="px-3 py-1 bg-red-600 text-[8px] md:text-[10px] font-black rounded-full uppercase tracking-widest">{employee.title}</span>
              </div>
              <div className="flex flex-wrap gap-x-4 gap-y-1 mt-1 text-[9px] font-black uppercase tracking-widest opacity-60">
                <span className="flex items-center gap-1"><Calendar className="w-3 h-3" /> Ingreso: {employee.join_date}</span>
                <span className="flex items-center gap-1"><Clock className="w-3 h-3" /> Antigüedad: {seniority}</span>
                <span className="flex items-center gap-1"><MapPin className="w-3 h-3" /> CECO: {employee.restaurant_id}</span>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-2 self-end md:self-auto">
            <button 
              onClick={() => setShowHistory(!showHistory)}
              className={`flex items-center gap-2 px-3 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${showHistory ? 'bg-white text-slate-900' : 'bg-white/10 text-white hover:bg-white/20'}`}
            >
              <History className="w-4 h-4" /> <span className="hidden sm:inline">Trayectoria</span>
            </button>
            <button onClick={onClose} className="p-2 bg-white/10 hover:bg-red-600 rounded-xl transition-all shadow-md"><X className="w-6 h-6"/></button>
          </div>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
          {/* Navegación de Grupos (Sidebar en MD, Horiz en SM) */}
          <div className="w-full md:w-72 bg-slate-50 border-r border-slate-200 flex md:flex-col overflow-x-auto md:overflow-y-auto p-4 gap-3 no-scrollbar shrink-0 sticky top-0 z-10 bg-slate-50 shadow-sm md:shadow-none">
            {Object.entries(EVALUATION_GROUPS).map(([id, group]) => {
              const isActive = activeGroup === id && !showHistory;
              const groupGrades = formGrades.filter(g => g.group === id);
              const groupAvg = groupGrades.length > 0 ? Math.round(groupGrades.reduce((s, g) => s + g.score, 0) / (group as any).categories.length) : 0;

              return (
                <button 
                  key={id} 
                  disabled={showHistory}
                  onClick={() => { setActiveGroup(id); setShowHistory(false); }} 
                  className={`p-3 md:p-5 rounded-2xl md:rounded-3xl text-left border-2 transition-all flex items-center gap-3 shrink-0 md:shrink ${isActive ? 'bg-white border-red-600 shadow-lg scale-105 md:scale-100' : 'bg-transparent border-transparent opacity-50'} ${showHistory ? 'cursor-not-allowed grayscale' : ''}`}
                >
                  <div className={`p-2 rounded-xl ${isActive ? 'bg-red-600 text-white' : 'bg-slate-200 text-slate-500'}`}>{GroupIcons[id]}</div>
                  <div className="hidden md:block flex-1 min-w-0">
                    <p className={`text-[10px] font-black uppercase tracking-tight ${isActive ? 'text-slate-900' : 'text-slate-500'}`}>{group.name}</p>
                    <div className="mt-2 flex items-center gap-2">
                       <div className="flex-1 h-1 bg-slate-200 rounded-full overflow-hidden">
                          <div className={`h-full ${groupAvg >= 90 ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${groupAvg}%`}} />
                       </div>
                       <span className="text-[9px] font-black text-slate-400">{groupAvg}%</span>
                    </div>
                  </div>
                </button>
              );
            })}
          </div>

          {/* Contenido Principal */}
          <div className="flex-1 overflow-y-auto p-4 md:p-12 bg-white no-scrollbar">
            <div className="max-w-2xl mx-auto">
              {showHistory ? (
                <div className="space-y-4">
                  <h3 className="text-lg font-black uppercase italic tracking-tight mb-6 flex items-center gap-3"><History className="w-5 h-5 text-red-600" /> Historial de Movimientos</h3>
                  {employee.history?.map((h, i) => (
                    <div key={i} className="bg-slate-50 p-5 rounded-3xl border border-slate-100 flex items-center justify-between">
                      <div>
                        <p className={`text-[9px] font-black uppercase ${h.action === 'INGRESO' ? 'text-emerald-600' : h.action === 'RETIRO' ? 'text-red-600' : 'text-blue-600'}`}>{h.action}</p>
                        <p className="text-sm font-black text-slate-800 uppercase italic mt-1">{h.restaurantName}</p>
                      </div>
                      <span className="text-[9px] font-black text-slate-400">{h.date}</span>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="space-y-6">
                  {/* Título de Grupo Visible en Móviles */}
                  <div className="md:hidden mb-2">
                    <div className="flex items-center gap-3 p-4 bg-slate-50 rounded-2xl border border-slate-100">
                      <div className="p-2 bg-red-600 text-white rounded-lg">{GroupIcons[activeGroup]}</div>
                      <div>
                        <p className="text-[11px] font-black text-slate-900 uppercase italic tracking-tight">{(EVALUATION_GROUPS as any)[activeGroup].name}</p>
                        <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">Grupo de Evaluación</p>
                      </div>
                    </div>
                  </div>

                  <div className="hidden md:flex items-center justify-between mb-8">
                    <h3 className="text-lg font-black uppercase italic tracking-tight">{(EVALUATION_GROUPS as any)[activeGroup].name}</h3>
                    {isPeriodLocked && <div className="flex items-center gap-1.5 bg-red-100 text-red-600 px-3 py-1 rounded-full text-[9px] font-black uppercase"><Lock className="w-3 h-3"/> Lectura</div>}
                  </div>

                  <div className="space-y-4">
                    {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                      const score = formGrades.find(g => g.group === activeGroup && g.category === cat)?.score ?? 0;
                      return (
                        <div key={cat} className="bg-slate-50/50 border-2 border-transparent rounded-[24px] p-5 flex items-center justify-between gap-6 transition-all hover:bg-white hover:border-slate-100">
                          <div className="flex-1">
                            <label className="text-[10px] font-black text-slate-900 uppercase mb-3 block">{cat}</label>
                            <div className="h-2 bg-slate-200 rounded-full overflow-hidden">
                              <div className={`h-full ${score >= 90 ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${score}%`}} />
                            </div>
                          </div>
                          <div className="relative">
                            <input 
                              type="number" 
                              disabled={isPeriodLocked}
                              value={score === 0 ? '' : score} 
                              onChange={e => handleScoreChange(activeGroup, cat, e.target.value)} 
                              className={`w-16 md:w-20 px-2 py-3 bg-white border-2 rounded-xl text-lg font-black text-center shadow-md outline-none ${isPeriodLocked ? 'text-slate-300' : score >= 90 ? 'border-emerald-100 text-emerald-700' : 'border-slate-200 text-slate-800 focus:border-red-500'}`} 
                            />
                            <span className="absolute -right-1 -top-1 text-[8px] font-black bg-slate-900 text-white px-1.5 py-0.5 rounded shadow">%</span>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="p-6 md:p-8 border-t border-slate-100 bg-slate-50 flex flex-col sm:flex-row gap-4 justify-between items-center shrink-0">
          <div className="hidden sm:block">
            {isPeriodLocked ? (
              <span className="text-[10px] font-black text-slate-400 uppercase italic">Registro histórico no editable</span>
            ) : (
              <div className="flex items-center gap-2 text-emerald-600 bg-emerald-50 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border border-emerald-100 shadow-sm animate-pulse">
                <Cloud className="w-4 h-4"/> Nube Activa
              </div>
            )}
          </div>
          <div className="flex items-center gap-4 w-full sm:w-auto">
            <button onClick={onClose} className="flex-1 sm:flex-none px-8 py-4 bg-white text-slate-400 font-black rounded-2xl border-2 border-slate-200 text-[10px] uppercase transition-all">Regresar</button>
            {!isPeriodLocked && (
              <button onClick={saveGrades} disabled={isSaving} className="flex-1 sm:flex-none px-10 py-4 bg-red-600 text-white text-[10px] font-black rounded-2xl shadow-xl hover:bg-red-700 transition-all uppercase flex items-center justify-center gap-2">
                {isSaving ? <RefreshCw className="w-4 h-4 animate-spin"/> : <Save className="w-4 h-4"/>}
                {isSaving ? 'Guardando...' : 'Guardar Notas'}
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default GradeEditor;

import React, { useMemo, useState } from 'react';
import { User, Restaurant, Employee, UserRole, JobHierarchy } from '../types';
import { Store, MapPin, Users, Award, ArrowLeft, User as UserIcon, TrendingUp, Briefcase, Search, Filter, Edit3, Clock } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import GradeEditor from './GradeEditor';

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
  onUpdate: () => void;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth, onUpdate }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [storeSearch, setStoreSearch] = useState('');
  const [empSearch, setEmpSearch] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');

  const calculateSeniority = (joinDate: string) => {
    if (!joinDate) return "N/A";
    const start = new Date(joinDate);
    const now = new Date();
    let diff = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth());
    if (diff < 0) return "Reciente";
    const years = Math.floor(diff / 12);
    const months = diff % 12;

    let result = "";
    if (years > 0) result += `${years} año${years > 1 ? 's' : ''} `;
    if (months > 0 || years === 0) result += `${months} mes${months !== 1 ? 'es' : ''}`;
    return result.trim();
  };

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    let zones = Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) zones = zones.filter(z => user.assignedZones.includes(z));
    return zones;
  }, [restaurants, filterRegion, user]);

  const assigned = useMemo(() => {
    let base = user.role === UserRole.ADMIN 
      ? restaurants 
      : restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));

    return base.filter(r => {
      const matchSearch = storeSearch === '' || r.name.toLowerCase().includes(storeSearch.toLowerCase()) || r.id.includes(storeSearch);
      const matchRegion = filterRegion === 'all' || r.region === filterRegion;
      const matchZone = filterZone === 'all' || r.zone === filterZone;
      return matchSearch && matchRegion && matchZone;
    });
  }, [user, restaurants, storeSearch, filterRegion, filterZone]);

  const getStoreStats = (storeId: string) => {
    const storeEmps = employees.filter(e => e.restaurant_id === storeId);
    if (storeEmps.length === 0) return { total: 0, approved: 0, percent: 0 };
    let approved = 0;
    const grades = dataService.getGrades().filter(g => g.month === selectedMonth);
    storeEmps.forEach(emp => {
      const empGrades = grades.filter(g => g.employeeId === emp.id);
      if (empGrades.length > 0) {
        const sum = empGrades.reduce((sum, g) => s + g.score, 0); // Note: s was sum in previous version, fixed here
        const avg = sum / TOTAL_CATEGORIES_COUNT;
        if (avg >= APPROVAL_THRESHOLD) approved++;
      }
    });
    return { total: storeEmps.length, approved, percent: Math.round((approved / storeEmps.length) * 100) };
  };

  const selectClasses = "p-3 bg-white border-2 border-slate-100 rounded-xl text-[10px] font-black uppercase text-slate-800 outline-none focus:border-red-500 transition-all shadow-sm";

  if (selectedStore) {
    const stats = getStoreStats(selectedStore.id);
    const storeEmps = employees
      .filter(e => e.restaurant_id === selectedStore.id && (user.role === UserRole.ADMIN ? true : e.active))
      .filter(e => empSearch === '' || e.name.toLowerCase().includes(empSearch.toLowerCase()) || e.id.includes(empSearch))
      .sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));

    return (
      <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center space-x-4">
            <button onClick={() => { setSelectedStore(null); setEmpSearch(''); }} className="p-3 bg-white border-2 border-slate-100 rounded-2xl text-slate-400 hover:text-red-600 transition-all shadow-sm"><ArrowLeft className="w-5 h-5" /></button>
            <div className="min-w-0">
              <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tighter uppercase italic leading-none truncate">{selectedStore.name}</h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-widest flex items-center mt-2 truncate"><MapPin className="w-3 h-3 mr-1.5 text-red-500" /> {selectedStore.zone} • {selectedStore.region}</p>
            </div>
          </div>
          <div className="relative w-full md:w-72">
            <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
            <input 
              type="text" 
              placeholder="Buscar colaborador..." 
              value={empSearch}
              onChange={e => setEmpSearch(e.target.value)}
              className="w-full pl-12 pr-4 py-3.5 bg-white border-2 border-slate-100 rounded-2xl text-xs font-black shadow-sm outline-none focus:border-red-500 transition-all" 
            />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <DetailStatCard icon={<Users className="w-6 h-6" />} label="Equipo" value={stats.total} color="blue" />
          <DetailStatCard icon={<Award className="w-6 h-6" />} label="Aprobados" value={stats.approved} color="green" />
          <DetailStatCard icon={<TrendingUp className="w-6 h-6" />} label="Éxito" value={`${stats.percent}%`} color="red" />
        </div>

        <div className="bg-white rounded-[32px] md:rounded-[40px] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b border-slate-50 flex justify-between items-center">
             <h3 className="text-[10px] font-black uppercase italic tracking-widest flex items-center">
               <Users className="w-4 h-4 mr-2 text-red-600" /> Colaboradores
             </h3>
             <span className="text-[8px] font-black bg-slate-100 px-3 py-1.5 rounded-full uppercase text-slate-400 hidden sm:inline">Orden Jerárquico</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50">
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Antigüedad</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Cargo</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {storeEmps.map(emp => (
                  <tr key={emp.id} className="hover:bg-slate-50/80 transition-all group">
                    <td className="px-4 md:px-8 py-4 text-center">
                      <button 
                        onClick={() => setEditingEmployee(emp)} 
                        className="px-4 py-3 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-red-600 shadow-lg shadow-slate-100 hover:shadow-red-100 transition-all uppercase tracking-widest flex items-center justify-center gap-2 mx-auto"
                      >
                        <Edit3 className="w-4 h-4" />
                        <span className="hidden sm:inline">Notas</span>
                      </button>
                    </td>
                    <td className="px-4 md:px-8 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-9 h-9 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-colors hidden sm:flex">
                          <UserIcon className="w-4 h-4" />
                        </div>
                        <div>
                          <p className="font-black text-slate-800 text-[12px] uppercase italic leading-tight group-hover:text-red-600 transition-colors">{emp.name}</p>
                          <p className="text-[8px] text-slate-400 font-black uppercase tracking-widest mt-0.5">ID: {emp.id}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-4 md:px-8 py-4">
                      <div className="flex items-center gap-2 text-slate-500">
                        <Clock className="w-3 h-3 text-slate-300" />
                        <span className="text-[10px] font-black uppercase">{calculateSeniority(emp.join_date)}</span>
                      </div>
                    </td>
                    <td className="px-4 md:px-8 py-4">
                      <span className="text-[10px] font-black text-slate-700 uppercase italic tracking-tight">{emp.title}</span>
                    </td>
                  </tr>
                ))}
                {storeEmps.length === 0 && (
                  <tr>
                    <td colSpan={4} className="p-20 text-center">
                      <p className="text-[11px] font-black text-slate-400 uppercase italic tracking-[0.2em]">Sin resultados</p>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
        {editingEmployee && <GradeEditor employee={editingEmployee} month={selectedMonth} onClose={() => { setEditingEmployee(null); onUpdate(); }} />}
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
          <select value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
          <select value={filterZone} onChange={(e) => setFilterZone(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
          </select>
        </div>
        <div className="md:col-span-2 space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Buscar Tienda</label>
          <input 
            type="text" 
            placeholder="CECO o Nombre..." 
            value={storeSearch}
            onChange={e => setStoreSearch(e.target.value)}
            className="w-full p-3.5 bg-slate-50 border-2 border-slate-100 rounded-xl text-xs font-black uppercase shadow-inner outline-none focus:bg-white focus:border-red-500 transition-all" 
          />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {assigned.map(store => {
