import React, { useState, useEffect, useMemo } from 'react';
import { Employee, GradeEntry } from '../types';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { dataService } from '../dataService';
import { X, Save, User, Calendar, Clock, GraduationCap, Star, Trophy, ClipboardCheck, Vault, ChevronRight, CheckCircle2, MapPin, Cloud, History, ArrowRight, Lock, RefreshCw } from 'lucide-react';

interface GradeEditorProps {
  employee: Employee;
  month: string;
  onClose: () => void;
}

const GroupIcons: Record<string, React.ReactNode> = {
  'A': <GraduationCap className="w-5 h-5" />,
  'B': <Star className="w-5 h-5" />,
  'C': <Trophy className="w-5 h-5" />,
  'D': <ClipboardCheck className="w-5 h-5" />,
  'E': <Vault className="w-5 h-5" />,
};

const GradeEditor: React.FC<GradeEditorProps> = ({ employee, month, onClose }) => {
  const [activeGroup, setActiveGroup] = useState<string>('A');
  const [formGrades, setFormGrades] = useState<GradeEntry[]>([]);
  const [isSaving, setIsSaving] = useState(false);
  const [showHistory, setShowHistory] = useState(false);

  const currentMonthStr = new Date().toISOString().slice(0, 7);
  const isPeriodLocked = month < currentMonthStr;

  useEffect(() => {
    // Lógica de Pre-carga:
    // 1. Intentamos obtener notas exactas del mes.
    // 2. Si no hay, cargamos las notas efectivas (las últimas conocidas).
    const existing = dataService.getGrades().filter(g => g.employeeId === employee.id && g.month === month);
    if (existing.length > 0) {
      setFormGrades(existing);
    } else {
      const effective = dataService.getEffectiveGrades(employee.id, month);
      setFormGrades(effective.map(g => ({ ...g, month }))); // Mapeamos al mes actual para que al guardar se graben en este periodo
    }
  }, [employee, month]);

  const seniority = useMemo(() => {
    if (!employee.join_date) return "N/A";
    const start = new Date(employee.join_date);
    const now = new Date();
    let diff = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth());
    if (diff < 0) return "Reciente";
    const years = Math.floor(diff / 12);
    const months = diff % 12;

    let result = "";
    if (years > 0) result += `${years} año${years > 1 ? 's' : ''} `;
    if (months > 0 || years === 0) result += `${months} mes${months !== 1 ? 'es' : ''}`;
    return result.trim();
  }, [employee.join_date]);

  const handleScoreChange = (group: string, category: string, scoreStr: string) => {
    if (isPeriodLocked) return;
    let score = scoreStr === '' ? 0 : Math.max(0, Math.min(100, parseInt(scoreStr) || 0));
    setFormGrades(prev => {
      const idx = prev.findIndex(g => g.group === group && g.category === category);
      if (idx > -1) { 
        const next = [...prev]; 
        next[idx] = { ...next[idx], score }; 
        return next; 
      }
      return [...prev, { employeeId: employee.id, month, group, category, score, restaurantId: employee.restaurant_id }];
    });
  };

  const saveGrades = async () => {
    if (isPeriodLocked) return;
    setIsSaving(true);
    try {
      await dataService.saveEmployeeGrades(employee.id, month, formGrades);
      onClose();
    } catch (err: any) {
      console.error(err);
      alert(`Error al guardar notas: ${err.message || 'Error de base de datos'}`);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-950/90 backdrop-blur-xl animate-in fade-in duration-300">
      <div className="bg-white h-full w-full md:h-[92vh] md:max-w-6xl md:rounded-[48px] flex flex-col overflow-hidden relative shadow-2xl">

        <div className="p-5 md:p-8 bg-slate-900 text-white shrink-0 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div className="flex items-center space-x-4 md:space-x-6">
            <div className="w-12 h-12 md:w-16 md:h-16 bg-red-600 rounded-2xl md:rounded-3xl flex items-center justify-center shadow-lg border-4 border-white/10">
              <User className="w-6 h-6 md:w-9 md:h-9 text-white" />
            </div>
            <div>
              <div className="flex flex-wrap items-center gap-2 md:gap-4">
                 <h2 className="text-lg md:text-2xl font-black uppercase italic truncate max-w-[200px] md:max-w-none">{employee.name}</h2>
                 <span className="px-3 py-1 bg-red-600 text-[8px] md:text-[10px] font-black rounded-full uppercase tracking-widest">{employee.title}</span>
              </div>
              <div className="flex flex-wrap gap-x-4 gap-y-1 mt-1 text-[9px] font-black uppercase tracking-widest opacity-60">
                <span className="flex items-center gap-1"><Calendar className="w-3 h-3" /> Ingreso: {employee.join_date}</span>
                <span className="flex items-center gap-1"><MapPin className="w-3 h-3" /> Tienda Actual: {employee.restaurant_id}</span>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-2 self-end md:self-auto">
             <div className="hidden sm:flex items-center gap-2 px-4 py-2 bg-white/10 rounded-xl text-[9px] font-black uppercase tracking-widest">
               <History className="w-3 h-3 text-red-500" /> Notas por Arrastre Activas
             </div>
             <button onClick={onClose} className="p-2 bg-white/10 hover:bg-red-600 rounded-xl transition-all shadow-md"><X className="w-6 h-6"/></button>
          </div>
        </div>

        <div className="flex-1 flex flex-col md:flex-row overflow-hidden">
          <div className="w-full md:w-72 bg-slate-50 border-r border-slate-200 flex md:flex-col overflow-x-auto md:overflow-y-auto p-4 gap-3 no-scrollbar shrink-0 sticky top-0 z-10 bg-slate-50 shadow-sm md:shadow-none">
            {Object.entries(EVALUATION_GROUPS).map(([id, group]) => {
              const isActive = activeGroup === id && !showHistory;
              const groupGrades = formGrades.filter(g => g.group === id);
              const groupAvg = groupGrades.length > 0 ? Math.round(groupGrades.reduce((s, g) => s + g.score, 0) / (group as any).categories.length) : 0;

              return (
                <button 
                  key={id} 
                  onClick={() => { setActiveGroup(id); setShowHistory(false); }} 
                  className={`p-3 md:p-5 rounded-2xl md:rounded-3xl text-left border-2 transition-all flex items-center gap-3 shrink-0 md:shrink ${isActive ? 'bg-white border-red-600 shadow-lg scale-105 md:scale-100' : 'bg-transparent border-transparent opacity-50'}`}
                >
                  <div className={`p-2 rounded-xl ${isActive ? 'bg-red-600 text-white' : 'bg-slate-200 text-slate-500'}`}>{GroupIcons[id]}</div>
                  <div className="hidden md:block flex-1 min-w-0">
                    <p className={`text-[10px] font-black uppercase tracking-tight ${isActive ? 'text-slate-900' : 'text-slate-500'}`}>{group.name}</p>
                    <div className="mt-2 flex items-center gap-2">
                       <div className="flex-1 h-1 bg-slate-200 rounded-full overflow-hidden">
                          <div className={`h-full ${groupAvg >= 90 ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${groupAvg}%`}} />
                       </div>
                       <span className="text-[9px] font-black text-slate-400">{groupAvg}%</span>
                    </div>
                  </div>
                </button>
              );
            })}
          </div>

          <div className="flex-1 overflow-y-auto p-4 md:p-12 bg-white no-scrollbar">
            <div className="max-w-2xl mx-auto">
              <div className="space-y-6">
                <div className="flex items-center justify-between mb-8">
                  <h3 className="text-lg font-black uppercase italic tracking-tight">{(EVALUATION_GROUPS as any)[activeGroup].name}</h3>
                  {isPeriodLocked && <div className="flex items-center gap-1.5 bg-red-100 text-red-600 px-3 py-1 rounded-full text-[9px] font-black uppercase"><Lock className="w-3 h-3"/> Lectura</div>}
                </div>

                <div className="space-y-4">
                  {(EVALUATION_GROUPS as any)[activeGroup].categories.map((cat: string) => {
                    const grade = formGrades.find(g => g.group === activeGroup && g.category === cat);
                    const score = grade?.score ?? 0;
                    const isInherited = grade && grade.month !== month;

                    return (
                      <div key={cat} className="bg-slate-50/50 border-2 border-transparent rounded-[24px] p-5 flex items-center justify-between gap-6 transition-all hover:bg-white hover:border-slate-100">
                        <div className="flex-1">
                          <div className="flex items-center gap-2 mb-3">
                            <label className="text-[10px] font-black text-slate-900 uppercase block">{cat}</label>
                            {isInherited && <span className="text-[8px] bg-slate-900 text-white px-2 py-0.5 rounded uppercase font-black">Heredado</span>}
                          </div>
                          <div className="h-2 bg-slate-200 rounded-full overflow-hidden">
                            <div className={`h-full ${score >= 90 ? 'bg-emerald-500' : 'bg-red-500'}`} style={{width: `${score}%`}} />
                          </div>
                        </div>
                        <div className="relative">
                          <input 
                            type="number" 
                            disabled={isPeriodLocked}
                            value={score === 0 ? '' : score} 
                            onChange={e => handleScoreChange(activeGroup, cat, e.target.value)} 
                            className={`w-16 md:w-20 px-2 py-3 bg-white border-2 rounded-xl text-lg font-black text-center shadow-md outline-none ${isPeriodLocked ? 'text-slate-300' : score >= 90 ? 'border-emerald-100 text-emerald-700' : 'border-slate-200 text-slate-800 focus:border-red-500'}`} 
                          />
                          <span className="absolute -right-1 -top-1 text-[8px] font-black bg-slate-900 text-white px-1.5 py-0.5 rounded shadow">%</span>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="p-6 md:p-8 border-t border-slate-100 bg-slate-50 flex flex-col sm:flex-row gap-4 justify-between items-center shrink-0">
          <div className="hidden sm:block">
            <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-relaxed">
              * El sistema mantiene la última nota grabada.<br/>
              * Guardar una nota en este mes la hará permanente para este periodo.
            </div>
          </div>
          <div className="flex items-center gap-4 w-full sm:w-auto">
            <button onClick={onClose} className="flex-1 sm:flex-none px-8 py-4 bg-white text-slate-400 font-black rounded-2xl border-2 border-slate-200 text-[10px] uppercase transition-all">Regresar</button>
            {!isPeriodLocked && (
              <button onClick={saveGrades} disabled={isSaving} className="flex-1 sm:flex-none px-10 py-4 bg-red-600 text-white text-[10px] font-black rounded-2xl shadow-xl hover:bg-red-700 transition-all uppercase flex items-center justify-center gap-2">
                {isSaving ? <RefreshCw className="w-4 h-4 animate-spin"/> : <Save className="w-4 h-4"/>}
                {isSaving ? 'Sincronizando...' : 'Guardar y Certificar'}
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

