            </div>

            <div className="p-8 space-y-6">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nombre de Usuario</label>
                  <input 
                    type="text" 
                    autoFocus
                    autoComplete="off"
                    value={newUser.username} 
                    onChange={e => setNewUser({...newUser, username: e.target.value})} 
                    className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-black !text-slate-900 outline-none focus:border-red-500 focus:bg-white transition-all placeholder:text-slate-300" 
                    placeholder="Ej: especialista_01" 
                  />
