                    className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-black !text-slate-900 outline-none focus:border-red-500 focus:bg-white transition-all placeholder:text-slate-300" 
                    placeholder="Contraseña" 
                  />
