                    <ChevronDown className={`w-4 h-4 text-slate-400 transition-transform ${showZoneDropdown ? 'rotate-180' : ''}`} />
                  </button>

                  {showZoneDropdown && (
                    <div className="absolute top-full left-0 right-0 mt-3 bg-white border-2 border-slate-100 rounded-2xl shadow-2xl z-[210] overflow-hidden animate-in fade-in slide-in-from-top-2 border-red-50">
                      <div className="max-h-[200px] overflow-y-auto p-2 space-y-1 no-scrollbar">
