              <div className="pt-4">
                <button 
                  onClick={handleCreateUser} 
                  disabled={isCreatingUser || !newUser.username || !newUser.password}
                  className={`
                    w-full py-5 px-8 rounded-full flex items-center justify-center gap-4 
                    transition-all duration-300 uppercase tracking-[0.2em] text-[12px] font-black
                    shadow-[0_20px_50px_rgba(239,68,68,0.2)] hover:shadow-[0_20px_50px_rgba(239,68,68,0.4)]
                    active:scale-[0.98] disabled:opacity-50 disabled:grayscale disabled:cursor-not-allowed
                    ${isCreatingUser ? 'bg-slate-800 text-white' : 'bg-red-600 text-white hover:bg-red-700'}
                  `}
                >
                  <div className={`
