export default AdminPanel;

import React, { useMemo, useState } from 'react';
import { User, Restaurant, Employee, UserRole, JobHierarchy } from '../types';
import { Store, MapPin, Users, Award, ArrowLeft, User as UserIcon, TrendingUp, Briefcase, Search, Filter, Edit3, FileText, Download, X, Calendar, RefreshCw } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT, EVALUATION_GROUPS } from '../constants';
import GradeEditor from './GradeEditor';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

// Extender tipo para jspdf-autotable
declare module 'jspdf' {
  interface jsPDF {
    autoTable: any;
  }
}

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
  onUpdate: () => void;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth, onUpdate }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [storeSearch, setStoreSearch] = useState('');
  const [empSearch, setEmpSearch] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');

  // PDF Generation State
  const [showPdfModal, setShowPdfModal] = useState(false);
  const [pdfMonth, setPdfMonth] = useState(selectedMonth);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    let zones = Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) zones = zones.filter(z => user.assignedZones.includes(z));
    return zones;
  }, [restaurants, filterRegion, user]);

  const assigned = useMemo(() => {
    let base = user.role === UserRole.ADMIN 
      ? restaurants 
      : restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));

    return base.filter(r => {
      const matchSearch = storeSearch === '' || r.name.toLowerCase().includes(storeSearch.toLowerCase()) || r.id.includes(storeSearch);
      const matchRegion = filterRegion === 'all' || r.region === filterRegion;
      const matchZone = filterZone === 'all' || r.zone === filterZone;
      return matchSearch && matchRegion && matchZone;
    });
  }, [user, restaurants, storeSearch, filterRegion, filterZone]);

  const getStoreStats = (storeId: string, month: string) => {
    const storeEmps = employees.filter(e => e.restaurant_id === storeId && e.active);
    if (storeEmps.length === 0) return { total: 0, approved: 0, percent: 0, groupAvgs: [] };

    let approved = 0;
    const groupTotals: Record<string, { sum: number, count: number }> = {};

    storeEmps.forEach(emp => {
      const effective = dataService.getEffectiveGrades(emp.id, month);
      const sum = effective.reduce((s, g) => s + g.score, 0);
      const avg = TOTAL_CATEGORIES_COUNT > 0 ? sum / TOTAL_CATEGORIES_COUNT : 0;
      if (effective.length > 0 && avg >= APPROVAL_THRESHOLD) approved++;

      // Totales para gráficas
      Object.entries(EVALUATION_GROUPS).forEach(([gid, gconfig]) => {
        const groupGrades = effective.filter(g => g.group === gid);
        const gSum = groupGrades.reduce((s, g) => s + g.score, 0);
        if (!groupTotals[gid]) groupTotals[gid] = { sum: 0, count: 0 };
        groupTotals[gid].sum += (gSum / gconfig.categories.length);
        groupTotals[gid].count++;
      });
    });

    const groupAvgs = Object.entries(EVALUATION_GROUPS).map(([id, config]) => ({
      id,
      name: config.name,
      avg: groupTotals[id] ? Math.round(groupTotals[id].sum / groupTotals[id].count) : 0
    }));

    return { total: storeEmps.length, approved, percent: Math.round((approved / storeEmps.length) * 100), groupAvgs };
  };

  const handleGeneratePDF = async () => {
    if (!selectedStore) return;
    setIsGeneratingPdf(true);

    try {
      const doc = new jsPDF({ orientation: 'landscape', unit: 'mm', format: 'a4' });
      const stats = getStoreStats(selectedStore.id, pdfMonth);
      const storeEmps = employees.filter(e => e.restaurant_id === selectedStore.id && e.active);

      // Colores KFC
      const primaryRed = [227, 24, 55];
      const darkSlate = [15, 23, 42];

      // --- PAGINA 1: PORTADA Y GRAFICAS ---
      doc.setFillColor(darkSlate[0], darkSlate[1], darkSlate[2]);
      doc.rect(0, 0, 297, 40, 'F');

      doc.setTextColor(255, 255, 255);
      doc.setFontSize(22);
      doc.setFont('helvetica', 'bold');
      doc.text('REPORTE DE CURVAS DE CERTIFICACIÓN', 15, 20);

      doc.setFontSize(10);
      doc.setFont('helvetica', 'normal');
      doc.text(`RESTAURANTE: ${selectedStore.name} (${selectedStore.id})`, 15, 30);
      doc.text(`PERIODO: ${pdfMonth}`, 180, 20);
      doc.text(`ZONA: ${selectedStore.zone} | REGIONAL: ${selectedStore.region}`, 180, 30);

      // Graficas de barras simuladas (Resumen de Tienda)
      doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
      doc.setFontSize(14);
      doc.text('RESUMEN DE DESEMPEÑO POR GRUPO (PROMEDIO TIENDA)', 15, 60);

      let startX = 20;
      const chartHeight = 60;
      const barWidth = 35;
      const spacing = 15;

      stats.groupAvgs.forEach((g, i) => {
        const x = startX + (i * (barWidth + spacing));
        const yBase = 140;
        const bHeight = (g.avg / 100) * chartHeight;

        // Dibujar barra
        doc.setFillColor(g.avg >= APPROVAL_THRESHOLD ? 16, 185, 129 : primaryRed[0], primaryRed[1], primaryRed[2]);
        doc.rect(x, yBase - bHeight, barWidth, bHeight, 'F');

        // Etiqueta Nombre Grupo
        doc.setFontSize(8);
        doc.setTextColor(100, 116, 139);
        const splitName = doc.splitTextToSize(g.name, barWidth);
        doc.text(splitName, x, yBase + 5);

        // Etiqueta Valor
        doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
        doc.setFontSize(10);
        doc.setFont('helvetica', 'bold');
        doc.text(`${g.avg}%`, x + (barWidth/2) - 4, yBase - bHeight - 5);
      });

      // Caja de Estadisticas Rapidas
      doc.setFillColor(248, 250, 252);
      doc.roundedRect(220, 55, 60, 85, 5, 5, 'F');
      doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
      doc.setFontSize(10);
      doc.text('INDICADORES CLAVE', 225, 65);

      doc.setFontSize(8);
      doc.text('PERSONAL ACTIVO', 225, 80);
      doc.setFontSize(14);
      doc.text(`${stats.total}`, 225, 90);

      doc.setFontSize(8);
      doc.text('CERTIFICADOS', 225, 105);
      doc.setFontSize(14);
      doc.text(`${stats.approved}`, 225, 115);

      doc.setFontSize(8);
      doc.text('ÉXITO TIENDA', 225, 130);
      doc.setFontSize(14);
      doc.setTextColor(stats.percent >= APPROVAL_THRESHOLD ? 16, 185, 129 : primaryRed[0], primaryRed[1], primaryRed[2]);
      doc.text(`${stats.percent}%`, 225, 140);

      // --- PAGINA 2 EN ADELANTE: LISTADO DETALLADO ---
      doc.addPage();
      doc.setFillColor(primaryRed[0], primaryRed[1], primaryRed[2]);
      doc.rect(0, 0, 297, 15, 'F');
      doc.setTextColor(255, 255, 255);
      doc.setFontSize(10);
      doc.text(`LISTADO DETALLADO DE COLABORADORES - ${selectedStore.name}`, 10, 10);

      const tableData = storeEmps.sort((a,b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99)).map(emp => {
        const effective = dataService.getEffectiveGrades(emp.id, pdfMonth);
        const sum = effective.reduce((s, g) => s + g.score, 0);
        const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);

        // Construir string de sub-notas
        const subNotesStr = Object.entries(EVALUATION_GROUPS).map(([gid, config]) => {
          const gGrades = effective.filter(g => g.group === gid);
          const gAvg = gGrades.length > 0 ? Math.round(gGrades.reduce((s, g) => s + g.score, 0) / config.categories.length) : 0;
          return `${config.name}: ${gAvg}%`;
        }).join(' | ');

        return [
          emp.id,
          emp.name,
          emp.title,
          emp.join_date,
          `${avg}%`,
          subNotesStr
        ];
      });

      doc.autoTable({
        head: [['CÉDULA', 'NOMBRE COMPLETO', 'CARGO', 'INGRESO', 'PROM.', 'DESGLOSE POR GRUPO (SUB-NOTAS)']],
        body: tableData,
        startY: 25,
        theme: 'grid',
        headStyles: { fillColor: darkSlate, fontSize: 8, fontStyle: 'bold' },
        bodyStyles: { fontSize: 7, textColor: [50, 50, 50] },
        columnStyles: {
          0: { cellWidth: 25 },
          1: { cellWidth: 45 },
          2: { cellWidth: 30 },
          3: { cellWidth: 25 },
          4: { cellWidth: 15, fontStyle: 'bold' },
          5: { cellWidth: 'auto' }
        },
        alternateRowStyles: { fillColor: [250, 250, 250] }
      });

      doc.save(`Curvas (${selectedStore.name}),(${pdfMonth}).pdf`);
      setShowPdfModal(false);
    } catch (e) {
      console.error(e);
      alert("Error al generar el PDF. Verifica los datos.");
    } finally {
      setIsGeneratingPdf(false);
    }
  };

  const selectClasses = "p-3 bg-white border-2 border-slate-100 rounded-xl text-[10px] font-black uppercase text-slate-800 outline-none focus:border-red-500 transition-all shadow-sm";

  if (selectedStore) {
    const stats = getStoreStats(selectedStore.id, selectedMonth);
    const storeEmps = employees
      .filter(e => e.restaurant_id === selectedStore.id && (user.role === UserRole.ADMIN ? true : e.active))
      .filter(e => empSearch === '' || e.name.toLowerCase().includes(empSearch.toLowerCase()) || e.id.includes(empSearch))
      .sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));

    return (
      <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center space-x-4">
            <button onClick={() => { setSelectedStore(null); setEmpSearch(''); }} className="p-3 bg-white border-2 border-slate-100 rounded-2xl text-slate-400 hover:text-red-600 transition-all shadow-sm"><ArrowLeft className="w-5 h-5" /></button>
            <div className="min-w-0">
              <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tighter uppercase italic leading-none truncate">{selectedStore.name}</h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-widest flex items-center mt-2 truncate"><MapPin className="w-3 h-3 mr-1.5 text-red-500" /> {selectedStore.zone} • {selectedStore.region}</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={() => { setPdfMonth(selectedMonth); setShowPdfModal(true); }}
              className="flex items-center gap-2 px-6 py-3.5 bg-red-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-red-700 transition-all shadow-lg"
            >
              <FileText className="w-4 h-4" /> <span>Reporte PDF</span>
            </button>
            <div className="relative w-full md:w-72">
              <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
              <input 
                type="text" 
                placeholder="Buscar colaborador..." 
                value={empSearch}
                onChange={e => setEmpSearch(e.target.value)}
                className="w-full pl-12 pr-4 py-3.5 bg-white border-2 border-slate-100 rounded-2xl text-xs font-black shadow-sm outline-none focus:border-red-500 transition-all" 
              />
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <DetailStatCard icon={<Users className="w-6 h-6" />} label="Equipo Activo" value={stats.total} color="blue" />
          <DetailStatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approved} color="green" />
          <DetailStatCard icon={<TrendingUp className="w-6 h-6" />} label="Éxito Tienda" value={`${stats.percent}%`} color="red" />
        </div>

        <div className="bg-white rounded-[32px] md:rounded-[40px] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b border-slate-50 flex justify-between items-center">
             <h3 className="text-[10px] font-black uppercase italic tracking-widest flex items-center">
               <Users className="w-4 h-4 mr-2 text-red-600" /> Listado con Arrastre
             </h3>
             <span className="text-[8px] font-black bg-slate-100 px-3 py-1.5 rounded-full uppercase text-slate-400 hidden sm:inline">Prioridad por Cargo</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50">
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Certificación</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Cargo</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {storeEmps.map(emp => {
                  const effective = dataService.getEffectiveGrades(emp.id, selectedMonth);
                  const sum = effective.reduce((s, g) => s + g.score, 0);
                  const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);
                  const status = effective.length === 0 ? 'PENDING' : (avg >= APPROVAL_THRESHOLD ? 'APPROVED' : 'FAILED');

                  return (
                    <tr key={emp.id} className="hover:bg-slate-50/80 transition-all group">
                      <td className="px-4 md:px-8 py-4 text-center">
                        <button 
                          onClick={() => setEditingEmployee(emp)} 
                          className="px-4 py-3 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-red-600 shadow-lg transition-all uppercase tracking-widest flex items-center justify-center gap-2 mx-auto"
                        >
                          <Edit3 className="w-4 h-4" />
                          <span className="hidden sm:inline">Calificar</span>
                        </button>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex items-center gap-3">
                          <div className="w-9 h-9 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-colors hidden sm:flex">
                            <UserIcon className="w-4 h-4" />
                          </div>
                          <div>
                            <p className="font-black text-slate-800 text-[12px] uppercase italic leading-tight group-hover:text-red-600 transition-colors">{emp.name}</p>
                            <p className="text-[8px] text-slate-400 font-black uppercase tracking-widest mt-0.5">ID: {emp.id}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex flex-col">
                          <span className={`text-[9px] font-black uppercase px-2 py-1 rounded-lg w-fit ${status === 'APPROVED' ? 'bg-emerald-50 text-emerald-600' : status === 'FAILED' ? 'bg-red-50 text-red-600' : 'bg-slate-100 text-slate-400'}`}>
                            {status === 'APPROVED' ? 'Certificado' : status === 'FAILED' ? 'No Certificado' : 'Sin Nota'}
                          </span>
                          {status !== 'PENDING' && <span className="text-[7px] font-black text-slate-300 uppercase mt-1">Promedio: {avg}%</span>}
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <span className="text-[10px] font-black text-slate-700 uppercase italic tracking-tight">{emp.title}</span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
        {editingEmployee && <GradeEditor employee={editingEmployee} month={selectedMonth} onClose={() => { setEditingEmployee(null); onUpdate(); }} />}

        {/* PDF Selection Modal */}
        {showPdfModal && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-4 animate-in fade-in duration-300">
            <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-md overflow-hidden border-2 border-white/20">
              <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-red-600 rounded-2xl shadow-xl shadow-red-900/20">
                    <FileText className="w-6 h-6 text-white" />
                  </div>
                  <h3 className="font-black uppercase italic tracking-tighter text-xl">Generar Curvas</h3>
                </div>
                <button onClick={() => setShowPdfModal(false)}><X className="w-6 h-6"/></button>
              </div>
              <div className="p-8 space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                    <Calendar className="w-3 h-3 text-red-500" /> Seleccionar Mes del Reporte
                  </label>
                  <input 
                    type="month" 
                    value={pdfMonth} 
                    onChange={e => setPdfMonth(e.target.value)}
                    className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-black text-slate-900 outline-none focus:border-red-500 transition-all" 
                  />
                </div>

                <div className="bg-slate-50 p-6 rounded-3xl space-y-3">
                   <p className="text-[10px] font-black uppercase text-slate-400 italic">Resumen a exportar:</p>
                   <div className="flex items-center justify-between">
                     <span className="text-[9px] font-black uppercase text-slate-600">Restaurante</span>
                     <span className="text-[11px] font-black uppercase text-slate-900">{selectedStore.name}</span>
                   </div>
                   <div className="flex items-center justify-between">
                     <span className="text-[9px] font-black uppercase text-slate-600">Personal</span>
                     <span className="text-[11px] font-black uppercase text-slate-900">{storeEmps.length} Colaboradores</span>
                   </div>
                </div>

                <button 
                  onClick={handleGeneratePDF}
                  disabled={isGeneratingPdf}
                  className="w-full py-5 bg-red-600 text-white font-black rounded-3xl hover:bg-red-700 shadow-xl shadow-red-500/10 transition-all uppercase tracking-widest text-[11px] flex items-center justify-center gap-3"
                >
                  {isGeneratingPdf ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
                  {isGeneratingPdf ? 'Generando Documento...' : 'Descargar Curvas PDF'}
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
          <select value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
          <select value={filterZone} onChange={(e) => setFilterZone(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
          </select>
        </div>
        <div className="md:col-span-2 space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Buscar Tienda</label>
          <input 
            type="text" 
            placeholder="CECO o Nombre..." 
            value={storeSearch}
            onChange={e => setStoreSearch(e.target.value)}
            className="w-full p-3.5 bg-slate-50 border-2 border-slate-100 rounded-xl text-xs font-black uppercase shadow-inner outline-none focus:bg-white focus:border-red-500 transition-all" 
          />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {assigned.map(store => {
          const stats = getStoreStats(store.id, selectedMonth);
          return (
            <div key={store.id} onClick={() => setSelectedStore(store)} className="bg-white rounded-[32px] shadow-sm border-2 border-slate-50 overflow-hidden hover:border-red-500 hover:shadow-2xl hover:shadow-red-50 transition-all group cursor-pointer flex flex-col p-8">
              <div className="flex items-start justify-between mb-8">
                <div className="flex items-center space-x-4">
                  <div className="w-14 h-14 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400 group-hover:bg-red-600 group-hover:text-white transition-all shadow-inner"><Store className="w-7 h-7" /></div>
                  <div className="min-w-0">
                    <h3 className="font-black text-slate-800 text-lg truncate uppercase tracking-tighter leading-tight italic">{store.name}</h3>
                    <p className="text-[9px] text-slate-400 font-black uppercase truncate tracking-widest mt-1">{store.region} • {store.zone}</p>
                  </div>
                </div>
              </div>
              <div className="mt-auto grid grid-cols-2 gap-4">
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Equipo Activo</p><p className="text-xl font-black text-slate-800 tracking-tighter">{stats.total}</p></div>
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Éxito</p><p className={`text-xl font-black tracking-tighter ${stats.percent >= 90 ? 'text-emerald-600' : 'text-red-600'}`}>{stats.percent}%</p></div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

const DetailStatCard: React.FC<{ icon: React.ReactNode, label: string, value: string | number, color: string }> = ({ icon, label, value, color }) => {
  const colorMap: any = { 
    blue: 'bg-blue-50 text-blue-600 border-blue-100', 
    green: 'bg-emerald-50 text-emerald-600 border-emerald-100', 
    red: 'bg-red-50 text-red-600 border-red-100' 
  };
  return (
    <div className={`bg-white p-5 md:p-6 rounded-[32px] border-2 shadow-sm flex items-center space-x-5 transition-transform hover:scale-[1.03] ${colorMap[color]}`}>
      <div className={`p-3 md:p-4 rounded-2xl bg-white shadow-lg`}>{icon}</div>
      <div>
        <p className="text-[8px] md:text-[10px] font-black uppercase tracking-[0.2em] opacity-60">{label}</p>
        <h4 className="text-2xl md:text-3xl font-black tracking-tighter leading-none mt-1">{value}</h4>
      </div>
    </div>
  );
};

export default MyStores;

import React, { useMemo, useState } from 'react';
import { User, Restaurant, Employee, UserRole, JobHierarchy } from '../types';
import { Store, MapPin, Users, Award, ArrowLeft, User as UserIcon, TrendingUp, Briefcase, Search, Filter, Edit3, FileText, Download, X, Calendar, RefreshCw } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT, EVALUATION_GROUPS } from '../constants';
import GradeEditor from './GradeEditor';
import { jsPDF } from 'jspdf';
// Use functional import for autoTable to avoid prototype augmentation issues and fix TS error
import autoTable from 'jspdf-autotable';

// Extender tipo para jspdf-autotable
declare module 'jspdf' {
  interface jsPDF {
    autoTable: any;
  }
}

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
  onUpdate: () => void;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth, onUpdate }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [storeSearch, setStoreSearch] = useState('');
  const [empSearch, setEmpSearch] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');

  // PDF Generation State
  const [showPdfModal, setShowPdfModal] = useState(false);
  const [pdfMonth, setPdfMonth] = useState(selectedMonth);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    let zones = Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) zones = zones.filter(z => user.assignedZones.includes(z));
    return zones;
  }, [restaurants, filterRegion, user]);

  const assigned = useMemo(() => {
    let base = user.role === UserRole.ADMIN 
      ? restaurants 
      : restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));

    return base.filter(r => {
      const matchSearch = storeSearch === '' || r.name.toLowerCase().includes(storeSearch.toLowerCase()) || r.id.includes(storeSearch);
      const matchRegion = filterRegion === 'all' || r.region === filterRegion;
      const matchZone = filterZone === 'all' || r.zone === filterZone;
      return matchSearch && matchRegion && matchZone;
    });
  }, [user, restaurants, storeSearch, filterRegion, filterZone]);

  const getStoreStats = (storeId: string, month: string) => {
    const storeEmps = employees.filter(e => e.restaurant_id === storeId && e.active);
    if (storeEmps.length === 0) return { total: 0, approved: 0, percent: 0, groupAvgs: [] };

    let approved = 0;
    const groupTotals: Record<string, { sum: number, count: number }> = {};

    storeEmps.forEach(emp => {
      const effective = dataService.getEffectiveGrades(emp.id, month);
      const sum = effective.reduce((s, g) => s + g.score, 0);
      const avg = TOTAL_CATEGORIES_COUNT > 0 ? sum / TOTAL_CATEGORIES_COUNT : 0;
      if (effective.length > 0 && avg >= APPROVAL_THRESHOLD) approved++;

      // Totales para gráficas
      Object.entries(EVALUATION_GROUPS).forEach(([gid, gconfig]) => {
        const groupGrades = effective.filter(g => g.group === gid);
        const gSum = groupGrades.reduce((s, g) => s + g.score, 0);
        if (!groupTotals[gid]) groupTotals[gid] = { sum: 0, count: 0 };
        groupTotals[gid].sum += (gSum / gconfig.categories.length);
        groupTotals[gid].count++;
      });
    });

    const groupAvgs = Object.entries(EVALUATION_GROUPS).map(([id, config]) => ({
      id,
      name: config.name,
      avg: groupTotals[id] ? Math.round(groupTotals[id].sum / groupTotals[id].count) : 0
    }));

    return { total: storeEmps.length, approved, percent: Math.round((approved / storeEmps.length) * 100), groupAvgs };
  };

  const handleGeneratePDF = async () => {
    if (!selectedStore) return;
    setIsGeneratingPdf(true);

    try {
      const doc = new jsPDF({ orientation: 'landscape', unit: 'mm', format: 'a4' });
      const stats = getStoreStats(selectedStore.id, pdfMonth);
      const storeEmps = employees.filter(e => e.restaurant_id === selectedStore.id && e.active);

      // Colores KFC
      const primaryRed = [227, 24, 55];
      const darkSlate = [15, 23, 42];

      // --- PAGINA 1: PORTADA Y GRAFICAS ---
      doc.setFillColor(darkSlate[0], darkSlate[1], darkSlate[2]);
      doc.rect(0, 0, 297, 40, 'F');

      doc.setTextColor(255, 255, 255);
      doc.setFontSize(22);
      doc.setFont('helvetica', 'bold');
      doc.text('REPORTE DE CURVAS DE CERTIFICACIÓN', 15, 20);

      doc.setFontSize(10);
      doc.setFont('helvetica', 'normal');
      doc.text(`RESTAURANTE: ${selectedStore.name} (${selectedStore.id})`, 15, 30);
      doc.text(`PERIODO: ${pdfMonth}`, 180, 20);
      doc.text(`ZONA: ${selectedStore.zone} | REGIONAL: ${selectedStore.region}`, 180, 30);

      // Graficas de barras simuladas (Resumen de Tienda)
      doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
      doc.setFontSize(14);
      doc.text('RESUMEN DE DESEMPEÑO POR GRUPO (PROMEDIO TIENDA)', 15, 60);

      let startX = 20;
      const chartHeight = 60;
      const barWidth = 35;
      const spacing = 15;

      stats.groupAvgs.forEach((g, i) => {
        const x = startX + (i * (barWidth + spacing));
        const yBase = 140;
        const bHeight = (g.avg / 100) * chartHeight;

        // Dibujar barra
        doc.setFillColor(g.avg >= APPROVAL_THRESHOLD ? 16, 185, 129 : primaryRed[0], primaryRed[1], primaryRed[2]);
        doc.rect(x, yBase - bHeight, barWidth, bHeight, 'F');

        // Etiqueta Nombre Grupo
        doc.setFontSize(8);
        doc.setTextColor(100, 116, 139);
        const splitName = doc.splitTextToSize(g.name, barWidth);
        doc.text(splitName, x, yBase + 5);

        // Etiqueta Valor
        doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
        doc.setFontSize(10);
        doc.setFont('helvetica', 'bold');
        doc.text(`${g.avg}%`, x + (barWidth/2) - 4, yBase - bHeight - 5);
      });

      // Caja de Estadisticas Rapidas
      doc.setFillColor(248, 250, 252);
      doc.roundedRect(220, 55, 60, 85, 5, 5, 'F');
      doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
      doc.setFontSize(10);
      doc.text('INDICADORES CLAVE', 225, 65);

      doc.setFontSize(8);
      doc.text('PERSONAL ACTIVO', 225, 80);
      doc.setFontSize(14);
      doc.text(`${stats.total}`, 225, 90);

      doc.setFontSize(8);
      doc.text('CERTIFICADOS', 225, 105);
      doc.setFontSize(14);
      doc.text(`${stats.approved}`, 225, 115);

      doc.setFontSize(8);
      doc.text('ÉXITO TIENDA', 225, 140);
      doc.setFontSize(14);
      doc.setTextColor(stats.percent >= APPROVAL_THRESHOLD ? 16, 185, 129 : primaryRed[0], primaryRed[1], primaryRed[2]);
      doc.text(`${stats.percent}%`, 225, 140);

      // --- PAGINA 2 EN ADELANTE: LISTADO DETALLADO ---
      doc.addPage();
      doc.setFillColor(primaryRed[0], primaryRed[1], primaryRed[2]);
      doc.rect(0, 0, 297, 15, 'F');
      doc.setTextColor(255, 255, 255);
      doc.setFontSize(10);
      doc.text(`LISTADO DETALLADO DE COLABORADORES - ${selectedStore.name}`, 10, 10);

      const tableData = storeEmps.sort((a,b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99)).map(emp => {
        const effective = dataService.getEffectiveGrades(emp.id, pdfMonth);
        const sum = effective.reduce((s, g) => s + g.score, 0);
        const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);

        // Construir string de sub-notas
        const subNotesStr = Object.entries(EVALUATION_GROUPS).map(([gid, config]) => {
          const gGrades = effective.filter(g => g.group === gid);
          const gAvg = gGrades.length > 0 ? Math.round(gGrades.reduce((s, g) => s + g.score, 0) / config.categories.length) : 0;
          return `${config.name}: ${gAvg}%`;
        }).join(' | ');

        return [
          emp.id,
          emp.name,
          emp.title,
          emp.join_date,
          `${avg}%`,
          subNotesStr
        ];
      });

      // Use functional autoTable call to avoid prototype-based issues
      autoTable(doc, {
        head: [['CÉDULA', 'NOMBRE COMPLETO', 'CARGO', 'INGRESO', 'PROM.', 'DESGLOSE POR GRUPO (SUB-NOTAS)']],
        body: tableData,
        startY: 25,
        theme: 'grid',
        headStyles: { fillColor: darkSlate, fontSize: 8, fontStyle: 'bold' },
        bodyStyles: { fontSize: 7, textColor: [50, 50, 50] },
        columnStyles: {
          0: { cellWidth: 25 },
          1: { cellWidth: 45 },
          2: { cellWidth: 30 },
          3: { cellWidth: 25 },
          4: { cellWidth: 15, fontStyle: 'bold' },
          5: { cellWidth: 'auto' }
        },
        alternateRowStyles: { fillColor: [250, 250, 250] }
      });

      doc.save(`Curvas (${selectedStore.name}),(${pdfMonth}).pdf`);
      setShowPdfModal(false);
    } catch (e) {
      console.error(e);
      alert("Error al generar el PDF. Verifica los datos.");
    } finally {
      setIsGeneratingPdf(false);
    }
  };

  const selectClasses = "p-3 bg-white border-2 border-slate-100 rounded-xl text-[10px] font-black uppercase text-slate-800 outline-none focus:border-red-500 transition-all shadow-sm";

  if (selectedStore) {
    const stats = getStoreStats(selectedStore.id, selectedMonth);
    const storeEmps = employees
      .filter(e => e.restaurant_id === selectedStore.id && (user.role === UserRole.ADMIN ? true : e.active))
      .filter(e => empSearch === '' || e.name.toLowerCase().includes(empSearch.toLowerCase()) || e.id.includes(empSearch))
      .sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));

    return (
      <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center space-x-4">
            <button onClick={() => { setSelectedStore(null); setEmpSearch(''); }} className="p-3 bg-white border-2 border-slate-100 rounded-2xl text-slate-400 hover:text-red-600 transition-all shadow-sm"><ArrowLeft className="w-5 h-5" /></button>
            <div className="min-w-0">
              <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tighter uppercase italic leading-none truncate">{selectedStore.name}</h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-widest flex items-center mt-2 truncate"><MapPin className="w-3 h-3 mr-1.5 text-red-500" /> {selectedStore.zone} • {selectedStore.region}</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={() => { setPdfMonth(selectedMonth); setShowPdfModal(true); }}
              className="flex items-center gap-2 px-6 py-3.5 bg-red-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-red-700 transition-all shadow-lg"
            >
              <FileText className="w-4 h-4" /> <span>Reporte PDF</span>
            </button>
            <div className="relative w-full md:w-72">
              <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
              <input 
                type="text" 
                placeholder="Buscar colaborador..." 
                value={empSearch}
                onChange={e => setEmpSearch(e.target.value)}
                className="w-full pl-12 pr-4 py-3.5 bg-white border-2 border-slate-100 rounded-2xl text-xs font-black shadow-sm outline-none focus:border-red-500 transition-all" 
              />
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <DetailStatCard icon={<Users className="w-6 h-6" />} label="Equipo Activo" value={stats.total} color="blue" />
          <DetailStatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approved} color="green" />
          <DetailStatCard icon={<TrendingUp className="w-6 h-6" />} label="Éxito Tienda" value={`${stats.percent}%`} color="red" />
        </div>

        <div className="bg-white rounded-[32px] md:rounded-[40px] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b border-slate-50 flex justify-between items-center">
             <h3 className="text-[10px] font-black uppercase italic tracking-widest flex items-center">
               <Users className="w-4 h-4 mr-2 text-red-600" /> Listado con Arrastre
             </h3>
             <span className="text-[8px] font-black bg-slate-100 px-3 py-1.5 rounded-full uppercase text-slate-400 hidden sm:inline">Prioridad por Cargo</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50">
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Certificación</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Cargo</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {storeEmps.map(emp => {
                  const effective = dataService.getEffectiveGrades(emp.id, selectedMonth);
                  const sum = effective.reduce((s, g) => s + g.score, 0);
                  const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);
                  const status = effective.length === 0 ? 'PENDING' : (avg >= APPROVAL_THRESHOLD ? 'APPROVED' : 'FAILED');

                  return (
                    <tr key={emp.id} className="hover:bg-slate-50/80 transition-all group">
                      <td className="px-4 md:px-8 py-4 text-center">
                        <button 
                          onClick={() => setEditingEmployee(emp)} 
                          className="px-4 py-3 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-red-600 shadow-lg transition-all uppercase tracking-widest flex items-center justify-center gap-2 mx-auto"
                        >
                          <Edit3 className="w-4 h-4" />
                          <span className="hidden sm:inline">Calificar</span>
                        </button>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex items-center gap-3">
                          <div className="w-9 h-9 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-colors hidden sm:flex">
                            <UserIcon className="w-4 h-4" />
                          </div>
                          <div>
                            <p className="font-black text-slate-800 text-[12px] uppercase italic leading-tight group-hover:text-red-600 transition-colors">{emp.name}</p>
                            <p className="text-[8px] text-slate-400 font-black uppercase tracking-widest mt-0.5">ID: {emp.id}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex flex-col">
                          <span className={`text-[9px] font-black uppercase px-2 py-1 rounded-lg w-fit ${status === 'APPROVED' ? 'bg-emerald-50 text-emerald-600' : status === 'FAILED' ? 'bg-red-50 text-red-600' : 'bg-slate-100 text-slate-400'}`}>
                            {status === 'APPROVED' ? 'Certificado' : status === 'FAILED' ? 'No Certificado' : 'Sin Nota'}
                          </span>
                          {status !== 'PENDING' && <span className="text-[7px] font-black text-slate-300 uppercase mt-1">Promedio: {avg}%</span>}
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <span className="text-[10px] font-black text-slate-700 uppercase italic tracking-tight">{emp.title}</span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
        {editingEmployee && <GradeEditor employee={editingEmployee} month={selectedMonth} onClose={() => { setEditingEmployee(null); onUpdate(); }} />}

        {/* PDF Selection Modal */}
        {showPdfModal && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-4 animate-in fade-in duration-300">
            <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-md overflow-hidden border-2 border-white/20">
              <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-red-600 rounded-2xl shadow-xl shadow-red-900/20">
                    <FileText className="w-6 h-6 text-white" />
                  </div>
                  <h3 className="font-black uppercase italic tracking-tighter text-xl">Generar Curvas</h3>
                </div>
                <button onClick={() => setShowPdfModal(false)}><X className="w-6 h-6"/></button>
              </div>
              <div className="p-8 space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                    <Calendar className="w-3 h-3 text-red-500" /> Seleccionar Mes del Reporte
                  </label>
                  <input 
                    type="month" 
                    value={pdfMonth} 
                    onChange={e => setPdfMonth(e.target.value)}
                    className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-black text-slate-900 outline-none focus:border-red-500 transition-all" 
                  />
                </div>

                <div className="bg-slate-50 p-6 rounded-3xl space-y-3">
                   <p className="text-[10px] font-black uppercase text-slate-400 italic">Resumen a exportar:</p>
                   <div className="flex items-center justify-between">
                     <span className="text-[9px] font-black uppercase text-slate-600">Restaurante</span>
                     <span className="text-[11px] font-black uppercase text-slate-900">{selectedStore.name}</span>
                   </div>
                   <div className="flex items-center justify-between">
                     <span className="text-[9px] font-black uppercase text-slate-600">Personal</span>
                     <span className="text-[11px] font-black uppercase text-slate-900">{storeEmps.length} Colaboradores</span>
                   </div>
                </div>

                <button 
                  onClick={handleGeneratePDF}
                  disabled={isGeneratingPdf}
                  className="w-full py-5 bg-red-600 text-white font-black rounded-3xl hover:bg-red-700 shadow-xl shadow-red-500/10 transition-all uppercase tracking-widest text-[11px] flex items-center justify-center gap-3"
                >
                  {isGeneratingPdf ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
                  {isGeneratingPdf ? 'Generando Documento...' : 'Descargar Curvas PDF'}
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
          <select value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
          <select value={filterZone} onChange={(e) => setFilterZone(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
          </select>
        </div>
        <div className="md:col-span-2 space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Buscar Tienda</label>
          <input 
            type="text" 
            placeholder="CECO o Nombre..." 
            value={storeSearch}
            onChange={e => setStoreSearch(e.target.value)}
            className="w-full p-3.5 bg-slate-50 border-2 border-slate-100 rounded-xl text-xs font-black uppercase shadow-inner outline-none focus:bg-white focus:border-red-500 transition-all" 
          />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {assigned.map(store => {
          const stats = getStoreStats(store.id, selectedMonth);
          return (
            <div key={store.id} onClick={() => setSelectedStore(store)} className="bg-white rounded-[32px] shadow-sm border-2 border-slate-50 overflow-hidden hover:border-red-500 hover:shadow-2xl hover:shadow-red-50 transition-all group cursor-pointer flex flex-col p-8">
              <div className="flex items-start justify-between mb-8">
                <div className="flex items-center space-x-4">
                  <div className="w-14 h-14 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400 group-hover:bg-red-600 group-hover:text-white transition-all shadow-inner"><Store className="w-7 h-7" /></div>
                  <div className="min-w-0">
                    <h3 className="font-black text-slate-800 text-lg truncate uppercase tracking-tighter leading-tight italic">{store.name}</h3>
                    <p className="text-[9px] text-slate-400 font-black uppercase truncate tracking-widest mt-1">{store.region} • {store.zone}</p>
                  </div>
                </div>
              </div>
              <div className="mt-auto grid grid-cols-2 gap-4">
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Equipo Activo</p><p className="text-xl font-black text-slate-800 tracking-tighter">{stats.total}</p></div>
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Éxito</p><p className={`text-xl font-black tracking-tighter ${stats.percent >= 90 ? 'text-emerald-600' : 'text-red-600'}`}>{stats.percent}%</p></div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

const DetailStatCard: React.FC<{ icon: React.ReactNode, label: string, value: string | number, color: string }> = ({ icon, label, value, color }) => {
  const colorMap: any = { 
    blue: 'bg-blue-50 text-blue-600 border-blue-100', 
    green: 'bg-emerald-50 text-emerald-600 border-emerald-100', 
    red: 'bg-red-50 text-red-600 border-red-100' 
  };
  return (
    <div className={`bg-white p-5 md:p-6 rounded-[32px] border-2 shadow-sm flex items-center space-x-5 transition-transform hover:scale-[1.03] ${colorMap[color]}`}>
      <div className={`p-3 md:p-4 rounded-2xl bg-white shadow-lg`}>{icon}</div>
      <div>
        <p className="text-[8px] md:text-[10px] font-black uppercase tracking-[0.2em] opacity-60">{label}</p>
        <h4 className="text-2xl md:text-3xl font-black tracking-tighter leading-none mt-1">{value}</h4>
      </div>
    </div>
  );
};

export default MyStores;

import React, { useMemo, useState } from 'react';
import { User, Restaurant, Employee, UserRole, JobHierarchy } from '../types';
import { Store, MapPin, Users, Award, ArrowLeft, User as UserIcon, TrendingUp, Briefcase, Search, Filter, Edit3, FileText, Download, X, Calendar, RefreshCw } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT, EVALUATION_GROUPS } from '../constants';
import GradeEditor from './GradeEditor';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

// Extender tipo para jspdf-autotable
declare module 'jspdf' {
  interface jsPDF {
    autoTable: any;
  }
}

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
  onUpdate: () => void;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth, onUpdate }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [storeSearch, setStoreSearch] = useState('');
  const [empSearch, setEmpSearch] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');

  // PDF Generation State
  const [showPdfModal, setShowPdfModal] = useState(false);
  const [pdfMonth, setPdfMonth] = useState(selectedMonth);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    let zones = Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) zones = zones.filter(z => user.assignedZones.includes(z));
    return zones;
  }, [restaurants, filterRegion, user]);

  const assigned = useMemo(() => {
    let base = user.role === UserRole.ADMIN 
      ? restaurants 
      : restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));

    return base.filter(r => {
      const matchSearch = storeSearch === '' || r.name.toLowerCase().includes(storeSearch.toLowerCase()) || r.id.includes(storeSearch);
      const matchRegion = filterRegion === 'all' || r.region === filterRegion;
      const matchZone = filterZone === 'all' || r.zone === filterZone;
      return matchSearch && matchRegion && matchZone;
    });
  }, [user, restaurants, storeSearch, filterRegion, filterZone]);

  const getStoreStats = (storeId: string, month: string) => {
    const storeEmps = employees.filter(e => e.restaurant_id === storeId && e.active);
    if (storeEmps.length === 0) return { total: 0, approved: 0, percent: 0, groupAvgs: [] };

    let approved = 0;
    const groupTotals: Record<string, { sum: number, count: number }> = {};

    storeEmps.forEach(emp => {
      const effective = dataService.getEffectiveGrades(emp.id, month);
      const sum = effective.reduce((s, g) => s + g.score, 0);
      const avg = TOTAL_CATEGORIES_COUNT > 0 ? sum / TOTAL_CATEGORIES_COUNT : 0;
      if (effective.length > 0 && avg >= APPROVAL_THRESHOLD) approved++;

      // Totales para gráficas
      Object.entries(EVALUATION_GROUPS).forEach(([gid, gconfig]) => {
        const groupGrades = effective.filter(g => g.group === gid);
        const gSum = groupGrades.reduce((s, g) => s + g.score, 0);
        if (!groupTotals[gid]) groupTotals[gid] = { sum: 0, count: 0 };
        groupTotals[gid].sum += (gSum / gconfig.categories.length);
        groupTotals[gid].count++;
      });
    });

    const groupAvgs = Object.entries(EVALUATION_GROUPS).map(([id, config]) => ({
      id,
      name: config.name,
      avg: groupTotals[id] ? Math.round(groupTotals[id].sum / groupTotals[id].count) : 0
    }));

    return { total: storeEmps.length, approved, percent: Math.round((approved / storeEmps.length) * 100), groupAvgs };
  };

  const handleGeneratePDF = async () => {
    if (!selectedStore) return;
    setIsGeneratingPdf(true);

    try {
      const doc = new jsPDF({ orientation: 'landscape', unit: 'mm', format: 'a4' });
      const stats = getStoreStats(selectedStore.id, pdfMonth);
      const storeEmps = employees.filter(e => e.restaurant_id === selectedStore.id && e.active);

      // Colores KFC
      const primaryRed = [227, 24, 55];
      const darkSlate = [15, 23, 42];
      const emeraldGreen = [16, 185, 129];

      // --- PAGINA 1: PORTADA Y GRAFICAS ---
      doc.setFillColor(darkSlate[0], darkSlate[1], darkSlate[2]);
      doc.rect(0, 0, 297, 40, 'F');

      doc.setTextColor(255, 255, 255);
      doc.setFontSize(22);
      doc.setFont('helvetica', 'bold');
      doc.text('REPORTE DE CURVAS DE CERTIFICACIÓN', 15, 20);

      doc.setFontSize(10);
      doc.setFont('helvetica', 'normal');
      doc.text(`RESTAURANTE: ${selectedStore.name} (${selectedStore.id})`, 15, 30);
      doc.text(`PERIODO: ${pdfMonth}`, 180, 20);
      doc.text(`ZONA: ${selectedStore.zone} | REGIONAL: ${selectedStore.region}`, 180, 30);

      // Graficas de barras simuladas (Resumen de Tienda)
      doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
      doc.setFontSize(14);
      doc.text('RESUMEN DE DESEMPEÑO POR GRUPO (PROMEDIO TIENDA)', 15, 60);

      let startX = 20;
      const chartHeight = 60;
      const barWidth = 35;
      const spacing = 15;

      stats.groupAvgs.forEach((g, i) => {
        const x = startX + (i * (barWidth + spacing));
        const yBase = 140;
        const bHeight = (g.avg / 100) * chartHeight;

        // Corregido: Cálculo de color para setFillColor
        const barColor = g.avg >= APPROVAL_THRESHOLD ? emeraldGreen : primaryRed;
        doc.setFillColor(barColor[0], barColor[1], barColor[2]);
        doc.rect(x, yBase - bHeight, barWidth, bHeight, 'F');

        // Etiqueta Nombre Grupo
        doc.setFontSize(8);
        doc.setTextColor(100, 116, 139);
        const splitName = doc.splitTextToSize(g.name, barWidth);
        doc.text(splitName, x, yBase + 5);

        // Etiqueta Valor
        doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
        doc.setFontSize(10);
        doc.setFont('helvetica', 'bold');
        doc.text(`${g.avg}%`, x + (barWidth/2) - 4, yBase - bHeight - 5);
      });

      // Caja de Estadisticas Rapidas
      doc.setFillColor(248, 250, 252);
      doc.roundedRect(220, 55, 60, 85, 5, 5, 'F');
      doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
      doc.setFontSize(10);
      doc.text('INDICADORES CLAVE', 225, 65);

      doc.setFontSize(8);
      doc.text('PERSONAL ACTIVO', 225, 80);
      doc.setFontSize(14);
      doc.text(`${stats.total}`, 225, 90);

      doc.setFontSize(8);
      doc.text('CERTIFICADOS', 225, 105);
      doc.setFontSize(14);
      doc.text(`${stats.approved}`, 225, 115);

      doc.setFontSize(8);
      doc.text('ÉXITO TIENDA', 225, 130);
      doc.setFontSize(14);

      // Corregido: Cálculo de color para setTextColor
      const successColor = stats.percent >= APPROVAL_THRESHOLD ? emeraldGreen : primaryRed;
      doc.setTextColor(successColor[0], successColor[1], successColor[2]);
      doc.text(`${stats.percent}%`, 225, 140);

      // --- PAGINA 2 EN ADELANTE: LISTADO DETALLADO ---
      doc.addPage();
      doc.setFillColor(primaryRed[0], primaryRed[1], primaryRed[2]);
      doc.rect(0, 0, 297, 15, 'F');
      doc.setTextColor(255, 255, 255);
      doc.setFontSize(10);
      doc.text(`LISTADO DETALLADO DE COLABORADORES - ${selectedStore.name}`, 10, 10);

      const tableData = storeEmps.sort((a,b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99)).map(emp => {
        const effective = dataService.getEffectiveGrades(emp.id, pdfMonth);
        const sum = effective.reduce((s, g) => s + g.score, 0);
        const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);

        // Construir string de sub-notas
        const subNotesStr = Object.entries(EVALUATION_GROUPS).map(([gid, config]) => {
          const gGrades = effective.filter(g => g.group === gid);
          const gAvg = gGrades.length > 0 ? Math.round(gGrades.reduce((s, g) => s + g.score, 0) / config.categories.length) : 0;
          return `${config.name}: ${gAvg}%`;
        }).join(' | ');

        return [
          emp.id,
          emp.name,
          emp.title,
          emp.join_date,
          `${avg}%`,
          subNotesStr
        ];
      });

      autoTable(doc, {
        head: [['CÉDULA', 'NOMBRE COMPLETO', 'CARGO', 'INGRESO', 'PROM.', 'DESGLOSE POR GRUPO (SUB-NOTAS)']],
        body: tableData,
        startY: 25,
        theme: 'grid',
        headStyles: { fillColor: darkSlate, fontSize: 8, fontStyle: 'bold' },
        bodyStyles: { fontSize: 7, textColor: [50, 50, 50] },
        columnStyles: {
          0: { cellWidth: 25 },
          1: { cellWidth: 45 },
          2: { cellWidth: 30 },
          3: { cellWidth: 25 },
          4: { cellWidth: 15, fontStyle: 'bold' },
          5: { cellWidth: 'auto' }
        },
        alternateRowStyles: { fillColor: [250, 250, 250] }
      });

      doc.save(`Curvas (${selectedStore.name}),(${pdfMonth}).pdf`);
      setShowPdfModal(false);
    } catch (e) {
      console.error(e);
      alert("Error al generar el PDF. Verifica los datos.");
    } finally {
      setIsGeneratingPdf(false);
    }
  };

  const selectClasses = "p-3 bg-white border-2 border-slate-100 rounded-xl text-[10px] font-black uppercase text-slate-800 outline-none focus:border-red-500 transition-all shadow-sm";

  if (selectedStore) {
    const stats = getStoreStats(selectedStore.id, selectedMonth);
    const storeEmps = employees
      .filter(e => e.restaurant_id === selectedStore.id && (user.role === UserRole.ADMIN ? true : e.active))
      .filter(e => empSearch === '' || e.name.toLowerCase().includes(empSearch.toLowerCase()) || e.id.includes(empSearch))
      .sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));

    return (
      <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center space-x-4">
            <button onClick={() => { setSelectedStore(null); setEmpSearch(''); }} className="p-3 bg-white border-2 border-slate-100 rounded-2xl text-slate-400 hover:text-red-600 transition-all shadow-sm"><ArrowLeft className="w-5 h-5" /></button>
            <div className="min-w-0">
              <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tighter uppercase italic leading-none truncate">{selectedStore.name}</h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-widest flex items-center mt-2 truncate"><MapPin className="w-3 h-3 mr-1.5 text-red-500" /> {selectedStore.zone} • {selectedStore.region}</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={() => { setPdfMonth(selectedMonth); setShowPdfModal(true); }}
              className="flex items-center gap-2 px-6 py-3.5 bg-red-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-red-700 transition-all shadow-lg"
            >
              <FileText className="w-4 h-4" /> <span>Reporte PDF</span>
            </button>
            <div className="relative w-full md:w-72">
              <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
              <input 
                type="text" 
                placeholder="Buscar colaborador..." 
                value={empSearch}
                onChange={e => setEmpSearch(e.target.value)}
                className="w-full pl-12 pr-4 py-3.5 bg-white border-2 border-slate-100 rounded-2xl text-xs font-black shadow-sm outline-none focus:border-red-500 transition-all" 
              />
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <DetailStatCard icon={<Users className="w-6 h-6" />} label="Equipo Activo" value={stats.total} color="blue" />
          <DetailStatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approved} color="green" />
          <DetailStatCard icon={<TrendingUp className="w-6 h-6" />} label="Éxito Tienda" value={`${stats.percent}%`} color="red" />
        </div>

        <div className="bg-white rounded-[32px] md:rounded-[40px] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b border-slate-50 flex justify-between items-center">
             <h3 className="text-[10px] font-black uppercase italic tracking-widest flex items-center">
               <Users className="w-4 h-4 mr-2 text-red-600" /> Listado con Arrastre
             </h3>
             <span className="text-[8px] font-black bg-slate-100 px-3 py-1.5 rounded-full uppercase text-slate-400 hidden sm:inline">Prioridad por Cargo</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50">
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Certificación</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Cargo</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {storeEmps.map(emp => {
                  const effective = dataService.getEffectiveGrades(emp.id, selectedMonth);
                  const sum = effective.reduce((s, g) => s + g.score, 0);
                  const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);
                  const status = effective.length === 0 ? 'PENDING' : (avg >= APPROVAL_THRESHOLD ? 'APPROVED' : 'FAILED');

                  return (
                    <tr key={emp.id} className="hover:bg-slate-50/80 transition-all group">
                      <td className="px-4 md:px-8 py-4 text-center">
                        <button 
                          onClick={() => setEditingEmployee(emp)} 
                          className="px-4 py-3 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-red-600 shadow-lg transition-all uppercase tracking-widest flex items-center justify-center gap-2 mx-auto"
                        >
                          <Edit3 className="w-4 h-4" />
                          <span className="hidden sm:inline">Calificar</span>
                        </button>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex items-center gap-3">
                          <div className="w-9 h-9 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-colors hidden sm:flex">
                            <UserIcon className="w-4 h-4" />
                          </div>
                          <div>
                            <p className="font-black text-slate-800 text-[12px] uppercase italic leading-tight group-hover:text-red-600 transition-colors">{emp.name}</p>
                            <p className="text-[8px] text-slate-400 font-black uppercase tracking-widest mt-0.5">ID: {emp.id}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex flex-col">
                          <span className={`text-[9px] font-black uppercase px-2 py-1 rounded-lg w-fit ${status === 'APPROVED' ? 'bg-emerald-50 text-emerald-600' : status === 'FAILED' ? 'bg-red-50 text-red-600' : 'bg-slate-100 text-slate-400'}`}>
                            {status === 'APPROVED' ? 'Certificado' : status === 'FAILED' ? 'No Certificado' : 'Sin Nota'}
                          </span>
                          {status !== 'PENDING' && <span className="text-[7px] font-black text-slate-300 uppercase mt-1">Promedio: {avg}%</span>}
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <span className="text-[10px] font-black text-slate-700 uppercase italic tracking-tight">{emp.title}</span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
        {editingEmployee && <GradeEditor employee={editingEmployee} month={selectedMonth} onClose={() => { setEditingEmployee(null); onUpdate(); }} />}

        {/* PDF Selection Modal */}
        {showPdfModal && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-4 animate-in fade-in duration-300">
            <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-md overflow-hidden border-2 border-white/20">
              <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-red-600 rounded-2xl shadow-xl shadow-red-900/20">
                    <FileText className="w-6 h-6 text-white" />
                  </div>
                  <h3 className="font-black uppercase italic tracking-tighter text-xl">Generar Curvas</h3>
                </div>
                <button onClick={() => setShowPdfModal(false)}><X className="w-6 h-6"/></button>
              </div>
              <div className="p-8 space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                    <Calendar className="w-3 h-3 text-red-500" /> Seleccionar Mes del Reporte
                  </label>
                  <input 
                    type="month" 
                    value={pdfMonth} 
                    onChange={e => setPdfMonth(e.target.value)}
                    className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-black text-slate-900 outline-none focus:border-red-500 transition-all" 
                  />
                </div>

                <div className="bg-slate-50 p-6 rounded-3xl space-y-3">
                   <p className="text-[10px] font-black uppercase text-slate-400 italic">Resumen a exportar:</p>
                   <div className="flex items-center justify-between">
                     <span className="text-[9px] font-black uppercase text-slate-600">Restaurante</span>
                     <span className="text-[11px] font-black uppercase text-slate-900">{selectedStore.name}</span>
                   </div>
                   <div className="flex items-center justify-between">
                     <span className="text-[9px] font-black uppercase text-slate-600">Personal</span>
                     <span className="text-[11px] font-black uppercase text-slate-900">{storeEmps.length} Colaboradores</span>
                   </div>
                </div>

                <button 
                  onClick={handleGeneratePDF}
                  disabled={isGeneratingPdf}
                  className="w-full py-5 bg-red-600 text-white font-black rounded-3xl hover:bg-red-700 shadow-xl shadow-red-500/10 transition-all uppercase tracking-widest text-[11px] flex items-center justify-center gap-3"
                >
                  {isGeneratingPdf ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
                  {isGeneratingPdf ? 'Generando Documento...' : 'Descargar Curvas PDF'}
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
          <select value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
          <select value={filterZone} onChange={(e) => setFilterZone(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
          </select>
        </div>
        <div className="md:col-span-2 space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Buscar Tienda</label>
          <input 
            type="text" 
            placeholder="CECO o Nombre..." 
            value={storeSearch}
            onChange={e => setStoreSearch(e.target.value)}
            className="w-full p-3.5 bg-slate-50 border-2 border-slate-100 rounded-xl text-xs font-black uppercase shadow-inner outline-none focus:bg-white focus:border-red-500 transition-all" 
          />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {assigned.map(store => {
          const stats = getStoreStats(store.id, selectedMonth);
          return (
            <div key={store.id} onClick={() => setSelectedStore(store)} className="bg-white rounded-[32px] shadow-sm border-2 border-slate-50 overflow-hidden hover:border-red-500 hover:shadow-2xl hover:shadow-red-50 transition-all group cursor-pointer flex flex-col p-8">
              <div className="flex items-start justify-between mb-8">
                <div className="flex items-center space-x-4">
                  <div className="w-14 h-14 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400 group-hover:bg-red-600 group-hover:text-white transition-all shadow-inner"><Store className="w-7 h-7" /></div>
                  <div className="min-w-0">
                    <h3 className="font-black text-slate-800 text-lg truncate uppercase tracking-tighter leading-tight italic">{store.name}</h3>
                    <p className="text-[9px] text-slate-400 font-black uppercase truncate tracking-widest mt-1">{store.region} • {store.zone}</p>
                  </div>
                </div>
              </div>
              <div className="mt-auto grid grid-cols-2 gap-4">
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Equipo Activo</p><p className="text-xl font-black text-slate-800 tracking-tighter">{stats.total}</p></div>
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Éxito</p><p className={`text-xl font-black tracking-tighter ${stats.percent >= 90 ? 'text-emerald-600' : 'text-red-600'}`}>{stats.percent}%</p></div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

const DetailStatCard: React.FC<{ icon: React.ReactNode, label: string, value: string | number, color: string }> = ({ icon, label, value, color }) => {
  const colorMap: any = { 
    blue: 'bg-blue-50 text-blue-600 border-blue-100', 
    green: 'bg-emerald-50 text-emerald-600 border-emerald-100', 
    red: 'bg-red-50 text-red-600 border-red-100' 
  };
  return (
    <div className={`bg-white p-5 md:p-6 rounded-[32px] border-2 shadow-sm flex items-center space-x-5 transition-transform hover:scale-[1.03] ${colorMap[color]}`}>
      <div className={`p-3 md:p-4 rounded-2xl bg-white shadow-lg`}>{icon}</div>
      <div>
        <p className="text-[8px] md:text-[10px] font-black uppercase tracking-[0.2em] opacity-60">{label}</p>
        <h4 className="text-2xl md:text-3xl font-black tracking-tighter leading-none mt-1">{value}</h4>
      </div>
    </div>
  );
};

export default MyStores;

import React, { useMemo, useState } from 'react';
import { User, Restaurant, Employee, UserRole, JobHierarchy } from '../types';
import { Store, MapPin, Users, Award, ArrowLeft, User as UserIcon, TrendingUp, Briefcase, Search, Filter, Edit3, FileText, Download, X, Calendar, RefreshCw } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT, EVALUATION_GROUPS } from '../constants';
import GradeEditor from './GradeEditor';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
  onUpdate: () => void;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth, onUpdate }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [storeSearch, setStoreSearch] = useState('');
  const [empSearch, setEmpSearch] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');

  // PDF Generation State
  const [showPdfModal, setShowPdfModal] = useState(false);
  const [pdfMonth, setPdfMonth] = useState(selectedMonth);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    let zones = Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) zones = zones.filter(z => user.assignedZones.includes(z));
    return zones;
  }, [restaurants, filterRegion, user]);

  const assigned = useMemo(() => {
    let base = user.role === UserRole.ADMIN 
      ? restaurants 
      : restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));

    return base.filter(r => {
      const matchSearch = storeSearch === '' || r.name.toLowerCase().includes(storeSearch.toLowerCase()) || r.id.includes(storeSearch);
      const matchRegion = filterRegion === 'all' || r.region === filterRegion;
      const matchZone = filterZone === 'all' || r.zone === filterZone;
      return matchSearch && matchRegion && matchZone;
    });
  }, [user, restaurants, storeSearch, filterRegion, filterZone]);

  const getStoreStats = (storeId: string, month: string) => {
    const storeEmps = employees.filter(e => e.restaurant_id === storeId && e.active);
    if (storeEmps.length === 0) return { total: 0, approved: 0, percent: 0, groupAvgs: [] };

    let approved = 0;
    const groupTotals: Record<string, { sum: number, count: number }> = {};

    storeEmps.forEach(emp => {
      const effective = dataService.getEffectiveGrades(emp.id, month);
      const sum = effective.reduce((s, g) => s + g.score, 0);
      const avg = TOTAL_CATEGORIES_COUNT > 0 ? sum / TOTAL_CATEGORIES_COUNT : 0;
      if (effective.length > 0 && avg >= APPROVAL_THRESHOLD) approved++;

      // Totales para gráficas
      Object.entries(EVALUATION_GROUPS).forEach(([gid, gconfig]) => {
        const groupGrades = effective.filter(g => g.group === gid);
        const gSum = groupGrades.reduce((s, g) => s + g.score, 0);
        if (!groupTotals[gid]) groupTotals[gid] = { sum: 0, count: 0 };
        groupTotals[gid].sum += (gSum / gconfig.categories.length);
        groupTotals[gid].count++;
      });
    });

    const groupAvgs = Object.entries(EVALUATION_GROUPS).map(([id, config]) => ({
      id,
      name: config.name,
      avg: groupTotals[id] ? Math.round(groupTotals[id].sum / groupTotals[id].count) : 0
    }));

    return { total: storeEmps.length, approved, percent: Math.round((approved / storeEmps.length) * 100), groupAvgs };
  };

  const handleGeneratePDF = async () => {
    if (!selectedStore) return;
    setIsGeneratingPdf(true);

    try {
      const doc = new jsPDF({ orientation: 'landscape', unit: 'mm', format: 'a4' });
      const stats = getStoreStats(selectedStore.id, pdfMonth);
      const storeEmps = employees.filter(e => e.restaurant_id === selectedStore.id && e.active);

      // Colores KFC
      const primaryRed = [227, 24, 55];
      const darkSlate = [15, 23, 42];
      const emeraldGreen = [16, 185, 129];

      // --- PAGINA 1: PORTADA Y GRAFICAS ---
      doc.setFillColor(darkSlate[0], darkSlate[1], darkSlate[2]);
      doc.rect(0, 0, 297, 40, 'F');

      doc.setTextColor(255, 255, 255);
      doc.setFontSize(22);
      doc.setFont('helvetica', 'bold');
      doc.text('REPORTE DE CURVAS DE CERTIFICACIÓN', 15, 20);

      doc.setFontSize(10);
      doc.setFont('helvetica', 'normal');
      doc.text(`RESTAURANTE: ${selectedStore.name} (${selectedStore.id})`, 15, 30);
      doc.text(`PERIODO: ${pdfMonth}`, 180, 20);
      doc.text(`ZONA: ${selectedStore.zone} | REGIONAL: ${selectedStore.region}`, 180, 30);

      // Graficas de barras simuladas (Resumen de Tienda)
      doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
      doc.setFontSize(14);
      doc.text('RESUMEN DE DESEMPEÑO POR GRUPO (PROMEDIO TIENDA)', 15, 60);

      let startX = 20;
      const chartHeight = 60;
      const barWidth = 35;
      const spacing = 15;

      stats.groupAvgs.forEach((g, i) => {
        const x = startX + (i * (barWidth + spacing));
        const yBase = 140;
        const bHeight = (g.avg / 100) * chartHeight;

        // Corregido: Cálculo de color para setFillColor
        const barColor = g.avg >= APPROVAL_THRESHOLD ? emeraldGreen : primaryRed;
        doc.setFillColor(barColor[0], barColor[1], barColor[2]);
        doc.rect(x, yBase - bHeight, barWidth, bHeight, 'F');

        // Etiqueta Nombre Grupo
        doc.setFontSize(8);
        doc.setTextColor(100, 116, 139);
        const splitName = doc.splitTextToSize(g.name, barWidth);
        doc.text(splitName, x, yBase + 5);

        // Etiqueta Valor
        doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
        doc.setFontSize(10);
        doc.setFont('helvetica', 'bold');
        doc.text(`${g.avg}%`, x + (barWidth/2) - 4, yBase - bHeight - 5);
      });

      // Caja de Estadisticas Rapidas
      doc.setFillColor(248, 250, 252);
      doc.roundedRect(220, 55, 60, 85, 5, 5, 'F');
      doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
      doc.setFontSize(10);
      doc.text('INDICADORES CLAVE', 225, 65);

      doc.setFontSize(8);
      doc.text('PERSONAL ACTIVO', 225, 80);
      doc.setFontSize(14);
      doc.text(`${stats.total}`, 225, 90);

      doc.setFontSize(8);
      doc.text('CERTIFICADOS', 225, 105);
      doc.setFontSize(14);
      doc.text(`${stats.approved}`, 225, 115);

      doc.setFontSize(8);
      doc.text('ÉXITO TIENDA', 225, 130);
      doc.setFontSize(14);

      // Corregido: Cálculo de color para setTextColor
      const successColor = stats.percent >= APPROVAL_THRESHOLD ? emeraldGreen : primaryRed;
      doc.setTextColor(successColor[0], successColor[1], successColor[2]);
      doc.text(`${stats.percent}%`, 225, 140);

      // --- PAGINA 2 EN ADELANTE: LISTADO DETALLADO ---
      doc.addPage();
      doc.setFillColor(primaryRed[0], primaryRed[1], primaryRed[2]);
      doc.rect(0, 0, 297, 15, 'F');
      doc.setTextColor(255, 255, 255);
      doc.setFontSize(10);
      doc.text(`LISTADO DETALLADO DE COLABORADORES - ${selectedStore.name}`, 10, 10);

      const tableData = storeEmps.sort((a,b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99)).map(emp => {
        const effective = dataService.getEffectiveGrades(emp.id, pdfMonth);
        const sum = effective.reduce((s, g) => s + g.score, 0);
        const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);

        // Construir string de sub-notas
        const subNotesStr = Object.entries(EVALUATION_GROUPS).map(([gid, config]) => {
          const gGrades = effective.filter(g => g.group === gid);
          const gAvg = gGrades.length > 0 ? Math.round(gGrades.reduce((s, g) => s + g.score, 0) / config.categories.length) : 0;
          return `${config.name}: ${gAvg}%`;
        }).join(' | ');

        return [
          emp.id,
          emp.name,
          emp.title,
          emp.join_date,
          `${avg}%`,
          subNotesStr
        ];
      });

      autoTable(doc, {
        head: [['CÉDULA', 'NOMBRE COMPLETO', 'CARGO', 'INGRESO', 'PROM.', 'DESGLOSE POR GRUPO (SUB-NOTAS)']],
        body: tableData,
        startY: 25,
        theme: 'grid',
        headStyles: { fillColor: darkSlate, fontSize: 8, fontStyle: 'bold' },
        bodyStyles: { fontSize: 7, textColor: [50, 50, 50] },
        columnStyles: {
          0: { cellWidth: 25 },
          1: { cellWidth: 45 },
          2: { cellWidth: 30 },
          3: { cellWidth: 25 },
          4: { cellWidth: 15, fontStyle: 'bold' },
          5: { cellWidth: 'auto' }
        },
        alternateRowStyles: { fillColor: [250, 250, 250] }
      });

      doc.save(`Curvas (${selectedStore.name}),(${pdfMonth}).pdf`);
      setShowPdfModal(false);
    } catch (e) {
      console.error(e);
      alert("Error al generar el PDF. Verifica los datos.");
    } finally {
      setIsGeneratingPdf(false);
    }
  };

  const selectClasses = "p-3 bg-white border-2 border-slate-100 rounded-xl text-[10px] font-black uppercase text-slate-800 outline-none focus:border-red-500 transition-all shadow-sm";

  if (selectedStore) {
    const stats = getStoreStats(selectedStore.id, selectedMonth);
    const storeEmps = employees
      .filter(e => e.restaurant_id === selectedStore.id && (user.role === UserRole.ADMIN ? true : e.active))
      .filter(e => empSearch === '' || e.name.toLowerCase().includes(empSearch.toLowerCase()) || e.id.includes(empSearch))
      .sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));

    return (
      <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center space-x-4">
            <button onClick={() => { setSelectedStore(null); setEmpSearch(''); }} className="p-3 bg-white border-2 border-slate-100 rounded-2xl text-slate-400 hover:text-red-600 transition-all shadow-sm"><ArrowLeft className="w-5 h-5" /></button>
            <div className="min-w-0">
              <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tighter uppercase italic leading-none truncate">{selectedStore.name}</h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-widest flex items-center mt-2 truncate"><MapPin className="w-3 h-3 mr-1.5 text-red-500" /> {selectedStore.zone} • {selectedStore.region}</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={() => { setPdfMonth(selectedMonth); setShowPdfModal(true); }}
              className="flex items-center gap-2 px-6 py-3.5 bg-red-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-red-700 transition-all shadow-lg"
            >
              <FileText className="w-4 h-4" /> <span>Reporte PDF</span>
            </button>
            <div className="relative w-full md:w-72">
              <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
              <input 
                type="text" 
                placeholder="Buscar colaborador..." 
                value={empSearch}
                onChange={e => setEmpSearch(e.target.value)}
                className="w-full pl-12 pr-4 py-3.5 bg-white border-2 border-slate-100 rounded-2xl text-xs font-black shadow-sm outline-none focus:border-red-500 transition-all" 
              />
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <DetailStatCard icon={<Users className="w-6 h-6" />} label="Equipo Activo" value={stats.total} color="blue" />
          <DetailStatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approved} color="green" />
          <DetailStatCard icon={<TrendingUp className="w-6 h-6" />} label="Éxito Tienda" value={`${stats.percent}%`} color="red" />
        </div>

        <div className="bg-white rounded-[32px] md:rounded-[40px] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b border-slate-50 flex justify-between items-center">
             <h3 className="text-[10px] font-black uppercase italic tracking-widest flex items-center">
               <Users className="w-4 h-4 mr-2 text-red-600" /> Listado con Arrastre
             </h3>
             <span className="text-[8px] font-black bg-slate-100 px-3 py-1.5 rounded-full uppercase text-slate-400 hidden sm:inline">Prioridad por Cargo</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50">
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Certificación</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Cargo</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {storeEmps.map(emp => {
                  const effective = dataService.getEffectiveGrades(emp.id, selectedMonth);
                  const sum = effective.reduce((s, g) => s + g.score, 0);
                  const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);
                  const status = effective.length === 0 ? 'PENDING' : (avg >= APPROVAL_THRESHOLD ? 'APPROVED' : 'FAILED');

                  return (
                    <tr key={emp.id} className="hover:bg-slate-50/80 transition-all group">
                      <td className="px-4 md:px-8 py-4 text-center">
                        <button 
                          onClick={() => setEditingEmployee(emp)} 
                          className="px-4 py-3 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-red-600 shadow-lg transition-all uppercase tracking-widest flex items-center justify-center gap-2 mx-auto"
                        >
                          <Edit3 className="w-4 h-4" />
                          <span className="hidden sm:inline">Calificar</span>
                        </button>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex items-center gap-3">
                          <div className="w-9 h-9 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-colors hidden sm:flex">
                            <UserIcon className="w-4 h-4" />
                          </div>
                          <div>
                            <p className="font-black text-slate-800 text-[12px] uppercase italic leading-tight group-hover:text-red-600 transition-colors">{emp.name}</p>
                            <p className="text-[8px] text-slate-400 font-black uppercase tracking-widest mt-0.5">ID: {emp.id}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex flex-col">
                          <span className={`text-[9px] font-black uppercase px-2 py-1 rounded-lg w-fit ${status === 'APPROVED' ? 'bg-emerald-50 text-emerald-600' : status === 'FAILED' ? 'bg-red-50 text-red-600' : 'bg-slate-100 text-slate-400'}`}>
                            {status === 'APPROVED' ? 'Certificado' : status === 'FAILED' ? 'No Certificado' : 'Sin Nota'}
                          </span>
                          {status !== 'PENDING' && <span className="text-[7px] font-black text-slate-300 uppercase mt-1">Promedio: {avg}%</span>}
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <span className="text-[10px] font-black text-slate-700 uppercase italic tracking-tight">{emp.title}</span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
        {editingEmployee && <GradeEditor employee={editingEmployee} month={selectedMonth} onClose={() => { setEditingEmployee(null); onUpdate(); }} />}

        {/* PDF Selection Modal */}
        {showPdfModal && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-4 animate-in fade-in duration-300">
            <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-md overflow-hidden border-2 border-white/20">
              <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-red-600 rounded-2xl shadow-xl shadow-red-900/20">
                    <FileText className="w-6 h-6 text-white" />
                  </div>
                  <h3 className="font-black uppercase italic tracking-tighter text-xl">Generar Curvas</h3>
                </div>
                <button onClick={() => setShowPdfModal(false)}><X className="w-6 h-6"/></button>
              </div>
              <div className="p-8 space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                    <Calendar className="w-3 h-3 text-red-500" /> Seleccionar Mes del Reporte
                  </label>
                  <input 
                    type="month" 
                    value={pdfMonth} 
                    onChange={e => setPdfMonth(e.target.value)}
                    className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-black text-slate-900 outline-none focus:border-red-500 transition-all" 
                  />
                </div>

                <div className="bg-slate-50 p-6 rounded-3xl space-y-3">
                   <p className="text-[10px] font-black uppercase text-slate-400 italic">Resumen a exportar:</p>
                   <div className="flex items-center justify-between">
                     <span className="text-[9px] font-black uppercase text-slate-600">Restaurante</span>
                     <span className="text-[11px] font-black uppercase text-slate-900">{selectedStore.name}</span>
                   </div>
                   <div className="flex items-center justify-between">
                     <span className="text-[9px] font-black uppercase text-slate-600">Personal</span>
                     <span className="text-[11px] font-black uppercase text-slate-900">{storeEmps.length} Colaboradores</span>
                   </div>
                </div>

                <button 
                  onClick={handleGeneratePDF}
                  disabled={isGeneratingPdf}
                  className="w-full py-5 bg-red-600 text-white font-black rounded-3xl hover:bg-red-700 shadow-xl shadow-red-500/10 transition-all uppercase tracking-widest text-[11px] flex items-center justify-center gap-3"
                >
                  {isGeneratingPdf ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
                  {isGeneratingPdf ? 'Generando Documento...' : 'Descargar Curvas PDF'}
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
          <select value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
          <select value={filterZone} onChange={(e) => setFilterZone(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
          </select>
        </div>
        <div className="md:col-span-2 space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Buscar Tienda</label>
          <input 
            type="text" 
            placeholder="CECO o Nombre..." 
            value={storeSearch}
            onChange={e => setStoreSearch(e.target.value)}
            className="w-full p-3.5 bg-slate-50 border-2 border-slate-100 rounded-xl text-xs font-black uppercase shadow-inner outline-none focus:bg-white focus:border-red-500 transition-all" 
          />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {assigned.map(store => {
          const stats = getStoreStats(store.id, selectedMonth);
          return (
            <div key={store.id} onClick={() => setSelectedStore(store)} className="bg-white rounded-[32px] shadow-sm border-2 border-slate-50 overflow-hidden hover:border-red-500 hover:shadow-2xl hover:shadow-red-50 transition-all group cursor-pointer flex flex-col p-8">
              <div className="flex items-start justify-between mb-8">
                <div className="flex items-center space-x-4">
                  <div className="w-14 h-14 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400 group-hover:bg-red-600 group-hover:text-white transition-all shadow-inner"><Store className="w-7 h-7" /></div>
                  <div className="min-w-0">
                    <h3 className="font-black text-slate-800 text-lg truncate uppercase tracking-tighter leading-tight italic">{store.name}</h3>
                    <p className="text-[9px] text-slate-400 font-black uppercase truncate tracking-widest mt-1">{store.region} • {store.zone}</p>
                  </div>
                </div>
              </div>
              <div className="mt-auto grid grid-cols-2 gap-4">
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Equipo Activo</p><p className="text-xl font-black text-slate-800 tracking-tighter">{stats.total}</p></div>
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Éxito</p><p className={`text-xl font-black tracking-tighter ${stats.percent >= 90 ? 'text-emerald-600' : 'text-red-600'}`}>{stats.percent}%</p></div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

const DetailStatCard: React.FC<{ icon: React.ReactNode, label: string, value: string | number, color: string }> = ({ icon, label, value, color }) => {
  const colorMap: any = { 
    blue: 'bg-blue-50 text-blue-600 border-blue-100', 
    green: 'bg-emerald-50 text-emerald-600 border-emerald-100', 
    red: 'bg-red-50 text-red-600 border-red-100' 
  };
  return (
    <div className={`bg-white p-5 md:p-6 rounded-[32px] border-2 shadow-sm flex items-center space-x-5 transition-transform hover:scale-[1.03] ${colorMap[color]}`}>
      <div className={`p-3 md:p-4 rounded-2xl bg-white shadow-lg`}>{icon}</div>
      <div>
        <p className="text-[8px] md:text-[10px] font-black uppercase tracking-[0.2em] opacity-60">{label}</p>
        <h4 className="text-2xl md:text-3xl font-black tracking-tighter leading-none mt-1">{value}</h4>
      </div>
    </div>
  );
};

export default MyStores;

import React, { useMemo, useState } from 'react';
import { User, Restaurant, Employee, UserRole, JobHierarchy } from '../types';
import { Store, MapPin, Users, Award, ArrowLeft, User as UserIcon, TrendingUp, Briefcase, Search, Filter, Edit3, FileText, Download, X, Calendar, RefreshCw } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT, EVALUATION_GROUPS } from '../constants';
import GradeEditor from './GradeEditor';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
  onUpdate: () => void;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth, onUpdate }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [storeSearch, setStoreSearch] = useState('');
  const [empSearch, setEmpSearch] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');

  // PDF Generation State
  const [showPdfModal, setShowPdfModal] = useState(false);
  const [pdfMonth, setPdfMonth] = useState(selectedMonth);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    let zones = Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) zones = zones.filter(z => user.assignedZones.includes(z));
    return zones;
  }, [restaurants, filterRegion, user]);

  const assigned = useMemo(() => {
    let base = user.role === UserRole.ADMIN 
      ? restaurants 
      : restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));

    return base.filter(r => {
      const matchSearch = storeSearch === '' || r.name.toLowerCase().includes(storeSearch.toLowerCase()) || r.id.includes(storeSearch);
      const matchRegion = filterRegion === 'all' || r.region === filterRegion;
      const matchZone = filterZone === 'all' || r.zone === filterZone;
      return matchSearch && matchRegion && matchZone;
    });
  }, [user, restaurants, storeSearch, filterRegion, filterZone]);

  const getStoreStats = (storeId: string, month: string) => {
    const storeEmps = employees.filter(e => e.restaurant_id === storeId && e.active);
    if (storeEmps.length === 0) return { total: 0, approved: 0, percent: 0, groupAvgs: [] };

    let approved = 0;
    const groupTotals: Record<string, { sum: number, count: number }> = {};

    storeEmps.forEach(emp => {
      const effective = dataService.getEffectiveGrades(emp.id, month);
      const sum = effective.reduce((s, g) => s + g.score, 0);
      const avg = TOTAL_CATEGORIES_COUNT > 0 ? sum / TOTAL_CATEGORIES_COUNT : 0;
      if (effective.length > 0 && avg >= APPROVAL_THRESHOLD) approved++;

      Object.entries(EVALUATION_GROUPS).forEach(([gid, gconfig]) => {
        const groupGrades = effective.filter(g => g.group === gid);
        const gSum = groupGrades.reduce((s, g) => s + g.score, 0);
        if (!groupTotals[gid]) groupTotals[gid] = { sum: 0, count: 0 };
        groupTotals[gid].sum += (gSum / gconfig.categories.length);
        groupTotals[gid].count++;
      });
    });

    const groupAvgs = Object.entries(EVALUATION_GROUPS).map(([id, config]) => ({
      id,
      name: config.name,
      avg: groupTotals[id] ? Math.round(groupTotals[id].sum / groupTotals[id].count) : 0
    }));

    return { total: storeEmps.length, approved, percent: Math.round((approved / storeEmps.length) * 100), groupAvgs };
  };

  const handleGeneratePDF = async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (!selectedStore) return;
    setIsGeneratingPdf(true);

    try {
      const doc = new jsPDF({ orientation: 'landscape', unit: 'mm', format: 'a4' });
      const stats = getStoreStats(selectedStore.id, pdfMonth);
      const storeEmps = employees.filter(e => e.restaurant_id === selectedStore.id && e.active);

      const primaryRed = [227, 24, 55];
      const darkSlate = [15, 23, 42];
      const emeraldGreen = [16, 185, 129];

      // --- PAGINA 1: PORTADA Y GRÁFICAS ---
      doc.setFillColor(darkSlate[0], darkSlate[1], darkSlate[2]);
      doc.rect(0, 0, 297, 40, 'F');

      doc.setTextColor(255, 255, 255);
      doc.setFontSize(22);
      doc.setFont('helvetica', 'bold');
      doc.text('REPORTE DE CURVAS DE CERTIFICACIÓN', 15, 20);

      doc.setFontSize(10);
      doc.setFont('helvetica', 'normal');
      doc.text(`RESTAURANTE: ${selectedStore.name} (${selectedStore.id})`, 15, 30);
      doc.text(`PERIODO: ${pdfMonth}`, 180, 20);
      doc.text(`ZONA: ${selectedStore.zone} | REGIONAL: ${selectedStore.region}`, 180, 30);

      doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
      doc.setFontSize(14);
      doc.text('DESEMPEÑO PROMEDIO DE LA TIENDA POR GRUPO', 15, 60);

      let startX = 20;
      const chartHeight = 60;
      const barWidth = 35;
      const spacing = 15;

      stats.groupAvgs.forEach((g, i) => {
        const x = startX + (i * (barWidth + spacing));
        const yBase = 140;
        const bHeight = (g.avg / 100) * chartHeight;

        const barColor = g.avg >= APPROVAL_THRESHOLD ? emeraldGreen : primaryRed;
        doc.setFillColor(barColor[0], barColor[1], barColor[2]);
        doc.rect(x, yBase - bHeight, barWidth, bHeight, 'F');

        doc.setFontSize(8);
        doc.setTextColor(100, 116, 139);
        const splitName = doc.splitTextToSize(g.name, barWidth);
        doc.text(splitName, x, yBase + 5);

        doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
        doc.setFontSize(10);
        doc.setFont('helvetica', 'bold');
        doc.text(`${g.avg}%`, x + (barWidth/2) - 4, yBase - bHeight - 5);
      });

      doc.setFillColor(248, 250, 252);
      doc.roundedRect(220, 55, 60, 95, 5, 5, 'F');
      doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
      doc.setFontSize(10);
      doc.text('MÉTRICAS CLAVE', 225, 65);

      doc.setFontSize(8);
      doc.text('EQUIPO ACTIVO', 225, 80);
      doc.setFontSize(14);
      doc.text(`${stats.total}`, 225, 90);

      doc.setFontSize(8);
      doc.text('PERSONAL CERTIFICADO', 225, 105);
      doc.setFontSize(14);
      doc.text(`${stats.approved}`, 225, 115);

      doc.setFontSize(8);
      doc.text('% ÉXITO TIENDA', 225, 130);
      doc.setFontSize(14);
      const successColor = stats.percent >= APPROVAL_THRESHOLD ? emeraldGreen : primaryRed;
      doc.setTextColor(successColor[0], successColor[1], successColor[2]);
      doc.text(`${stats.percent}%`, 225, 140);

      // --- PAGINA 2: TABLA DETALLADA ---
      doc.addPage();
      doc.setFillColor(primaryRed[0], primaryRed[1], primaryRed[2]);
      doc.rect(0, 0, 297, 15, 'F');
      doc.setTextColor(255, 255, 255);
      doc.setFontSize(10);
      doc.text(`DESGLOSE DETALLADO DE COLABORADORES - ${selectedStore.name}`, 10, 10);

      const tableData = storeEmps.sort((a,b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99)).map(emp => {
        const effective = dataService.getEffectiveGrades(emp.id, pdfMonth);
        const sum = effective.reduce((s, g) => s + g.score, 0);
        const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);

        const subNotesStr = Object.entries(EVALUATION_GROUPS).map(([gid, config]) => {
          const gGrades = effective.filter(g => g.group === gid);
          const gAvg = gGrades.length > 0 ? Math.round(gGrades.reduce((s, g) => s + g.score, 0) / config.categories.length) : 0;
          return `${config.name}: ${gAvg}%`;
        }).join('\n');

        return [
          emp.id,
          emp.name,
          emp.title,
          emp.join_date,
          `${avg}%`,
          subNotesStr
        ];
      });

      autoTable(doc, {
        head: [['CÉDULA', 'NOMBRE COMPLETO', 'CARGO', 'INGRESO', 'PROM.', 'DESGLOSE DE SUB-NOTAS POR GRUPO']],
        body: tableData,
        startY: 25,
        theme: 'grid',
        headStyles: { fillColor: darkSlate, fontSize: 8, fontStyle: 'bold' },
        bodyStyles: { fontSize: 7, textColor: [50, 50, 50], cellPadding: 3 },
        columnStyles: {
          0: { cellWidth: 25 },
          1: { cellWidth: 45 },
          2: { cellWidth: 35 },
          3: { cellWidth: 25 },
          4: { cellWidth: 15, fontStyle: 'bold' },
          5: { cellWidth: 'auto' }
        },
        alternateRowStyles: { fillColor: [250, 250, 250] }
      });

      doc.save(`Curvas (${selectedStore.name}),(${pdfMonth}).pdf`);
      setShowPdfModal(false);
    } catch (e) {
      console.error(e);
      alert("Error al generar el PDF. Verifica los datos.");
    } finally {
      setIsGeneratingPdf(false);
    }
  };

  const selectClasses = "p-3 bg-white border-2 border-slate-100 rounded-xl text-[10px] font-black uppercase text-slate-800 outline-none focus:border-red-500 transition-all shadow-sm";

  if (selectedStore) {
    const stats = getStoreStats(selectedStore.id, selectedMonth);
    const storeEmps = employees
      .filter(e => e.restaurant_id === selectedStore.id && (user.role === UserRole.ADMIN ? true : e.active))
      .filter(e => empSearch === '' || e.name.toLowerCase().includes(empSearch.toLowerCase()) || e.id.includes(empSearch))
      .sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));

    return (
      <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center space-x-4">
            <button onClick={() => { setSelectedStore(null); setEmpSearch(''); }} className="p-3 bg-white border-2 border-slate-100 rounded-2xl text-slate-400 hover:text-red-600 transition-all shadow-sm"><ArrowLeft className="w-5 h-5" /></button>
            <div className="min-w-0">
              <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tighter uppercase italic leading-none truncate">{selectedStore.name}</h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-widest flex items-center mt-2 truncate"><MapPin className="w-3 h-3 mr-1.5 text-red-500" /> {selectedStore.zone} • {selectedStore.region}</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={(e) => { e.preventDefault(); setPdfMonth(selectedMonth); setShowPdfModal(true); }}
              className="flex items-center gap-2 px-6 py-3.5 bg-red-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-red-700 transition-all shadow-lg"
            >
              <FileText className="w-4 h-4" /> <span>Reporte PDF</span>
            </button>
            <div className="relative w-full md:w-72">
              <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
              <input 
                type="text" 
                placeholder="Buscar colaborador..." 
                value={empSearch}
                onChange={e => setEmpSearch(e.target.value)}
                className="w-full pl-12 pr-4 py-3.5 bg-white border-2 border-slate-100 rounded-2xl text-xs font-black shadow-sm outline-none focus:border-red-500 transition-all" 
              />
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <DetailStatCard icon={<Users className="w-6 h-6" />} label="Equipo Activo" value={stats.total} color="blue" />
          <DetailStatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approved} color="green" />
          <DetailStatCard icon={<TrendingUp className="w-6 h-6" />} label="Éxito Tienda" value={`${stats.percent}%`} color="red" />
        </div>

        <div className="bg-white rounded-[32px] md:rounded-[40px] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b border-slate-50 flex justify-between items-center">
             <h3 className="text-[10px] font-black uppercase italic tracking-widest flex items-center">
               <Users className="w-4 h-4 mr-2 text-red-600" /> Listado con Arrastre
             </h3>
             <span className="text-[8px] font-black bg-slate-100 px-3 py-1.5 rounded-full uppercase text-slate-400 hidden sm:inline">Prioridad por Cargo</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50">
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Certificación</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Cargo</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {storeEmps.map(emp => {
                  const effective = dataService.getEffectiveGrades(emp.id, selectedMonth);
                  const sum = effective.reduce((s, g) => s + g.score, 0);
                  const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);
                  const status = effective.length === 0 ? 'PENDING' : (avg >= APPROVAL_THRESHOLD ? 'APPROVED' : 'FAILED');

                  return (
                    <tr key={emp.id} className="hover:bg-slate-50/80 transition-all group">
                      <td className="px-4 md:px-8 py-4 text-center">
                        <button 
                          onClick={() => setEditingEmployee(emp)} 
                          className="px-4 py-3 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-red-600 shadow-lg transition-all uppercase tracking-widest flex items-center justify-center gap-2 mx-auto"
                        >
                          <Edit3 className="w-4 h-4" />
                          <span className="hidden sm:inline">Calificar</span>
                        </button>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex items-center gap-3">
                          <div className="w-9 h-9 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-colors hidden sm:flex">
                            <UserIcon className="w-4 h-4" />
                          </div>
                          <div>
                            <p className="font-black text-slate-800 text-[12px] uppercase italic leading-tight group-hover:text-red-600 transition-colors">{emp.name}</p>
                            <p className="text-[8px] text-slate-400 font-black uppercase tracking-widest mt-0.5">ID: {emp.id}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex flex-col">
                          <span className={`text-[9px] font-black uppercase px-2 py-1 rounded-lg w-fit ${status === 'APPROVED' ? 'bg-emerald-50 text-emerald-600' : status === 'FAILED' ? 'bg-red-50 text-red-600' : 'bg-slate-100 text-slate-400'}`}>
                            {status === 'APPROVED' ? 'Certificado' : status === 'FAILED' ? 'No Certificado' : 'Sin Nota'}
                          </span>
                          {status !== 'PENDING' && <span className="text-[7px] font-black text-slate-300 uppercase mt-1">Promedio: {avg}%</span>}
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <span className="text-[10px] font-black text-slate-700 uppercase italic tracking-tight">{emp.title}</span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
        {editingEmployee && <GradeEditor employee={editingEmployee} month={selectedMonth} onClose={() => { setEditingEmployee(null); onUpdate(); }} />}

        {/* PDF Selection Modal */}
        {showPdfModal && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-4 animate-in fade-in duration-300">
            <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-md overflow-hidden border-2 border-white/20">
              <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-red-600 rounded-2xl shadow-xl shadow-red-900/20">
                    <FileText className="w-6 h-6 text-white" />
                  </div>
                  <h3 className="font-black uppercase italic tracking-tighter text-xl">Generar Curvas</h3>
                </div>
                <button onClick={(e) => { e.preventDefault(); setShowPdfModal(false); }}><X className="w-6 h-6"/></button>
              </div>
              <div className="p-8 space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                    <Calendar className="w-3 h-3 text-red-500" /> Periodo del Reporte
                  </label>
                  {/* Se remueve el onClick para evitar que despliegue la fecha automáticamente al enfocar */}
                  <input 
                    type="month" 
                    value={pdfMonth} 
                    onChange={e => setPdfMonth(e.target.value)}
                    className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-black text-slate-900 outline-none focus:border-red-500 transition-all" 
                  />
                </div>

                <div className="bg-slate-50 p-6 rounded-3xl space-y-3">
                   <p className="text-[10px] font-black uppercase text-slate-400 italic">Información de la Tienda:</p>
                   <div className="flex items-center justify-between">
                     <span className="text-[9px] font-black uppercase text-slate-600">Nombre</span>
                     <span className="text-[11px] font-black uppercase text-slate-900 truncate max-w-[150px]">{selectedStore.name}</span>
                   </div>
                   <div className="flex items-center justify-between">
                     <span className="text-[9px] font-black uppercase text-slate-600">Colaboradores</span>
                     <span className="text-[11px] font-black uppercase text-slate-900">{storeEmps.length} activos</span>
                   </div>
                </div>

                <button 
                  onClick={handleGeneratePDF}
                  disabled={isGeneratingPdf}
                  className="w-full py-5 bg-red-600 text-white font-black rounded-3xl hover:bg-red-700 shadow-xl shadow-red-500/10 transition-all uppercase tracking-widest text-[11px] flex items-center justify-center gap-3"
                >
                  {isGeneratingPdf ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
                  {isGeneratingPdf ? 'Preparando...' : 'Descargar Reporte PDF'}
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
          <select value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
          <select value={filterZone} onChange={(e) => setFilterZone(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
          </select>
        </div>
        <div className="md:col-span-2 space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Buscar Tienda</label>
          <input 
            type="text" 
            placeholder="CECO o Nombre..." 
            value={storeSearch}
            onChange={e => setStoreSearch(e.target.value)}
            className="w-full p-3.5 bg-slate-50 border-2 border-slate-100 rounded-xl text-xs font-black uppercase shadow-inner outline-none focus:bg-white focus:border-red-500 transition-all" 
          />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {assigned.map(store => {
          const stats = getStoreStats(store.id, selectedMonth);
          return (
            <div key={store.id} onClick={() => setSelectedStore(store)} className="bg-white rounded-[32px] shadow-sm border-2 border-slate-50 overflow-hidden hover:border-red-500 hover:shadow-2xl hover:shadow-red-50 transition-all group cursor-pointer flex flex-col p-8">
              <div className="flex items-start justify-between mb-8">
                <div className="flex items-center space-x-4">
                  <div className="w-14 h-14 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400 group-hover:bg-red-600 group-hover:text-white transition-all shadow-inner"><Store className="w-7 h-7" /></div>
                  <div className="min-w-0">
                    <h3 className="font-black text-slate-800 text-lg truncate uppercase tracking-tighter leading-tight italic">{store.name}</h3>
                    <p className="text-[9px] text-slate-400 font-black uppercase truncate tracking-widest mt-1">{store.region} • {store.zone}</p>
                  </div>
                </div>
              </div>
              <div className="mt-auto grid grid-cols-2 gap-4">
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Equipo Activo</p><p className="text-xl font-black text-slate-800 tracking-tighter">{stats.total}</p></div>
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Éxito</p><p className={`text-xl font-black tracking-tighter ${stats.percent >= 90 ? 'text-emerald-600' : 'text-red-600'}`}>{stats.percent}%</p></div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

const DetailStatCard: React.FC<{ icon: React.ReactNode, label: string, value: string | number, color: string }> = ({ icon, label, value, color }) => {
  const colorMap: any = { 
    blue: 'bg-blue-50 text-blue-600 border-blue-100', 
    green: 'bg-emerald-50 text-emerald-600 border-emerald-100', 
    red: 'bg-red-50 text-red-600 border-red-100' 
  };
  return (
    <div className={`bg-white p-5 md:p-6 rounded-[32px] border-2 shadow-sm flex items-center space-x-5 transition-transform hover:scale-[1.03] ${colorMap[color]}`}>
      <div className={`p-3 md:p-4 rounded-2xl bg-white shadow-lg`}>{icon}</div>
      <div>
        <p className="text-[8px] md:text-[10px] font-black uppercase tracking-[0.2em] opacity-60">{label}</p>
        <h4 className="text-2xl md:text-3xl font-black tracking-tighter leading-none mt-1">{value}</h4>
      </div>
    </div>
  );
};

export default MyStores;

import React, { useMemo, useState } from 'react';
import { User, Restaurant, Employee, UserRole, JobHierarchy } from '../types';
import { Store, MapPin, Users, Award, ArrowLeft, User as UserIcon, TrendingUp, Briefcase, Search, Filter, Edit3, FileText, Download, X, Calendar, RefreshCw } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT, EVALUATION_GROUPS } from '../constants';
import GradeEditor from './GradeEditor';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
  onUpdate: () => void;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth, onUpdate }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [storeSearch, setStoreSearch] = useState('');
  const [empSearch, setEmpSearch] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');

  // PDF Generation State
  const [showPdfModal, setShowPdfModal] = useState(false);
  const [pdfMonth, setPdfMonth] = useState(selectedMonth);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    let zones = Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) zones = zones.filter(z => user.assignedZones.includes(z));
    return zones;
  }, [restaurants, filterRegion, user]);

  const assigned = useMemo(() => {
    let base = user.role === UserRole.ADMIN 
      ? restaurants 
      : restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));

    return base.filter(r => {
      const matchSearch = storeSearch === '' || r.name.toLowerCase().includes(storeSearch.toLowerCase()) || r.id.includes(storeSearch);
      const matchRegion = filterRegion === 'all' || r.region === filterRegion;
      const matchZone = filterZone === 'all' || r.zone === filterZone;
      return matchSearch && matchRegion && matchZone;
    });
  }, [user, restaurants, storeSearch, filterRegion, filterZone]);

  const getStoreStats = (storeId: string, month: string) => {
    const storeEmps = employees.filter(e => e.restaurant_id === storeId && e.active);
    if (storeEmps.length === 0) return { total: 0, approved: 0, percent: 0, groupAvgs: [] };

    let approved = 0;
    const groupTotals: Record<string, { sum: number, count: number }> = {};

    storeEmps.forEach(emp => {
      const effective = dataService.getEffectiveGrades(emp.id, month);
      const sum = effective.reduce((s, g) => s + g.score, 0);
      const avg = TOTAL_CATEGORIES_COUNT > 0 ? sum / TOTAL_CATEGORIES_COUNT : 0;
      if (effective.length > 0 && avg >= APPROVAL_THRESHOLD) approved++;

      Object.entries(EVALUATION_GROUPS).forEach(([gid, gconfig]) => {
        const groupGrades = effective.filter(g => g.group === gid);
        const gSum = groupGrades.reduce((s, g) => s + g.score, 0);
        if (!groupTotals[gid]) groupTotals[gid] = { sum: 0, count: 0 };
        groupTotals[gid].sum += (gSum / gconfig.categories.length);
        groupTotals[gid].count++;
      });
    });

    const groupAvgs = Object.entries(EVALUATION_GROUPS).map(([id, config]) => ({
      id,
      name: config.name,
      avg: groupTotals[id] ? Math.round(groupTotals[id].sum / groupTotals[id].count) : 0
    }));

    return { total: storeEmps.length, approved, percent: Math.round((approved / storeEmps.length) * 100), groupAvgs };
  };

  const handleGeneratePDF = async (e: React.MouseEvent) => {
    // Bloquear cualquier comportamiento por defecto del navegador inmediatamente
    e.preventDefault();
    e.stopPropagation();

    if (!selectedStore || isGeneratingPdf) return;
    setIsGeneratingPdf(true);

    // Usar un timeout para sacar la generación del PDF del ciclo de renderizado inmediato
    setTimeout(async () => {
      try {
        const doc = new jsPDF({ orientation: 'landscape', unit: 'mm', format: 'a4' });
        const stats = getStoreStats(selectedStore.id, pdfMonth);
        const storeEmps = employees.filter(e => e.restaurant_id === selectedStore.id && e.active);

        const primaryRed = [227, 24, 55];
        const darkSlate = [15, 23, 42];
        const emeraldGreen = [16, 185, 129];

        // --- PAGINA 1: PORTADA ---
        doc.setFillColor(darkSlate[0], darkSlate[1], darkSlate[2]);
        doc.rect(0, 0, 297, 40, 'F');
        doc.setTextColor(255, 255, 255);
        doc.setFontSize(22);
        doc.setFont('helvetica', 'bold');
        doc.text('REPORTE DE CURVAS DE CERTIFICACIÓN', 15, 20);
        doc.setFontSize(10);
        doc.setFont('helvetica', 'normal');
        doc.text(`RESTAURANTE: ${selectedStore.name} (${selectedStore.id})`, 15, 30);
        doc.text(`PERIODO: ${pdfMonth}`, 180, 20);
        doc.text(`ZONA: ${selectedStore.zone} | REGIONAL: ${selectedStore.region}`, 180, 30);

        doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
        doc.setFontSize(14);
        doc.text('DESEMPEÑO PROMEDIO DE LA TIENDA POR GRUPO', 15, 60);

        let startX = 20;
        const chartHeight = 60;
        const barWidth = 35;
        const spacing = 15;

        stats.groupAvgs.forEach((g, i) => {
          const x = startX + (i * (barWidth + spacing));
          const yBase = 140;
          const bHeight = (g.avg / 100) * chartHeight;
          const barColor = g.avg >= APPROVAL_THRESHOLD ? emeraldGreen : primaryRed;
          doc.setFillColor(barColor[0], barColor[1], barColor[2]);
          doc.rect(x, yBase - bHeight, barWidth, bHeight, 'F');
          doc.setFontSize(8);
          doc.setTextColor(100, 116, 139);
          const splitName = doc.splitTextToSize(g.name, barWidth);
          doc.text(splitName, x, yBase + 5);
          doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
          doc.setFontSize(10);
          doc.setFont('helvetica', 'bold');
          doc.text(`${g.avg}%`, x + (barWidth/2) - 4, yBase - bHeight - 5);
        });

        doc.setFillColor(248, 250, 252);
        doc.roundedRect(220, 55, 60, 95, 5, 5, 'F');
        doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
        doc.setFontSize(10);
        doc.text('MÉTRICAS CLAVE', 225, 65);
        doc.setFontSize(8);
        doc.text('EQUIPO ACTIVO', 225, 80);
        doc.setFontSize(14);
        doc.text(`${stats.total}`, 225, 90);
        doc.setFontSize(8);
        doc.text('PERSONAL CERTIFICADO', 225, 105);
        doc.setFontSize(14);
        doc.text(`${stats.approved}`, 225, 115);
        doc.setFontSize(8);
        doc.text('% ÉXITO TIENDA', 225, 130);
        doc.setFontSize(14);
        const successColor = stats.percent >= APPROVAL_THRESHOLD ? emeraldGreen : primaryRed;
        doc.setTextColor(successColor[0], successColor[1], successColor[2]);
        doc.text(`${stats.percent}%`, 225, 140);

        // --- PAGINA 2: TABLA ---
        doc.addPage();
        doc.setFillColor(primaryRed[0], primaryRed[1], primaryRed[2]);
        doc.rect(0, 0, 297, 15, 'F');
        doc.setTextColor(255, 255, 255);
        doc.setFontSize(10);
        doc.text(`DESGLOSE DETALLADO DE COLABORADORES - ${selectedStore.name}`, 10, 10);

        const tableData = storeEmps.sort((a,b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99)).map(emp => {
          const effective = dataService.getEffectiveGrades(emp.id, pdfMonth);
          const sum = effective.reduce((s, g) => s + g.score, 0);
          const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);
          const subNotesStr = Object.entries(EVALUATION_GROUPS).map(([gid, config]) => {
            const gGrades = effective.filter(g => g.group === gid);
            const gAvg = gGrades.length > 0 ? Math.round(gGrades.reduce((s, g) => s + g.score, 0) / config.categories.length) : 0;
            return `${config.name}: ${gAvg}%`;
          }).join('\n');
          return [emp.id, emp.name, emp.title, emp.join_date, `${avg}%`, subNotesStr];
        });

        autoTable(doc, {
          head: [['CÉDULA', 'NOMBRE COMPLETO', 'CARGO', 'INGRESO', 'PROM.', 'DESGLOSE DE SUB-NOTAS POR GRUPO']],
          body: tableData,
          startY: 25,
          theme: 'grid',
          headStyles: { fillColor: darkSlate, fontSize: 8, fontStyle: 'bold' },
          bodyStyles: { fontSize: 7, textColor: [50, 50, 50], cellPadding: 3 },
          columnStyles: { 0: { cellWidth: 25 }, 1: { cellWidth: 45 }, 2: { cellWidth: 35 }, 3: { cellWidth: 25 }, 4: { cellWidth: 15, fontStyle: 'bold' }, 5: { cellWidth: 'auto' } },
          alternateRowStyles: { fillColor: [250, 250, 250] }
        });

        doc.save(`Curvas (${selectedStore.name}),(${pdfMonth}).pdf`);
        setShowPdfModal(false);
      } catch (e) {
        console.error(e);
        alert("Error al generar el PDF.");
      } finally {
        setIsGeneratingPdf(false);
      }
    }, 100);
  };

  const selectClasses = "p-3 bg-white border-2 border-slate-100 rounded-xl text-[10px] font-black uppercase text-slate-800 outline-none focus:border-red-500 transition-all shadow-sm";

  if (selectedStore) {
    const stats = getStoreStats(selectedStore.id, selectedMonth);
    const storeEmps = employees
      .filter(e => e.restaurant_id === selectedStore.id && (user.role === UserRole.ADMIN ? true : e.active))
      .filter(e => empSearch === '' || e.name.toLowerCase().includes(empSearch.toLowerCase()) || e.id.includes(empSearch))
      .sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));

    return (
      <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center space-x-4">
            <button type="button" onClick={() => { setSelectedStore(null); setEmpSearch(''); }} className="p-3 bg-white border-2 border-slate-100 rounded-2xl text-slate-400 hover:text-red-600 transition-all shadow-sm"><ArrowLeft className="w-5 h-5" /></button>
            <div className="min-w-0">
              <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tighter uppercase italic leading-none truncate">{selectedStore.name}</h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-widest flex items-center mt-2 truncate"><MapPin className="w-3 h-3 mr-1.5 text-red-500" /> {selectedStore.zone} • {selectedStore.region}</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              type="button"
              onClick={(e) => { e.preventDefault(); setPdfMonth(selectedMonth); setShowPdfModal(true); }}
              className="flex items-center gap-2 px-6 py-3.5 bg-red-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-red-700 transition-all shadow-lg"
            >
              <FileText className="w-4 h-4" /> <span>Reporte PDF</span>
            </button>
            <div className="relative w-full md:w-72">
              <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" />
              <input 
                type="text" 
                placeholder="Buscar colaborador..." 
                value={empSearch}
                onChange={e => setEmpSearch(e.target.value)}
                className="w-full pl-12 pr-4 py-3.5 bg-white border-2 border-slate-100 rounded-2xl text-xs font-black shadow-sm outline-none focus:border-red-500 transition-all" 
              />
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <DetailStatCard icon={<Users className="w-6 h-6" />} label="Equipo Activo" value={stats.total} color="blue" />
          <DetailStatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approved} color="green" />
          <DetailStatCard icon={<TrendingUp className="w-6 h-6" />} label="Éxito Tienda" value={`${stats.percent}%`} color="red" />
        </div>

        <div className="bg-white rounded-[32px] md:rounded-[40px] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b border-slate-50 flex justify-between items-center">
             <h3 className="text-[10px] font-black uppercase italic tracking-widest flex items-center">
               <Users className="w-4 h-4 mr-2 text-red-600" /> Listado con Arrastre
             </h3>
             <span className="text-[8px] font-black bg-slate-100 px-3 py-1.5 rounded-full uppercase text-slate-400 hidden sm:inline">Prioridad por Cargo</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50">
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Certificación</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Cargo</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {storeEmps.map(emp => {
                  const effective = dataService.getEffectiveGrades(emp.id, selectedMonth);
                  const sum = effective.reduce((s, g) => s + g.score, 0);
                  const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);
                  const status = effective.length === 0 ? 'PENDING' : (avg >= APPROVAL_THRESHOLD ? 'APPROVED' : 'FAILED');
                  return (
                    <tr key={emp.id} className="hover:bg-slate-50/80 transition-all group">
                      <td className="px-4 md:px-8 py-4 text-center">
                        <button 
                          type="button"
                          onClick={() => setEditingEmployee(emp)} 
                          className="px-4 py-3 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-red-600 shadow-lg transition-all uppercase tracking-widest flex items-center justify-center gap-2 mx-auto"
                        >
                          <Edit3 className="w-4 h-4" />
                          <span className="hidden sm:inline">Calificar</span>
                        </button>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex items-center gap-3">
                          <div className="w-9 h-9 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-colors hidden sm:flex">
                            <UserIcon className="w-4 h-4" />
                          </div>
                          <div>
                            <p className="font-black text-slate-800 text-[12px] uppercase italic leading-tight group-hover:text-red-600 transition-colors">{emp.name}</p>
                            <p className="text-[8px] text-slate-400 font-black uppercase tracking-widest mt-0.5">ID: {emp.id}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex flex-col">
                          <span className={`text-[9px] font-black uppercase px-2 py-1 rounded-lg w-fit ${status === 'APPROVED' ? 'bg-emerald-50 text-emerald-600' : status === 'FAILED' ? 'bg-red-50 text-red-600' : 'bg-slate-100 text-slate-400'}`}>
                            {status === 'APPROVED' ? 'Certificado' : status === 'FAILED' ? 'No Certificado' : 'Sin Nota'}
                          </span>
                          {status !== 'PENDING' && <span className="text-[7px] font-black text-slate-300 uppercase mt-1">Promedio: {avg}%</span>}
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <span className="text-[10px] font-black text-slate-700 uppercase italic tracking-tight">{emp.title}</span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
        {editingEmployee && <GradeEditor employee={editingEmployee} month={selectedMonth} onClose={() => { setEditingEmployee(null); onUpdate(); }} />}

        {/* PDF Selection Modal */}
        {showPdfModal && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-4 animate-in fade-in duration-300">
            <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-md overflow-hidden border-2 border-white/20">
              <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-red-600 rounded-2xl shadow-xl shadow-red-900/20">
                    <FileText className="w-6 h-6 text-white" />
                  </div>
                  <h3 className="font-black uppercase italic tracking-tighter text-xl">Generar Curvas</h3>
                </div>
                <button type="button" onClick={(e) => { e.preventDefault(); setShowPdfModal(false); }}><X className="w-6 h-6"/></button>
              </div>
              <div className="p-8 space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                    <Calendar className="w-3 h-3 text-red-500" /> Periodo del Reporte
                  </label>
                  <input 
                    type="month" 
                    value={pdfMonth} 
                    onChange={e => setPdfMonth(e.target.value)}
                    className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-black text-slate-900 outline-none focus:border-red-500 transition-all" 
                  />
                </div>

                <div className="bg-slate-50 p-6 rounded-3xl space-y-3">
                   <p className="text-[10px] font-black uppercase text-slate-400 italic">Información de la Tienda:</p>
                   <div className="flex items-center justify-between">
                     <span className="text-[9px] font-black uppercase text-slate-600">Nombre</span>
                     <span className="text-[11px] font-black uppercase text-slate-900 truncate max-w-[150px]">{selectedStore.name}</span>
                   </div>
                   <div className="flex items-center justify-between">
                     <span className="text-[9px] font-black uppercase text-slate-600">Colaboradores</span>
                     <span className="text-[11px] font-black uppercase text-slate-900">{storeEmps.length} activos</span>
                   </div>
                </div>

                <button 
                  type="button"
                  onClick={handleGeneratePDF}
                  disabled={isGeneratingPdf}
                  className="w-full py-5 bg-red-600 text-white font-black rounded-3xl hover:bg-red-700 shadow-xl shadow-red-500/10 transition-all uppercase tracking-widest text-[11px] flex items-center justify-center gap-3"
                >
                  {isGeneratingPdf ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
                  {isGeneratingPdf ? 'Preparando...' : 'Descargar Reporte PDF'}
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
          <select value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
          <select value={filterZone} onChange={(e) => setFilterZone(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
          </select>
        </div>
        <div className="md:col-span-2 space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Buscar Tienda</label>
          <input 
            type="text" 
            placeholder="CECO o Nombre..." 
            value={storeSearch}
            onChange={e => setStoreSearch(e.target.value)}
            className="w-full p-3.5 bg-slate-50 border-2 border-slate-100 rounded-xl text-xs font-black uppercase shadow-inner outline-none focus:bg-white focus:border-red-500 transition-all" 
          />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {assigned.map(store => {
          const stats = getStoreStats(store.id, selectedMonth);
          return (
            <div key={store.id} onClick={() => setSelectedStore(store)} className="bg-white rounded-[32px] shadow-sm border-2 border-slate-50 overflow-hidden hover:border-red-500 hover:shadow-2xl hover:shadow-red-50 transition-all group cursor-pointer flex flex-col p-8">
              <div className="flex items-start justify-between mb-8">
                <div className="flex items-center space-x-4">
                  <div className="w-14 h-14 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400 group-hover:bg-red-600 group-hover:text-white transition-all shadow-inner"><Store className="w-7 h-7" /></div>
                  <div className="min-w-0">
                    <h3 className="font-black text-slate-800 text-lg truncate uppercase tracking-tighter leading-tight italic">{store.name}</h3>
                    <p className="text-[9px] text-slate-400 font-black uppercase truncate tracking-widest mt-1">{store.region} • {store.zone}</p>
                  </div>
                </div>
              </div>
              <div className="mt-auto grid grid-cols-2 gap-4">
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Equipo Activo</p><p className="text-xl font-black text-slate-800 tracking-tighter">{stats.total}</p></div>
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Éxito</p><p className={`text-xl font-black tracking-tighter ${stats.percent >= 90 ? 'text-emerald-600' : 'text-red-600'}`}>{stats.percent}%</p></div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

const DetailStatCard: React.FC<{ icon: React.ReactNode, label: string, value: string | number, color: string }> = ({ icon, label, value, color }) => {
  const colorMap: any = { 
    blue: 'bg-blue-50 text-blue-600 border-blue-100', 
    green: 'bg-emerald-50 text-emerald-600 border-emerald-100', 
    red: 'bg-red-50 text-red-600 border-red-100' 
  };
  return (
    <div className={`bg-white p-5 md:p-6 rounded-[32px] border-2 shadow-sm flex items-center space-x-5 transition-transform hover:scale-[1.03] ${colorMap[color]}`}>
      <div className={`p-3 md:p-4 rounded-2xl bg-white shadow-lg`}>{icon}</div>
      <div>
        <p className="text-[8px] md:text-[10px] font-black uppercase tracking-[0.2em] opacity-60">{label}</p>
        <h4 className="text-2xl md:text-3xl font-black tracking-tighter leading-none mt-1">{value}</h4>
      </div>
    </div>
  );
};

export default MyStores;

import React, { useMemo, useState } from 'react';
import { User, Restaurant, Employee, UserRole, JobHierarchy } from '../types';
import { Store, MapPin, Users, Award, ArrowLeft, User as UserIcon, TrendingUp, Briefcase, Search, Filter, Edit3, FileText, Download, X, Calendar, RefreshCw } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT, EVALUATION_GROUPS } from '../constants';
import GradeEditor from './GradeEditor';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
  onUpdate: () => void;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth, onUpdate }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [storeSearch, setStoreSearch] = useState('');
  const [empSearch, setEmpSearch] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');

  // PDF Generation State
  const [showPdfModal, setShowPdfModal] = useState(false);
  const [pdfMonth, setPdfMonth] = useState(selectedMonth);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    let zones = Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) zones = zones.filter(z => user.assignedZones.includes(z));
    return zones;
  }, [restaurants, filterRegion, user]);

  const assigned = useMemo(() => {
    let base = user.role === UserRole.ADMIN 
      ? restaurants 
      : restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));

    return base.filter(r => {
      const matchSearch = storeSearch === '' || r.name.toLowerCase().includes(storeSearch.toLowerCase()) || r.id.includes(storeSearch);
      const matchRegion = filterRegion === 'all' || r.region === filterRegion;
      const matchZone = filterZone === 'all' || r.zone === filterZone;
      return matchSearch && matchRegion && matchZone;
    });
  }, [user, restaurants, storeSearch, filterRegion, filterZone]);

  const getStoreStats = (storeId: string, month: string) => {
    const storeEmps = employees.filter(e => e.restaurant_id === storeId && e.active);
    if (storeEmps.length === 0) return { total: 0, approved: 0, percent: 0, groupAvgs: [] };

    let approved = 0;
    const groupTotals: Record<string, { sum: number, count: number }> = {};

    storeEmps.forEach(emp => {
      const effective = dataService.getEffectiveGrades(emp.id, month);
      const sum = effective.reduce((s, g) => s + g.score, 0);
      const avg = TOTAL_CATEGORIES_COUNT > 0 ? sum / TOTAL_CATEGORIES_COUNT : 0;
      if (effective.length > 0 && avg >= APPROVAL_THRESHOLD) approved++;

      Object.entries(EVALUATION_GROUPS).forEach(([gid, gconfig]) => {
        const groupGrades = effective.filter(g => g.group === gid);
        const gSum = groupGrades.reduce((s, g) => s + g.score, 0);
        if (!groupTotals[gid]) groupTotals[gid] = { sum: 0, count: 0 };
        groupTotals[gid].sum += (gSum / gconfig.categories.length);
        groupTotals[gid].count++;
      });
    });

    const groupAvgs = Object.entries(EVALUATION_GROUPS).map(([id, config]) => ({
      id,
      name: config.name,
      avg: groupTotals[id] ? Math.round(groupTotals[id].sum / groupTotals[id].count) : 0
    }));

    return { total: storeEmps.length, approved, percent: Math.round((approved / storeEmps.length) * 100), groupAvgs };
  };

  const handleGeneratePDF = async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (!selectedStore || isGeneratingPdf) return;
    setIsGeneratingPdf(true);

    // Pequeño delay para que la UI responda antes de la carga pesada del PDF
    setTimeout(async () => {
      try {
        const doc = new jsPDF({ orientation: 'landscape', unit: 'mm', format: 'a4' });
        const stats = getStoreStats(selectedStore.id, pdfMonth);
        const storeEmps = employees.filter(e => e.restaurant_id === selectedStore.id && e.active);

        const primaryRed = [227, 24, 55];
        const darkSlate = [15, 23, 42];
        const emeraldGreen = [16, 185, 129];

        // --- PAGINA 1: PORTADA ---
        doc.setFillColor(darkSlate[0], darkSlate[1], darkSlate[2]);
        doc.rect(0, 0, 297, 40, 'F');
        doc.setTextColor(255, 255, 255);
        doc.setFontSize(22);
        doc.setFont('helvetica', 'bold');
        doc.text('REPORTE DE CURVAS DE CERTIFICACIÓN', 15, 20);
        doc.setFontSize(10);
        doc.setFont('helvetica', 'normal');
        doc.text(`RESTAURANTE: ${selectedStore.name} (${selectedStore.id})`, 15, 30);
        doc.text(`PERIODO: ${pdfMonth}`, 180, 20);
        doc.text(`ZONA: ${selectedStore.zone} | REGIONAL: ${selectedStore.region}`, 180, 30);

        doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
        doc.setFontSize(14);
        doc.text('DESEMPEÑO PROMEDIO DE LA TIENDA POR GRUPO', 15, 60);

        let startX = 20;
        const chartHeight = 60;
        const barWidth = 35;
        const spacing = 15;

        stats.groupAvgs.forEach((g, i) => {
          const x = startX + (i * (barWidth + spacing));
          const yBase = 140;
          const bHeight = (g.avg / 100) * chartHeight;
          const barColor = g.avg >= APPROVAL_THRESHOLD ? emeraldGreen : primaryRed;
          doc.setFillColor(barColor[0], barColor[1], barColor[2]);
          doc.rect(x, yBase - bHeight, barWidth, bHeight, 'F');
          doc.setFontSize(8);
          doc.setTextColor(100, 116, 139);
          const splitName = doc.splitTextToSize(g.name, barWidth);
          doc.text(splitName, x, yBase + 5);
          doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
          doc.setFontSize(10);
          doc.setFont('helvetica', 'bold');
          doc.text(`${g.avg}%`, x + (barWidth/2) - 4, yBase - bHeight - 5);
        });

        doc.setFillColor(248, 250, 252);
        doc.roundedRect(220, 55, 60, 95, 5, 5, 'F');
        doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
        doc.setFontSize(10);
        doc.text('MÉTRICAS CLAVE', 225, 65);
        doc.setFontSize(8);
        doc.text('EQUIPO ACTIVO', 225, 80);
        doc.setFontSize(14);
        doc.text(`${stats.total}`, 225, 90);
        doc.setFontSize(8);
        doc.text('PERSONAL CERTIFICADO', 225, 105);
        doc.setFontSize(14);
        doc.text(`${stats.approved}`, 225, 115);
        doc.setFontSize(8);
        doc.text('% ÉXITO TIENDA', 225, 130);
        doc.setFontSize(14);
        const successColor = stats.percent >= APPROVAL_THRESHOLD ? emeraldGreen : primaryRed;
        doc.setTextColor(successColor[0], successColor[1], successColor[2]);
        doc.text(`${stats.percent}%`, 225, 140);

        // --- PAGINA 2: TABLA ---
        doc.addPage();
        doc.setFillColor(primaryRed[0], primaryRed[1], primaryRed[2]);
        doc.rect(0, 0, 297, 15, 'F');
        doc.setTextColor(255, 255, 255);
        doc.setFontSize(10);
        doc.text(`DESGLOSE DETALLADO DE COLABORADORES - ${selectedStore.name}`, 10, 10);

        const tableData = storeEmps.sort((a,b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99)).map(emp => {
          const effective = dataService.getEffectiveGrades(emp.id, pdfMonth);
          const sum = effective.reduce((s, g) => s + g.score, 0);
          const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);
          const subNotesStr = Object.entries(EVALUATION_GROUPS).map(([gid, config]) => {
            const gGrades = effective.filter(g => g.group === gid);
            const gAvg = gGrades.length > 0 ? Math.round(gGrades.reduce((s, g) => s + g.score, 0) / config.categories.length) : 0;
            return `${config.name}: ${gAvg}%`;
          }).join('\n');
          return [emp.id, emp.name, emp.title, emp.join_date, `${avg}%`, subNotesStr];
        });

        autoTable(doc, {
          head: [['CÉDULA', 'NOMBRE COMPLETO', 'CARGO', 'INGRESO', 'PROM.', 'DESGLOSE DE SUB-NOTAS POR GRUPO']],
          body: tableData,
          startY: 25,
          theme: 'grid',
          headStyles: { fillColor: darkSlate, fontSize: 8, fontStyle: 'bold' },
          bodyStyles: { fontSize: 7, textColor: [50, 50, 50], cellPadding: 3 },
          columnStyles: { 0: { cellWidth: 25 }, 1: { cellWidth: 45 }, 2: { cellWidth: 35 }, 3: { cellWidth: 25 }, 4: { cellWidth: 15, fontStyle: 'bold' }, 5: { cellWidth: 'auto' } },
          alternateRowStyles: { fillColor: [250, 250, 250] }
        });

        doc.save(`Curvas (${selectedStore.name}),(${pdfMonth}).pdf`);
        setShowPdfModal(false);
      } catch (e) {
        console.error(e);
        alert("Error al generar el PDF.");
      } finally {
        setIsGeneratingPdf(false);
      }
    }, 150);
  };

  const selectClasses = "p-3 bg-white border-2 border-slate-100 rounded-xl text-[10px] font-black uppercase text-slate-800 outline-none focus:border-red-500 transition-all shadow-sm";

  if (selectedStore) {
    const stats = getStoreStats(selectedStore.id, selectedMonth);
    const storeEmps = employees
      .filter(e => e.restaurant_id === selectedStore.id && (user.role === UserRole.ADMIN ? true : e.active))
      .filter(e => empSearch === '' || e.name.toLowerCase().includes(empSearch.toLowerCase()) || e.id.includes(empSearch))
      .sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));

    return (
      <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center space-x-4">
            <button type="button" onClick={() => { setSelectedStore(null); setEmpSearch(''); }} className="p-3 bg-white border-2 border-slate-100 rounded-2xl text-slate-400 hover:text-red-600 transition-all shadow-sm relative z-20"><ArrowLeft className="w-5 h-5" /></button>
            <div className="min-w-0">
              <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tighter uppercase italic leading-none truncate">{selectedStore.name}</h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-widest flex items-center mt-2 truncate"><MapPin className="w-3 h-3 mr-1.5 text-red-500" /> {selectedStore.zone} • {selectedStore.region}</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              type="button"
              onClick={(e) => { e.preventDefault(); e.stopPropagation(); setPdfMonth(selectedMonth); setShowPdfModal(true); }}
              className="flex items-center gap-2 px-6 py-3.5 bg-red-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-red-700 transition-all shadow-lg relative z-20"
            >
              <FileText className="w-4 h-4" /> <span>Reporte PDF</span>
            </button>
            <div className="relative w-full md:w-72">
              <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
              <input 
                type="text" 
                placeholder="Buscar colaborador..." 
                value={empSearch}
                onChange={e => setEmpSearch(e.target.value)}
                className="w-full pl-12 pr-4 py-3.5 bg-white border-2 border-slate-100 rounded-2xl text-xs font-black shadow-sm outline-none focus:border-red-500 transition-all relative z-0" 
              />
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <DetailStatCard icon={<Users className="w-6 h-6" />} label="Equipo Activo" value={stats.total} color="blue" />
          <DetailStatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approved} color="green" />
          <DetailStatCard icon={<TrendingUp className="w-6 h-6" />} label="Éxito Tienda" value={`${stats.percent}%`} color="red" />
        </div>

        <div className="bg-white rounded-[32px] md:rounded-[40px] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b border-slate-50 flex justify-between items-center">
             <h3 className="text-[10px] font-black uppercase italic tracking-widest flex items-center">
               <Users className="w-4 h-4 mr-2 text-red-600" /> Listado con Arrastre
             </h3>
             <span className="text-[8px] font-black bg-slate-100 px-3 py-1.5 rounded-full uppercase text-slate-400 hidden sm:inline">Prioridad por Cargo</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50">
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Certificación</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Cargo</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {storeEmps.map(emp => {
                  const effective = dataService.getEffectiveGrades(emp.id, selectedMonth);
                  const sum = effective.reduce((s, g) => s + g.score, 0);
                  const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);
                  const status = effective.length === 0 ? 'PENDING' : (avg >= APPROVAL_THRESHOLD ? 'APPROVED' : 'FAILED');
                  return (
                    <tr key={emp.id} className="hover:bg-slate-50/80 transition-all group">
                      <td className="px-4 md:px-8 py-4 text-center">
                        <button 
                          type="button"
                          onClick={() => setEditingEmployee(emp)} 
                          className="px-4 py-3 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-red-600 shadow-lg transition-all uppercase tracking-widest flex items-center justify-center gap-2 mx-auto"
                        >
                          <Edit3 className="w-4 h-4" />
                          <span className="hidden sm:inline">Calificar</span>
                        </button>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex items-center gap-3">
                          <div className="w-9 h-9 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-colors hidden sm:flex">
                            <UserIcon className="w-4 h-4" />
                          </div>
                          <div>
                            <p className="font-black text-slate-800 text-[12px] uppercase italic leading-tight group-hover:text-red-600 transition-colors">{emp.name}</p>
                            <p className="text-[8px] text-slate-400 font-black uppercase tracking-widest mt-0.5">ID: {emp.id}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex flex-col">
                          <span className={`text-[9px] font-black uppercase px-2 py-1 rounded-lg w-fit ${status === 'APPROVED' ? 'bg-emerald-50 text-emerald-600' : status === 'FAILED' ? 'bg-red-50 text-red-600' : 'bg-slate-100 text-slate-400'}`}>
                            {status === 'APPROVED' ? 'Certificado' : status === 'FAILED' ? 'No Certificado' : 'Sin Nota'}
                          </span>
                          {status !== 'PENDING' && <span className="text-[7px] font-black text-slate-300 uppercase mt-1">Promedio: {avg}%</span>}
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <span className="text-[10px] font-black text-slate-700 uppercase italic tracking-tight">{emp.title}</span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
        {editingEmployee && <GradeEditor employee={editingEmployee} month={selectedMonth} onClose={() => { setEditingEmployee(null); onUpdate(); }} />}

        {/* PDF Selection Modal */}
        {showPdfModal && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-4 animate-in fade-in duration-300">
            <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-md overflow-hidden border-2 border-white/20 relative">
              <div className="p-8 bg-slate-900 text-white flex justify-between items-center relative z-10">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-red-600 rounded-2xl shadow-xl shadow-red-900/20">
                    <FileText className="w-6 h-6 text-white" />
                  </div>
                  <h3 className="font-black uppercase italic tracking-tighter text-xl">Generar Curvas</h3>
                </div>
                <button type="button" onClick={(e) => { e.preventDefault(); e.stopPropagation(); setShowPdfModal(false); }} className="p-2 bg-white/10 hover:bg-white/20 rounded-xl transition-all"><X className="w-6 h-6"/></button>
              </div>
              <div className="p-8 space-y-6 relative z-10 bg-white">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                    <Calendar className="w-3 h-3 text-red-500" /> Periodo del Reporte
                  </label>
                  {/* CRÍTICO: El input debe estar en un contenedor relative para que el pseudo-elemento del calendario en index.html se limite a este div */}
                  <div className="relative">
                    <input 
                      type="month" 
                      value={pdfMonth} 
                      onChange={e => { e.stopPropagation(); setPdfMonth(e.target.value); }}
                      className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-sm font-black text-slate-900 outline-none focus:border-red-500 transition-all relative z-10" 
                    />
                  </div>
                </div>

                <div className="bg-slate-50 p-6 rounded-3xl space-y-3">
                   <p className="text-[10px] font-black uppercase text-slate-400 italic">Información de la Tienda:</p>
                   <div className="flex items-center justify-between">
                     <span className="text-[9px] font-black uppercase text-slate-600">Nombre</span>
                     <span className="text-[11px] font-black uppercase text-slate-900 truncate max-w-[150px]">{selectedStore.name}</span>
                   </div>
                   <div className="flex items-center justify-between">
                     <span className="text-[9px] font-black uppercase text-slate-600">Colaboradores</span>
                     <span className="text-[11px] font-black uppercase text-slate-900">{storeEmps.length} activos</span>
                   </div>
                </div>

                <button 
                  type="button"
                  onClick={handleGeneratePDF}
                  disabled={isGeneratingPdf}
                  className="w-full py-5 bg-red-600 text-white font-black rounded-3xl hover:bg-red-700 shadow-xl shadow-red-500/10 transition-all uppercase tracking-widest text-[11px] flex items-center justify-center gap-3 relative z-20"
                >
                  {isGeneratingPdf ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
                  {isGeneratingPdf ? 'Preparando...' : 'Descargar Reporte PDF'}
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
          <select value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
          <select value={filterZone} onChange={(e) => setFilterZone(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
          </select>
        </div>
        <div className="md:col-span-2 space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Buscar Tienda</label>
          <input 
            type="text" 
            placeholder="CECO o Nombre..." 
            value={storeSearch}
            onChange={e => setStoreSearch(e.target.value)}
            className="w-full p-3.5 bg-slate-50 border-2 border-slate-100 rounded-xl text-xs font-black uppercase shadow-inner outline-none focus:bg-white focus:border-red-500 transition-all" 
          />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {assigned.map(store => {
          const stats = getStoreStats(store.id, selectedMonth);
          return (
            <div key={store.id} onClick={() => setSelectedStore(store)} className="bg-white rounded-[32px] shadow-sm border-2 border-slate-50 overflow-hidden hover:border-red-500 hover:shadow-2xl hover:shadow-red-50 transition-all group cursor-pointer flex flex-col p-8">
              <div className="flex items-start justify-between mb-8">
                <div className="flex items-center space-x-4">
                  <div className="w-14 h-14 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400 group-hover:bg-red-600 group-hover:text-white transition-all shadow-inner"><Store className="w-7 h-7" /></div>
                  <div className="min-w-0">
                    <h3 className="font-black text-slate-800 text-lg truncate uppercase tracking-tighter leading-tight italic">{store.name}</h3>
                    <p className="text-[9px] text-slate-400 font-black uppercase truncate tracking-widest mt-1">{store.region} • {store.zone}</p>
                  </div>
                </div>
              </div>
              <div className="mt-auto grid grid-cols-2 gap-4">
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Equipo Activo</p><p className="text-xl font-black text-slate-800 tracking-tighter">{stats.total}</p></div>
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Éxito</p><p className={`text-xl font-black tracking-tighter ${stats.percent >= 90 ? 'text-emerald-600' : 'text-red-600'}`}>{stats.percent}%</p></div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

const DetailStatCard: React.FC<{ icon: React.ReactNode, label: string, value: string | number, color: string }> = ({ icon, label, value, color }) => {
  const colorMap: any = { 
    blue: 'bg-blue-50 text-blue-600 border-blue-100', 
    green: 'bg-emerald-50 text-emerald-600 border-emerald-100', 
    red: 'bg-red-50 text-red-600 border-red-100' 
  };
  return (
    <div className={`bg-white p-5 md:p-6 rounded-[32px] border-2 shadow-sm flex items-center space-x-5 transition-transform hover:scale-[1.03] ${colorMap[color]}`}>
      <div className={`p-3 md:p-4 rounded-2xl bg-white shadow-lg`}>{icon}</div>
      <div>
        <p className="text-[8px] md:text-[10px] font-black uppercase tracking-[0.2em] opacity-60">{label}</p>
        <h4 className="text-2xl md:text-3xl font-black tracking-tighter leading-none mt-1">{value}</h4>
      </div>
    </div>
  );
};

export default MyStores;

import React, { useMemo, useState } from 'react';
import { User, Restaurant, Employee, UserRole, JobHierarchy } from '../types';
import { Store, MapPin, Users, Award, ArrowLeft, User as UserIcon, TrendingUp, Briefcase, Search, Filter, Edit3, FileText, Download, X, Calendar, RefreshCw } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT, EVALUATION_GROUPS } from '../constants';
import GradeEditor from './GradeEditor';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
  onUpdate: () => void;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth, onUpdate }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [storeSearch, setStoreSearch] = useState('');
  const [empSearch, setEmpSearch] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');

  const [showPdfModal, setShowPdfModal] = useState(false);
  const [pdfMonth, setPdfMonth] = useState(selectedMonth);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    let zones = Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) zones = zones.filter(z => user.assignedZones.includes(z));
    return zones;
  }, [restaurants, filterRegion, user]);

  const assigned = useMemo(() => {
    let base = user.role === UserRole.ADMIN 
      ? restaurants 
      : restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));

    return base.filter(r => {
      const matchSearch = storeSearch === '' || r.name.toLowerCase().includes(storeSearch.toLowerCase()) || r.id.includes(storeSearch);
      const matchRegion = filterRegion === 'all' || r.region === filterRegion;
      const matchZone = filterZone === 'all' || r.zone === filterZone;
      return matchSearch && matchRegion && matchZone;
    });
  }, [user, restaurants, storeSearch, filterRegion, filterZone]);

  const getStoreStats = (storeId: string, month: string) => {
    const storeEmps = employees.filter(e => e.restaurant_id === storeId && e.active);
    if (storeEmps.length === 0) return { total: 0, approved: 0, percent: 0, groupAvgs: [] };

    let approved = 0;
    const groupTotals: Record<string, { sum: number, count: number }> = {};

    storeEmps.forEach(emp => {
      const effective = dataService.getEffectiveGrades(emp.id, month);
      const sum = effective.reduce((s, g) => s + g.score, 0);
      const avg = TOTAL_CATEGORIES_COUNT > 0 ? sum / TOTAL_CATEGORIES_COUNT : 0;
      if (effective.length > 0 && avg >= APPROVAL_THRESHOLD) approved++;

      Object.entries(EVALUATION_GROUPS).forEach(([gid, gconfig]) => {
        const groupGrades = effective.filter(g => g.group === gid);
        const gSum = groupGrades.reduce((s, g) => s + g.score, 0);
        if (!groupTotals[gid]) groupTotals[gid] = { sum: 0, count: 0 };
        groupTotals[gid].sum += (gSum / gconfig.categories.length);
        groupTotals[gid].count++;
      });
    });

    const groupAvgs = Object.entries(EVALUATION_GROUPS).map(([id, config]) => ({
      id,
      name: config.name,
      avg: groupTotals[id] ? Math.round(groupTotals[id].sum / groupTotals[id].count) : 0
    }));

    return { total: storeEmps.length, approved, percent: Math.round((approved / storeEmps.length) * 100), groupAvgs };
  };

  const handleGeneratePDF = async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (!selectedStore || isGeneratingPdf) return;
    setIsGeneratingPdf(true);

    setTimeout(async () => {
      try {
        const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
        const stats = getStoreStats(selectedStore.id, pdfMonth);
        const storeEmps = employees.filter(e => e.restaurant_id === selectedStore.id && e.active);

        const primaryRed = [227, 24, 55];
        const darkSlate = [15, 23, 42];
        const emeraldGreen = [16, 185, 129];
        const lightGray = [241, 245, 249];

        // --- PÁGINA 1: MÉTRICAS Y GRÁFICAS (VERTICAL) ---
        // Header
        doc.setFillColor(primaryRed[0], primaryRed[1], primaryRed[2]);
        doc.rect(0, 0, 210, 45, 'F');
        doc.setTextColor(255, 255, 255);
        doc.setFontSize(24);
        doc.setFont('helvetica', 'bold');
        doc.text('REPORTE DE CURVAS', 15, 20);
        doc.setFontSize(10);
        doc.setFont('helvetica', 'normal');
        doc.text(`TIENDA: ${selectedStore.name} (${selectedStore.id})`, 15, 30);
        doc.text(`PERIODO: ${pdfMonth}`, 15, 36);
        doc.text(`ZONA: ${selectedStore.zone} | REGIONAL: ${selectedStore.region}`, 120, 30);

        // Metrics Section
        doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
        doc.setFontSize(14);
        doc.setFont('helvetica', 'bold');
        doc.text('RESUMEN DE DESEMPEÑO', 15, 60);

        const cardW = 55;
        const cardH = 25;
        const cardY = 65;

        // Card 1: Equipo
        doc.setFillColor(lightGray[0], lightGray[1], lightGray[2]);
        doc.roundedRect(15, cardY, cardW, cardH, 3, 3, 'F');
        doc.setFontSize(8);
        doc.text('EQUIPO ACTIVO', 20, cardY + 8);
        doc.setFontSize(14);
        doc.text(`${stats.total}`, 20, cardY + 18);

        // Card 2: Certificados
        doc.roundedRect(15 + cardW + 5, cardY, cardW, cardH, 3, 3, 'F');
        doc.setFontSize(8);
        doc.text('CERTIFICADOS', 20 + cardW + 5, cardY + 8);
        doc.setFontSize(14);
        doc.text(`${stats.approved}`, 20 + cardW + 5, cardY + 18);

        // Card 3: % Éxito
        doc.setFillColor(stats.percent >= APPROVAL_THRESHOLD ? emeraldGreen[0] : primaryRed[0], stats.percent >= APPROVAL_THRESHOLD ? emeraldGreen[1] : primaryRed[1], stats.percent >= APPROVAL_THRESHOLD ? emeraldGreen[2] : primaryRed[2]);
        doc.roundedRect(15 + (cardW + 5) * 2, cardY, cardW, cardH, 3, 3, 'F');
        doc.setTextColor(255, 255, 255);
        doc.setFontSize(8);
        doc.text('% ÉXITO TIENDA', 20 + (cardW + 5) * 2, cardY + 8);
        doc.setFontSize(14);
        doc.text(`${stats.percent}%`, 20 + (cardW + 5) * 2, cardY + 18);

        // Independent Group Charts
        doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);
        doc.setFontSize(14);
        doc.text('PROMEDIO POR CATEGORÍA', 15, 110);

        let groupY = 120;
        stats.groupAvgs.forEach((g) => {
          // Label
          doc.setFontSize(10);
          doc.setFont('helvetica', 'bold');
          doc.text(g.name, 15, groupY);

          // Progress Bar Background
          doc.setFillColor(240, 240, 240);
          doc.roundedRect(15, groupY + 3, 150, 6, 2, 2, 'F');

          // Progress Bar Foreground
          const barColor = g.avg >= APPROVAL_THRESHOLD ? emeraldGreen : primaryRed;
          doc.setFillColor(barColor[0], barColor[1], barColor[2]);
          doc.roundedRect(15, groupY + 3, (g.avg / 100) * 150, 6, 2, 2, 'F');

          // Percentage Text
          doc.setTextColor(barColor[0], barColor[1], barColor[2]);
          doc.text(`${g.avg}%`, 170, groupY + 8);
          doc.setTextColor(darkSlate[0], darkSlate[1], darkSlate[2]);

          groupY += 22;
        });

        // --- PÁGINA 2: LISTADO DE PERSONAL (VERTICAL) ---
        doc.addPage();
        doc.setFillColor(darkSlate[0], darkSlate[1], darkSlate[2]);
        doc.rect(0, 0, 210, 15, 'F');
        doc.setTextColor(255, 255, 255);
        doc.setFontSize(10);
        doc.text(`LISTADO DE PERSONAL ORGANIZADO POR JERARQUÍA`, 15, 10);

        const tableData = storeEmps
          .sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99))
          .map(emp => {
            const effective = dataService.getEffectiveGrades(emp.id, pdfMonth);
            const sum = effective.reduce((s, g) => s + g.score, 0);
            const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);
            const breakdown = Object.entries(EVALUATION_GROUPS).map(([gid, config]) => {
              const gGrades = effective.filter(g => g.group === gid);
              const gAvg = gGrades.length > 0 ? Math.round(gGrades.reduce((s, g) => s + g.score, 0) / config.categories.length) : 0;
              return `${config.name.charAt(0)}: ${gAvg}%`;
            }).join(' | ');

            return [
              emp.id,
              emp.name,
              emp.title,
              emp.join_date,
              `${avg}%`,
              breakdown
            ];
          });

        autoTable(doc, {
          head: [['ID', 'NOMBRE', 'CARGO', 'INGRESO', 'NOTA', 'DESGLOSE']],
          body: tableData,
          startY: 25,
          theme: 'grid',
          styles: { fontSize: 7, cellPadding: 2 },
          headStyles: { fillColor: primaryRed, fontStyle: 'bold' },
          columnStyles: {
            0: { cellWidth: 20 },
            1: { cellWidth: 45 },
            2: { cellWidth: 35 },
            3: { cellWidth: 20 },
            4: { cellWidth: 15, fontStyle: 'bold' },
            5: { cellWidth: 'auto' }
          }
        });

        doc.save(`Curvas (${selectedStore.name}),(${pdfMonth}).pdf`);
        setShowPdfModal(false);
      } catch (err) {
        console.error(err);
        alert("Error al generar el PDF.");
      } finally {
        setIsGeneratingPdf(false);
      }
    }, 150);
  };

  const selectClasses = "p-3 bg-white border-2 border-slate-100 rounded-xl text-[10px] font-black uppercase text-slate-800 outline-none focus:border-red-500 transition-all shadow-sm";

  if (selectedStore) {
    const stats = getStoreStats(selectedStore.id, selectedMonth);
    const storeEmps = employees
      .filter(e => e.restaurant_id === selectedStore.id && (user.role === UserRole.ADMIN ? true : e.active))
      .filter(e => empSearch === '' || e.name.toLowerCase().includes(empSearch.toLowerCase()) || e.id.includes(empSearch))
      .sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));

    return (
      <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center space-x-4">
            <button type="button" onClick={() => { setSelectedStore(null); setEmpSearch(''); }} className="p-3 bg-white border-2 border-slate-100 rounded-2xl text-slate-400 hover:text-red-600 transition-all shadow-sm relative z-20"><ArrowLeft className="w-5 h-5" /></button>
            <div className="min-w-0">
              <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tighter uppercase italic leading-none truncate">{selectedStore.name}</h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-widest flex items-center mt-2 truncate"><MapPin className="w-3 h-3 mr-1.5 text-red-500" /> {selectedStore.zone} • {selectedStore.region}</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              type="button"
              onClick={(e) => { e.preventDefault(); e.stopPropagation(); setPdfMonth(selectedMonth); setShowPdfModal(true); }}
              className="flex items-center gap-2 px-6 py-3.5 bg-red-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-red-700 transition-all shadow-lg relative z-20"
            >
              <FileText className="w-4 h-4" /> <span>Reporte PDF</span>
            </button>
            <div className="relative w-full md:w-72">
              <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
              <input 
                type="text" 
                placeholder="Buscar..." 
                value={empSearch}
                onChange={e => setEmpSearch(e.target.value)}
                className="w-full pl-12 pr-4 py-3.5 bg-white border-2 border-slate-100 rounded-2xl text-xs font-black shadow-sm outline-none focus:border-red-500 transition-all relative z-0" 
              />
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <DetailStatCard icon={<Users className="w-6 h-6" />} label="Equipo Activo" value={stats.total} color="blue" />
          <DetailStatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approved} color="green" />
          <DetailStatCard icon={<TrendingUp className="w-6 h-6" />} label="Éxito Tienda" value={`${stats.percent}%`} color="red" />
        </div>

        <div className="bg-white rounded-[32px] md:rounded-[40px] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b border-slate-50 flex justify-between items-center">
             <h3 className="text-[10px] font-black uppercase italic tracking-widest flex items-center">
               <Users className="w-4 h-4 mr-2 text-red-600" /> Listado con Arrastre
             </h3>
             <span className="text-[8px] font-black bg-slate-100 px-3 py-1.5 rounded-full uppercase text-slate-400 hidden sm:inline">Prioridad por Cargo</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50">
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Certificación</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Cargo</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {storeEmps.map(emp => {
                  const effective = dataService.getEffectiveGrades(emp.id, selectedMonth);
                  const sum = effective.reduce((s, g) => s + g.score, 0);
                  const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);
                  const status = effective.length === 0 ? 'PENDING' : (avg >= APPROVAL_THRESHOLD ? 'APPROVED' : 'FAILED');
                  return (
                    <tr key={emp.id} className="hover:bg-slate-50/80 transition-all group">
                      <td className="px-4 md:px-8 py-4 text-center">
                        <button 
                          type="button"
                          onClick={() => setEditingEmployee(emp)} 
                          className="px-4 py-3 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-red-600 shadow-lg transition-all uppercase tracking-widest flex items-center justify-center gap-2 mx-auto"
                        >
                          <Edit3 className="w-4 h-4" />
                          <span className="hidden sm:inline">Calificar</span>
                        </button>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex items-center gap-3">
                          <div className="w-9 h-9 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-colors hidden sm:flex">
                            <UserIcon className="w-4 h-4" />
                          </div>
                          <div>
                            <p className="font-black text-slate-800 text-[12px] uppercase italic leading-tight group-hover:text-red-600 transition-colors">{emp.name}</p>
                            <p className="text-[8px] text-slate-400 font-black uppercase tracking-widest mt-0.5">ID: {emp.id}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex flex-col">
                          <span className={`text-[9px] font-black uppercase px-2 py-1 rounded-lg w-fit ${status === 'APPROVED' ? 'bg-emerald-50 text-emerald-600' : status === 'FAILED' ? 'bg-red-50 text-red-600' : 'bg-slate-100 text-slate-400'}`}>
                            {status === 'APPROVED' ? 'Certificado' : status === 'FAILED' ? 'No Certificado' : 'Sin Nota'}
                          </span>
                          {status !== 'PENDING' && <span className="text-[7px] font-black text-slate-300 uppercase mt-1">Promedio: {avg}%</span>}
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <span className="text-[10px] font-black text-slate-700 uppercase italic tracking-tight">{emp.title}</span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
        {editingEmployee && <GradeEditor employee={editingEmployee} month={selectedMonth} onClose={() => { setEditingEmployee(null); onUpdate(); }} />}

        {/* MODAL REDISEÑADO PARA EVITAR BUGS DE FECHA */}
        {showPdfModal && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-950/90 backdrop-blur-md p-4 animate-in fade-in duration-300">
            <div className="bg-white rounded-[48px] shadow-2xl w-full max-w-md overflow-hidden border-2 border-white/20 relative">
              <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-red-600 rounded-2xl shadow-xl shadow-red-900/20">
                    <FileText className="w-6 h-6 text-white" />
                  </div>
                  <h3 className="font-black uppercase italic tracking-tighter text-xl">Generar Curvas</h3>
                </div>
                <button type="button" onClick={() => setShowPdfModal(false)} className="p-2 bg-white/10 hover:bg-white/20 rounded-xl transition-all relative z-50">
                  <X className="w-6 h-6"/>
                </button>
              </div>

              <div className="p-10 space-y-8 bg-white relative z-10">
                <div className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1 flex items-center gap-2">
                    <Calendar className="w-3 h-3 text-red-500" /> Seleccionar Periodo
                  </label>
                  <div className="relative group">
                    <input 
                      type="month" 
                      value={pdfMonth} 
                      onChange={e => setPdfMonth(e.target.value)}
                      className="w-full px-6 py-5 bg-slate-50 border-2 border-slate-100 rounded-3xl text-sm font-black text-slate-900 outline-none focus:border-red-500 focus:bg-white transition-all shadow-inner" 
                    />
                  </div>
                </div>

                <div className="bg-slate-50 p-6 rounded-[32px] space-y-4 border border-slate-100">
                   <p className="text-[10px] font-black uppercase text-slate-400 italic tracking-widest">Vista Previa:</p>
                   <div className="flex justify-between items-center"><span className="text-[10px] font-black uppercase text-slate-500">Tienda</span><span className="text-[12px] font-black uppercase text-slate-900 truncate max-w-[140px]">{selectedStore.name}</span></div>
                   <div className="flex justify-between items-center"><span className="text-[10px] font-black uppercase text-slate-500">Formato</span><span className="text-[10px] font-black uppercase text-red-600">Vertical A4</span></div>
                </div>

                <button 
                  type="button"
                  onClick={handleGeneratePDF}
                  disabled={isGeneratingPdf}
                  className="w-full py-6 bg-red-600 text-white font-black rounded-[32px] hover:bg-red-700 shadow-2xl shadow-red-500/30 transition-all uppercase tracking-[0.2em] text-[11px] flex items-center justify-center gap-4 relative z-50 disabled:grayscale disabled:opacity-50"
                >
                  {isGeneratingPdf ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
                  {isGeneratingPdf ? 'Construyendo PDF...' : 'Descargar Reporte'}
                </button>
              </div>

              <div className="p-4 bg-slate-50 text-center border-t border-slate-100">
                <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest">Reporte Oficial La Akademia v3.0</p>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
          <select value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
          <select value={filterZone} onChange={(e) => setFilterZone(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
          </select>
        </div>
        <div className="md:col-span-2 space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Buscar Tienda</label>
          <input 
            type="text" 
            placeholder="CECO o Nombre..." 
            value={storeSearch}
            onChange={e => setStoreSearch(e.target.value)}
            className="w-full p-3.5 bg-slate-50 border-2 border-slate-100 rounded-xl text-xs font-black uppercase shadow-inner outline-none focus:bg-white focus:border-red-500 transition-all" 
          />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {assigned.map(store => {
          const stats = getStoreStats(store.id, selectedMonth);
          return (
            <div key={store.id} onClick={() => setSelectedStore(store)} className="bg-white rounded-[32px] shadow-sm border-2 border-slate-50 overflow-hidden hover:border-red-500 hover:shadow-2xl hover:shadow-red-50 transition-all group cursor-pointer flex flex-col p-8">
              <div className="flex items-start justify-between mb-8">
                <div className="flex items-center space-x-4">
                  <div className="w-14 h-14 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400 group-hover:bg-red-600 group-hover:text-white transition-all shadow-inner"><Store className="w-7 h-7" /></div>
                  <div className="min-w-0">
                    <h3 className="font-black text-slate-800 text-lg truncate uppercase tracking-tighter leading-tight italic">{store.name}</h3>
                    <p className="text-[9px] text-slate-400 font-black uppercase truncate tracking-widest mt-1">{store.region} • {store.zone}</p>
                  </div>
                </div>
              </div>
              <div className="mt-auto grid grid-cols-2 gap-4">
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Equipo Activo</p><p className="text-xl font-black text-slate-800 tracking-tighter">{stats.total}</p></div>
                 <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100 text-center transition-colors group-hover:bg-white"><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Éxito</p><p className={`text-xl font-black tracking-tighter ${stats.percent >= 90 ? 'text-emerald-600' : 'text-red-600'}`}>{stats.percent}%</p></div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

