};

export default MyStores;

import React, { useMemo, useState } from 'react';
import { Employee, GradeEntry, User, Restaurant, UserRole } from '../types';
import { dataService } from '../dataService';
import { EVALUATION_GROUPS, APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, LabelList } from 'recharts';
import { XCircle, Users, Award, TrendingUp, Search, MapPin, Filter, Download, X, Check, FileText } from 'lucide-react';
import * as XLSX from 'xlsx';

interface DashboardProps {
  employees: Employee[];
  restaurants: Restaurant[];
  selectedMonth: string;
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ employees: initialEmployees, restaurants, selectedMonth, user }) => {
  const [searchPerson, setSearchPerson] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');
  const [filterStore, setFilterStore] = useState('all');

  const [showExportModal, setShowExportModal] = useState(false);
  const [exportConfig, setExportConfig] = useState({
    groups: Object.keys(EVALUATION_GROUPS),
    includeDetails: false
  });

  const allGrades = useMemo(() => dataService.getGrades(), []);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);

  const dynamicZones = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') baseStores = baseStores.filter(r => r.region === filterRegion);
    let zones = Array.from(new Set(baseStores.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) zones = zones.filter(z => user.assignedZones.includes(z));
    return zones;
  }, [restaurants, filterRegion, user]);

  const dynamicStores = useMemo(() => {
    let baseStores = restaurants;
    if (filterRegion !== 'all') baseStores = baseStores.filter(r => r.region === filterRegion);
    if (filterZone !== 'all') baseStores = baseStores.filter(r => r.zone === filterZone);
    if (user.role === UserRole.SPECIALIST) baseStores = baseStores.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));
    return baseStores.sort((a, b) => a.name.localeCompare(b.name));
  }, [restaurants, filterRegion, filterZone, user]);

  const employeesWithEffectiveGrades = useMemo(() => {
    return initialEmployees.map(emp => {
      const effectiveGrades = dataService.getEffectiveGrades(emp.id, selectedMonth);
      const exactMonthGrades = effectiveGrades.filter(g => g.month === selectedMonth);
      const storeIdAtPeriod = exactMonthGrades.length > 0 ? exactMonthGrades[0].restaurantId : emp.restaurant_id;
      const sum = effectiveGrades.reduce((s, g) => s + g.score, 0);
      const avg = TOTAL_CATEGORIES_COUNT > 0 ? Math.round(sum / TOTAL_CATEGORIES_COUNT) : 0;
      const isApproved = effectiveGrades.length > 0 && avg >= APPROVAL_THRESHOLD;
      const isPending = effectiveGrades.length === 0;

      return {
        ...emp,
        effectiveGrades,
        storeIdAtPeriod,
        avg,
        isApproved,
        isPending
      };
    });
  }, [initialEmployees, selectedMonth, allGrades]);

  const filteredData = useMemo(() => {
    return employeesWithEffectiveGrades.filter(e => {
      const store = restaurants.find(r => r.id === e.storeIdAtPeriod);
      const matchPerson = searchPerson === '' || e.name.toLowerCase().includes(searchPerson.toLowerCase()) || e.id.includes(searchPerson);
      const matchRegion = filterRegion === 'all' || store?.region === filterRegion;
      const matchZone = filterZone === 'all' || store?.zone === filterZone;
      const matchStore = filterStore === 'all' || e.storeIdAtPeriod === filterStore;

      return matchPerson && matchStore && matchZone && matchRegion;
    });
  }, [employeesWithEffectiveGrades, searchPerson, filterStore, filterZone, filterRegion, restaurants]);

  const stats = useMemo(() => {
    const totalEmployees = filteredData.length;
    const approvedCount = filteredData.filter(e => e.isApproved).length;

    const groupAvgs = Object.keys(EVALUATION_GROUPS).map(groupId => {
      const groupData = (EVALUATION_GROUPS as any)[groupId];
      let totalScores = 0;
      let totalCatsPossible = filteredData.length * groupData.categories.length;

      filteredData.forEach(e => {
        const groupGrades = e.effectiveGrades.filter(g => g.group === groupId);
        totalScores += groupGrades.reduce((s, g) => s + g.score, 0);
      });

      const avg = totalCatsPossible > 0 ? totalScores / totalCatsPossible : 0;
      return { id: groupId, name: groupData.name, avg: Math.round(avg) };
    });

    return { totalEmployees, approvedCount, groupAvgs };
  }, [filteredData]);

  const toggleExportGroup = (groupId: string) => {
    setExportConfig(prev => ({
      ...prev,
      groups: prev.groups.includes(groupId)
        ? prev.groups.filter(id => id !== groupId)
        : [...prev.groups, groupId]
    }));
  };

  const handleExportFinal = () => {
    const exportData = filteredData.map(emp => {
      const empStore = restaurants.find(r => r.id === emp.storeIdAtPeriod);
      const dynamicColumns: any = {};

      exportConfig.groups.forEach(gid => {
        const gConfig = (EVALUATION_GROUPS as any)[gid];
        const gGrades = emp.effectiveGrades.filter(g => g.group === gid);
        const sum = gGrades.reduce((s, g) => s + g.score, 0);
        const avg = gConfig.categories.length > 0 ? Math.round(sum / gConfig.categories.length) : 0;
        dynamicColumns[`${gConfig.name} %`] = `${avg}%`;

        if (exportConfig.includeDetails) {
          gConfig.categories.forEach((cat: string) => {
            const grade = gGrades.find(g => g.category === cat);
            dynamicColumns[`[${gConfig.name}] ${cat}`] = grade ? `${grade.score}%` : '0%';
          });
        }
      });

      return {
        "Documento": emp.id,
        "Nombre completo": emp.name,
        "Estado": emp.active ? "Activo" : "Retirado",
        "Cargo": emp.title,
        "Tienda Reportada": empStore?.name || emp.storeIdAtPeriod,
        "Ceco": emp.storeIdAtPeriod,
        "Jefe de area": empStore?.zone || emp.zone,
        "Mes Reporte": selectedMonth,
        "Promedio General": `${emp.avg}%`,
        "Certificación": emp.isPending ? 'Pendiente' : (emp.isApproved ? 'Aprobado' : 'No Cumple'),
        "Origen Nota": emp.isPending ? 'N/A' : (emp.effectiveGrades.some(g => g.month === selectedMonth) ? 'Mes Actual' : 'Heredada'),
        ...dynamicColumns
      };
    });

    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Reporte_Akademia");
    XLSX.writeFile(wb, `Reporte_Akademia_${selectedMonth}.xlsx`);
    setShowExportModal(false);
  };

  const selectClasses = "w-full p-3 bg-white border-2 border-slate-100 rounded-xl text-xs font-black uppercase text-slate-800 outline-none focus:border-red-500 transition-all shadow-sm";

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6 items-end">
        {user.role === UserRole.ADMIN && (
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1"><MapPin className="w-3 h-3 mr-1 inline" /> Región</label>
            <select value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)} className={selectClasses}>
              <option value="all">Todas</option>
              {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
            </select>
          </div>
        )}
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1"><Filter className="w-3 h-3 mr-1 inline" /> Zona</label>
          <select value={filterZone} onChange={(e) => setFilterZone(e.target.value)} className={selectClasses}>
            <option value="all">Todas</option>
            {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1"><Filter className="w-3 h-3 mr-1 inline" /> Tienda</label>
          <select value={filterStore} onChange={(e) => setFilterStore(e.target.value)} className={selectClasses}>
            <option value="all">Todas</option>
            {dynamicStores.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1"><Search className="w-3 h-3 mr-1 inline" /> Persona</label>
          <input type="text" placeholder="Nombre o ID..." value={searchPerson} onChange={(e) => setSearchPerson(e.target.value)} className="w-full p-3 bg-white border-2 border-slate-100 rounded-xl text-xs font-black uppercase text-slate-800" />
        </div>
        <button onClick={() => setShowExportModal(true)} className="w-full flex items-center justify-center space-x-2 px-4 py-3.5 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-black transition-all shadow-lg">
          <Download className="w-4 h-4" /> <span>Exportar Excel</span>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard icon={<Users className="w-6 h-6" />} label="Equipo" value={stats.totalEmployees} subValue={`Trabajadores en ${selectedMonth}`} />
        <StatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approvedCount} subValue="Nivel de Excelencia" color="green" />
        <StatCard icon={<TrendingUp className="w-6 h-6" />} label="Promedio" value={`${stats.groupAvgs.length > 0 ? Math.round(stats.groupAvgs.reduce((s, g) => s + g.avg, 0) / stats.groupAvgs.length) : 0}%`} subValue="General" color="blue" />
        <StatCard icon={<XCircle className="w-6 h-6" />} label="Pendientes" value={filteredData.filter(e => e.isPending).length} subValue="Sin ninguna nota grabada" color="red" />
      </div>

      <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
        <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center mb-8"><TrendingUp className="w-4 h-4 mr-2 text-red-500" /> Desempeño por Grupo</h3>
        <div className="h-[300px]">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={stats.groupAvgs} margin={{ top: 20, right: 0, left: -25, bottom: 0 }}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
              <YAxis domain={[0, 100]} axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
              <Tooltip cursor={{ fill: '#f8fafc' }} />
              <Bar dataKey="avg" radius={[10, 10, 0, 0]} barSize={45}>
                <LabelList dataKey="avg" position="top" formatter={(v: any) => `${v}%`} style={{ fontSize: '10px', fontWeight: '900', fill: '#64748b' }} />
                {stats.groupAvgs.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.avg >= APPROVAL_THRESHOLD ? '#10b981' : '#ef4444'} />)}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {showExportModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-4 animate-in fade-in duration-300">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-lg overflow-hidden border-2 border-white/20">
            <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
              <div className="flex items-center gap-4">
                <FileText className="w-6 h-6 text-red-500" />
                <h3 className="font-black uppercase italic tracking-tighter text-xl">Configurar Exportación</h3>
              </div>
              <button onClick={() => setShowExportModal(false)}><X className="w-6 h-6"/></button>
            </div>
            <div className="p-8 space-y-6">
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Grupos a incluir</label>
                <div className="grid grid-cols-2 gap-2">
                  {Object.entries(EVALUATION_GROUPS).map(([id, group]) => (
                    <button
                      key={id}
                      onClick={() => toggleExportGroup(id)}
                      className={`flex items-center gap-3 p-3 rounded-2xl text-[10px] font-black uppercase transition-all ${exportConfig.groups.includes(id) ? 'bg-red-50 border-2 border-red-500 text-red-600' : 'bg-slate-50 border-2 border-transparent text-slate-400'}`}
                    >
                      <div className={`w-4 h-4 rounded flex items-center justify-center ${exportConfig.groups.includes(id) ? 'bg-red-600 text-white' : 'bg-slate-200'}`}>
                        {exportConfig.groups.includes(id) && <Check className="w-3 h-3" />}
                      </div>
                      {group.name}
                    </button>
                  ))}
                </div>
              </div>

              <div className="p-4 bg-slate-50 rounded-2xl flex items-center justify-between">
                <div>
                  <p className="text-[10px] font-black uppercase text-slate-900">Incluir detalle por categoría</p>
                  <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Saca notas individuales por item</p>
                </div>
                <button 
                  onClick={() => setExportConfig(prev => ({ ...prev, includeDetails: !prev.includeDetails }))}
                  className={`w-12 h-6 rounded-full transition-all relative ${exportConfig.includeDetails ? 'bg-emerald-500' : 'bg-slate-300'}`}
                >
                  <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${exportConfig.includeDetails ? 'left-7' : 'left-1'}`} />
                </button>
              </div>

              <button 
                onClick={handleExportFinal} 
                className="w-full py-4 bg-red-600 text-white font-black rounded-2xl hover:bg-red-700 shadow-xl transition-all uppercase tracking-widest text-xs"
              >
                Generar Reporte Excel
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const StatCard: React.FC<{ icon: React.ReactNode, label: string, value: string | number, subValue: string, color?: string }> = ({ icon, label, value, subValue, color = 'gray' }) => {
  const colorMap: any = { red: 'bg-red-50 text-red-600', green: 'bg-emerald-50 text-emerald-600', blue: 'bg-blue-50 text-blue-600', gray: 'bg-slate-50 text-slate-600' };
  return (
    <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 transition-transform hover:scale-[1.02]">
      <div className="flex items-center space-x-5">
        <div className={`p-4 rounded-2xl ${colorMap[color]}`}>{icon}</div>
        <div>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-1">{label}</p>
          <h4 className="text-3xl font-black text-slate-800 tracking-tighter leading-none">{value}</h4>
          <p className="text-[10px] text-slate-400 font-bold mt-2">{subValue}</p>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useMemo, useState } from 'react';
import { User, Restaurant, Employee, UserRole, JobHierarchy, JobTitle } from '../types';
import { Store, MapPin, Users, Award, ArrowLeft, User as UserIcon, TrendingUp, Briefcase, Search, Filter, Edit3, FileText, Download, X, Calendar, RefreshCw } from 'lucide-react';
import { dataService } from '../dataService';
import { APPROVAL_THRESHOLD, TOTAL_CATEGORIES_COUNT, EVALUATION_GROUPS } from '../constants';
import GradeEditor from './GradeEditor';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

interface MyStoresProps {
  user: User;
  restaurants: Restaurant[];
  employees: Employee[];
  selectedMonth: string;
  onUpdate: () => void;
}

const MyStores: React.FC<MyStoresProps> = ({ user, restaurants, employees, selectedMonth, onUpdate }) => {
  const [selectedStore, setSelectedStore] = useState<Restaurant | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [storeSearch, setStoreSearch] = useState('');
  const [empSearch, setEmpSearch] = useState('');
  const [filterRegion, setFilterRegion] = useState('all');
  const [filterZone, setFilterZone] = useState('all');

  const [showPdfModal, setShowPdfModal] = useState(false);
  const [pdfMonth, setPdfMonth] = useState(selectedMonth);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  const dynamicRegions = useMemo(() => Array.from(new Set(restaurants.map(r => r.region))).filter(Boolean).sort(), [restaurants]);
  const dynamicZones = useMemo(() => {
    let base = restaurants;
    if (filterRegion !== 'all') base = base.filter(r => r.region === filterRegion);
    let zones = Array.from(new Set(base.map(r => r.zone))).filter(Boolean).sort();
    if (user.role === UserRole.SPECIALIST) zones = zones.filter(z => user.assignedZones.includes(z));
    return zones;
  }, [restaurants, filterRegion, user]);

  const assigned = useMemo(() => {
    let base = user.role === UserRole.ADMIN 
      ? restaurants 
      : restaurants.filter(r => user.assignedRestaurants.includes(r.id) || user.assignedZones.includes(r.zone));

    return base.filter(r => {
      const matchSearch = storeSearch === '' || r.name.toLowerCase().includes(storeSearch.toLowerCase()) || r.id.includes(storeSearch);
      const matchRegion = filterRegion === 'all' || r.region === filterRegion;
      const matchZone = filterZone === 'all' || r.zone === filterZone;
      return matchSearch && matchRegion && matchZone;
    });
  }, [user, restaurants, storeSearch, filterRegion, filterZone]);

  const getStoreStatsForMonth = (storeId: string, month: string) => {
    const storeEmps = employees.filter(e => e.restaurant_id === storeId && e.active);
    if (storeEmps.length === 0) return { total: 0, approved: 0, percent: 0, groupAvgs: {} as Record<string, number>, cargoCounts: {} as Record<string, number> };

    let approved = 0;
    const groupTotals: Record<string, { sum: number, count: number }> = {};
    const cargoCounts: Record<string, number> = {};

    storeEmps.forEach(emp => {
      cargoCounts[emp.title] = (cargoCounts[emp.title] || 0) + 1;
      const effective = dataService.getEffectiveGrades(emp.id, month);
      const sum = effective.reduce((s, g) => s + g.score, 0);
      const avg = TOTAL_CATEGORIES_COUNT > 0 ? sum / TOTAL_CATEGORIES_COUNT : 0;
      if (effective.length > 0 && avg >= APPROVAL_THRESHOLD) approved++;

      Object.entries(EVALUATION_GROUPS).forEach(([gid, gconfig]) => {
        const groupGrades = effective.filter(g => g.group === gid);
        const gSum = groupGrades.reduce((s, g) => s + g.score, 0);
        if (!groupTotals[gid]) groupTotals[gid] = { sum: 0, count: 0 };
        groupTotals[gid].sum += (gSum / gconfig.categories.length);
        groupTotals[gid].count++;
      });
    });

    const groupAvgs: Record<string, number> = {};
    Object.keys(EVALUATION_GROUPS).forEach(id => {
      groupAvgs[id] = groupTotals[id] ? Math.round(groupTotals[id].sum / groupTotals[id].count) : 0;
    });

    return { total: storeEmps.length, approved, percent: Math.round((approved / storeEmps.length) * 100), groupAvgs, cargoCounts };
  };

  const handleGeneratePDF = async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (!selectedStore || isGeneratingPdf) return;
    setIsGeneratingPdf(true);

    setTimeout(async () => {
      try {
        const doc = new jsPDF({ orientation: 'landscape', unit: 'mm', format: 'a4' });
        const year = pdfMonth.split('-')[0];
        const monthNames = ['ENE', 'FEB', 'MAR', 'ABR', 'MAY', 'JUN', 'JUL', 'AGO', 'SEP', 'OCT', 'NOV', 'DIC'];

        const colors = {
          red: [227, 24, 55],
          yellow: [255, 191, 0],
          green: [34, 197, 94],
          purple: [168, 85, 247],
          slate: [30, 41, 59],
          lightBlue: [219, 234, 254],
          grid: [235, 235, 235]
        };

        const currentYearStats = monthNames.map((_, i) => {
          const m = `${year}-${String(i + 1).padStart(2, '0')}`;
          return getStoreStatsForMonth(selectedStore.id, m);
        });

        const selectedIdx = parseInt(pdfMonth.split('-')[1]) - 1;
        const stats = currentYearStats[selectedIdx];
        const storeEmps = employees.filter(e => e.restaurant_id === selectedStore.id && e.active);

        const drawBadge = (x: number, y: number, text: string, color: number[]) => {
          doc.setFillColor(color[0], color[1], color[2]);
          doc.circle(x, y, 9, 'F');
          doc.setTextColor(255, 255, 255);
          doc.setFontSize(9);
          doc.setFont('helvetica', 'bold');
          const tw = doc.getTextWidth(text);
          doc.text(text, x - (tw / 2), y + 2.5);
        };

        const drawMiniChart = (x: number, y: number, w: number, h: number, gid: string, color: number[], title: string) => {
          doc.setDrawColor(220);
          doc.line(x, y + h, x + w, y + h); // Eje X
          doc.setTextColor(color[0], color[1], color[2]);
          doc.setFontSize(8);
          doc.setFont('helvetica', 'bold');
          doc.text(title, x, y - 5);

          monthNames.forEach((m, i) => {
            const barW = (w / 12) - 1.5;
            const barX = x + (i * (w / 12)) + 0.75;
            const val = currentYearStats[i].groupAvgs[gid] || 0;
            const barH = (val / 100) * h;
            doc.setFillColor(color[0], color[1], color[2]);
            doc.rect(barX, y + h - barH, barW, barH, 'F');
            doc.setFontSize(4);
            doc.setTextColor(150);
            doc.text(m, barX, y + h + 3);
          });
        };

        // --- PÁGINA 1: DASHBOARD ---
        doc.setDrawColor(colors.grid[0], colors.grid[1], colors.grid[2]);
        doc.setLineWidth(0.1);
        for (let i = 0; i < 297; i += 5) doc.line(i, 0, i, 210);
        for (let j = 0; j < 210; j += 5) doc.line(0, j, 297, j);

        doc.setFillColor(colors.lightBlue[0], colors.lightBlue[1], colors.lightBlue[2]);
        doc.rect(40, 10, 217, 12, 'F');
        doc.setTextColor(0, 0, 0);
        doc.setFontSize(16);
        doc.setFont('helvetica', 'bold');
        const headerText = `${selectedStore.name.toUpperCase()} - ${monthNames[selectedIdx]} ${year} | ÉXITO TOTAL: ${stats.percent}%`;
        doc.text(headerText, 148.5 - (doc.getTextWidth(headerText) / 2), 18);

        // Bloques del Dashboard
        const bW = 138, bH = 80;

        // Bloque 1: Estructura
        const b1X = 10, b1Y = 30;
        doc.setDrawColor(colors.red[0], colors.red[1], colors.red[2]);
        doc.setLineWidth(1);
        doc.roundedRect(b1X, b1Y, bW, bH, 8, 8, 'D');
        doc.text('ESTRUCTURA DE EQUIPO', b1X + 15, b1Y + 10);

        autoTable(doc, {
          startY: b1Y + 15, margin: { left: b1X + 5 }, tableWidth: 60,
          head: [['CARGO', 'CANT']],
          body: [
            ...Object.values(JobTitle).map(t => [t.toUpperCase(), stats.cargoCounts[t] || 0]),
            [{ content: 'TOTAL', styles: { fontStyle: 'bold' } }, { content: stats.total, styles: { fillColor: colors.red, textColor: 255 } }]
          ],
          theme: 'grid', styles: { fontSize: 6.5, halign: 'center' },
          headStyles: { fillColor: colors.red }
        });

        // Bloque 2: STAR (B)
        const b2X = 150, b2Y = 30;
        doc.setDrawColor(colors.yellow[0], colors.yellow[1], colors.yellow[2]);
        doc.roundedRect(b2X, b2Y, bW, bH, 8, 8, 'D');
        drawMiniChart(b2X + 10, b2Y + 25, 118, 45, 'B', colors.red, 'STAR (B) - HISTÓRICO');
        drawBadge(b2X + bW, b2Y, `${stats.groupAvgs['B']}%`, colors.yellow);

        // Bloque 3: ALL STAR (C) + PLAN SST (D)
        const b3X = 10, b3Y = 118;
        doc.setDrawColor(colors.green[0], colors.green[1], colors.green[2]);
        doc.roundedRect(b3X, b3Y, bW, bH, 8, 8, 'D');
        drawMiniChart(b3X + 10, b3Y + 25, 55, 45, 'C', colors.yellow, 'ALL STAR (C)');
        drawMiniChart(b3X + 75, b3Y + 25, 55, 45, 'D', colors.green, 'PLAN SST (D)');
        drawBadge(b3X + bW, b3Y, `${stats.groupAvgs['D']}%`, colors.green);

        // Bloque 4: THE VAULT (E)
        const b4X = 150, b4Y = 118;
        doc.setDrawColor(colors.purple[0], colors.purple[1], colors.purple[2]);
        doc.roundedRect(b4X, b4Y, bW, bH, 8, 8, 'D');
        drawMiniChart(b4X + 10, b4Y + 25, 118, 45, 'E', colors.purple, 'THE VAULT (E) - HISTÓRICO');
        drawBadge(b4X + bW, b4Y, `${stats.groupAvgs['E']}%`, colors.purple);

        // --- PÁGINA 2: TABLA DETALLADA ---
        doc.addPage();
        doc.setFillColor(colors.slate[0], colors.slate[1], colors.slate[2]);
        doc.rect(0, 0, 297, 15, 'F');
        doc.setTextColor(255, 255, 255);
        doc.setFontSize(10);
        doc.text(`NOTAS ESPECÍFICAS POR COLABORADOR - ${selectedStore.name} - ${pdfMonth}`, 15, 10);

        const tableData = storeEmps
          .sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99))
          .map(emp => {
            const effective = dataService.getEffectiveGrades(emp.id, pdfMonth);
            const sum = effective.reduce((s, g) => s + g.score, 0);
            const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);
            const getGA = (gid: string) => {
              const gConfig = (EVALUATION_GROUPS as any)[gid];
              const gGrades = effective.filter(g => g.group === gid);
              return gGrades.length > 0 ? `${Math.round(gGrades.reduce((s, g) => s + g.score, 0) / gConfig.categories.length)}%` : '0%';
            };
            return [emp.id, emp.name, emp.title, `${avg}%`, getGA('A'), getGA('B'), getGA('C'), getGA('D'), getGA('E')];
          });

        autoTable(doc, {
          head: [['ID', 'NOMBRE', 'CARGO', 'PROM.', 'BÁSICOS', 'STAR', 'ALLSTAR', 'SST', 'VAULT']],
          body: tableData, startY: 25, theme: 'grid', styles: { fontSize: 8, halign: 'center' },
          headStyles: { fillColor: colors.red },
          columnStyles: { 1: { halign: 'left', cellWidth: 50 }, 2: { halign: 'left', cellWidth: 35 } }
        });

        doc.save(`Reporte_Akademia_${selectedStore.name}_${pdfMonth}.pdf`);
        setShowPdfModal(false);
      } catch (err) {
        console.error(err);
        alert("Error al generar el reporte.");
      } finally {
        setIsGeneratingPdf(false);
      }
    }, 200);
  };

  const selectClasses = "p-3 bg-white border-2 border-slate-100 rounded-xl text-[10px] font-black uppercase text-slate-800 outline-none focus:border-red-500 transition-all shadow-sm";

  if (selectedStore) {
    const stats = getStoreStatsForMonth(selectedStore.id, selectedMonth);
    const storeEmps = employees
      .filter(e => e.restaurant_id === selectedStore.id && (user.role === UserRole.ADMIN ? true : e.active))
      .filter(e => empSearch === '' || e.name.toLowerCase().includes(empSearch.toLowerCase()) || e.id.includes(empSearch))
      .sort((a, b) => (JobHierarchy[a.title] || 99) - (JobHierarchy[b.title] || 99));

    return (
      <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center space-x-4">
            <button type="button" onClick={() => { setSelectedStore(null); setEmpSearch(''); }} className="p-3 bg-white border-2 border-slate-100 rounded-2xl text-slate-400 hover:text-red-600 transition-all shadow-sm relative z-20"><ArrowLeft className="w-5 h-5" /></button>
            <div className="min-w-0">
              <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tighter uppercase italic leading-none truncate">{selectedStore.name}</h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-widest flex items-center mt-2 truncate"><MapPin className="w-3 h-3 mr-1.5 text-red-500" /> {selectedStore.zone} • {selectedStore.region}</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              type="button"
              onClick={(e) => { e.preventDefault(); e.stopPropagation(); setPdfMonth(selectedMonth); setShowPdfModal(true); }}
              className="flex items-center gap-2 px-6 py-3.5 bg-red-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-red-700 transition-all shadow-lg relative z-20"
            >
              <FileText className="w-4 h-4" /> <span>Generar Reporte</span>
            </button>
            <div className="relative w-full md:w-72">
              <Search className="w-4 h-4 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2 z-10" />
              <input 
                type="text" 
                placeholder="Buscar..." 
                value={empSearch}
                onChange={e => setEmpSearch(e.target.value)}
                className="w-full pl-12 pr-4 py-3.5 bg-white border-2 border-slate-100 rounded-2xl text-xs font-black shadow-sm outline-none focus:border-red-500 transition-all relative z-0" 
              />
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <DetailStatCard icon={<Users className="w-6 h-6" />} label="Equipo Activo" value={stats.total} color="blue" />
          <DetailStatCard icon={<Award className="w-6 h-6" />} label="Certificados" value={stats.approved} color="green" />
          <DetailStatCard icon={<TrendingUp className="w-6 h-6" />} label="Éxito Tienda" value={`${stats.percent}%`} color="red" />
        </div>

        <div className="bg-white rounded-[32px] md:rounded-[40px] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b border-slate-50 flex justify-between items-center">
             <h3 className="text-[10px] font-black uppercase italic tracking-widest flex items-center">
               <Users className="w-4 h-4 mr-2 text-red-600" /> Personal de Tienda
             </h3>
             <span className="text-[8px] font-black bg-slate-100 px-3 py-1.5 rounded-full uppercase text-slate-400 hidden sm:inline">Prioridad Jerárquica</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50">
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Gestión</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Certificación</th>
                  <th className="px-4 md:px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Cargo</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {storeEmps.map(emp => {
                  const effective = dataService.getEffectiveGrades(emp.id, selectedMonth);
                  const sum = effective.reduce((s, g) => s + g.score, 0);
                  const avg = Math.round(sum / TOTAL_CATEGORIES_COUNT);
                  const status = effective.length === 0 ? 'PENDING' : (avg >= APPROVAL_THRESHOLD ? 'APPROVED' : 'FAILED');
                  return (
                    <tr key={emp.id} className="hover:bg-slate-50/80 transition-all group">
                      <td className="px-4 md:px-8 py-4 text-center">
                        <button 
                          type="button"
                          onClick={() => setEditingEmployee(emp)} 
                          className="px-4 py-3 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-red-600 shadow-lg transition-all uppercase tracking-widest flex items-center justify-center gap-2 mx-auto"
                        >
                          <Edit3 className="w-4 h-4" />
                          <span className="hidden sm:inline">Calificar</span>
                        </button>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex items-center gap-3">
                          <div className="w-9 h-9 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-red-50 group-hover:text-red-600 transition-colors hidden sm:flex">
                            <UserIcon className="w-4 h-4" />
                          </div>
                          <div>
                            <p className="font-black text-slate-800 text-[12px] uppercase italic leading-tight group-hover:text-red-600 transition-colors">{emp.name}</p>
                            <p className="text-[8px] text-slate-400 font-black uppercase tracking-widest mt-0.5">ID: {emp.id}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <div className="flex flex-col">
                          <span className={`text-[9px] font-black uppercase px-2 py-1 rounded-lg w-fit ${status === 'APPROVED' ? 'bg-emerald-50 text-emerald-600' : status === 'FAILED' ? 'bg-red-50 text-red-600' : 'bg-slate-100 text-slate-400'}`}>
                            {status === 'APPROVED' ? 'Certificado' : status === 'FAILED' ? 'No Certificado' : 'Sin Nota'}
                          </span>
                          {status !== 'PENDING' && <span className="text-[7px] font-black text-slate-300 uppercase mt-1">Promedio: {avg}%</span>}
                        </div>
                      </td>
                      <td className="px-4 md:px-8 py-4">
                        <span className="text-[10px] font-black text-slate-700 uppercase italic tracking-tight">{emp.title}</span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
        {editingEmployee && <GradeEditor employee={editingEmployee} month={selectedMonth} onClose={() => { setEditingEmployee(null); onUpdate(); }} />}

        {showPdfModal && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-950/90 backdrop-blur-md p-4 animate-in fade-in duration-300">
            <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-sm overflow-hidden border-2 border-white/20 relative">
              <div className="p-8 bg-slate-900 text-white flex justify-between items-center relative z-10">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-red-600 rounded-2xl shadow-xl shadow-red-900/20">
                    <FileText className="w-6 h-6 text-white" />
                  </div>
                  <h3 className="font-black uppercase italic tracking-tighter text-xl">Reporte Oficial</h3>
                </div>
                <button type="button" onClick={() => setShowPdfModal(false)} className="p-2 bg-white/10 hover:bg-white/20 rounded-xl transition-all">
                  <X className="w-5 h-5"/>
                </button>
              </div>

              <div className="p-10 space-y-8 bg-white relative z-10">
                <div className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1 flex items-center gap-2">
                    <Calendar className="w-3 h-3 text-red-500" /> Seleccionar Periodo
                  </label>
                  <div className="relative">
                    <input 
                      type="month" 
                      value={pdfMonth} 
                      onChange={e => setPdfMonth(e.target.value)}
                      className="w-full px-6 py-5 bg-slate-50 border-2 border-slate-100 rounded-3xl text-sm font-black text-slate-900 outline-none focus:border-red-500 focus:bg-white transition-all shadow-inner" 
                    />
                  </div>
                </div>

                <div className="bg-slate-50 p-6 rounded-[32px] space-y-4 border border-slate-100">
                   <div className="space-y-1">
                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Tienda</p>
                      <p className="text-xs font-black text-slate-800 uppercase italic truncate">{selectedStore.name}</p>
                   </div>
                   <div className="space-y-1">
                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Total Colaboradores</p>
                      <p className="text-xl font-black text-red-600">{stats.total}</p>
                   </div>
                </div>

                <button 
                  type="button"
                  onClick={handleGeneratePDF}
                  disabled={isGeneratingPdf}
                  className="w-full py-6 bg-red-600 text-white font-black rounded-[32px] hover:bg-red-700 shadow-2xl shadow-red-500/30 transition-all uppercase tracking-[0.2em] text-[11px] flex items-center justify-center gap-4 disabled:grayscale disabled:opacity-50"
                >
                  {isGeneratingPdf ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
                  {isGeneratingPdf ? 'Preparando...' : 'Descargar Reporte PDF'}
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Región</label>
          <select value={filterRegion} onChange={(e) => setFilterRegion(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicRegions.map(r => <option key={r} value={r}>{r}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Zona</label>
          <select value={filterZone} onChange={(e) => setFilterZone(e.target.value)} className={selectClasses + " w-full"}>
            <option value="all">Todas</option>
            {dynamicZones.map(z => <option key={z} value={z}>{z}</option>)}
          </select>
        </div>
        <div className="md:col-span-2 space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Buscar Tienda</label>
          <input 
            type="text" 
            placeholder="CECO o Nombre..." 
            value={storeSearch}
            onChange={e => setStoreSearch(e.target.value)}
            className="w-full p-3.5 bg-slate-50 border-2 border-slate-100 rounded-xl text-xs font-black uppercase shadow-inner outline-none focus:bg-white focus:border-red-500 transition-all" 
          />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {assigned.map(store => {
          const stats = getStoreStatsForMonth(store.id, selectedMonth);
          return (
